import { useQuery, useMutation } from "@tanstack/react-query";
import AdminSidebar from "@/components/AdminSidebar";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle, AlertDialogTrigger } from "@/components/ui/alert-dialog";
import { useState } from "react";
import { Plus, Building2, Users, Trash2, Edit } from "lucide-react";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { insertBrokerageSchema, insertUserSchema, type Brokerage, type User } from "@shared/schema";
import { z } from "zod";

type EnrichedBrokerage = Brokerage & {
  agentCount: number;
  clientCount: number;
  tourCount: number;
};

type EnrichedAgent = User & {
  brokerageName: string;
  clientCount: number;
  tourCount: number;
  upcomingTours: number;
  offerCount: number;
};

const brokerageFormSchema = insertBrokerageSchema.extend({
  name: z.string().min(1, "Brokerage name is required"),
});

const agentFormSchema = insertUserSchema.extend({
  email: z.string().email("Valid email is required"),
  firstName: z.string().min(1, "First name is required"),
  lastName: z.string().min(1, "Last name is required"),
  role: z.literal("agent"),
  brokerageId: z.string().optional(),
});

type BrokerageFormValues = z.infer<typeof brokerageFormSchema>;
type AgentFormValues = z.infer<typeof agentFormSchema>;

export default function AdminSettingsPage() {
  const { toast } = useToast();
  const [brokerageDialogOpen, setBrokerageDialogOpen] = useState(false);
  const [agentDialogOpen, setAgentDialogOpen] = useState(false);
  const [editingBrokerage, setEditingBrokerage] = useState<EnrichedBrokerage | null>(null);
  const [editingAgent, setEditingAgent] = useState<EnrichedAgent | null>(null);

  const brokerageForm = useForm<BrokerageFormValues>({
    resolver: zodResolver(brokerageFormSchema),
    defaultValues: {
      name: "",
      contactEmail: "",
      contactPhone: "",
      website: "",
      status: "active",
    },
  });

  const agentForm = useForm<AgentFormValues>({
    resolver: zodResolver(agentFormSchema),
    defaultValues: {
      email: "",
      firstName: "",
      lastName: "",
      role: "agent",
      brokerageId: "independent",
    },
  });

  const { data: brokerages, isLoading: brokeragesLoading } = useQuery<EnrichedBrokerage[]>({
    queryKey: ['/api/admin/brokerages'],
  });

  const { data: agents, isLoading: agentsLoading } = useQuery<EnrichedAgent[]>({
    queryKey: ['/api/admin/agents'],
  });

  const createBrokerageMutation = useMutation({
    mutationFn: async (data: BrokerageFormValues) => {
      return await apiRequest('/api/admin/brokerages', 'POST', data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/admin/brokerages'] });
      queryClient.invalidateQueries({ queryKey: ['/api/admin/kpis'] });
      setBrokerageDialogOpen(false);
      brokerageForm.reset();
      setEditingBrokerage(null);
      toast({ title: "Success", description: "Brokerage created successfully" });
    },
    onError: () => {
      toast({ title: "Error", description: "Failed to create brokerage", variant: "destructive" });
    }
  });

  const updateBrokerageMutation = useMutation({
    mutationFn: async ({ id, data }: { id: string; data: BrokerageFormValues }) => {
      return await apiRequest(`/api/admin/brokerages/${id}`, 'PUT', data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/admin/brokerages'] });
      queryClient.invalidateQueries({ queryKey: ['/api/admin/kpis'] });
      setBrokerageDialogOpen(false);
      brokerageForm.reset();
      setEditingBrokerage(null);
      toast({ title: "Success", description: "Brokerage updated successfully" });
    },
    onError: () => {
      toast({ title: "Error", description: "Failed to update brokerage", variant: "destructive" });
    }
  });

  const deleteBrokerageMutation = useMutation({
    mutationFn: async (id: string) => {
      return await apiRequest(`/api/admin/brokerages/${id}`, 'DELETE', {});
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/admin/brokerages'] });
      queryClient.invalidateQueries({ queryKey: ['/api/admin/kpis'] });
      toast({ title: "Success", description: "Brokerage deleted successfully" });
    },
    onError: () => {
      toast({ title: "Error", description: "Failed to delete brokerage", variant: "destructive" });
    }
  });

  const createAgentMutation = useMutation({
    mutationFn: async (data: AgentFormValues) => {
      const submitData = {
        ...data,
        brokerageId: data.brokerageId === "independent" ? undefined : data.brokerageId
      };
      return await apiRequest('/api/admin/agents', 'POST', submitData);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/admin/agents'] });
      queryClient.invalidateQueries({ queryKey: ['/api/admin/kpis'] });
      setAgentDialogOpen(false);
      agentForm.reset();
      setEditingAgent(null);
      toast({ title: "Success", description: "Agent created successfully" });
    },
    onError: () => {
      toast({ title: "Error", description: "Failed to create agent", variant: "destructive" });
    }
  });

  const updateAgentMutation = useMutation({
    mutationFn: async ({ id, data }: { id: string; data: AgentFormValues }) => {
      const submitData = {
        ...data,
        brokerageId: data.brokerageId === "independent" ? undefined : data.brokerageId
      };
      return await apiRequest(`/api/admin/agents/${id}`, 'PUT', submitData);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/admin/agents'] });
      queryClient.invalidateQueries({ queryKey: ['/api/admin/kpis'] });
      setAgentDialogOpen(false);
      agentForm.reset();
      setEditingAgent(null);
      toast({ title: "Success", description: "Agent updated successfully" });
    },
    onError: () => {
      toast({ title: "Error", description: "Failed to update agent", variant: "destructive" });
    }
  });

  const deleteAgentMutation = useMutation({
    mutationFn: async (id: string) => {
      return await apiRequest(`/api/admin/agents/${id}`, 'DELETE', {});
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/admin/agents'] });
      queryClient.invalidateQueries({ queryKey: ['/api/admin/kpis'] });
      toast({ title: "Success", description: "Agent deleted successfully" });
    },
    onError: () => {
      toast({ title: "Error", description: "Failed to delete agent", variant: "destructive" });
    }
  });

  const handleBrokerageSubmit = brokerageForm.handleSubmit((data) => {
    if (editingBrokerage) {
      updateBrokerageMutation.mutate({ id: editingBrokerage.id, data });
    } else {
      createBrokerageMutation.mutate(data);
    }
  });

  const handleAgentSubmit = agentForm.handleSubmit((data) => {
    if (editingAgent) {
      updateAgentMutation.mutate({ id: editingAgent.id, data });
    } else {
      createAgentMutation.mutate(data);
    }
  });

  const openEditBrokerage = (brokerage: EnrichedBrokerage) => {
    setEditingBrokerage(brokerage);
    brokerageForm.reset({
      name: brokerage.name,
      contactEmail: brokerage.contactEmail || "",
      contactPhone: brokerage.contactPhone || "",
      website: brokerage.website || "",
      status: brokerage.status || "active",
    });
    setBrokerageDialogOpen(true);
  };

  const openEditAgent = (agent: EnrichedAgent) => {
    setEditingAgent(agent);
    const brokerageId = agent.brokerageName === 'Independent' ? 'independent' : 
      (brokerages?.find((b) => b.name === agent.brokerageName)?.id || 'independent');
    agentForm.reset({
      email: agent.email || "",
      firstName: agent.firstName || "",
      lastName: agent.lastName || "",
      role: "agent",
      brokerageId: brokerageId,
    });
    setAgentDialogOpen(true);
  };

  const closeBrokerageDialog = () => {
    setBrokerageDialogOpen(false);
    brokerageForm.reset();
    setEditingBrokerage(null);
  };

  const closeAgentDialog = () => {
    setAgentDialogOpen(false);
    agentForm.reset();
    setEditingAgent(null);
  };

  return (
    <div className="flex">
      <AdminSidebar />
      <div className="flex-1 p-8 space-y-6" data-testid="admin-settings-page">
        <div>
          <h1 className="text-3xl font-bold" data-testid="heading-settings">Settings</h1>
          <p className="text-muted-foreground">Manage brokerages and agents</p>
        </div>

        <Tabs defaultValue="brokerages" className="w-full">
          <TabsList>
            <TabsTrigger value="brokerages" data-testid="tab-brokerages">
              <Building2 className="h-4 w-4 mr-2" />
              Brokerages
            </TabsTrigger>
            <TabsTrigger value="agents" data-testid="tab-agents">
              <Users className="h-4 w-4 mr-2" />
              Agents
            </TabsTrigger>
          </TabsList>

          <TabsContent value="brokerages" className="space-y-4">
            <div className="flex justify-end">
              <Dialog open={brokerageDialogOpen} onOpenChange={(open) => { if (!open) closeBrokerageDialog(); else setBrokerageDialogOpen(true); }}>
                <DialogTrigger asChild>
                  <Button data-testid="button-add-brokerage">
                    <Plus className="mr-2 h-4 w-4" />
                    Add Brokerage
                  </Button>
                </DialogTrigger>
                <DialogContent data-testid="dialog-brokerage">
                  <DialogHeader>
                    <DialogTitle>{editingBrokerage ? 'Edit Brokerage' : 'Add New Brokerage'}</DialogTitle>
                  </DialogHeader>
                  <Form {...brokerageForm}>
                    <form onSubmit={handleBrokerageSubmit} className="space-y-4">
                      <FormField
                        control={brokerageForm.control}
                        name="name"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Brokerage Name *</FormLabel>
                            <FormControl>
                              <Input {...field} data-testid="input-brokerage-name" />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                      <FormField
                        control={brokerageForm.control}
                        name="contactEmail"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Contact Email</FormLabel>
                            <FormControl>
                              <Input {...field} value={field.value || ""} data-testid="input-brokerage-email" />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                      <FormField
                        control={brokerageForm.control}
                        name="contactPhone"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Contact Phone</FormLabel>
                            <FormControl>
                              <Input {...field} value={field.value || ""} data-testid="input-brokerage-phone" />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                      <FormField
                        control={brokerageForm.control}
                        name="website"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Website</FormLabel>
                            <FormControl>
                              <Input {...field} value={field.value || ""} data-testid="input-brokerage-website" />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                      <div className="flex justify-end gap-2">
                        <Button type="button" variant="outline" onClick={closeBrokerageDialog} data-testid="button-cancel-brokerage">
                          Cancel
                        </Button>
                        <Button type="submit" disabled={createBrokerageMutation.isPending || updateBrokerageMutation.isPending} data-testid="button-submit-brokerage">
                          {editingBrokerage ? 'Update' : 'Create'}
                        </Button>
                      </div>
                    </form>
                  </Form>
                </DialogContent>
              </Dialog>
            </div>

            <Card>
              <CardContent className="p-6">
                {brokeragesLoading ? (
                  <div className="animate-pulse space-y-2">
                    {[...Array(3)].map((_, i) => (
                      <div key={i} className="h-16 bg-muted rounded"></div>
                    ))}
                  </div>
                ) : (
                  <div className="rounded-lg border">
                    <table className="w-full">
                      <thead className="bg-muted/50">
                        <tr>
                          <th className="text-left p-4 font-medium">Name</th>
                          <th className="text-left p-4 font-medium">Contact Email</th>
                          <th className="text-left p-4 font-medium">Contact Phone</th>
                          <th className="text-left p-4 font-medium">Agents</th>
                          <th className="text-left p-4 font-medium">Status</th>
                          <th className="text-right p-4 font-medium">Actions</th>
                        </tr>
                      </thead>
                      <tbody>
                        {brokerages && brokerages.length > 0 ? (
                          brokerages.map((brokerage) => (
                            <tr key={brokerage.id} className="border-t hover:bg-muted/50" data-testid={`row-brokerage-${brokerage.id}`}>
                              <td className="p-4 font-medium" data-testid={`text-brokerage-name-${brokerage.id}`}>{brokerage.name}</td>
                              <td className="p-4 text-muted-foreground">{brokerage.contactEmail || '-'}</td>
                              <td className="p-4 text-muted-foreground">{brokerage.contactPhone || '-'}</td>
                              <td className="p-4">{brokerage.agentCount}</td>
                              <td className="p-4">
                                <span className={`px-2 py-1 rounded text-xs ${
                                  brokerage.status === 'active' 
                                    ? 'bg-green-100 text-green-800' 
                                    : 'bg-red-100 text-red-800'
                                }`}>
                                  {brokerage.status || 'active'}
                                </span>
                              </td>
                              <td className="p-4">
                                <div className="flex justify-end gap-2">
                                  <Button
                                    variant="outline"
                                    size="sm"
                                    onClick={() => openEditBrokerage(brokerage)}
                                    data-testid={`button-edit-brokerage-${brokerage.id}`}
                                  >
                                    <Edit className="h-4 w-4" />
                                  </Button>
                                  <AlertDialog>
                                    <AlertDialogTrigger asChild>
                                      <Button
                                        variant="outline"
                                        size="sm"
                                        data-testid={`button-delete-brokerage-${brokerage.id}`}
                                      >
                                        <Trash2 className="h-4 w-4 text-red-600" />
                                      </Button>
                                    </AlertDialogTrigger>
                                    <AlertDialogContent>
                                      <AlertDialogHeader>
                                        <AlertDialogTitle>Delete Brokerage</AlertDialogTitle>
                                        <AlertDialogDescription>
                                          Are you sure you want to delete "{brokerage.name}"? This will also remove all agent associations with this brokerage. This action cannot be undone.
                                        </AlertDialogDescription>
                                      </AlertDialogHeader>
                                      <AlertDialogFooter>
                                        <AlertDialogCancel data-testid="button-cancel-delete-brokerage">Cancel</AlertDialogCancel>
                                        <AlertDialogAction
                                          onClick={() => deleteBrokerageMutation.mutate(brokerage.id)}
                                          className="bg-red-600 hover:bg-red-700"
                                          data-testid="button-confirm-delete-brokerage"
                                        >
                                          Delete
                                        </AlertDialogAction>
                                      </AlertDialogFooter>
                                    </AlertDialogContent>
                                  </AlertDialog>
                                </div>
                              </td>
                            </tr>
                          ))
                        ) : (
                          <tr>
                            <td colSpan={6} className="p-8 text-center text-muted-foreground">
                              No brokerages found. Create your first brokerage to get started.
                            </td>
                          </tr>
                        )}
                      </tbody>
                    </table>
                  </div>
                )}
              </CardContent>
            </Card>
          </TabsContent>

          <TabsContent value="agents" className="space-y-4">
            <div className="flex justify-end">
              <Dialog open={agentDialogOpen} onOpenChange={(open) => { if (!open) closeAgentDialog(); else setAgentDialogOpen(true); }}>
                <DialogTrigger asChild>
                  <Button data-testid="button-add-agent">
                    <Plus className="mr-2 h-4 w-4" />
                    Add Agent
                  </Button>
                </DialogTrigger>
                <DialogContent data-testid="dialog-agent">
                  <DialogHeader>
                    <DialogTitle>{editingAgent ? 'Edit Agent' : 'Add New Agent'}</DialogTitle>
                  </DialogHeader>
                  <Form {...agentForm}>
                    <form onSubmit={handleAgentSubmit} className="space-y-4">
                      <FormField
                        control={agentForm.control}
                        name="email"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Email *</FormLabel>
                            <FormControl>
                              <Input {...field} type="email" data-testid="input-agent-email" />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                      <FormField
                        control={agentForm.control}
                        name="firstName"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>First Name *</FormLabel>
                            <FormControl>
                              <Input {...field} data-testid="input-agent-firstname" />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                      <FormField
                        control={agentForm.control}
                        name="lastName"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Last Name *</FormLabel>
                            <FormControl>
                              <Input {...field} data-testid="input-agent-lastname" />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                      <FormField
                        control={agentForm.control}
                        name="brokerageId"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Brokerage</FormLabel>
                            <Select
                              value={field.value}
                              onValueChange={field.onChange}
                            >
                              <FormControl>
                                <SelectTrigger data-testid="select-agent-brokerage">
                                  <SelectValue placeholder="Select brokerage" />
                                </SelectTrigger>
                              </FormControl>
                              <SelectContent>
                                <SelectItem value="independent">Independent Agent</SelectItem>
                                {brokerages?.map((brokerage) => (
                                  <SelectItem key={brokerage.id} value={brokerage.id}>
                                    {brokerage.name}
                                  </SelectItem>
                                ))}
                              </SelectContent>
                            </Select>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                      <div className="flex justify-end gap-2">
                        <Button type="button" variant="outline" onClick={closeAgentDialog} data-testid="button-cancel-agent">
                          Cancel
                        </Button>
                        <Button type="submit" disabled={createAgentMutation.isPending || updateAgentMutation.isPending} data-testid="button-submit-agent">
                          {editingAgent ? 'Update' : 'Create'}
                        </Button>
                      </div>
                    </form>
                  </Form>
                </DialogContent>
              </Dialog>
            </div>

            <Card>
              <CardContent className="p-6">
                {agentsLoading ? (
                  <div className="animate-pulse space-y-2">
                    {[...Array(5)].map((_, i) => (
                      <div key={i} className="h-16 bg-muted rounded"></div>
                    ))}
                  </div>
                ) : (
                  <div className="rounded-lg border">
                    <table className="w-full">
                      <thead className="bg-muted/50">
                        <tr>
                          <th className="text-left p-4 font-medium">Name</th>
                          <th className="text-left p-4 font-medium">Email</th>
                          <th className="text-left p-4 font-medium">Brokerage</th>
                          <th className="text-left p-4 font-medium">Clients</th>
                          <th className="text-left p-4 font-medium">Tours</th>
                          <th className="text-right p-4 font-medium">Actions</th>
                        </tr>
                      </thead>
                      <tbody>
                        {agents && agents.length > 0 ? (
                          agents.map((agent) => (
                            <tr key={agent.id} className="border-t hover:bg-muted/50" data-testid={`row-agent-${agent.id}`}>
                              <td className="p-4 font-medium" data-testid={`text-agent-name-${agent.id}`}>
                                {agent.firstName} {agent.lastName}
                              </td>
                              <td className="p-4 text-muted-foreground">{agent.email}</td>
                              <td className="p-4">
                                <span className={`px-2 py-1 rounded text-xs ${
                                  agent.brokerageName === 'Independent'
                                    ? 'bg-blue-100 text-blue-800'
                                    : 'bg-purple-100 text-purple-800'
                                }`}>
                                  {agent.brokerageName}
                                </span>
                              </td>
                              <td className="p-4">{agent.clientCount || 0}</td>
                              <td className="p-4">{agent.tourCount || 0}</td>
                              <td className="p-4">
                                <div className="flex justify-end gap-2">
                                  <Button
                                    variant="outline"
                                    size="sm"
                                    onClick={() => openEditAgent(agent)}
                                    data-testid={`button-edit-agent-${agent.id}`}
                                  >
                                    <Edit className="h-4 w-4" />
                                  </Button>
                                  <AlertDialog>
                                    <AlertDialogTrigger asChild>
                                      <Button
                                        variant="outline"
                                        size="sm"
                                        data-testid={`button-delete-agent-${agent.id}`}
                                      >
                                        <Trash2 className="h-4 w-4 text-red-600" />
                                      </Button>
                                    </AlertDialogTrigger>
                                    <AlertDialogContent>
                                      <AlertDialogHeader>
                                        <AlertDialogTitle>Delete Agent</AlertDialogTitle>
                                        <AlertDialogDescription>
                                          Are you sure you want to delete "{agent.firstName} {agent.lastName}"? This will remove the agent and unassign their clients. This action cannot be undone.
                                        </AlertDialogDescription>
                                      </AlertDialogHeader>
                                      <AlertDialogFooter>
                                        <AlertDialogCancel data-testid="button-cancel-delete-agent">Cancel</AlertDialogCancel>
                                        <AlertDialogAction
                                          onClick={() => deleteAgentMutation.mutate(agent.id)}
                                          className="bg-red-600 hover:bg-red-700"
                                          data-testid="button-confirm-delete-agent"
                                        >
                                          Delete
                                        </AlertDialogAction>
                                      </AlertDialogFooter>
                                    </AlertDialogContent>
                                  </AlertDialog>
                                </div>
                              </td>
                            </tr>
                          ))
                        ) : (
                          <tr>
                            <td colSpan={6} className="p-8 text-center text-muted-foreground">
                              No agents found. Create your first agent to get started.
                            </td>
                          </tr>
                        )}
                      </tbody>
                    </table>
                  </div>
                )}
              </CardContent>
            </Card>
          </TabsContent>
        </Tabs>
      </div>
    </div>
  );
}

client/src/pages/ToursPage.tsx.content:
import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { useAuth } from "@/hooks/useAuth";
import { useViewMode } from "@/contexts/ViewModeContext";
import type { Tour } from "@shared/schema";
import Header from "@/components/Header";
import AgentSidebar from "@/components/AgentSidebar";
import { SidebarProvider, SidebarInset } from "@/components/ui/sidebar";
import TourWizardModal from "@/components/TourWizardModal";
import TourRecapModal from "@/components/TourRecapModal";
import ScheduleEditModal from "@/components/ScheduleEditModal";
import ClientProfileModal from "@/components/ClientProfileModal";
import TourRemindersModal from "@/components/TourRemindersModal";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Plus, Calendar, MapPin, Clock, Users, Route, Bell } from "lucide-react";
import { format } from "date-fns";

export default function ToursPage() {
  const { user } = useAuth();
  const { effectiveMode } = useViewMode();
  const [showTourWizard, setShowTourWizard] = useState(false);
  const [showTourRecap, setShowTourRecap] = useState(false);
  const [showScheduleEdit, setShowScheduleEdit] = useState(false);
  const [showClientProfile, setShowClientProfile] = useState(false);
  const [showReminders, setShowReminders] = useState(false);
  const [selectedTour, setSelectedTour] = useState<Tour | null>(null);
  const [selectedClient, setSelectedClient] = useState<any | null>(null);

  // Fetch tours for the agent
  const { data: tours = [], isLoading } = useQuery<Tour[]>({
    queryKey: ["/api/tours"],
    enabled: !!user && effectiveMode === 'agent',
  });

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'scheduled': return 'bg-blue-100 text-blue-800';
      case 'in_progress': return 'bg-green-100 text-green-800';
      case 'completed': return 'bg-gray-100 text-gray-800';
      case 'cancelled': return 'bg-red-100 text-red-800';
      default: return 'bg-yellow-100 text-yellow-800';
    }
  };

  const handleEditTour = (tour: Tour) => {
    setSelectedTour(tour);
    setShowScheduleEdit(true);
  };

  const handleTourRecap = (tour: Tour) => {
    setSelectedTour(tour);
    setShowTourRecap(true);
  };

  const handleClientClick = (tour: any) => {
    const client = {
      id: tour.clientId,
      firstName: tour.clientFirstName,
      lastName: tour.clientLastName,
      email: tour.clientEmail,
    };
    setSelectedClient(client);
    setShowClientProfile(true);
  };

  if (!user) {
    return <div>Loading...</div>;
  }

  return (
    <SidebarProvider>
      <div className="min-h-screen bg-background">
        <Header userRole="agent" />
        <div className="flex">
          <AgentSidebar />
          <SidebarInset>
            <main className="flex-1 p-4 md:p-6">
              <div className="flex justify-between items-center mb-6">
            <div>
              <h1 className="text-2xl md:text-3xl font-bold">Tours & Scheduling</h1>
              <p className="text-sm md:text-base text-muted-foreground">Manage your property tours and schedules</p>
            </div>
            <Button 
              onClick={() => setShowTourWizard(true)}
              className="gap-2"
              data-testid="button-new-tour"
            >
              <Plus className="h-4 w-4" />
              New Tour
            </Button>
          </div>

          {isLoading ? (
            <div className="flex items-center justify-center py-12">
              <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
            </div>
          ) : tours.length === 0 ? (
            <Card>
              <CardContent className="flex flex-col items-center justify-center py-12">
                <Calendar className="h-12 w-12 text-muted-foreground mb-4" />
                <h3 className="text-lg font-semibold mb-2">No tours scheduled</h3>
                <p className="text-muted-foreground text-center mb-4">
                  Create your first tour to get started with property showings.
                </p>
                <Button 
                  onClick={() => setShowTourWizard(true)}
                  className="gap-2"
                >
                  <Plus className="h-4 w-4" />
                  Create First Tour
                </Button>
              </CardContent>
            </Card>
          ) : (
            <div className="grid gap-6">
              {tours.map((tour) => (
                <Card key={tour.id} className="hover:shadow-md transition-shadow">
                  <CardHeader>
                    <div className="flex items-center justify-between">
                      <CardTitle className="flex items-center gap-2">
                        <Calendar className="h-5 w-5" />
                        Tour on {tour.scheduledDate ? format(new Date(tour.scheduledDate), 'MMM dd, yyyy') : 'Date TBD'}
                      </CardTitle>
                      <Badge className={getStatusColor(tour.status || 'requested')}>
                        {tour.status || 'requested'}
                      </Badge>
                    </div>
                  </CardHeader>
                  <CardContent>
                    <div className="grid md:grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <div className="flex items-center gap-2 text-sm">
                          <Clock className="h-4 w-4 text-muted-foreground" />
                          {tour.startTime ? format(new Date(tour.startTime), 'h:mm a') : 'Time TBD'}
                        </div>
                        <div className="flex items-center gap-2 text-sm">
                          <Users className="h-4 w-4 text-muted-foreground" />
                          {(tour as any).clientName ? (
                            <button
                              onClick={() => handleClientClick(tour)}
                              className="text-primary hover:underline font-medium"
                              data-testid={`link-client-${tour.clientId}`}
                            >
                              {(tour as any).clientName}
                            </button>
                          ) : (
                            'Client Tour'
                          )}
                        </div>
                        {tour.totalDistance && (
                          <div className="flex items-center gap-2 text-sm">
                            <Route className="h-4 w-4 text-muted-foreground" />
                            {tour.totalDistance} km total distance
                          </div>
                        )}
                      </div>
                      <div className="flex gap-2 justify-end flex-wrap">
                        <Button 
                          variant="outline" 
                          size="sm"
                          onClick={() => handleEditTour(tour)}
                          data-testid={`button-edit-tour-${tour.id}`}
                        >
                          Edit Schedule
                        </Button>
                        {tour.status === 'scheduled' && (
                          <Button 
                            variant="outline" 
                            size="sm"
                            onClick={() => {
                              setSelectedTour(tour);
                              setShowReminders(true);
                            }}
                            className="gap-2"
                            data-testid={`button-set-reminders-${tour.id}`}
                          >
                            <Bell className="h-4 w-4" />
                            Set Reminders
                          </Button>
                        )}
                        {tour.status === 'completed' && (
                          <Button 
                            variant="outline" 
                            size="sm"
                            onClick={() => handleTourRecap(tour)}
                            data-testid={`button-tour-recap-${tour.id}`}
                          >
                            View Recap
                          </Button>
                        )}
                      </div>
                    </div>
                    {tour.notes && (
                      <div className="mt-4 p-3 bg-muted rounded-md">
                        <p className="text-sm">{tour.notes}</p>
                      </div>
                    )}
                  </CardContent>
                </Card>
              ))}
            </div>
          )}
            </main>
          </SidebarInset>
        </div>
      </div>

      <TourWizardModal 
        isOpen={showTourWizard}
        onClose={() => setShowTourWizard(false)}
      />

      {selectedTour && selectedTour.scheduledDate && (
        <>
          <TourRecapModal
            isOpen={showTourRecap}
            onClose={() => {
              setShowTourRecap(false);
              setSelectedTour(null);
            }}
            selectedDate={new Date(selectedTour.scheduledDate)}
          />
          <ScheduleEditModal
            isOpen={showScheduleEdit}
            onClose={() => {
              setShowScheduleEdit(false);
              setSelectedTour(null);
            }}
            selectedDate={new Date(selectedTour.scheduledDate)}
          />
        </>
      )}

      {selectedClient && (
        <ClientProfileModal
          isOpen={showClientProfile}
          onClose={() => {
            setShowClientProfile(false);
            setSelectedClient(null);
          }}
          client={selectedClient}
        />
      )}

      {selectedTour && (
        <TourRemindersModal
          isOpen={showReminders}
          onClose={() => {
            setShowReminders(false);
            setSelectedTour(null);
          }}
          tourId={selectedTour.id}
        />
      )}
    </SidebarProvider>
  );
}

