client/src/components/RequirementsFormMo.content:
import { useState } from "react";
import { useMutation, useQuery } from "@tanstack/react-query";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Separator } from "@/components/ui/separator";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
  FormDescription,
} from "@/components/ui/form";
import { Checkbox } from "@/components/ui/checkbox";
import {
  Home,
  DollarSign,
  MapPin,
  Calendar,
  User,
  AlertTriangle,
  CheckCircle,
  Clock,
  Target,
  Building2,
  Car,
  FileText,
} from "lucide-react";

// Form input schema (before transformation)
const requirementsFormInputSchema = z.object({
  // Common fields
  budgetMin: z.string().min(1, "Minimum budget is required"),
  budgetMax: z.string().min(1, "Maximum budget is required"), 
  preferredAreas: z.string().min(1, "Please specify at least one preferred area"),
  propertyTypes: z.array(z.string()).min(1, "Select at least one property type"),
  bedrooms: z.number().min(1, "Number of bedrooms is required"),
  bathrooms: z.string().min(1, "Number of bathrooms is required"),
  parkingRequired: z.boolean(),
  parkingSpots: z.number().default(0),
  urgencyLevel: z.enum(["low", "medium", "high", "urgent"]),
  timeframe: z.enum(["asap", "1_month", "3_months", "6_months", "flexible"]),

  // Buyer-specific fields
  preApprovalAmount: z.string().optional(),
  downPaymentAmount: z.string().optional(),
  mortgagePreApprovalExpiry: z.string().optional(),
  firstTimeBuyer: z.boolean(),
  desiredClosingDate: z.string().optional(),

  // Renter-specific fields
  combinedFamilyIncome: z.string().optional(),
  monthlyIncomeVerified: z.boolean(),
  preferredMoveInDate: z.string().optional(),
  willingToPrepayRent: z.boolean(),
  prepayMonths: z.number().default(0),

  // Additional fields
  notes: z.string().optional(),
});

// Output schema (after transformation)
const requirementsFormSchema = requirementsFormInputSchema.transform((data) => ({
  ...data,
  budgetMin: Number(data.budgetMin),
  budgetMax: Number(data.budgetMax),
  bathrooms: Number(data.bathrooms),
  preApprovalAmount: data.preApprovalAmount ? Number(data.preApprovalAmount) : undefined,
  downPaymentAmount: data.downPaymentAmount ? Number(data.downPaymentAmount) : undefined,
  combinedFamilyIncome: data.combinedFamilyIncome ? Number(data.combinedFamilyIncome) : undefined,
})).refine(
  (data) => data.budgetMax >= data.budgetMin,
  {
    message: "Maximum budget must be greater than minimum budget",
    path: ["budgetMax"],
  }
);

type RequirementsFormData = z.infer<typeof requirementsFormInputSchema>;
type RequirementsOutputData = z.infer<typeof requirementsFormSchema>;

interface RequirementsFormModalProps {
  isOpen: boolean;
  onClose: () => void;
  client: any;
}

export default function RequirementsFormModal({ isOpen, onClose, client }: RequirementsFormModalProps) {
  const { toast } = useToast();
  const [validationResults, setValidationResults] = useState<{
    score: number;
    issues: string[];
  } | null>(null);

  // Fetch existing requirements (client-facing endpoint)
  const { data: existingRequirements, isLoading } = useQuery({
    queryKey: ["/api/client-requirements"],
    enabled: isOpen && !!client?.id,
  });

  const form = useForm<RequirementsFormData>({
    resolver: zodResolver(requirementsFormInputSchema),
    defaultValues: {
      budgetMin: "400000",
      budgetMax: "600000",
      preferredAreas: "Downtown",
      propertyTypes: ["condo"],
      bedrooms: 1,
      bathrooms: "1",
      parkingRequired: false,
      parkingSpots: 0,
      urgencyLevel: "medium",
      timeframe: "3_months",
      preApprovalAmount: "500000",
      downPaymentAmount: "100000",
      mortgagePreApprovalExpiry: "",
      firstTimeBuyer: false,
      desiredClosingDate: "",
      combinedFamilyIncome: "100000",
      monthlyIncomeVerified: false,
      preferredMoveInDate: "",
      willingToPrepayRent: false,
      prepayMonths: 0,
      notes: "",
    },
  });

  // Create requirements mutation (client-facing endpoint)
  const createRequirementsMutation = useMutation({
    mutationFn: async (data: RequirementsFormData) => {
      try {
        // Transform the data using the output schema
        const transformedData = requirementsFormSchema.parse(data);

        const formattedData = {
          ...transformedData,
          targetClientId: client?.id,
          preferredAreas: data.preferredAreas.split(',').map(area => area.trim()).filter(Boolean),
          mortgagePreApprovalExpiry: data.mortgagePreApprovalExpiry ? data.mortgagePreApprovalExpiry : undefined,
          desiredClosingDate: data.desiredClosingDate ? data.desiredClosingDate : undefined,
          preferredMoveInDate: data.preferredMoveInDate ? data.preferredMoveInDate : undefined,
        };

        const response = await apiRequest("POST", `/api/client-requirements`, formattedData);
        const result = await response.json();
        return result;
      } catch (error) {
        throw error;
      }
    },
    onSuccess: (result) => {
      // Show validation results if available
      if (result.validation) {
        setValidationResults(result.validation);
      }

      // CRITICAL: Immediately update cache to prevent race condition
      // This ensures the hard-gating useEffect sees requirements exist and doesn't reopen modal
      // Store the full requirement object to match the API response shape
      if (result.requirement) {
        queryClient.setQueryData(["/api/client-requirements"], result.requirement);
      }

      // Invalidate queries to refresh full data
      queryClient.invalidateQueries({ queryKey: ["/api/client-requirements"] });
      queryClient.invalidateQueries({ queryKey: ["/api/clients"] });

      // Show success toast
      toast({
        title: "Requirements Created",
        description: result.validation 
          ? `Requirements created with ${(result.validation.score * 100).toFixed(0)}% completeness score.`
          : "Requirements created successfully.",
      });

      if (result.validation && result.validation.score >= 0.8) {
        toast({
          title: "Validation Complete",
          description: "Requirements are fully validated and ready for property matching.",
        });
      }

      // Close modal after successful creation
      onClose();
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to create requirements. Please try again.",
        variant: "destructive",
      });
    },
  });

  const onSubmit = (data: RequirementsFormData) => {
    createRequirementsMutation.mutate(data);
  };

  const handleClose = () => {
    form.reset();
    setValidationResults(null);
    onClose();
  };

  const [parkingRequired, willingToPrepayRent] = form.watch(["parkingRequired", "willingToPrepayRent"]);
  const clientType = client?.clientType || 'buyer';

  const propertyTypeOptions = [
    { value: "condo", label: "Condo", icon: Building2 },
    { value: "townhouse", label: "Townhouse", icon: Home },
    { value: "detached", label: "Detached House", icon: Home },
    { value: "apartment", label: "Apartment", icon: Building2 },
    { value: "basement", label: "Basement Suite", icon: Home },
    { value: "duplex", label: "Duplex", icon: Home },
  ];

  return (
    <Dialog open={isOpen} onOpenChange={(open) => !open && handleClose()}>
      <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto" data-testid="dialog-requirements-form">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Target className="h-5 w-5" />
            {clientType === 'buyer' ? 'Buyer' : 'Renter'} Requirements - {client?.firstName} {client?.lastName}
          </DialogTitle>
          <DialogDescription>
            Complete requirements profile with hard-gated validation for optimal property matching
          </DialogDescription>
        </DialogHeader>

        {validationResults && (
          <div className="mb-6 p-4 border rounded-lg bg-muted/50">
            <div className="flex items-center justify-between mb-2">
              <h3 className="font-semibold text-sm">Validation Results</h3>
              <Badge variant={validationResults.score >= 0.8 ? "default" : "secondary"}>
                {(validationResults.score * 100).toFixed(0)}% Complete
              </Badge>
            </div>
            <Progress value={validationResults.score * 100} className="mb-3" />
            {validationResults.issues.length > 0 && (
              <div className="space-y-1">
                {validationResults.issues.map((issue, index) => (
                  <div key={index} className="flex items-center gap-2 text-sm text-muted-foreground">
                    <AlertTriangle className="h-4 w-4 text-orange-500" />
                    {issue}
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        <Form {...form}>
          <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
            {/* Budget Section */}
            <div className="space-y-4">
              <div className="flex items-center gap-2">
                <DollarSign className="h-4 w-4" />
                <h3 className="font-semibold">Budget Range</h3>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <FormField
                  control={form.control}
                  name="budgetMin"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Minimum Budget (CAD)</FormLabel>
                      <FormControl>
                        <Input
                          placeholder="e.g. 500000"
                          data-testid="input-budget-min"
                          {...field}
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
                <FormField
                  control={form.control}
                  name="budgetMax"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Maximum Budget (CAD)</FormLabel>
                      <FormControl>
                        <Input
                          placeholder="e.g. 750000"
                          data-testid="input-budget-max"
                          {...field}
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </div>
            </div>

            <Separator />

            {/* Location & Property Type Section */}
            <div className="space-y-4">
              <div className="flex items-center gap-2">
                <MapPin className="h-4 w-4" />
                <h3 className="font-semibold">Location & Property Preferences</h3>
              </div>

              <FormField
                control={form.control}
                name="preferredAreas"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Preferred Areas</FormLabel>
                    <FormControl>
                      <Input
                        placeholder="e.g. Downtown, Midtown, North York (comma-separated)"
                        data-testid="input-preferred-areas"
                        {...field}
                      />
                    </FormControl>
                    <FormDescription>
                      Enter multiple areas separated by commas
                    </FormDescription>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <FormField
                control={form.control}
                name="propertyTypes"
                render={() => (
                  <FormItem>
                    <FormLabel>Property Types</FormLabel>
                    <div className="grid grid-cols-3 gap-3">
                      {propertyTypeOptions.map((option) => (
                        <FormField
                          key={option.value}
                          control={form.control}
                          name="propertyTypes"
                          render={({ field }) => (
                            <FormItem
                              key={option.value}
                              className="flex flex-row items-start space-x-3 space-y-0"
                            >
                              <FormControl>
                                <Checkbox
                                  checked={field.value?.includes(option.value)}
                                  onCheckedChange={(checked) => {
                                    return checked
                                      ? field.onChange([...field.value, option.value])
                                      : field.onChange(
                                          field.value?.filter((value) => value !== option.value)
                                        );
                                  }}
                                  data-testid={`checkbox-property-type-${option.value}`}
                                />
                              </FormControl>
                              <FormLabel className="text-sm font-normal flex items-center gap-2">
                                <option.icon className="h-4 w-4" />
                                {option.label}
                              </FormLabel>
                            </FormItem>
                          )}
                        />
                      ))}
                    </div>
                    <FormMessage />
                  </FormItem>
                )}
              />
            </div>

            <Separator />

            {/* Size & Amenities Section */}
            <div className="space-y-4">
              <div className="flex items-center gap-2">
                <Home className="h-4 w-4" />
                <h3 className="font-semibold">Size & Amenities</h3>
              </div>

              <div className="grid grid-cols-3 gap-4">
                <FormField
                  control={form.control}
                  name="bedrooms"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Bedrooms</FormLabel>
                      <Select onValueChange={(value) => field.onChange(Number(value))} defaultValue={field.value?.toString()}>
                        <FormControl>
                          <SelectTrigger data-testid="select-bedrooms">
                            <SelectValue placeholder="Select" />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          {[1, 2, 3, 4, 5].map((num) => (
                            <SelectItem key={num} value={num.toString()}>
                              {num} {num === 1 ? 'bedroom' : 'bedrooms'}
                            </SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="bathrooms"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Bathrooms</FormLabel>
                      <Select onValueChange={field.onChange} defaultValue={field.value}>
                        <FormControl>
                          <SelectTrigger data-testid="select-bathrooms">
                            <SelectValue placeholder="Select" />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          {["1", "1.5", "2", "2.5", "3", "3.5", "4"].map((num) => (
                            <SelectItem key={num} value={num}>
                              {num} {parseFloat(num) === 1 ? 'bathroom' : 'bathrooms'}
                            </SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <div className="space-y-3">
                  <FormField
                    control={form.control}
                    name="parkingRequired"
                    render={({ field }) => (
                      <FormItem className="flex flex-row items-start space-x-3 space-y-0">
                        <FormControl>
                          <Checkbox
                            checked={field.value}
                            onCheckedChange={field.onChange}
                            data-testid="checkbox-parking-required"
                          />
                        </FormControl>
                        <div className="space-y-1 leading-none">
                          <FormLabel className="flex items-center gap-2">
                            <Car className="h-4 w-4" />
                            Parking Required
                          </FormLabel>
                        </div>
                      </FormItem>
                    )}
                  />

                  {parkingRequired && (
                    <FormField
                      control={form.control}
                      name="parkingSpots"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Parking Spots</FormLabel>
                          <Select onValueChange={(value) => field.onChange(Number(value))} defaultValue={field.value?.toString()}>
                            <FormControl>
                              <SelectTrigger data-testid="select-parking-spots">
                                <SelectValue placeholder="Select" />
                              </SelectTrigger>
                            </FormControl>
                            <SelectContent>
                              {[1, 2, 3, 4].map((num) => (
                                <SelectItem key={num} value={num.toString()}>
                                  {num} {num === 1 ? 'spot' : 'spots'}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  )}
                </div>
              </div>
            </div>

            <Separator />

            {/* Timeline Section */}
            <div className="space-y-4">
              <div className="flex items-center gap-2">
                <Clock className="h-4 w-4" />
                <h3 className="font-semibold">Timeline & Urgency</h3>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <FormField
                  control={form.control}
                  name="urgencyLevel"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Urgency Level</FormLabel>
                      <Select onValueChange={field.onChange} defaultValue={field.value}>
                        <FormControl>
                          <SelectTrigger data-testid="select-urgency">
                            <SelectValue placeholder="Select urgency" />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          <SelectItem value="low">Low - Just browsing</SelectItem>
                          <SelectItem value="medium">Medium - Actively looking</SelectItem>
                          <SelectItem value="high">High - Need to find soon</SelectItem>
                          <SelectItem value="urgent">Urgent - Must find ASAP</SelectItem>
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="timeframe"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Timeframe</FormLabel>
                      <Select onValueChange={field.onChange} defaultValue={field.value}>
                        <FormControl>
                          <SelectTrigger data-testid="select-timeframe">
                            <SelectValue placeholder="Select timeframe" />
                          </SelectTrigger>
                        </FormControl>
                        <SelectContent>
                          <SelectItem value="asap">ASAP (within 2 weeks)</SelectItem>
                          <SelectItem value="1_month">Within 1 month</SelectItem>
                          <SelectItem value="3_months">Within 3 months</SelectItem>
                          <SelectItem value="6_months">Within 6 months</SelectItem>
                          <SelectItem value="flexible">Flexible timeline</SelectItem>
                        </SelectContent>
                      </Select>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </div>
            </div>

            <Separator />

            {/* Client-Type Specific Sections */}
            {clientType === 'buyer' ? (
              <div className="space-y-4">
                <div className="flex items-center gap-2">
                  <User className="h-4 w-4" />
                  <h3 className="font-semibold">Buyer-Specific Requirements</h3>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <FormField
                    control={form.control}
                    name="preApprovalAmount"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Pre-approval Amount (CAD)</FormLabel>
                        <FormControl>
                          <Input
                            placeholder="e.g. 800000"
                            data-testid="input-pre-approval"
                            {...field}
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="downPaymentAmount"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Down Payment Amount (CAD)</FormLabel>
                        <FormControl>
                          <Input
                            placeholder="e.g. 160000"
                            data-testid="input-down-payment"
                            {...field}
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="mortgagePreApprovalExpiry"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Pre-approval Expiry Date</FormLabel>
                        <FormControl>
                          <Input
                            type="date"
                            data-testid="input-pre-approval-expiry"
                            {...field}
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="desiredClosingDate"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Desired Closing Date</FormLabel>
                        <FormControl>
                          <Input
                            type="date"
                            data-testid="input-closing-date"
                            {...field}
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </div>

                <FormField
                  control={form.control}
                  name="firstTimeBuyer"
                  render={({ field }) => (
                    <FormItem className="flex flex-row items-start space-x-3 space-y-0">
                      <FormControl>
                        <Checkbox
                          checked={field.value}
                          onCheckedChange={field.onChange}
                          data-testid="checkbox-first-time-buyer"
                        />
                      </FormControl>
                      <div className="space-y-1 leading-none">
                        <FormLabel>First-time home buyer</FormLabel>
                        <FormDescription>
                          Check if this is their first home purchase (may qualify for special programs)
                        </FormDescription>
                      </div>
                    </FormItem>
                  )}
                />
              </div>
            ) : (
              <div className="space-y-4">
                <div className="flex items-center gap-2">
                  <User className="h-4 w-4" />
                  <h3 className="font-semibold">Renter-Specific Requirements</h3>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <FormField
                    control={form.control}
                    name="combinedFamilyIncome"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Combined Family Income (CAD/year)</FormLabel>
                        <FormControl>
                          <Input
                            placeholder="e.g. 75000"
                            data-testid="input-family-income"
                            {...field}
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="preferredMoveInDate"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Preferred Move-in Date</FormLabel>
                        <FormControl>
                          <Input
                            type="date"
                            data-testid="input-move-in-date"
                            {...field}
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </div>

                <div className="space-y-3">
                  <FormField
                    control={form.control}
                    name="monthlyIncomeVerified"
                    render={({ field }) => (
                      <FormItem className="flex flex-row items-start space-x-3 space-y-0">
                        <FormControl>
                          <Checkbox
                            checked={field.value}
                            onCheckedChange={field.onChange}
                            data-testid="checkbox-income-verified"
                          />
                        </FormControl>
                        <div className="space-y-1 leading-none">
                          <FormLabel>Monthly income verified</FormLabel>
                          <FormDescription>
                            Check if income documentation has been verified
                          </FormDescription>
                        </div>
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="willingToPrepayRent"
                    render={({ field }) => (
                      <FormItem className="flex flex-row items-start space-x-3 space-y-0">
                        <FormControl>
                          <Checkbox
                            checked={field.value}
                            onCheckedChange={field.onChange}
                            data-testid="checkbox-prepay-rent"
                          />
                        </FormControl>
                        <div className="space-y-1 leading-none">
                          <FormLabel>Willing to prepay rent</FormLabel>
                          <FormDescription>
                            Check if client is willing to pay multiple months upfront
                          </FormDescription>
                        </div>
                      </FormItem>
                    )}
                  />

                  {willingToPrepayRent && (
                    <FormField
                      control={form.control}
                      name="prepayMonths"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Months willing to prepay</FormLabel>
                          <Select onValueChange={(value) => field.onChange(Number(value))} defaultValue={field.value?.toString()}>
                            <FormControl>
                              <SelectTrigger data-testid="select-prepay-months">
                                <SelectValue placeholder="Select months" />
                              </SelectTrigger>
                            </FormControl>
                            <SelectContent>
                              {[1, 2, 3, 6, 12].map((num) => (
                                <SelectItem key={num} value={num.toString()}>
                                  {num} {num === 1 ? 'month' : 'months'}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  )}
                </div>
              </div>
            )}

            <Separator />

            {/* Notes Section */}
            <FormField
              control={form.control}
              name="notes"
              render={({ field }) => (
                <FormItem>
                  <FormLabel className="flex items-center gap-2">
                    <FileText className="h-4 w-4" />
                    Additional Notes
                  </FormLabel>
                  <FormControl>
                    <Textarea
                      placeholder="Any additional requirements, preferences, or special circumstances..."
                      className="min-h-[100px]"
                      data-testid="textarea-notes"
                      {...field}
                    />
                  </FormControl>
                  <FormDescription>
                    Include any special circumstances, deal-breakers, or additional preferences
                  </FormDescription>
                  <FormMessage />
                </FormItem>
              )}
            />

            {/* Submit Section */}
            <div className="flex justify-end gap-3 pt-6">
              <Button
                type="button"
                variant="outline"
                onClick={handleClose}
                data-testid="button-cancel-requirements"
              >
                Cancel
              </Button>
              <Button
                type="submit"
                disabled={createRequirementsMutation.isPending}
                data-testid="button-save-requirements"
                className="min-w-[120px]"
              >
                {createRequirementsMutation.isPending ? (
                  "Creating..."
                ) : (
                  <>
                    <CheckCircle className="h-4 w-4 mr-2" />
                    Create Requirements
                  </>
                )}
              </Button>
            </div>
          </form>
        </Form>
      </DialogContent>
    </Dialog>
  );
}

