import { useState } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Checkbox } from "@/components/ui/checkbox";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";
import { insertRentalProfileSchema, type InsertRentalProfile } from "@shared/schema";
import { z } from "zod";
import { Home, DollarSign, Calendar, Users, MapPin, Car } from "lucide-react";

// Form validation schema extending the rental profile schema but excluding userId (server-side field)
const rentalFormSchema = insertRentalProfileSchema.omit({ userId: true }).extend({
  preferredAreasText: z.string().min(1, "Please specify at least one preferred area"),
});

type RentalFormData = z.infer<typeof rentalFormSchema>;

interface RentalFormModalProps {
  isOpen: boolean;
  onClose: () => void;
  onComplete: () => void;
}

export function RentalFormModal({ isOpen, onClose, onComplete }: RentalFormModalProps) {
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const form = useForm<RentalFormData>({
    resolver: zodResolver(rentalFormSchema),
    defaultValues: {
      bedrooms: 1,
      bathrooms: "1",
      parkingRequired: false,
      parkingSpots: 0,
      numberOfOccupants: 1,
      monthlyBudget: "0",
      propertyType: "condo",
      willingToPrepayRent: false,
      prepayMonths: 0,
      combinedFamilyIncome: "0",
      preferredAreasText: "",
    },
  });

  const createRentalProfileMutation = useMutation({
    mutationFn: async (data: RentalFormData) => {
      const { preferredAreasText, ...profileData } = data;
      const profileWithAreas = {
        ...profileData,
        preferredAreas: preferredAreasText.split(',').map(area => area.trim()).filter(Boolean),
        // monthlyBudget and combinedFamilyIncome are already strings from the form
      };

      const response = await apiRequest("POST", "/api/rental-profile", profileWithAreas);
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/auth/user"] });
      queryClient.invalidateQueries({ queryKey: ["/api/rental-profile"] });
      toast({
        title: "Rental Profile Created",
        description: "Your rental preferences have been saved successfully.",
      });
      onComplete();
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to save rental profile. Please try again.",
        variant: "destructive",
      });
    },
  });

  const onSubmit = (data: RentalFormData) => {
    console.log("Form submitted with data:", data);
    console.log("Form errors:", form.formState.errors);
    createRentalProfileMutation.mutate(data);
  };

  const [parkingRequired, willingToPrepayRent] = form.watch(["parkingRequired", "willingToPrepayRent"]);

  const handleOpenChange = (open: boolean) => {
    if (!open) {
      onClose();
    }
  };

  return (
    <Dialog open={isOpen} onOpenChange={handleOpenChange}>
      <DialogContent className="max-w-4xl max-h-[80vh] overflow-y-auto" data-testid="dialog-rental-form">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Home className="h-5 w-5" />
            Rental Preferences
          </DialogTitle>
          <p className="text-muted-foreground">
            Help us find the perfect rental property for you by providing your preferences
          </p>
        </DialogHeader>

        <Form {...form}>
          <form onSubmit={form.handleSubmit(onSubmit, (errors) => {
            console.log("Form validation failed:", errors);
            toast({
              title: "Form Error",
              description: "Please check all required fields are filled correctly.",
              variant: "destructive",
            });
          })} className="space-y-6">
            {/* Property Requirements */}
            <Card>
              <CardHeader>
                <CardTitle className="text-lg flex items-center gap-2">
                  <Home className="h-5 w-5" />
                  Property Requirements
                </CardTitle>
              </CardHeader>
              <CardContent className="grid md:grid-cols-2 gap-4">
                <FormField
                  control={form.control}
                  name="bedrooms"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Number of Bedrooms</FormLabel>
                      <FormControl>
                        <Select value={String(field.value)} onValueChange={(value) => field.onChange(parseInt(value))}>
                          <SelectTrigger data-testid="select-bedrooms">
                            <SelectValue />
                          </SelectTrigger>
                          <SelectContent>
                            {[1, 2, 3, 4, 5].map((num) => (
                              <SelectItem key={num} value={String(num)}>
                                {num} {num === 1 ? "Bedroom" : "Bedrooms"}
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="bathrooms"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Number of Bathrooms</FormLabel>
                      <FormControl>
                        <Select 
                          value={field.value} 
                          onValueChange={field.onChange}
                        >
                          <SelectTrigger data-testid="select-bathrooms">
                            <SelectValue />
                          </SelectTrigger>
                          <SelectContent>
                            {[1, 1.5, 2, 2.5, 3, 3.5, 4].map((num) => (
                              <SelectItem key={num} value={String(num)}>
                                {num} {num === 1 ? "Bathroom" : "Bathrooms"}
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="propertyType"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Property Type</FormLabel>
                      <FormControl>
                        <Select value={field.value} onValueChange={field.onChange}>
                          <SelectTrigger data-testid="select-property-type">
                            <SelectValue />
                          </SelectTrigger>
                          <SelectContent>
                            <SelectItem value="condo">Condo</SelectItem>
                            <SelectItem value="townhouse">Townhouse</SelectItem>
                            <SelectItem value="detached">Detached House</SelectItem>
                            <SelectItem value="apartment">Apartment</SelectItem>
                            <SelectItem value="basement">Basement Suite</SelectItem>
                            <SelectItem value="duplex">Duplex</SelectItem>
                            <SelectItem value="other">Other</SelectItem>
                          </SelectContent>
                        </Select>
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="numberOfOccupants"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Number of Occupants</FormLabel>
                      <FormControl>
                        <Input 
                          type="number" 
                          min="1" 
                          {...field}
                          onChange={(e) => field.onChange(parseInt(e.target.value))}
                          data-testid="input-occupants"
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </CardContent>
            </Card>

            {/* Parking Requirements */}
            <Card>
              <CardHeader>
                <CardTitle className="text-lg flex items-center gap-2">
                  <Car className="h-5 w-5" />
                  Parking Requirements
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <FormField
                  control={form.control}
                  name="parkingRequired"
                  render={({ field }) => (
                    <FormItem className="flex flex-row items-start space-x-3 space-y-0">
                      <FormControl>
                        <Checkbox
                          checked={field.value || false}
                          onCheckedChange={field.onChange}
                          data-testid="checkbox-parking-required"
                        />
                      </FormControl>
                      <div className="space-y-1 leading-none">
                        <FormLabel>Parking required</FormLabel>
                        <p className="text-sm text-muted-foreground">
                          Check this if you need dedicated parking
                        </p>
                      </div>
                    </FormItem>
                  )}
                />

                {parkingRequired && (
                  <FormField
                    control={form.control}
                    name="parkingSpots"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Number of Parking Spots</FormLabel>
                        <FormControl>
                          <Select value={String(field.value)} onValueChange={(value) => field.onChange(parseInt(value))}>
                            <SelectTrigger data-testid="select-parking-spots">
                              <SelectValue />
                            </SelectTrigger>
                            <SelectContent>
                              {[1, 2, 3, 4].map((num) => (
                                <SelectItem key={num} value={String(num)}>
                                  {num} {num === 1 ? "Spot" : "Spots"}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                )}
              </CardContent>
            </Card>

            {/* Budget & Financial Information */}
            <Card>
              <CardHeader>
                <CardTitle className="text-lg flex items-center gap-2">
                  <DollarSign className="h-5 w-5" />
                  Budget & Financial Information
                </CardTitle>
              </CardHeader>
              <CardContent className="grid md:grid-cols-2 gap-4">
                <FormField
                  control={form.control}
                  name="monthlyBudget"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Monthly Budget (CAD)</FormLabel>
                      <FormControl>
                        <Input 
                          type="number" 
                          min="0" 
                          step="50"
                          placeholder="e.g. 2000"
                          {...field}
                          onChange={(e) => field.onChange(e.target.value)}
                          data-testid="input-monthly-budget"
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="combinedFamilyIncome"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Combined Annual Family Income (CAD)</FormLabel>
                      <FormControl>
                        <Input 
                          type="number" 
                          min="0" 
                          step="1000"
                          placeholder="e.g. 75000"
                          {...field}
                          onChange={(e) => field.onChange(e.target.value)}
                          data-testid="input-family-income"
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <div className="md:col-span-2">
                  <FormField
                    control={form.control}
                    name="willingToPrepayRent"
                    render={({ field }) => (
                      <FormItem className="flex flex-row items-start space-x-3 space-y-0">
                        <FormControl>
                          <Checkbox
                            checked={field.value || false}
                            onCheckedChange={field.onChange}
                            data-testid="checkbox-prepay-rent"
                          />
                        </FormControl>
                        <div className="space-y-1 leading-none">
                          <FormLabel>Willing to prepay rent</FormLabel>
                          <p className="text-sm text-muted-foreground">
                            Check this if you can pay multiple months in advance
                          </p>
                        </div>
                      </FormItem>
                    )}
                  />
                </div>

                {willingToPrepayRent && (
                  <FormField
                    control={form.control}
                    name="prepayMonths"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>How many months can you prepay?</FormLabel>
                        <FormControl>
                          <Select value={String(field.value)} onValueChange={(value) => field.onChange(parseInt(value))}>
                            <SelectTrigger data-testid="select-prepay-months">
                              <SelectValue />
                            </SelectTrigger>
                            <SelectContent>
                              {[1, 2, 3, 6, 12].map((num) => (
                                <SelectItem key={num} value={String(num)}>
                                  {num} {num === 1 ? "Month" : "Months"}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                )}
              </CardContent>
            </Card>

            {/* Location & Timing */}
            <Card>
              <CardHeader>
                <CardTitle className="text-lg flex items-center gap-2">
                  <MapPin className="h-5 w-5" />
                  Location & Timing
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <FormField
                  control={form.control}
                  name="preferredAreasText"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Preferred Areas/Cities</FormLabel>
                      <FormControl>
                        <Textarea 
                          placeholder="e.g. Downtown Toronto, North York, Mississauga"
                          {...field}
                          data-testid="textarea-preferred-areas"
                        />
                      </FormControl>
                      <p className="text-sm text-muted-foreground">
                        Separate multiple areas with commas
                      </p>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="preferredMoveInDate"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Preferred Move-in Date</FormLabel>
                      <FormControl>
                        <Input 
                          type="date"
                          {...field}
                          value={field.value ? new Date(field.value).toISOString().split('T')[0] : ''}
                          onChange={(e) => field.onChange(e.target.value ? new Date(e.target.value) : undefined)}
                          data-testid="input-move-in-date"
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              </CardContent>
            </Card>

            <div className="flex justify-end gap-3">
              <Button 
                type="button"
                variant="outline"
                onClick={onClose}
                disabled={createRentalProfileMutation.isPending}
                data-testid="button-cancel-rental-form"
              >
                Cancel
              </Button>
              <Button 
                type="submit"
                disabled={createRentalProfileMutation.isPending}
                className="w-full sm:w-auto"
                data-testid="button-submit-rental-form"
              >
                {createRentalProfileMutation.isPending ? "Saving..." : "Save Rental Preferences"}
              </Button>
            </div>
          </form>
        </Form>
      </DialogContent>
    </Dialog>
  );
}

client/src/pages/BrokerageSettingsPage.t.content:
import { useQuery, useMutation } from "@tanstack/react-query";
import BrokerageSidebar, { BrokerageMobileHeader } from "@/components/BrokerageSidebar";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Settings, Building2, Mail, Phone, Save, Loader2 } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { useState, useEffect } from "react";
import { apiRequest, queryClient } from "@/lib/queryClient";
import type { Brokerage } from "@shared/schema";

export default function BrokerageSettingsPage() {
  const { toast } = useToast();
  const { data: settings, isLoading } = useQuery<Brokerage>({
    queryKey: ['/api/broker/settings'],
  });

  const [brokerageName, setBrokerageName] = useState("");
  const [contactEmail, setContactEmail] = useState("");
  const [contactPhone, setContactPhone] = useState("");
  const [website, setWebsite] = useState("");
  const [logoUrl, setLogoUrl] = useState("");

  useEffect(() => {
    if (settings) {
      setBrokerageName(settings.name || "");
      setContactEmail(settings.contactEmail || "");
      setContactPhone(settings.contactPhone || "");
      setWebsite(settings.website || "");
      setLogoUrl(settings.logoUrl || "");
    }
  }, [settings]);

  const saveMutation = useMutation({
    mutationFn: async (data: Partial<Brokerage>) => {
      return await apiRequest('/api/broker/settings', 'PUT', data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/broker/settings'] });
      toast({
        title: "Settings Saved",
        description: "Your brokerage settings have been updated successfully.",
      });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to save settings. Please try again.",
        variant: "destructive",
      });
    },
  });

  const handleSaveGeneral = () => {
    if (!settings?.id) return;
    saveMutation.mutate({
      id: settings.id,
      name: brokerageName,
      contactEmail,
      contactPhone,
      website,
    });
  };

  const handleSaveBranding = () => {
    if (!settings?.id) return;
    saveMutation.mutate({
      id: settings.id,
      logoUrl,
    });
  };

  return (
    <>
      <BrokerageMobileHeader />
      <div className="flex min-h-screen">
        <BrokerageSidebar />
        <div className="flex-1 p-4 md:p-8 pt-16 md:pt-8 space-y-4 md:space-y-6" data-testid="brokerage-settings-page">
          <div>
            <h1 className="text-2xl md:text-3xl font-bold" data-testid="heading-settings">Brokerage Settings</h1>
            <p className="text-sm md:text-base text-muted-foreground">Manage your brokerage configuration and preferences</p>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 md:gap-6">
          <Card data-testid="card-general-settings">
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Building2 className="h-5 w-5" />
                General Information
              </CardTitle>
              <CardDescription>Basic details about your brokerage</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="brokerage-name">Brokerage Name</Label>
                <Input
                  id="brokerage-name"
                  data-testid="input-brokerage-name"
                  value={brokerageName}
                  onChange={(e) => setBrokerageName(e.target.value)}
                  placeholder="Premier Realty Group"
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="contact-email">Contact Email</Label>
                <Input
                  id="contact-email"
                  data-testid="input-contact-email"
                  type="email"
                  value={contactEmail}
                  onChange={(e) => setContactEmail(e.target.value)}
                  placeholder="info@premierrealtygroup.com"
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="contact-phone">Contact Phone</Label>
                <Input
                  id="contact-phone"
                  data-testid="input-contact-phone"
                  type="tel"
                  value={contactPhone}
                  onChange={(e) => setContactPhone(e.target.value)}
                  placeholder="416-555-1234"
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="website">Website</Label>
                <Input
                  id="website"
                  data-testid="input-website"
                  type="url"
                  value={website}
                  onChange={(e) => setWebsite(e.target.value)}
                  placeholder="https://premierrealtygroup.com"
                />
              </div>
              <Button 
                className="w-full" 
                onClick={handleSaveGeneral}
                disabled={saveMutation.isPending}
                data-testid="button-save-general"
              >
                {saveMutation.isPending ? (
                  <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                ) : (
                  <Save className="h-4 w-4 mr-2" />
                )}
                Save Changes
              </Button>
            </CardContent>
          </Card>

          <Card data-testid="card-branding">
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Settings className="h-5 w-5" />
                Branding
              </CardTitle>
              <CardDescription>Customize your brokerage brand</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="logo-url">Logo URL</Label>
                <Input
                  id="logo-url"
                  data-testid="input-logo-url"
                  type="url"
                  value={logoUrl}
                  onChange={(e) => setLogoUrl(e.target.value)}
                  placeholder="https://example.com/logo.png"
                />
              </div>
              <Button 
                className="w-full"
                onClick={handleSaveBranding}
                disabled={saveMutation.isPending}
                data-testid="button-save-branding"
              >
                {saveMutation.isPending ? (
                  <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                ) : (
                  <Save className="h-4 w-4 mr-2" />
                )}
                Save Branding
              </Button>
            </CardContent>
          </Card>
        </div>

        <Card data-testid="card-permissions">
          <CardHeader>
            <CardTitle>Agent Permissions</CardTitle>
            <CardDescription>Configure what agents can view and manage</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="flex items-center justify-between p-4 border rounded-lg">
              <div>
                <p className="font-medium">View Media</p>
                <p className="text-sm text-muted-foreground">Allow agents to view property photos and videos</p>
              </div>
              <Button variant="outline" size="sm" data-testid="toggle-view-media">
                Enabled
              </Button>
            </div>
            <div className="flex items-center justify-between p-4 border rounded-lg">
              <div>
                <p className="font-medium">View Documents</p>
                <p className="text-sm text-muted-foreground">Allow agents to access client documents</p>
              </div>
              <Button variant="outline" size="sm" data-testid="toggle-view-documents">
                Enabled
              </Button>
            </div>
            <div className="flex items-center justify-between p-4 border rounded-lg">
              <div>
                <p className="font-medium">Manage Tours</p>
                <p className="text-sm text-muted-foreground">Allow agents to create and manage property tours</p>
              </div>
              <Button variant="outline" size="sm" data-testid="toggle-manage-tours">
                Enabled
              </Button>
            </div>
            <div className="flex items-center justify-between p-4 border rounded-lg">
              <div>
                <p className="font-medium">Submit Offers</p>
                <p className="text-sm text-muted-foreground">Allow agents to submit offers on behalf of clients</p>
              </div>
              <Button variant="outline" size="sm" data-testid="toggle-submit-offers">
                Enabled
              </Button>
            </div>
          </CardContent>
        </Card>

        <Card data-testid="card-notifications">
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Mail className="h-5 w-5" />
              Notification Settings
            </CardTitle>
            <CardDescription>Configure how you receive updates</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="flex items-center justify-between p-4 border rounded-lg">
              <div>
                <p className="font-medium">Daily Performance Summary</p>
                <p className="text-sm text-muted-foreground">Receive daily email with brokerage performance</p>
              </div>
              <Button variant="outline" size="sm" data-testid="toggle-daily-summary">
                Enabled
              </Button>
            </div>
            <div className="flex items-center justify-between p-4 border rounded-lg">
              <div>
                <p className="font-medium">New Agent Activity</p>
                <p className="text-sm text-muted-foreground">Get notified when agents complete tours or submit offers</p>
              </div>
              <Button variant="outline" size="sm" data-testid="toggle-agent-activity">
                Enabled
              </Button>
            </div>
            <div className="flex items-center justify-between p-4 border rounded-lg">
              <div>
                <p className="font-medium">Weekly Reports</p>
                <p className="text-sm text-muted-foreground">Receive comprehensive weekly performance reports</p>
              </div>
              <Button variant="outline" size="sm" data-testid="toggle-weekly-reports">
                Enabled
              </Button>
            </div>
          </CardContent>
        </Card>
        </div>
      </div>
    </>
  );
}

client/src/components/LocationAnalyticsM.content:
import { useState, useEffect } from "react";
import { useQuery } from "@tanstack/react-query";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";
import { ScrollArea } from "@/components/ui/scroll-area";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";
import { 
  MapPin, 
  TrendingUp, 
  Clock, 
  Zap, 
  Home, 
  BarChart3,
  Calendar,
  Navigation,
  Activity
} from "lucide-react";
import type { LocationHistory } from "@shared/schema";
import { format } from "date-fns";

interface LocationAnalyticsModalProps {
  isOpen: boolean;
  onClose: () => void;
  userId: string;
}

interface LocationAnalytics {
  totalDistance: number;
  totalTime: number;
  visitedProperties: number;
  avgSpeed: number;
  activityBreakdown: { activityType: string; count: number; percentage: number }[];
  heatmapData: { latitude: number; longitude: number; weight: number }[];
}

export function LocationAnalyticsModal({ isOpen, onClose, userId }: LocationAnalyticsModalProps) {
  const { toast } = useToast();
  const [dateRange, setDateRange] = useState({
    startDate: new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0], // Last 7 days
    endDate: new Date().toISOString().split('T')[0]
  });

  // Fetch location analytics
  const { data: analytics, isLoading: analyticsLoading } = useQuery<LocationAnalytics>({
    queryKey: ["/api/location-analytics", userId, dateRange],
    queryFn: async () => {
      const params = new URLSearchParams({
        startDate: dateRange.startDate,
        endDate: dateRange.endDate
      });
      const response = await apiRequest("GET", `/api/location-analytics/${userId}?${params}`);
      return response.json();
    },
    enabled: isOpen && !!userId,
  });

  // Fetch recent location history
  const { data: locationHistory = [], isLoading: historyLoading } = useQuery<LocationHistory[]>({
    queryKey: ["/api/location-history", userId, dateRange],
    queryFn: async () => {
      const params = new URLSearchParams({
        startDate: dateRange.startDate,
        endDate: dateRange.endDate
      });
      const response = await apiRequest("GET", `/api/location-history/${userId}?${params}`);
      return response.json();
    },
    enabled: isOpen && !!userId,
  });

  const formatDistance = (meters: number) => {
    if (meters < 1000) return `${Math.round(meters)}m`;
    return `${(meters / 1000).toFixed(1)}km`;
  };

  const formatTime = (seconds: number) => {
    const hours = Math.floor(seconds / 3600);
    const minutes = Math.floor((seconds % 3600) / 60);
    if (hours > 0) return `${hours}h ${minutes}m`;
    return `${minutes}m`;
  };

  const getActivityIcon = (activityType: string) => {
    switch (activityType) {
      case 'touring': return <Home className="h-4 w-4" />;
      case 'traveling': return <Navigation className="h-4 w-4" />;
      case 'meeting': return <Activity className="h-4 w-4" />;
      case 'showing': return <MapPin className="h-4 w-4" />;
      case 'office': return <BarChart3 className="h-4 w-4" />;
      default: return <MapPin className="h-4 w-4" />;
    }
  };

  const getActivityColor = (activityType: string) => {
    switch (activityType) {
      case 'touring': return 'bg-blue-100 text-blue-800 dark:bg-blue-900 dark:text-blue-300';
      case 'traveling': return 'bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-300';
      case 'meeting': return 'bg-purple-100 text-purple-800 dark:bg-purple-900 dark:text-purple-300';
      case 'showing': return 'bg-orange-100 text-orange-800 dark:bg-orange-900 dark:text-orange-300';
      case 'office': return 'bg-gray-100 text-gray-800 dark:bg-gray-900 dark:text-gray-300';
      default: return 'bg-slate-100 text-slate-800 dark:bg-slate-900 dark:text-slate-300';
    }
  };

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-4xl max-h-[80vh]" data-testid="modal-location-analytics">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <BarChart3 className="h-5 w-5" />
            Location Analytics & Movement Patterns
          </DialogTitle>
        </DialogHeader>

        <div className="space-y-6">
          {/* Date Range Selector */}
          <Card>
            <CardHeader>
              <CardTitle className="text-sm flex items-center gap-2">
                <Calendar className="h-4 w-4" />
                Date Range
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="flex gap-4 items-center">
                <div>
                  <label className="text-sm font-medium">From</label>
                  <input
                    type="date"
                    value={dateRange.startDate}
                    onChange={(e) => setDateRange(prev => ({ ...prev, startDate: e.target.value }))}
                    className="mt-1 block w-full rounded-md border border-gray-300 dark:border-gray-700 px-3 py-2 text-sm"
                    data-testid="input-analytics-start-date"
                  />
                </div>
                <div>
                  <label className="text-sm font-medium">To</label>
                  <input
                    type="date"
                    value={dateRange.endDate}
                    onChange={(e) => setDateRange(prev => ({ ...prev, endDate: e.target.value }))}
                    className="mt-1 block w-full rounded-md border border-gray-300 dark:border-gray-700 px-3 py-2 text-sm"
                    data-testid="input-analytics-end-date"
                  />
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Analytics Summary Cards */}
          {analyticsLoading ? (
            <div className="text-center py-8" data-testid="loading-analytics">
              <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary mx-auto"></div>
              <p className="text-muted-foreground mt-2">Loading analytics...</p>
            </div>
          ) : analytics ? (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
              <Card data-testid="card-total-distance">
                <CardContent className="p-4">
                  <div className="flex items-center justify-between">
                    <div>
                      <p className="text-sm font-medium text-muted-foreground">Total Distance</p>
                      <p className="text-2xl font-bold">{formatDistance(analytics.totalDistance)}</p>
                    </div>
                    <Navigation className="h-8 w-8 text-muted-foreground" />
                  </div>
                </CardContent>
              </Card>

              <Card data-testid="card-total-time">
                <CardContent className="p-4">
                  <div className="flex items-center justify-between">
                    <div>
                      <p className="text-sm font-medium text-muted-foreground">Total Time</p>
                      <p className="text-2xl font-bold">{formatTime(analytics.totalTime)}</p>
                    </div>
                    <Clock className="h-8 w-8 text-muted-foreground" />
                  </div>
                </CardContent>
              </Card>

              <Card data-testid="card-properties-visited">
                <CardContent className="p-4">
                  <div className="flex items-center justify-between">
                    <div>
                      <p className="text-sm font-medium text-muted-foreground">Properties Visited</p>
                      <p className="text-2xl font-bold">{analytics.visitedProperties}</p>
                    </div>
                    <Home className="h-8 w-8 text-muted-foreground" />
                  </div>
                </CardContent>
              </Card>

              <Card data-testid="card-avg-speed">
                <CardContent className="p-4">
                  <div className="flex items-center justify-between">
                    <div>
                      <p className="text-sm font-medium text-muted-foreground">Avg Speed</p>
                      <p className="text-2xl font-bold">{analytics.avgSpeed.toFixed(1)} km/h</p>
                    </div>
                    <Zap className="h-8 w-8 text-muted-foreground" />
                  </div>
                </CardContent>
              </Card>
            </div>
          ) : null}

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            {/* Activity Breakdown */}
            {analytics && (
              <Card data-testid="card-activity-breakdown">
                <CardHeader>
                  <CardTitle className="text-lg flex items-center gap-2">
                    <TrendingUp className="h-5 w-5" />
                    Activity Breakdown
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="space-y-3">
                    {analytics.activityBreakdown.map((activity, index) => (
                      <div key={index} className="flex items-center justify-between">
                        <div className="flex items-center gap-2">
                          {getActivityIcon(activity.activityType)}
                          <span className="font-medium capitalize">{activity.activityType}</span>
                        </div>
                        <div className="flex items-center gap-2">
                          <Badge variant="secondary" className={getActivityColor(activity.activityType)}>
                            {activity.count} ({activity.percentage.toFixed(1)}%)
                          </Badge>
                        </div>
                      </div>
                    ))}
                  </div>
                </CardContent>
              </Card>
            )}

            {/* Recent Location History */}
            <Card data-testid="card-location-history">
              <CardHeader>
                <CardTitle className="text-lg flex items-center gap-2">
                  <MapPin className="h-5 w-5" />
                  Recent Location History
                </CardTitle>
              </CardHeader>
              <CardContent>
                <ScrollArea className="h-[300px]">
                  {historyLoading ? (
                    <div className="text-center py-8" data-testid="loading-history">
                      <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-primary mx-auto"></div>
                      <p className="text-sm text-muted-foreground mt-2">Loading history...</p>
                    </div>
                  ) : locationHistory.length > 0 ? (
                    <div className="space-y-3">
                      {locationHistory.slice(0, 20).map((location) => (
                        <div key={location.id} className="flex items-start gap-3 p-2 rounded-lg border" data-testid={`history-item-${location.id}`}>
                          <div className="mt-1">
                            {getActivityIcon(location.activityType || 'unknown')}
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center justify-between">
                              <Badge variant="outline" className={getActivityColor(location.activityType || 'unknown')}>
                                {location.activityType || 'unknown'}
                              </Badge>
                              <span className="text-xs text-muted-foreground">
                                {location.recordedAt ? format(new Date(location.recordedAt), 'MMM d, HH:mm') : 'Unknown time'}
                              </span>
                            </div>
                            {location.address && (
                              <p className="text-sm text-muted-foreground mt-1 truncate">{location.address}</p>
                            )}
                            <div className="flex items-center gap-4 text-xs text-muted-foreground mt-1">
                              <span>Lat: {Number(location.latitude).toFixed(4)}</span>
                              <span>Lng: {Number(location.longitude).toFixed(4)}</span>
                              {location.speed && Number(location.speed) > 0 && (
                                <span>Speed: {Number(location.speed).toFixed(1)} km/h</span>
                              )}
                            </div>
                          </div>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <div className="text-center py-8" data-testid="no-history">
                      <MapPin className="h-12 w-12 text-muted-foreground mx-auto mb-2" />
                      <p className="text-muted-foreground">No location history found for this period</p>
                    </div>
                  )}
                </ScrollArea>
              </CardContent>
            </Card>
          </div>

          {/* Action Buttons */}
          <div className="flex justify-end gap-3 pt-4 border-t">
            <Button variant="outline" onClick={onClose} data-testid="button-close">
              Close
            </Button>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

