import { useState } from "react";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";
import { Home, Key, Users, MapPin } from "lucide-react";

interface ClientTypeSelectionModalProps {
  isOpen: boolean;
  onClose: () => void;
  onClientTypeSelected: (clientType: "buyer" | "renter") => void;
}

export function ClientTypeSelectionModal({ 
  isOpen, 
  onClose, 
  onClientTypeSelected 
}: ClientTypeSelectionModalProps) {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [selectedType, setSelectedType] = useState<"buyer" | "renter" | null>(null);

  const updateClientTypeMutation = useMutation({
    mutationFn: async (clientType: "buyer" | "renter") => {
      const response = await apiRequest("PUT", "/api/auth/client-type", { clientType });
      return response.json();
    },
    onSuccess: (data, clientType) => {
      queryClient.invalidateQueries({ queryKey: ["/api/auth/user"] });
      toast({
        title: "Client Type Selected",
        description: `You've been set up as a ${clientType === "buyer" ? "buyer" : "renter"}.`,
      });
      onClientTypeSelected(clientType);
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to update client type. Please try again.",
        variant: "destructive",
      });
    },
  });

  const handleTypeSelection = (type: "buyer" | "renter") => {
    setSelectedType(type);
  };

  const handleConfirm = () => {
    if (selectedType) {
      updateClientTypeMutation.mutate(selectedType);
    }
  };

  return (
    <Dialog open={isOpen} onOpenChange={(open) => { if (!open) onClose(); }}>
      <DialogContent className="max-w-2xl" data-testid="dialog-client-type-selection">
        <DialogHeader>
          <DialogTitle>Welcome to Estate Vista!</DialogTitle>
