        </DialogHeader>

        <div className="grid md:grid-cols-2 gap-6 mt-6">
          {/* Buyer Option */}
          <Card 
            className={`cursor-pointer transition-all hover:shadow-md ${
              selectedType === "buyer" 
                ? "ring-2 ring-primary border-primary bg-primary/5" 
                : "hover:border-primary/50"
            }`}
            onClick={() => handleTypeSelection("buyer")}
            data-testid="card-buyer-option"
          >
            <CardHeader className="text-center pb-4">
              <div className="mx-auto w-16 h-16 bg-primary/10 rounded-full flex items-center justify-center mb-3">
                <Home className="h-8 w-8 text-primary" />
              </div>
              <CardTitle className="text-xl">Buyer</CardTitle>
            </CardHeader>
            <CardContent className="text-center">
              <p className="text-muted-foreground mb-4">
                Looking to purchase a property for long-term ownership
              </p>
              <div className="space-y-2 text-sm">
                <div className="flex items-center justify-center gap-2">
                  <Users className="h-4 w-4 text-muted-foreground" />
                  <span>Property viewings & tours</span>
                </div>
                <div className="flex items-center justify-center gap-2">
                  <MapPin className="h-4 w-4 text-muted-foreground" />
                  <span>Area exploration</span>
                </div>
                <div className="flex items-center justify-center gap-2">
                  <Home className="h-4 w-4 text-muted-foreground" />
                  <span>Purchase offers & negotiations</span>
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Renter Option */}
          <Card 
            className={`cursor-pointer transition-all hover:shadow-md ${
