  );
}

client/src/components/TourPlannerModal.t.content:
import { useState, useEffect } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { useToast } from "@/hooks/use-toast";
import { apiRequest, queryClient } from "@/lib/queryClient";
import Autocomplete from "react-google-autocomplete";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent } from "@/components/ui/card";
import { 
  Route, 
  Clock, 
  MapPin, 
  Navigation, 
  Calendar,
  Users,
  ArrowDown,
  Shuffle,
  Play
} from "lucide-react";

interface TourPlannerModalProps {
  isOpen: boolean;
  onClose: () => void;
  selectedDate: Date;
}

interface TourStop {
  id: string;
  propertyAddress: string;
  clientName: string;
  scheduledTime: string;
  duration: number;
  latitude?: number;
  longitude?: number;
}

interface RouteOptimization {
  optimizedOrder: TourStop[];
  totalDistance: string;
  totalDuration: string;
  startLocation: string;
}

export default function TourPlannerModal({ 
  isOpen, 
  onClose, 
  selectedDate 
}: TourPlannerModalProps) {
  const { toast } = useToast();
  const [startingAddress, setStartingAddress] = useState("");
  const [optimizedRoute, setOptimizedRoute] = useState<RouteOptimization | null>(null);
  const [isOptimizing, setIsOptimizing] = useState(false);

  // Fetch tours for the selected date
  const { data: dayTours = [], isLoading } = useQuery<any[]>({
    queryKey: ["/api/tours/date", selectedDate.toISOString().split('T')[0]],
    enabled: isOpen,
  });

  // Route optimization mutation
  const optimizeRouteMutation = useMutation({
    mutationFn: async (data: { startingAddress: string; tours: TourStop[] }) => {
      console.log("Making optimize-route request with data:", data);
      const response = await apiRequest("POST", "/api/tours/optimize-route", data);
      const result = await response.json();
      console.log("Optimize-route response:", result);
      return result;
    },
    onSuccess: (result: RouteOptimization) => {
      console.log("onSuccess called with result:", result);
      setOptimizedRoute(result);
      setIsOptimizing(false);
      toast({
        title: "Route Optimized",
        description: `Optimized route calculated: ${result.totalDistance}, ${result.totalDuration}`,
      });
    },
    onError: (error) => {
      console.error("onError called with error:", error);
      setIsOptimizing(false);
      toast({
        title: "Optimization Failed",
        description: "Could not optimize route. Please try again.",
        variant: "destructive",
      });
    },
  });

  const handleOptimizeRoute = () => {
    if (!startingAddress.trim()) {
      toast({
        title: "Starting Address Required",
        description: "Please enter your starting address for route optimization.",
        variant: "destructive",
      });
      return;
    }

    if (dayTours.length === 0) {
      toast({
        title: "No Tours Scheduled",
        description: "No tours scheduled for this date.",
        variant: "destructive",
      });
      return;
    }

    // Transform tours to ensure propertyAddress is included for backend optimization
    const toursWithAddresses = dayTours.map((tour: any) => ({
      id: tour.id,
      propertyAddress: tour.propertyAddress || tour.property?.address || "Unknown Address",
      clientName: tour.clientName || `${tour.client?.firstName || ""} ${tour.client?.lastName || ""}`.trim(),
      scheduledTime: tour.startTime || tour.scheduledDate || "",
      duration: tour.estimatedDuration || 30,
      latitude: tour.property?.latitude,
      longitude: tour.property?.longitude,
    }));

    setIsOptimizing(true);
    optimizeRouteMutation.mutate({
      startingAddress,
      tours: toursWithAddresses,
    });
  };

  const formatTime = (timeString: string) => {
    return new Date(timeString).toLocaleTimeString("en-US", {
      hour: "numeric",
      minute: "2-digit",
      hour12: true,
    });
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case "scheduled":
        return "bg-blue-100 text-blue-800";
      case "in_progress":
        return "bg-yellow-100 text-yellow-800";
      case "completed":
        return "bg-green-100 text-green-800";
      default:
        return "bg-gray-100 text-gray-800";
    }
  };

  const handleStartTourOnMaps = () => {
    if (!optimizedRoute || optimizedRoute.optimizedOrder.length === 0) {
      toast({
        title: "No Route Available",
        description: "Please optimize a route first.",
        variant: "destructive",
      });
      return;
    }

    try {
      // Extract origin and destination
      const origin = encodeURIComponent(optimizedRoute.startLocation);
      const stops = optimizedRoute.optimizedOrder;

      // Set destination as the last stop
      const destination = encodeURIComponent(stops[stops.length - 1].propertyAddress);

      // Create waypoints from all stops except the last one (which is the destination)
      const waypoints = stops
        .slice(0, -1)
        .map((stop) => encodeURIComponent(stop.propertyAddress))
        .join("|");

      // Construct Google Maps URL
      let mapsUrl = `https://www.google.com/maps/dir/?api=1&origin=${origin}&destination=${destination}`;

      if (waypoints) {
        mapsUrl += `&waypoints=${waypoints}`;
      }

      // Open Google Maps in a new tab
      window.open(mapsUrl, "_blank");

      toast({
        title: "Redirecting to Google Maps",
        description: "Opening your optimized route in Google Maps for navigation.",
      });
    } catch (error) {
      console.error("Error constructing Google Maps URL:", error);
      toast({
        title: "Error",
        description: "Failed to open Google Maps. Please try again.",
        variant: "destructive",
      });
    }
  };

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Route className="h-5 w-5" />
            Tour Route Planner - {selectedDate.toLocaleDateString()}
          </DialogTitle>
        </DialogHeader>

        <div className="space-y-6">
          {/* Starting Location Input */}
          <Card>
            <CardContent className="p-4">
              <div className="space-y-3">
                <div className="flex items-center gap-2">
                  <Navigation className="h-4 w-4 text-primary" />
                  <h3 className="font-medium">Starting Location</h3>
                </div>
                <div className="flex gap-3">
                  <Input
                    value={startingAddress}
                    onChange={(e) => setStartingAddress(e.target.value)}
                    placeholder="Enter your starting address (office, home, etc.)"
                    className="flex-1"
                    data-testid="input-starting-address"
                  />
                  <Button
                    onClick={handleOptimizeRoute}
                    disabled={isOptimizing || optimizeRouteMutation.isPending}
                    data-testid="button-optimize-route"
                  >
                    {isOptimizing ? (
                      <>
                        <Shuffle className="h-4 w-4 mr-2 animate-spin" />
                        Optimizing...
                      </>
                    ) : (
                      <>
                        <Shuffle className="h-4 w-4 mr-2" />
                        Optimize Route
                      </>
                    )}
                  </Button>
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Tours for the Day */}
          <Card>
            <CardContent className="p-4">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-2">
                  <Calendar className="h-4 w-4 text-primary" />
                  <h3 className="font-medium">Scheduled Tours</h3>
                  <Badge variant="secondary">{dayTours.length} tours</Badge>
                </div>
              </div>

              {isLoading ? (
                <div className="space-y-3">
                  {[1, 2, 3].map((i) => (
                    <div key={i} className="animate-pulse border rounded-lg p-4">
                      <div className="h-4 bg-muted rounded w-1/3 mb-2"></div>
                      <div className="h-3 bg-muted rounded w-1/2"></div>
                    </div>
                  ))}
                </div>
              ) : dayTours.length === 0 ? (
                <div className="text-center py-8">
                  <Calendar className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
                  <p className="text-muted-foreground">No tours scheduled for this date</p>
                </div>
              ) : (
                <div className="space-y-3">
                  {(optimizedRoute?.optimizedOrder || dayTours || []).map((tour: any, index: number) => (
                    <div key={tour.id} className="border rounded-lg p-4 hover:bg-muted/50 transition-colors">
                      <div className="flex items-start justify-between">
                        <div className="flex items-start gap-3">
                          <div className="flex items-center justify-center w-8 h-8 rounded-full bg-primary text-primary-foreground text-sm font-medium">
                            {index + 1}
                          </div>
                          <div className="flex-1">
                            <div className="flex items-center gap-2 mb-1">
                              <MapPin className="h-4 w-4 text-muted-foreground" />
                              <p className="font-medium">{tour.propertyAddress || tour.property?.address}</p>
                            </div>
                            <div className="flex items-center gap-2 mb-1">
                              <Users className="h-4 w-4 text-muted-foreground" />
                              <p className="text-sm text-muted-foreground">
                                Client: {tour.clientName || tour.client?.firstName + " " + tour.client?.lastName}
                              </p>
                            </div>
                            <div className="flex items-center gap-2">
                              <Clock className="h-4 w-4 text-muted-foreground" />
                              <p className="text-sm text-muted-foreground">
                                {formatTime(tour.scheduledDate || tour.startTime)} 
                                ({tour.estimatedDuration || 30} min)
                              </p>
                            </div>
                          </div>
                        </div>
                        <Badge className={getStatusColor(tour.status)}>
                          {tour.status || "scheduled"}
                        </Badge>
                      </div>
                      {index < (optimizedRoute?.optimizedOrder || dayTours || []).length - 1 && (
                        <div className="flex justify-center mt-3">
                          <ArrowDown className="h-4 w-4 text-muted-foreground" />
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              )}
            </CardContent>
          </Card>

          {/* Route Summary */}
          {optimizedRoute && (
            <Card>
              <CardContent className="p-4">
                <div className="flex items-center gap-2 mb-4">
                  <Route className="h-4 w-4 text-green-600" />
                  <h3 className="font-medium text-green-600">Optimized Route Summary</h3>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <div className="text-center p-3 bg-blue-50 rounded-lg">
                    <MapPin className="h-6 w-6 text-blue-600 mx-auto mb-2" />
                    <p className="text-sm text-blue-600 font-medium">Total Distance</p>
                    <p className="text-lg font-bold text-blue-800">{optimizedRoute.totalDistance}</p>
                  </div>
                  <div className="text-center p-3 bg-green-50 rounded-lg">
                    <Clock className="h-6 w-6 text-green-600 mx-auto mb-2" />
                    <p className="text-sm text-green-600 font-medium">Estimated Duration</p>
                    <p className="text-lg font-bold text-green-800">{optimizedRoute.totalDuration}</p>
                  </div>
                  <div className="text-center p-3 bg-purple-50 rounded-lg">
                    <Navigation className="h-6 w-6 text-purple-600 mx-auto mb-2" />
                    <p className="text-sm text-purple-600 font-medium">Total Stops</p>
                    <p className="text-lg font-bold text-purple-800">{optimizedRoute?.optimizedOrder?.length || 0}</p>
                  </div>
                </div>
              </CardContent>
            </Card>
          )}

          {/* Action Buttons */}
          <div className="flex justify-end gap-3">
            <Button variant="outline" onClick={onClose}>
              Close
            </Button>
            {optimizedRoute && (
              <Button 
                className="bg-green-600 hover:bg-green-700"
                onClick={handleStartTourOnMaps}
                data-testid="button-start-tour"
              >
                <Play className="h-4 w-4 mr-2" />
                Start Tour
              </Button>
            )}
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

