import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Bell, Trash2, Plus } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { format } from "date-fns";

interface TourRemindersModalProps {
  isOpen: boolean;
  onClose: () => void;
  tourId: string;
}

export default function TourRemindersModal({ isOpen, onClose, tourId }: TourRemindersModalProps) {
  const { toast } = useToast();
  const [reminderDate, setReminderDate] = useState("");
  const [reminderTime, setReminderTime] = useState("");
  const [reminderNotes, setReminderNotes] = useState("");

  const { data: reminders = [], isLoading } = useQuery<any[]>({
    queryKey: ["/api/tours", tourId, "reminders"],
    enabled: !!tourId && isOpen,
  });

  const addReminderMutation = useMutation({
    mutationFn: async (data: { reminderDate: string; notes: string }) => {
      return apiRequest("POST", `/api/tours/${tourId}/reminders`, data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/tours", tourId, "reminders"] });
      setReminderDate("");
      setReminderTime("");
      setReminderNotes("");
      toast({
        title: "Reminder added",
        description: "Tour reminder has been set successfully",
      });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to add reminder",
        variant: "destructive",
      });
    },
  });

  const deleteReminderMutation = useMutation({
    mutationFn: async (reminderId: string) => {
      return apiRequest("DELETE", `/api/tours/${tourId}/reminders/${reminderId}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/tours", tourId, "reminders"] });
      toast({
        title: "Reminder deleted",
        description: "Tour reminder has been removed",
      });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to delete reminder",
        variant: "destructive",
      });
    },
  });

  const handleAddReminder = () => {
    if (!reminderDate) {
      toast({
        title: "Validation Error",
        description: "Please select a date for the reminder",
        variant: "destructive",
      });
      return;
    }

    let reminderDateTime = reminderDate;
    if (reminderTime) {
      reminderDateTime = `${reminderDate}T${reminderTime}:00`;
    }

    addReminderMutation.mutate({
      reminderDate: reminderDateTime,
      notes: reminderNotes || "",
    });
  };

  const handleDeleteReminder = (reminderId: string) => {
    deleteReminderMutation.mutate(reminderId);
  };

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-2xl" data-testid="dialog-tour-reminders">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Bell className="h-5 w-5" />
            Tour Reminders
          </DialogTitle>
        </DialogHeader>

        <div className="space-y-6">
          {/* Add Reminder Section */}
          <div className="border rounded-lg p-4 space-y-4">
            <h3 className="font-semibold">Add New Reminder</h3>
            <div className="grid md:grid-cols-2 gap-4">
              <div>
                <Label htmlFor="reminder-date">Date</Label>
                <Input
                  id="reminder-date"
                  type="date"
                  value={reminderDate}
                  onChange={(e) => setReminderDate(e.target.value)}
                  data-testid="input-reminder-date"
                />
              </div>
              <div>
                <Label htmlFor="reminder-time">Time (Optional)</Label>
                <Input
                  id="reminder-time"
                  type="time"
                  value={reminderTime}
                  onChange={(e) => setReminderTime(e.target.value)}
                  data-testid="input-reminder-time"
                />
              </div>
            </div>
            <div>
              <Label htmlFor="reminder-notes">Notes (Optional)</Label>
              <Input
                id="reminder-notes"
                type="text"
                placeholder="e.g., Call client to confirm"
                value={reminderNotes}
                onChange={(e) => setReminderNotes(e.target.value)}
                data-testid="input-reminder-notes"
              />
            </div>
            <Button
              onClick={handleAddReminder}
              disabled={addReminderMutation.isPending || !reminderDate}
              className="gap-2"
              data-testid="button-add-reminder"
            >
              <Plus className="h-4 w-4" />
              Add Reminder
            </Button>
          </div>

          {/* Existing Reminders */}
          <div className="space-y-3">
            <h3 className="font-semibold">Scheduled Reminders</h3>
            {isLoading ? (
              <div className="flex items-center justify-center py-8">
                <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-primary"></div>
              </div>
            ) : reminders.length === 0 ? (
              <p className="text-sm text-muted-foreground py-4">No reminders set for this tour</p>
            ) : (
              <div className="space-y-2">
                {reminders.map((reminder) => (
                  <div
                    key={reminder.id}
                    className="flex items-center justify-between p-3 border rounded-lg hover:bg-muted/50 transition"
                    data-testid={`reminder-${reminder.id}`}
                  >
                    <div className="flex-1">
                      <div className="flex items-center gap-2">
                        <Bell className="h-4 w-4 text-muted-foreground" />
                        <span className="font-medium">
                          {format(new Date(reminder.reminderDate), "MMM dd, yyyy 'at' h:mm a")}
                        </span>
                        <Badge variant="outline" className="text-xs">
                          {reminder.status || "pending"}
                        </Badge>
                      </div>
                      {reminder.notes && (
                        <p className="text-sm text-muted-foreground mt-1 ml-6">{reminder.notes}</p>
                      )}
                    </div>
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => handleDeleteReminder(reminder.id)}
                      disabled={deleteReminderMutation.isPending}
                      data-testid={`button-delete-reminder-${reminder.id}`}
                    >
                      <Trash2 className="h-4 w-4 text-destructive" />
                    </Button>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        <div className="flex justify-end">
          <Button variant="outline" onClick={onClose} data-testid="button-close-reminders">
            Close
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
}

