import { useState, useEffect } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Checkbox } from "@/components/ui/checkbox";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { useToast } from "@/hooks/use-toast";
import { useAuth } from "@/hooks/useAuth";
import { useQuery } from "@tanstack/react-query";
import { apiRequest } from "@/lib/queryClient";
import { insertRentalApplicationSchema, type Property, type User as UserType } from "@shared/schema";
import { z } from "zod";
import { 
  FileText, 
  User, 
  Briefcase, 
  DollarSign, 
  Home, 
  Users, 
  Car, 
  CheckCircle 
} from "lucide-react";

// OREA Form 410 validation schema
const oreaForm410Schema = insertRentalApplicationSchema.extend({
  // Employment History (allow multiple entries)
  currentEmployment: z.object({
    employerName: z.string().min(1, "Employer name is required"),
    businessAddress: z.string().min(1, "Business address is required"),
    businessPhone: z.string().min(1, "Business phone is required"),
    position: z.string().min(1, "Position is required"),
    startDate: z.string().min(1, "Start date is required"),
    supervisorName: z.string().optional(),
    monthlySalary: z.string().min(1, "Monthly salary is required"),
    salaryType: z.enum(["hourly", "salary", "commission", "contract"]),
  }),
  previousEmployment: z.object({
    employerName: z.string().optional(),
    businessAddress: z.string().optional(),
    businessPhone: z.string().optional(),
    position: z.string().optional(),
    startDate: z.string().optional(),
    endDate: z.string().optional(),
    supervisorName: z.string().optional(),
    monthlySalary: z.string().optional(),
    salaryType: z.enum(["hourly", "salary", "commission", "contract"]).optional(),
  }).optional(),
  // Financial Information
  financialInfo: z.object({
    bankName: z.string().min(1, "Bank name is required"),
    branchAddress: z.string().min(1, "Branch address is required"),
    accountType: z.enum(["checking", "savings", "credit"]),
    accountNumber: z.string().min(1, "Account number is required"),
    monthlyIncome: z.string().min(1, "Monthly income is required"),
    otherIncome: z.string().default("0"),
    otherIncomeSource: z.string().optional(),
    monthlyDebts: z.string().default("0"),
    debtDetails: z.string().optional(),
    bankruptcyHistory: z.boolean().default(false),
    bankruptcyDetails: z.string().optional(),
  }),
  // Rental History (allow multiple entries)
  currentRental: z.object({
    address: z.string().optional(),
    landlordName: z.string().optional(),
    landlordPhone: z.string().optional(),
    landlordEmail: z.string().optional(),
    monthlyRent: z.string().optional(),
    startDate: z.string().optional(),
    reasonForLeaving: z.string().optional(),
    wasEvicted: z.boolean().default(false),
    latePayments: z.boolean().default(false),
  }).optional(),
  previousRental: z.object({
    address: z.string().optional(),
    landlordName: z.string().optional(),
    landlordPhone: z.string().optional(),
    landlordEmail: z.string().optional(),
    monthlyRent: z.string().optional(),
    startDate: z.string().optional(),
    endDate: z.string().optional(),
    reasonForLeaving: z.string().optional(),
    wasEvicted: z.boolean().default(false),
    latePayments: z.boolean().default(false),
  }).optional(),
  // Personal References
  reference1: z.object({
    name: z.string().min(1, "Reference name is required"),
    relationship: z.string().min(1, "Relationship is required"),
    phoneNumber: z.string().min(1, "Phone number is required"),
    email: z.string().email("Invalid email").optional(),
    yearsKnown: z.string().min(1, "Years known is required"),
  }),
  reference2: z.object({
    name: z.string().min(1, "Reference name is required"),
    relationship: z.string().min(1, "Relationship is required"),
    phoneNumber: z.string().min(1, "Phone number is required"),
    email: z.string().email("Invalid email").optional(),
    yearsKnown: z.string().min(1, "Years known is required"),
  }),
  // Additional Occupants (JSON field)
  additionalOccupantsText: z.string().optional(),
});

type OreaForm410Data = z.infer<typeof oreaForm410Schema>;

interface OreaForm410ModalProps {
  isOpen: boolean;
  onClose: () => void;
  onComplete: () => void;
  selectedProperty: Property | null;
}

export function OreaForm410Modal({ isOpen, onClose, onComplete, selectedProperty }: OreaForm410ModalProps) {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [activeTab, setActiveTab] = useState("property");

  // Get current user for server-managed fields
  const { data: user } = useQuery<UserType>({ queryKey: ['/api/auth/user'] });

  const form = useForm<OreaForm410Data>({
    resolver: zodResolver(oreaForm410Schema),
    defaultValues: {
      // Server-managed fields (required by schema) - add debug logging
      userId: user?.id || "",
      propertyId: selectedProperty?.id || "", 
      agentId: selectedProperty?.agentId || "",
      applicationNumber: `APP-${Date.now()}`,
      // Property & Lease Information
      monthlyRent: selectedProperty?.price?.toString() || "0",
      rentDueDate: 1,
      // Personal Information
      phoneNumber: "",
      occupation: "",
      // Vehicle Information
      vehicleMake: "",
      vehicleModel: "",
      vehicleYear: new Date().getFullYear(),
      vehicleLicensePlate: "",
      // Pet Information
      hasPets: false,
      petDetails: "",
      // Employment
      currentEmployment: {
        employerName: "",
        businessAddress: "",
        businessPhone: "",
        position: "",
        startDate: "",
        supervisorName: "",
        monthlySalary: "",
        salaryType: "salary",
      },
      // Financial
      financialInfo: {
        bankName: "",
        branchAddress: "",
        accountType: "checking",
        accountNumber: "",
        monthlyIncome: "",
        otherIncome: "0",
        monthlyDebts: "0",
        bankruptcyHistory: false,
      },
      // References
      reference1: {
        name: "",
        relationship: "",
        phoneNumber: "",
        email: "",
        yearsKnown: "",
      },
      reference2: {
        name: "",
        relationship: "",
        phoneNumber: "",
        email: "",
        yearsKnown: "",
      },
      // Additional occupants
      additionalOccupantsText: "",
      // Consent
      consentBackgroundCheck: false,
      consentCreditCheck: false,
      consentReferenceCheck: false,
    },
  });

  const createApplicationMutation = useMutation({
    mutationFn: async (data: OreaForm410Data) => {
      // Transform the form data to match the database schema
      const applicationData = {
        userId: user?.id,
        propertyId: selectedProperty?.id,
        agentId: selectedProperty?.agentId,
        applicationNumber: `APP-${Date.now()}`, // Generate unique application number
        intendedStartDate: data.intendedStartDate,
        monthlyRent: data.monthlyRent,
        rentDueDate: parseInt(data.rentDueDate?.toString() || "1"),
        dateOfBirth: data.dateOfBirth,
        socialInsuranceNumber: data.socialInsuranceNumber,
        driversLicenseNumber: data.driversLicenseNumber,
        phoneNumber: data.phoneNumber,
        occupation: data.occupation,
        vehicleMake: data.vehicleMake,
        vehicleModel: data.vehicleModel,
        vehicleYear: data.vehicleYear,
        vehicleLicensePlate: data.vehicleLicensePlate,
        hasPets: data.hasPets,
        petDetails: data.petDetails,
        additionalOccupants: data.additionalOccupantsText ? data.additionalOccupantsText.split('\n').filter(line => line.trim()) : [],
        consentBackgroundCheck: data.consentBackgroundCheck,
        consentCreditCheck: data.consentCreditCheck,
        consentReferenceCheck: data.consentReferenceCheck,
        // Include all section data for related tables
        currentEmployment: data.currentEmployment,
        previousEmployment: data.previousEmployment,
        financialInfo: data.financialInfo,
        currentRental: data.currentRental,
        previousRental: data.previousRental,
        reference1: data.reference1,
        reference2: data.reference2,
      };

      const response = await apiRequest("POST", "/api/rental-applications", applicationData);
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/rental-applications"] });
      toast({
        title: "Application Submitted",
        description: "Your OREA Form 410 rental application has been submitted successfully.",
      });
      onComplete();
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to submit rental application. Please try again.",
        variant: "destructive",
      });
    },
