                      />
                      <FormField
                        control={form.control}
                        name="consentCreditCheck"
                        render={({ field }) => (
                          <FormItem className="flex flex-row items-start space-x-3 space-y-0">
                            <FormControl>
                              <Checkbox
                                checked={field.value || false}
                                onCheckedChange={field.onChange}
                                data-testid="checkbox-consent-credit"
                              />
                            </FormControl>
                            <div className="space-y-1 leading-none">
                              <FormLabel>
                                I consent to a credit check being conducted
                              </FormLabel>
                              <p className="text-sm text-muted-foreground">
                                This will include your credit score, payment history, and outstanding debts.
                              </p>
                            </div>
                          </FormItem>
                        )}
                      />
                      <FormField
                        control={form.control}
                        name="consentReferenceCheck"
                        render={({ field }) => (
                          <FormItem className="flex flex-row items-start space-x-3 space-y-0">
                            <FormControl>
                              <Checkbox
                                checked={field.value || false}
                                onCheckedChange={field.onChange}
                                data-testid="checkbox-consent-references"
                              />
                            </FormControl>
                            <div className="space-y-1 leading-none">
                              <FormLabel>
                                I consent to reference checks being conducted
                              </FormLabel>
                              <p className="text-sm text-muted-foreground">
                                This includes contacting your personal references, employers, and previous landlords.
                              </p>
                            </div>
                          </FormItem>
                        )}
                      />
                      <div className="border-t pt-4">
                        <p className="text-sm text-muted-foreground">
                          By submitting this application, I declare that all information provided is true and accurate. I understand that providing false information may result in the rejection of this application or termination of any resulting tenancy.
                        </p>
                      </div>
                    </CardContent>
                  </Card>
                </TabsContent>

              </div>

              <div className="flex justify-between items-center pt-4 border-t">
                <Button
                  type="button"
                  variant="outline"
                  onClick={onClose}
                  data-testid="button-cancel-application"
                >
                  Cancel
                </Button>
                <div className="flex gap-2">
                  <Button
                    type="button"
                    variant="outline"
                    onClick={() => {
                      const currentIndex = tabs.findIndex(tab => tab.id === activeTab);
                      if (currentIndex > 0) {
                        setActiveTab(tabs[currentIndex - 1].id);
                      }
                    }}
                    disabled={activeTab === "property"}
                    data-testid="button-previous-tab"
                  >
                    Previous
                  </Button>
                  <Button
                    type="button"
                    onClick={() => {
                      const currentIndex = tabs.findIndex(tab => tab.id === activeTab);
                      if (currentIndex < tabs.length - 1) {
                        setActiveTab(tabs[currentIndex + 1].id);
                      }
                    }}
                    disabled={activeTab === "consent"}
                    data-testid="button-next-tab"
                  >
                    Next
                  </Button>
                  {activeTab === "consent" && (
                    <Button
                      type="submit"
                      disabled={createApplicationMutation.isPending}
                      onClick={(e) => {
                        console.log("OREA Form 410 - Submit button clicked");
                        console.log("Form errors:", form.formState.errors);
                        if (!form.formState.isValid) {
                          console.log("Form is invalid, checking errors:");
                          Object.entries(form.formState.errors).forEach(([key, error]) => {
                            console.log(`${key}:`, error);
                          });
                        }
                      }}
                      data-testid="button-submit-application"
                    >
                      {createApplicationMutation.isPending ? "Submitting..." : "Submit Application"}
                    </Button>
                  )}
                </div>
              </div>
            </Tabs>
          </form>
        </Form>
      </DialogContent>
    </Dialog>
  );
}

