import { useState } from "react";
import { useMutation } from "@tanstack/react-query";
import { useToast } from "@/hooks/use-toast";
import { apiRequest, queryClient } from "@/lib/queryClient";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Upload, X, Camera } from "lucide-react";

interface PhotoUploadModalProps {
  isOpen: boolean;
  onClose: () => void;
  propertyId: string;
  clientId?: string | null;
  onUploadSuccess?: () => void;
}

interface PhotoFile {
  file: File;
  preview: string;
  caption: string;
}

export default function PhotoUploadModal({ 
  isOpen, 
  onClose, 
  propertyId,
  clientId,
  onUploadSuccess 
}: PhotoUploadModalProps) {
  const { toast } = useToast();
  const [selectedFiles, setSelectedFiles] = useState<PhotoFile[]>([]);
  const [isDragging, setIsDragging] = useState(false);

  // Upload photos mutation
  const uploadPhotosMutation = useMutation({
    mutationFn: async (photos: PhotoFile[]) => {
      const uploadPromises = photos.map(async (photo) => {
        // Convert file to base64
        const base64Data = await fileToBase64(photo.file);

        const photoData = {
          filename: photo.file.name,
          mimeType: photo.file.type,
          size: photo.file.size,
          caption: photo.caption.trim() || null,
          clientId: clientId || null,
          base64Data,
        };

        return apiRequest("POST", `/api/properties/${propertyId}/photos`, photoData);
      });

      return Promise.all(uploadPromises);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [`/api/properties/${propertyId}/photos`] });
      queryClient.invalidateQueries({ queryKey: ["/api/properties"] });
      queryClient.invalidateQueries({ queryKey: ["/api/photos"] });
      toast({
        title: "Success",
        description: `${selectedFiles.length} photo(s) uploaded successfully!`,
      });
      onUploadSuccess?.();
      handleClose();
    },
    onError: (error) => {
      toast({
        title: "Upload Failed",
        description: "Failed to upload photos. Please try again.",
        variant: "destructive",
      });
      console.error("Photo upload error:", error);
    },
  });

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => {
        const result = reader.result as string;
        const base64 = result.split(",")[1]; // Remove data:image/jpeg;base64, prefix
        resolve(base64);
      };
      reader.onerror = (error) => reject(error);
    });
  };

  const handleFileSelect = (files: FileList) => {
    const newFiles: PhotoFile[] = [];

    Array.from(files).forEach((file) => {
      if (file.type.startsWith("image/")) {
        const preview = URL.createObjectURL(file);
        newFiles.push({
          file,
          preview,
          caption: "",
        });
      }
    });

    if (newFiles.length > 0) {
      setSelectedFiles(prev => [...prev, ...newFiles]);
    }

    if (files.length > newFiles.length) {
      toast({
        title: "Some files skipped",
        description: "Only image files are supported.",
        variant: "destructive",
      });
    }
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    handleFileSelect(e.dataTransfer.files);
  };

  const removeFile = (index: number) => {
    setSelectedFiles(prev => {
      const updated = [...prev];
      URL.revokeObjectURL(updated[index].preview);
      updated.splice(index, 1);
      return updated;
    });
  };

  const updateCaption = (index: number, caption: string) => {
    setSelectedFiles(prev => {
      const updated = [...prev];
      updated[index].caption = caption;
      return updated;
    });
  };

  const handleClose = () => {
    // Clean up preview URLs
    selectedFiles.forEach(file => URL.revokeObjectURL(file.preview));
    setSelectedFiles([]);
    setIsDragging(false);
    onClose();
  };

  const handleSubmit = () => {
    if (selectedFiles.length === 0) {
      toast({
        title: "No photos selected",
        description: "Please select at least one photo to upload.",
        variant: "destructive",
      });
      return;
    }
    uploadPhotosMutation.mutate(selectedFiles);
  };

  return (
    <Dialog open={isOpen} onOpenChange={handleClose}>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Camera className="h-5 w-5" />
            Upload Property Photos
          </DialogTitle>
        </DialogHeader>

        <div className="space-y-4">
          {/* File Drop Zone */}
          <div
            className={`border-2 border-dashed rounded-lg p-8 text-center transition-colors ${
              isDragging ? "border-primary bg-primary/5" : "border-muted-foreground/25"
            }`}
            onDragOver={handleDragOver}
            onDragLeave={handleDragLeave}
            onDrop={handleDrop}
          >
            <Upload className="h-8 w-8 mx-auto mb-2 text-muted-foreground" />
            <p className="text-sm text-muted-foreground mb-2">
              Drag and drop photos here, or click to select
            </p>
            <Input
              type="file"
              multiple
              accept="image/*"
              onChange={(e) => e.target.files && handleFileSelect(e.target.files)}
              className="hidden"
              id="photo-upload"
            />
            <Label htmlFor="photo-upload">
              <Button variant="outline" className="cursor-pointer" asChild>
                <span>Select Photos</span>
              </Button>
            </Label>
          </div>

          {/* Selected Photos */}
          {selectedFiles.length > 0 && (
            <div className="space-y-4">
              <h3 className="font-medium">Selected Photos ({selectedFiles.length})</h3>
              <div className="space-y-3 max-h-60 overflow-y-auto">
                {selectedFiles.map((photoFile, index) => (
                  <div key={index} className="flex items-start gap-3 p-3 border rounded-lg">
                    <img
                      src={photoFile.preview}
                      alt={`Preview ${index + 1}`}
                      className="w-16 h-16 object-cover rounded"
                    />
                    <div className="flex-1 space-y-2">
                      <p className="text-sm font-medium truncate">{photoFile.file.name}</p>
                      <Textarea
                        placeholder="Add a caption (optional)"
                        value={photoFile.caption}
                        onChange={(e) => updateCaption(index, e.target.value)}
                        className="text-sm"
                        rows={2}
                      />
                    </div>
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => removeFile(index)}
                      className="text-destructive hover:text-destructive"
                    >
                      <X className="h-4 w-4" />
                    </Button>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Action Buttons */}
          <div className="flex justify-end gap-3 pt-4">
            <Button variant="outline" onClick={handleClose}>
              Cancel
            </Button>
            <Button
              onClick={handleSubmit}
              disabled={selectedFiles.length === 0 || uploadPhotosMutation.isPending}
              data-testid="button-upload-photos"
            >
              {uploadPhotosMutation.isPending ? "Uploading..." : `Upload ${selectedFiles.length} Photo(s)`}
            </Button>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

