import { useState, useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { useAuth } from "@/hooks/useAuth";
import { useViewMode } from "@/contexts/ViewModeContext";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { SidebarProvider, SidebarInset } from "@/components/ui/sidebar";
import TopAppBar from "@/components/TopAppBar";
import AgentSidebar from "@/components/AgentSidebar";
import MobileNav from "@/components/MobileNav";
import { 
  Search, 
  Users, 
  Plus, 
  Phone, 
  Mail, 
  Calendar,
  Download,
  User,
  Building2
} from "lucide-react";
import { format } from "date-fns";

export default function DirectoryPage() {
  const { user, isAuthenticated } = useAuth();
  const { effectiveMode } = useViewMode();
  const [searchQuery, setSearchQuery] = useState("");
  const [relationshipFilter, setRelationshipFilter] = useState<string>("all");
  const [hasAppFilter, setHasAppFilter] = useState<string>("all");

  // Build query string for contacts API
  const queryParams = new URLSearchParams();
  if (searchQuery) queryParams.append('search', searchQuery);
  if (relationshipFilter !== 'all') queryParams.append('relationshipType', relationshipFilter);
  if (hasAppFilter !== 'all') queryParams.append('hasApp', hasAppFilter === 'yes' ? 'true' : 'false');
  const queryString = queryParams.toString();
  const contactsUrl = `/api/directory/contacts${queryString ? `?${queryString}` : ''}`;

  // Fetch directory contacts
  const { data: contacts = [], isLoading } = useQuery<any[]>({
    queryKey: [contactsUrl],
    enabled: isAuthenticated && effectiveMode === "agent",
  });

  // Calculate stats
  const stats = useMemo(() => {
    const totalContacts = contacts.length;
    const uniqueClients = new Set(contacts.map(c => c.primaryClient?.id).filter(Boolean)).size;
    const relatedPersons = contacts.filter(c => c.relationshipType && c.relationshipType !== "primary").length;

    // Get birthdays in next 30 days
    const now = new Date();
    const thirtyDaysFromNow = new Date(now.getTime() + 30 * 24 * 60 * 60 * 1000);
    const upcomingBirthdays = contacts.filter(c => {
      if (!c.dateOfBirth) return false;
      const birthDate = new Date(c.dateOfBirth);
      const thisYearBirthday = new Date(now.getFullYear(), birthDate.getMonth(), birthDate.getDate());
      return thisYearBirthday >= now && thisYearBirthday <= thirtyDaysFromNow;
    }).length;

    return { totalContacts, uniqueClients, relatedPersons, upcomingBirthdays };
  }, [contacts]);


  if (!isAuthenticated || effectiveMode !== "agent") {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <Card>
          <CardContent className="p-6">
            <p className="text-muted-foreground">Access denied. This page is for agents only.</p>
          </CardContent>
        </Card>
      </div>
    );
  }

  return (
    <SidebarProvider>
      <div className="min-h-screen flex w-full bg-background">
        <AgentSidebar 
          activeSection="directory"
          onSectionChange={() => {}}
          pendingRequests={0}
          upcomingTours={0}
        />

        <SidebarInset className="flex-1 flex flex-col">
          <TopAppBar 
            userRole="agent"
            onCreateTour={() => {}}
            onApproveRequests={() => {}}
            onRequestDocs={() => {}}
            onStartIntake={() => {}}
            onShowBranding={() => {}}
            onShowIntegrations={() => {}}
            onShowNotifications={() => {}}
          />

          <main className="flex-1 overflow-auto">
            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
              {/* Header */}
              <div className="flex flex-col md:flex-row md:items-center justify-between mb-4 md:mb-6">
                <div>
                  <h1 className="text-2xl md:text-3xl font-bold mb-2" data-testid="title-directory">Directory</h1>
                  <p className="text-sm md:text-base text-muted-foreground">
                    Manage all your contacts and related persons
                  </p>
                </div>
                <div className="flex items-center gap-3 mt-4 md:mt-0">
                  <Button 
                    variant="outline" 
                    size="sm"
                    data-testid="button-export-csv"
                  >
                    <Download className="h-4 w-4 mr-2" />
                    Export CSV
                  </Button>
                  <Button 
                    size="sm"
                    data-testid="button-add-contact"
                  >
                    <Plus className="h-4 w-4 mr-2" />
                    Add Contact
                  </Button>
                </div>
              </div>

              {/* Stats Cards */}
              <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-2 sm:gap-3 lg:gap-4 mb-6">
                <Card data-testid="card-total-contacts">
                  <CardContent className="p-2 sm:p-3 lg:p-4">
                    <div className="flex items-center">
                      <Users className="h-6 w-6 sm:h-8 sm:w-8 text-primary bg-primary/10 rounded p-1 flex-shrink-0" />
                      <div className="ml-2 sm:ml-3 min-w-0">
                        <p className="text-xs sm:text-sm font-medium text-muted-foreground truncate">Total</p>
                        <p className="text-lg sm:text-2xl font-bold" data-testid="text-total-contacts">{stats.totalContacts}</p>
                      </div>
                    </div>
                  </CardContent>
                </Card>

                <Card data-testid="card-households">
                  <CardContent className="p-2 sm:p-3 lg:p-4">
                    <div className="flex items-center">
                      <Building2 className="h-6 w-6 sm:h-8 sm:w-8 text-blue-600 bg-blue-100 rounded p-1 flex-shrink-0" />
                      <div className="ml-2 sm:ml-3 min-w-0">
                        <p className="text-xs sm:text-sm font-medium text-muted-foreground truncate">Households</p>
                        <p className="text-lg sm:text-2xl font-bold" data-testid="text-households">{stats.uniqueClients}</p>
                      </div>
                    </div>
                  </CardContent>
                </Card>

                <Card data-testid="card-related-persons">
                  <CardContent className="p-2 sm:p-3 lg:p-4">
                    <div className="flex items-center">
                      <User className="h-6 w-6 sm:h-8 sm:w-8 text-green-600 bg-green-100 rounded p-1 flex-shrink-0" />
                      <div className="ml-2 sm:ml-3 min-w-0">
                        <p className="text-xs sm:text-sm font-medium text-muted-foreground truncate">Related</p>
                        <p className="text-lg sm:text-2xl font-bold" data-testid="text-related-persons">{stats.relatedPersons}</p>
                      </div>
                    </div>
                  </CardContent>
                </Card>

                <Card data-testid="card-birthdays">
                  <CardContent className="p-2 sm:p-3 lg:p-4">
                    <div className="flex items-center">
                      <Calendar className="h-6 w-6 sm:h-8 sm:w-8 text-orange-600 bg-orange-100 rounded p-1 flex-shrink-0" />
                      <div className="ml-2 sm:ml-3 min-w-0">
                        <p className="text-xs sm:text-sm font-medium text-muted-foreground truncate">Birthdays</p>
                        <p className="text-lg sm:text-2xl font-bold" data-testid="text-birthdays">{stats.upcomingBirthdays}</p>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              </div>

              {/* Search and Filters */}
              <Card className="mb-6">
                <CardContent className="p-4">
                  <div className="flex flex-col md:flex-row gap-4">
                    <div className="flex-1">
                      <div className="relative">
                        <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-muted-foreground h-4 w-4" />
                        <Input
                          placeholder="Search by name, email, or phone..."
                          value={searchQuery}
                          onChange={(e) => setSearchQuery(e.target.value)}
                          className="pl-9"
                          data-testid="input-search-directory"
                        />
                      </div>
                    </div>

                    <Select value={relationshipFilter} onValueChange={setRelationshipFilter}>
                      <SelectTrigger className="w-full md:w-[200px]" data-testid="select-relationship-type">
                        <SelectValue placeholder="Relationship" />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="all">All Types</SelectItem>
                        <SelectItem value="primary">Primary</SelectItem>
                        <SelectItem value="spouse">Spouse/Partner</SelectItem>
                        <SelectItem value="parent">Parent</SelectItem>
                        <SelectItem value="child">Child</SelectItem>
                        <SelectItem value="cobuyer">Co-buyer</SelectItem>
                        <SelectItem value="guarantor">Guarantor</SelectItem>
                        <SelectItem value="roommate">Roommate</SelectItem>
                        <SelectItem value="friend">Friend</SelectItem>
                        <SelectItem value="attorney">Attorney</SelectItem>
                        <SelectItem value="broker">Mortgage Broker</SelectItem>
                        <SelectItem value="other">Other</SelectItem>
                      </SelectContent>
                    </Select>

                    <Select value={hasAppFilter} onValueChange={setHasAppFilter}>
                      <SelectTrigger className="w-full md:w-[180px]" data-testid="select-has-app">
                        <SelectValue placeholder="App Status" />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="all">All</SelectItem>
                        <SelectItem value="yes">Has App</SelectItem>
                        <SelectItem value="no">No App</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                </CardContent>
              </Card>

              {/* Contacts Table */}
              <Card>
                <CardHeader>
                  <CardTitle>Contacts ({contacts.length})</CardTitle>
                </CardHeader>
                <CardContent>
                  {isLoading ? (
                    <div className="space-y-4">
                      {[1, 2, 3].map((i) => (
                        <div key={i} className="flex items-center space-x-4 p-4 border rounded-lg animate-pulse">
                          <div className="w-12 h-12 bg-muted rounded-full"></div>
                          <div className="flex-1 space-y-2">
                            <div className="h-4 bg-muted rounded w-1/4"></div>
                            <div className="h-3 bg-muted rounded w-1/2"></div>
                          </div>
                        </div>
                      ))}
                    </div>
                  ) : contacts.length === 0 ? (
                    <div className="text-center py-12">
                      <Users className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
                      <h3 className="text-lg font-semibold mb-2">No contacts found</h3>
                      <p className="text-muted-foreground mb-4">
                        {searchQuery ? "Try adjusting your search" : "Start by adding your first contact"}
                      </p>
                      <Button data-testid="button-add-first-contact">
                        <Plus className="h-4 w-4 mr-2" />
                        Add Your First Contact
                      </Button>
                    </div>
                  ) : (
                    <div className="space-y-4">
                      {contacts.map((contact) => {
                        // Handle both object and string formats for emails and phones
                        const emails = Array.isArray(contact.emails) ? contact.emails : [];
                        const phones = Array.isArray(contact.phones) ? contact.phones : [];

                        // Get display values - support both {address: string} and string formats
                        const getEmailDisplay = (e: any) => typeof e === 'string' ? e : e?.address || '';
                        const getPhoneDisplay = (p: any) => typeof p === 'string' ? p : p?.number || '';

                        return (
                          <div 
                            key={contact.id}
                            className="flex items-center space-x-4 p-4 border rounded-lg hover:bg-muted/50 cursor-pointer transition-colors"
                            data-testid={`contact-row-${contact.id}`}
                          >
                            <div className="flex-1">
                              <div className="flex items-center gap-2 mb-1">
                                <h3 className="font-semibold text-lg" data-testid={`text-contact-name-${contact.id}`}>
                                  {contact.fullName}
                                </h3>
                                {contact.relationshipType && (
                                  <Badge variant="outline" data-testid={`badge-relationship-${contact.id}`}>
                                    {contact.relationshipType}
                                  </Badge>
                                )}
                                {contact.hasApp && (
                                  <Badge variant="default" data-testid={`badge-has-app-${contact.id}`}>
                                    Has App
                                  </Badge>
                                )}
                              </div>
                              <div className="flex items-center gap-4 text-sm text-muted-foreground">
                                {contact.primaryClient && (
                                  <span>
                                    Primary: {contact.primaryClient.firstName} {contact.primaryClient.lastName}
                                  </span>
                                )}
                                {phones.length > 0 && getPhoneDisplay(phones[0]) && (
                                  <span className="flex items-center gap-1">
                                    <Phone className="h-3 w-3" />
                                    {getPhoneDisplay(phones[0])}
                                  </span>
                                )}
                                {emails.length > 0 && getEmailDisplay(emails[0]) && (
                                  <span className="flex items-center gap-1">
                                    <Mail className="h-3 w-3" />
                                    {getEmailDisplay(emails[0])}
                                  </span>
                                )}
                                {contact.dateOfBirth && (
                                  <span className="flex items-center gap-1">
                                    <Calendar className="h-3 w-3" />
                                    {format(new Date(contact.dateOfBirth), 'dd-MMM')}
                                  </span>
                                )}
                              </div>
                            </div>

                            <div className="flex items-center gap-2">
                              <Button variant="ghost" size="sm" data-testid={`button-call-${contact.id}`}>
                                <Phone className="h-4 w-4" />
                              </Button>
                              <Button variant="ghost" size="sm" data-testid={`button-email-${contact.id}`}>
                                <Mail className="h-4 w-4" />
                              </Button>
                            </div>
                          </div>
                        );
                      })}
                    </div>
                  )}
                </CardContent>
              </Card>
            </div>
          </main>
        </SidebarInset>
      </div>
      <MobileNav userRole="agent" />
    </SidebarProvider>
  );
}

