import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { Home, Upload, Camera, Eye } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import PhotoUploadModal from "./PhotoUploadModal";
import PhotoGalleryModal from "./PhotoGalleryModal";

interface PropertyPhotoProps {
  propertyId: string;
  className?: string;
  showUploadButton?: boolean;
  showPhotoCount?: boolean;
  userRole?: "agent" | "client";
}

interface PropertyPhoto {
  id: string;
  url: string;
  caption?: string;
  filename: string;
  createdAt: string;
}

export default function PropertyPhoto({ 
  propertyId, 
  className = "",
  showUploadButton = false,
  showPhotoCount = false,
  userRole 
}: PropertyPhotoProps) {
  const [showUploadModal, setShowUploadModal] = useState(false);
  const [showGalleryModal, setShowGalleryModal] = useState(false);

  // Fetch photos for this property
  const { data: photos = [], isLoading } = useQuery<PropertyPhoto[]>({
    queryKey: [`/api/properties/${propertyId}/photos`],
    retry: false,
    throwOnError: false,
  });

  const primaryPhoto = photos.length > 0 ? photos[0] : null;

  if (isLoading) {
    return (
      <div className={`bg-muted rounded-md flex items-center justify-center animate-pulse ${className}`}>
        <Home className="h-8 w-8 text-muted-foreground" />
      </div>
    );
  }

  const handlePhotoClick = () => {
    if (photos.length > 0) {
      setShowGalleryModal(true);
    } else if (userRole === "agent") {
      setShowUploadModal(true);
    }
  };

  return (
    <>
      <div 
        className={`relative rounded-md overflow-hidden group cursor-pointer ${className}`}
        onClick={handlePhotoClick}
      >
        {primaryPhoto ? (
          <>
            <img
              src={primaryPhoto.url}
              alt={primaryPhoto.caption || "Property photo"}
              className="w-full h-full object-cover"
            />
            {/* Photo count badge */}
            {showPhotoCount && photos.length > 1 && (
              <Badge 
                variant="secondary" 
                className="absolute top-2 right-2 bg-black/70 text-white border-0"
              >
                <Camera className="h-3 w-3 mr-1" />
                {photos.length}
              </Badge>
            )}
            {/* Hover overlay */}
            <div className="absolute inset-0 bg-black/0 group-hover:bg-black/20 transition-colors duration-200 flex items-center justify-center">
              <Eye className="h-6 w-6 text-white opacity-0 group-hover:opacity-100 transition-opacity duration-200" />
            </div>
          </>
        ) : (
          <div className="w-full h-full bg-muted flex items-center justify-center group-hover:bg-muted/80 transition-colors">
            {userRole === "agent" ? (
              <div className="text-center">
                <Upload className="h-6 w-6 text-muted-foreground mx-auto mb-1" />
                <p className="text-xs text-muted-foreground">Click to upload</p>
              </div>
            ) : (
              <Home className="h-8 w-8 text-muted-foreground" />
            )}
          </div>
        )}
      </div>

      {/* Upload button for agents */}
      {showUploadButton && userRole === "agent" && (
        <Button
          variant="outline"
          size="sm"
          onClick={(e) => {
            e.stopPropagation();
            setShowUploadModal(true);
          }}
          className="mt-2"
        >
          <Camera className="h-4 w-4 mr-2" />
          {photos.length === 0 ? "Add Photos" : "Add More Photos"}
        </Button>
      )}

      {/* Photo Upload Modal */}
      <PhotoUploadModal
        isOpen={showUploadModal}
        onClose={() => setShowUploadModal(false)}
        propertyId={propertyId}
        onUploadSuccess={() => {
          // Photos will be refreshed automatically by React Query
        }}
      />

      {/* Photo Gallery Modal */}
      <PhotoGalleryModal
        isOpen={showGalleryModal}
        onClose={() => setShowGalleryModal(false)}
        propertyId={propertyId}
        canUpload={userRole === "agent"}
      />
    </>
  );
}

