import { useState, useEffect } from "react";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent } from "@/components/ui/card";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";
import { MapPin, Users, Clock, Share2, Eye, Trash2, Navigation } from "lucide-react";
import type { LocationShare, InsertLocationShare } from "@shared/schema";

interface LocationSharingModalProps {
  isOpen: boolean;
  onClose: () => void;
  userId: string;
  tourId?: string;
}

export function LocationSharingModal({ isOpen, onClose, userId, tourId }: LocationSharingModalProps) {
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const [isSharing, setIsSharing] = useState(false);
  const [currentLocation, setCurrentLocation] = useState<{ lat: number; lng: number } | null>(null);
  const [locationName, setLocationName] = useState("");

  // Fetch active location shares
  const { data: locationShares = [], isLoading } = useQuery<LocationShare[]>({
    queryKey: ["/api/location-shares", userId],
    queryFn: async () => {
      const response = await apiRequest("GET", `/api/location-shares/${userId}`);
      return response.json();
    },
    enabled: isOpen && !!userId,
  });

  // Get current location
  useEffect(() => {
    if (isOpen && navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setCurrentLocation({
            lat: position.coords.latitude,
            lng: position.coords.longitude,
          });
        },
        (error) => {
          console.error("Error getting location:", error);
          toast({
            title: "Location Error",
            description: "Could not get your current location. Please enable location services.",
            variant: "destructive",
          });
        }
      );
    }
  }, [isOpen, toast]);

  // Create location share mutation
  const createLocationShareMutation = useMutation({
    mutationFn: async (data: InsertLocationShare) => {
      const response = await apiRequest("POST", "/api/location-shares", data);
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/location-shares", userId] });
      toast({
        title: "Location Shared",
        description: "Your location has been shared successfully.",
      });
      setLocationName("");
    },
    onError: () => {
      toast({
        title: "Share Failed",
        description: "Failed to share location. Please try again.",
        variant: "destructive",
      });
    },
  });

  // Stop sharing mutation
  const stopSharingMutation = useMutation({
    mutationFn: async (shareId: string) => {
      await apiRequest("DELETE", `/api/location-shares/${shareId}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/location-shares", userId] });
      toast({
        title: "Sharing Stopped",
        description: "Location sharing has been stopped.",
      });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to stop sharing. Please try again.",
        variant: "destructive",
      });
    },
  });

  const handleStartSharing = () => {
    if (!currentLocation) {
      toast({
        title: "Location Required",
        description: "Please allow location access to share your location.",
        variant: "destructive",
      });
      return;
    }

    if (!locationName.trim()) {
      toast({
        title: "Name Required",
        description: "Please provide a name for this location share.",
        variant: "destructive",
      });
      return;
    }

    createLocationShareMutation.mutate({
      userId,
      tourId: tourId || null,
      latitude: currentLocation.lat.toString(),
      longitude: currentLocation.lng.toString(),
      address: locationName,
      sharingType: "live",
      isActive: true,
    });
  };

  const handleStopSharing = (shareId: string) => {
    if (confirm("Are you sure you want to stop sharing this location?")) {
      stopSharingMutation.mutate(shareId);
    }
  };

  const handleViewLocation = (location: LocationShare) => {
    const url = `https://www.google.com/maps?q=${location.latitude},${location.longitude}`;
    window.open(url, "_blank");
  };

  const formatDistance = (lat1: number, lng1: number, lat2: number, lng2: number) => {
    const R = 6371; // Earth's radius in km
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLng = (lng2 - lng1) * Math.PI / 180;
    const a = 
      Math.sin(dLat/2) * Math.sin(dLat/2) +
      Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) * 
      Math.sin(dLng/2) * Math.sin(dLng/2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
    const d = R * c;
    return d < 1 ? `${Math.round(d * 1000)}m` : `${d.toFixed(1)}km`;
  };

  const activeShares = locationShares.filter(share => share.isActive);
  const inactiveShares = locationShares.filter(share => !share.isActive);

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-2xl max-h-[80vh] overflow-y-auto" data-testid="dialog-location-sharing">
        <DialogHeader>
          <DialogTitle className="flex items-center">
            <MapPin className="mr-2 h-5 w-5" />
            Location Sharing
          </DialogTitle>
        </DialogHeader>

        <div className="space-y-6">
          {/* Start Sharing Section */}
          <Card>
            <CardContent className="p-6">
              <h3 className="text-lg font-semibold mb-4 flex items-center">
                <Share2 className="mr-2 h-5 w-5" />
                Share Your Location
              </h3>

              <div className="space-y-4">
                <div>
                  <Label htmlFor="location-name">Location Name</Label>
                  <Input
                    id="location-name"
                    value={locationName}
                    onChange={(e) => setLocationName(e.target.value)}
                    placeholder="e.g., At Property ABC, Heading to next tour"
                    data-testid="input-location-name"
                  />
                </div>

                {currentLocation && (
                  <div className="text-sm text-muted-foreground">
                    Current Location: {currentLocation.lat.toFixed(6)}, {currentLocation.lng.toFixed(6)}
                  </div>
                )}

                <Button
                  onClick={handleStartSharing}
                  disabled={createLocationShareMutation.isPending || !currentLocation || !locationName.trim()}
                  className="w-full"
                  data-testid="button-start-sharing"
                >
                  <Share2 className="mr-2 h-4 w-4" />
                  {createLocationShareMutation.isPending ? "Sharing..." : "Start Sharing Location"}
                </Button>
              </div>
            </CardContent>
          </Card>

          {/* Active Shares */}
          <div>
            <h3 className="text-lg font-semibold mb-4 flex items-center">
              <Navigation className="mr-2 h-5 w-5 text-green-600" />
              Active Location Shares
              <Badge variant="secondary" className="ml-2">
                {activeShares.length}
              </Badge>
            </h3>

            {isLoading ? (
              <div className="space-y-3">
                {[1, 2].map((i) => (
                  <div key={i} className="animate-pulse border rounded-lg p-4">
                    <div className="h-4 bg-muted rounded w-1/3 mb-2"></div>
                    <div className="h-3 bg-muted rounded w-1/2"></div>
                  </div>
                ))}
              </div>
            ) : activeShares.length === 0 ? (
              <div className="text-center py-8 text-muted-foreground border rounded-lg">
                No active location shares
              </div>
            ) : (
              <div className="space-y-3">
                {activeShares.map((share) => (
                  <div
                    key={share.id}
                    className="flex items-center justify-between p-4 border rounded-lg"
                    data-testid={`active-share-${share.id}`}
                  >
                    <div className="flex-1">
                      <div className="font-medium">{share.address || "Shared Location"}</div>
                      <div className="text-sm text-muted-foreground">
                        Shared {share.createdAt ? new Date(share.createdAt).toLocaleTimeString() : "Unknown time"}
                        {currentLocation && (
                          <span className="ml-2">
                            • {formatDistance(
                              currentLocation.lat,
                              currentLocation.lng,
                              parseFloat(share.latitude),
                              parseFloat(share.longitude)
                            )} away
                          </span>
                        )}
                      </div>
                    </div>
                    <div className="flex items-center gap-2">
                      <Badge variant="default" className="bg-green-600">
                        Active
                      </Badge>
                      <Button
                        variant="outline"
                        size="sm"
                        onClick={() => handleViewLocation(share)}
                        data-testid={`button-view-${share.id}`}
                      >
                        <Eye className="h-4 w-4" />
                      </Button>
                      <Button
                        variant="destructive"
                        size="sm"
                        onClick={() => handleStopSharing(share.id)}
                        data-testid={`button-stop-${share.id}`}
                      >
                        <Trash2 className="h-4 w-4" />
                      </Button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Recent Shares History */}
          {inactiveShares.length > 0 && (
            <div>
              <h3 className="text-lg font-semibold mb-4 flex items-center">
                <Clock className="mr-2 h-5 w-5 text-muted-foreground" />
                Recent Shares
              </h3>

              <div className="space-y-3">
                {inactiveShares.slice(0, 5).map((share) => (
                  <div
                    key={share.id}
                    className="flex items-center justify-between p-4 border rounded-lg bg-muted/30"
                    data-testid={`inactive-share-${share.id}`}
                  >
                    <div className="flex-1">
                      <div className="font-medium text-muted-foreground">{share.address || "Shared Location"}</div>
                      <div className="text-sm text-muted-foreground">
                        Shared {share.createdAt ? new Date(share.createdAt).toLocaleDateString() : "Unknown date"}
                      </div>
                    </div>
                    <div className="flex items-center gap-2">
                      <Badge variant="secondary">
                        Stopped
                      </Badge>
                      <Button
                        variant="outline"
                        size="sm"
                        onClick={() => handleViewLocation(share)}
                        data-testid={`button-view-inactive-${share.id}`}
                      >
                        <Eye className="h-4 w-4" />
                      </Button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>

        <div className="flex justify-end">
          <Button variant="outline" onClick={onClose} data-testid="button-close-location-sharing">
            Close
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
}

client/src/components/ClientRequirements.content:
import { useQuery } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { 
  DollarSign, 
  MapPin, 
  Home, 
  Bed, 
  Bath, 
  Car, 
  Calendar,
  Clock,
  FileText,
  CheckCircle2,
  Edit,
  Plus
} from "lucide-react";

interface ClientRequirement {
  id: string;
  userId: string;
  clientType: "buyer" | "renter";
  status: string;
  budgetMin: string;
  budgetMax: string;
  preferredAreas: string[];
  propertyTypes: string[];
  bedrooms: number;
  bathrooms: string;
  parkingRequired: boolean;
  parkingSpots: number;
  preApprovalAmount?: string;
  downPaymentAmount?: string;
  mortgagePreApprovalExpiry?: string;
  firstTimeBuyer?: boolean;
  desiredClosingDate?: string;
  combinedFamilyIncome?: string;
  preferredMoveInDate?: string;
  willingToPrepayRent?: boolean;
  prepayMonths?: number;
  urgencyLevel: string;
  timeframe: string;
  notes?: string;
  createdAt: string;
  updatedAt: string;
}

interface ClientRequirementsPanelProps {
  onEdit?: () => void;
}

export function ClientRequirementsPanel({ onEdit }: ClientRequirementsPanelProps) {
  const { data: requirements, isLoading, isError } = useQuery<ClientRequirement>({
    queryKey: ['/api/client-requirements'],
  });

  if (isLoading) {
    return (
      <Card data-testid="requirements-panel-loading">
        <CardHeader>
          <CardTitle className="flex items-center space-x-2">
            <FileText className="h-5 w-5" />
            <span>My Requirements</span>
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="animate-pulse space-y-4">
            <div className="h-4 bg-muted rounded w-3/4"></div>
            <div className="h-4 bg-muted rounded w-1/2"></div>
            <div className="h-4 bg-muted rounded w-2/3"></div>
          </div>
        </CardContent>
      </Card>
    );
  }

  if (isError || !requirements) {
    return (
      <Card data-testid="requirements-panel-error">
        <CardHeader>
          <CardTitle className="flex items-center space-x-2">
            <FileText className="h-5 w-5" />
            <span>My Requirements</span>
          </CardTitle>
        </CardHeader>
        <CardContent>
          <p className="text-sm text-muted-foreground">
            No requirements found. Please complete your intake form.
          </p>
          {onEdit && (
            <Button onClick={onEdit} className="mt-4" data-testid="button-add-requirements">
              <Plus className="h-4 w-4 mr-2" />
              Add Requirements
            </Button>
          )}
        </CardContent>
      </Card>
    );
  }

  const formatCurrency = (value?: string) => {
    if (!value) return "N/A";
    return `$${parseFloat(value).toLocaleString()}`;
  };

  const formatDate = (dateStr?: string) => {
    if (!dateStr) return "N/A";
    return new Date(dateStr).toLocaleDateString('en-US', { 
      year: 'numeric', 
      month: 'short', 
      day: 'numeric' 
    });
  };

  const getUrgencyColor = (level: string) => {
    switch (level) {
      case "urgent": return "destructive";
      case "high": return "default";
      case "medium": return "secondary";
      case "low": return "outline";
      default: return "secondary";
    }
  };

  const getTimeframeLabel = (timeframe: string) => {
    switch (timeframe) {
      case "asap": return "ASAP";
      case "1_month": return "1 Month";
      case "3_months": return "3 Months";
      case "6_months": return "6 Months";
      case "flexible": return "Flexible";
      default: return timeframe;
    }
  };

  const getPropertyTypeLabel = (type: string) => {
    return type.charAt(0).toUpperCase() + type.slice(1);
  };

  return (
    <Card data-testid="requirements-panel">
      <CardHeader>
        <div className="flex items-center justify-between">
          <CardTitle className="flex items-center space-x-2">
            <FileText className="h-5 w-5" />
            <span>My Requirements</span>
          </CardTitle>
          <div className="flex items-center space-x-2">
            <Badge 
              variant={requirements.status === "validated" ? "default" : "secondary"}
              data-testid="badge-status"
            >
              <CheckCircle2 className="h-3 w-3 mr-1" />
              {requirements.status === "validated" ? "Validated" : requirements.status}
            </Badge>
            {onEdit && (
              <Button 
                variant="ghost" 
                size="sm" 
                onClick={onEdit}
                data-testid="button-edit-requirements"
              >
                <Edit className="h-4 w-4" />
              </Button>
            )}
          </div>
        </div>
      </CardHeader>
      <CardContent className="space-y-6">
        {/* Budget */}
        <div className="space-y-2">
          <div className="flex items-center space-x-2 text-sm font-medium">
            <DollarSign className="h-4 w-4" />
            <span>Budget Range</span>
          </div>
          <div className="pl-6">
            <p className="text-lg font-semibold" data-testid="text-budget">
              {formatCurrency(requirements.budgetMin)} - {formatCurrency(requirements.budgetMax)}
            </p>
          </div>
        </div>

        {/* Preferred Areas */}
        <div className="space-y-2">
          <div className="flex items-center space-x-2 text-sm font-medium">
            <MapPin className="h-4 w-4" />
            <span>Preferred Areas</span>
          </div>
          <div className="pl-6 flex flex-wrap gap-2">
            {requirements.preferredAreas?.map((area, index) => (
              <Badge 
                key={index} 
                variant="outline"
                data-testid={`badge-area-${index}`}
              >
                {area}
              </Badge>
            ))}
          </div>
        </div>

        {/* Property Types */}
        <div className="space-y-2">
          <div className="flex items-center space-x-2 text-sm font-medium">
            <Home className="h-4 w-4" />
            <span>Property Types</span>
          </div>
          <div className="pl-6 flex flex-wrap gap-2">
            {requirements.propertyTypes?.map((type, index) => (
              <Badge 
                key={index} 
                variant="secondary"
                data-testid={`badge-type-${index}`}
              >
                {getPropertyTypeLabel(type)}
              </Badge>
            ))}
          </div>
        </div>

        {/* Beds & Baths */}
        <div className="grid grid-cols-2 gap-4">
          <div className="space-y-2">
            <div className="flex items-center space-x-2 text-sm font-medium">
              <Bed className="h-4 w-4" />
              <span>Bedrooms</span>
            </div>
            <div className="pl-6">
              <p className="text-lg font-semibold" data-testid="text-bedrooms">
                {requirements.bedrooms ? `${requirements.bedrooms} min` : "N/A"}
              </p>
            </div>
          </div>
          <div className="space-y-2">
            <div className="flex items-center space-x-2 text-sm font-medium">
              <Bath className="h-4 w-4" />
              <span>Bathrooms</span>
            </div>
            <div className="pl-6">
              <p className="text-lg font-semibold" data-testid="text-bathrooms">
                {requirements.bathrooms ? `${requirements.bathrooms} min` : "N/A"}
              </p>
            </div>
          </div>
        </div>

        {/* Parking */}
        {requirements.parkingRequired && (
          <div className="space-y-2">
            <div className="flex items-center space-x-2 text-sm font-medium">
              <Car className="h-4 w-4" />
              <span>Parking</span>
            </div>
            <div className="pl-6">
              <p className="text-sm" data-testid="text-parking">
                {requirements.parkingSpots} spot{requirements.parkingSpots !== 1 ? 's' : ''} required
              </p>
            </div>
          </div>
        )}

        {/* Buyer-Specific Fields */}
        {requirements.clientType === "buyer" && (
          <>
            {requirements.preApprovalAmount && (
              <div className="space-y-2">
                <div className="flex items-center space-x-2 text-sm font-medium">
                  <CheckCircle2 className="h-4 w-4" />
                  <span>Pre-Approval</span>
                </div>
                <div className="pl-6 space-y-1">
                  <p className="text-lg font-semibold" data-testid="text-pre-approval">
                    {formatCurrency(requirements.preApprovalAmount)}
                  </p>
                  {requirements.mortgagePreApprovalExpiry && (
                    <p className="text-sm text-muted-foreground">
                      Expires: {formatDate(requirements.mortgagePreApprovalExpiry)}
                    </p>
                  )}
                </div>
              </div>
            )}

            {requirements.downPaymentAmount && (
              <div className="space-y-2">
                <div className="flex items-center space-x-2 text-sm font-medium">
                  <DollarSign className="h-4 w-4" />
                  <span>Down Payment</span>
                </div>
                <div className="pl-6">
                  <p className="text-lg font-semibold" data-testid="text-down-payment">
                    {formatCurrency(requirements.downPaymentAmount)}
                  </p>
                </div>
              </div>
            )}

            {requirements.desiredClosingDate && (
              <div className="space-y-2">
                <div className="flex items-center space-x-2 text-sm font-medium">
                  <Calendar className="h-4 w-4" />
                  <span>Desired Closing Date</span>
                </div>
                <div className="pl-6">
                  <p className="text-sm" data-testid="text-closing-date">
                    {formatDate(requirements.desiredClosingDate)}
                  </p>
                </div>
              </div>
            )}

            {requirements.firstTimeBuyer && (
              <div className="space-y-2">
                <Badge variant="secondary" data-testid="badge-first-time-buyer">
                  First-Time Home Buyer
                </Badge>
              </div>
            )}
          </>
        )}

        {/* Renter-Specific Fields */}
        {requirements.clientType === "renter" && (
          <>
            {requirements.combinedFamilyIncome && (
              <div className="space-y-2">
                <div className="flex items-center space-x-2 text-sm font-medium">
                  <DollarSign className="h-4 w-4" />
                  <span>Combined Family Income</span>
                </div>
                <div className="pl-6">
                  <p className="text-lg font-semibold" data-testid="text-income">
                    {formatCurrency(requirements.combinedFamilyIncome)} / year
                  </p>
                </div>
              </div>
            )}

            {requirements.preferredMoveInDate && (
              <div className="space-y-2">
                <div className="flex items-center space-x-2 text-sm font-medium">
                  <Calendar className="h-4 w-4" />
                  <span>Preferred Move-In Date</span>
                </div>
                <div className="pl-6">
                  <p className="text-sm" data-testid="text-move-in-date">
                    {formatDate(requirements.preferredMoveInDate)}
                  </p>
                </div>
              </div>
            )}

            {requirements.willingToPrepayRent && (
              <div className="space-y-2">
                <div className="flex items-center space-x-2 text-sm font-medium">
                  <CheckCircle2 className="h-4 w-4" />
                  <span>Willing to Pre-pay Rent</span>
                </div>
                <div className="pl-6">
                  <p className="text-sm" data-testid="text-prepay-rent">
                    {requirements.prepayMonths} month{requirements.prepayMonths !== 1 ? 's' : ''}
                  </p>
                </div>
              </div>
            )}
          </>
        )}

        {/* Timeline */}
        <div className="grid grid-cols-2 gap-4">
          <div className="space-y-2">
            <div className="flex items-center space-x-2 text-sm font-medium">
              <Clock className="h-4 w-4" />
              <span>Urgency</span>
            </div>
            <div className="pl-6">
              <Badge 
                variant={getUrgencyColor(requirements.urgencyLevel)}
                data-testid="badge-urgency"
              >
                {requirements.urgencyLevel.toUpperCase()}
              </Badge>
            </div>
          </div>
          <div className="space-y-2">
            <div className="flex items-center space-x-2 text-sm font-medium">
              <Calendar className="h-4 w-4" />
              <span>Timeframe</span>
            </div>
            <div className="pl-6">
              <Badge variant="outline" data-testid="badge-timeframe">
                {getTimeframeLabel(requirements.timeframe)}
              </Badge>
            </div>
          </div>
        </div>

        {/* Notes */}
        {requirements.notes && (
          <div className="space-y-2">
            <div className="flex items-center space-x-2 text-sm font-medium">
              <FileText className="h-4 w-4" />
              <span>Additional Notes</span>
            </div>
            <div className="pl-6">
              <p className="text-sm text-muted-foreground" data-testid="text-notes">
                {requirements.notes}
              </p>
            </div>
          </div>
        )}

        {/* Last Updated */}
        <div className="pt-4 border-t border-border">
          <p className="text-xs text-muted-foreground" data-testid="text-last-updated">
            Last updated: {new Date(requirements.updatedAt).toLocaleString()}
          </p>
        </div>
      </CardContent>
    </Card>
  );
}

