import { useState, useEffect } from "react";
import { useMutation, useQuery } from "@tanstack/react-query";
import { useToast } from "@/hooks/use-toast";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { Button } from "@/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent } from "@/components/ui/card";
import { Bell, Mail, MessageSquare, Plus, Trash2, X } from "lucide-react";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";

interface Reminder {
  id?: string;
  method: "notification" | "email" | "sms";
  intervalValue: number;
  intervalUnit: "minutes" | "hours" | "days" | "weeks";
  timing: string;
}

interface TourRemindersManagerProps {
  isOpen: boolean;
  onClose: () => void;
  tourId: string;
  userId: string;
}

export default function TourRemindersManager({
  isOpen,
  onClose,
  tourId,
  userId,
}: TourRemindersManagerProps) {
  const { toast } = useToast();
  const [reminders, setReminders] = useState<Reminder[]>([]);

  // Fetch existing reminders for this tour
  const { data: existingReminders = [], isLoading } = useQuery({
    queryKey: [`/api/reminders/${userId}`, tourId],
    enabled: isOpen,
    select: (data: any[]) => data.filter((r) => r.tourId === tourId),
  });

  // Load existing reminders into state when fetched
  useEffect(() => {
    if (existingReminders.length > 0 && reminders.length === 0) {
      setReminders(existingReminders);
    }
  }, [existingReminders, tourId]);

  const saveRemindersMutation = useMutation({
    mutationFn: async (remindersToSave: Reminder[]) => {
      // Delete old reminders for this tour
      const deletePromises = existingReminders.map((r: any) =>
        apiRequest("DELETE", `/api/reminders/${r.id}`, {})
      );
      await Promise.all(deletePromises);

      // Create new reminders
      const createPromises = remindersToSave.map((reminder) =>
        apiRequest("POST", "/api/reminders", {
          userId,
          tourId,
          method: reminder.method,
          intervalValue: reminder.intervalValue,
          intervalUnit: reminder.intervalUnit,
          timing: reminder.timing,
        })
      );
      await Promise.all(createPromises);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [`/api/reminders/${userId}`] });
      toast({
        title: "Success",
        description: "Reminders saved successfully!",
      });
      onClose();
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to save reminders",
        variant: "destructive",
      });
    },
  });

  const addReminder = () => {
    setReminders([
      ...reminders,
      {
        method: "notification",
        intervalValue: 1,
        intervalUnit: "days",
        timing: "09:00",
      },
    ]);
  };

  const removeReminder = (index: number) => {
    setReminders(reminders.filter((_, i) => i !== index));
  };

  const updateReminder = (index: number, field: keyof Reminder, value: any) => {
    const updated = [...reminders];
    updated[index] = { ...updated[index], [field]: value };
    setReminders(updated);
  };

  const handleSave = () => {
    if (reminders.length === 0) {
      toast({
        title: "Info",
        description: "No reminders to save",
      });
      return;
    }
    saveRemindersMutation.mutate(reminders);
  };

  const getMethodIcon = (method: string) => {
    switch (method) {
      case "notification":
        return <Bell className="h-4 w-4" />;
      case "email":
        return <Mail className="h-4 w-4" />;
      case "sms":
        return <MessageSquare className="h-4 w-4" />;
      default:
        return <Bell className="h-4 w-4" />;
    }
  };

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-2xl" data-testid="dialog-tour-reminders">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Bell className="h-5 w-5" />
            Set Tour Reminders
          </DialogTitle>
        </DialogHeader>

        <div className="space-y-4">
          {isLoading ? (
            <div className="space-y-3">
              {[1, 2].map((i) => (
                <div key={i} className="animate-pulse h-20 bg-muted rounded-lg"></div>
              ))}
            </div>
          ) : (
            <>
              {reminders.length === 0 ? (
                <div className="text-center py-8 text-muted-foreground">
                  <Bell className="h-12 w-12 mx-auto mb-4 opacity-50" />
                  <p>No reminders set</p>
                  <p className="text-sm">Click "Add Reminder" to create one</p>
                </div>
              ) : (
                <div className="space-y-3 max-h-96 overflow-y-auto">
                  {reminders.map((reminder, index) => (
                    <Card key={index} data-testid={`reminder-card-${index}`}>
                      <CardContent className="p-4">
                        <div className="flex items-center gap-3">
                          <div className="flex items-center gap-2 flex-1">
                            {getMethodIcon(reminder.method)}
                            <Select
                              value={reminder.method}
                              onValueChange={(value: any) =>
                                updateReminder(index, "method", value)
                              }
                            >
                              <SelectTrigger className="w-36" data-testid={`select-method-${index}`}>
                                <SelectValue />
                              </SelectTrigger>
                              <SelectContent>
                                <SelectItem value="notification">Notification</SelectItem>
                                <SelectItem value="email">Email</SelectItem>
                                <SelectItem value="sms">SMS</SelectItem>
                              </SelectContent>
                            </Select>
                          </div>

                          <div className="flex items-center gap-2">
                            <Input
                              type="number"
                              min="1"
                              value={reminder.intervalValue}
                              onChange={(e) =>
                                updateReminder(
                                  index,
                                  "intervalValue",
                                  parseInt(e.target.value)
                                )
                              }
                              className="w-16"
                              data-testid={`input-interval-value-${index}`}
                            />

                            <Select
                              value={reminder.intervalUnit}
                              onValueChange={(value: any) =>
                                updateReminder(index, "intervalUnit", value)
                              }
                            >
                              <SelectTrigger className="w-28" data-testid={`select-interval-unit-${index}`}>
                                <SelectValue />
                              </SelectTrigger>
                              <SelectContent>
                                <SelectItem value="minutes">minutes</SelectItem>
                                <SelectItem value="hours">hours</SelectItem>
                                <SelectItem value="days">days</SelectItem>
                                <SelectItem value="weeks">weeks</SelectItem>
                              </SelectContent>
                            </Select>

                            <span className="text-sm text-muted-foreground whitespace-nowrap">
                              before at
                            </span>

                            <Input
                              type="time"
                              value={reminder.timing}
                              onChange={(e) =>
                                updateReminder(index, "timing", e.target.value)
                              }
                              className="w-32"
                              data-testid={`input-timing-${index}`}
                            />
                          </div>

                          <Button
                            variant="ghost"
                            size="icon"
                            onClick={() => removeReminder(index)}
                            data-testid={`button-remove-reminder-${index}`}
                          >
                            <Trash2 className="h-4 w-4 text-destructive" />
                          </Button>
                        </div>
                      </CardContent>
                    </Card>
                  ))}
                </div>
              )}
            </>
          )}

          <Button
            variant="outline"
            onClick={addReminder}
            className="w-full"
            data-testid="button-add-reminder"
          >
            <Plus className="h-4 w-4 mr-2" />
            Add Reminder
          </Button>

          <div className="flex gap-3 pt-4">
            <Button
              onClick={handleSave}
              className="flex-1"
              disabled={saveRemindersMutation.isPending}
              data-testid="button-save-reminders"
            >
              {saveRemindersMutation.isPending ? "Saving..." : "Save Reminders"}
            </Button>
            <Button
              variant="outline"
              onClick={onClose}
              data-testid="button-cancel-reminders"
            >
              Cancel
            </Button>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

