import { useQuery, useMutation } from "@tanstack/react-query";
import AdminSidebar from "@/components/AdminSidebar";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { useState } from "react";
import { Plus, Users, Building2, MapPin, FileText } from "lucide-react";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";

export default function AdminAgentsPage() {
  const { toast } = useToast();
  const [dialogOpen, setDialogOpen] = useState(false);
  const [formData, setFormData] = useState({
    email: "",
    firstName: "",
    lastName: "",
    brokerageId: "independent"
  });

  const { data: agents, isLoading, isError, error } = useQuery({
    queryKey: ['/api/admin/agents'],
  });

  const { data: brokerages } = useQuery({
    queryKey: ['/api/admin/brokerages'],
  });

  const createMutation = useMutation({
    mutationFn: async (data: any) => {
      return await apiRequest('/api/admin/agents', 'POST', data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/admin/agents'] });
      queryClient.invalidateQueries({ queryKey: ['/api/admin/kpis'] });
      setDialogOpen(false);
      setFormData({ email: "", firstName: "", lastName: "", brokerageId: "independent" });
      toast({ title: "Success", description: "Agent created successfully" });
    },
    onError: () => {
      toast({ title: "Error", description: "Failed to create agent", variant: "destructive" });
    }
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const submitData = {
      ...formData,
      brokerageId: formData.brokerageId === "independent" ? undefined : formData.brokerageId
    };
    createMutation.mutate(submitData);
  };

  if (isLoading) {
    return (
      <div className="flex">
        <AdminSidebar />
        <div className="flex-1 p-8">
          <div className="animate-pulse space-y-4">
            <div className="h-8 bg-muted rounded w-1/3"></div>
            <div className="h-96 bg-muted rounded"></div>
          </div>
        </div>
      </div>
    );
  }

  if (isError) {
    return (
      <div className="flex">
        <AdminSidebar />
        <div className="flex-1 p-8">
          <Card className="border-red-200 bg-red-50" data-testid="error-agents">
            <CardContent className="p-6">
              <h3 className="text-lg font-semibold text-red-900 mb-2">Failed to load agents</h3>
              <p className="text-red-700">{error?.message || "An error occurred while loading agents. Please try again."}</p>
            </CardContent>
          </Card>
        </div>
      </div>
    );
  }

  return (
    <div className="flex">
      <AdminSidebar />
      <div className="flex-1 p-8 space-y-6" data-testid="admin-agents-page">
        <div className="flex justify-between items-center">
          <div>
            <h1 className="text-3xl font-bold" data-testid="heading-agents">Agents</h1>
            <p className="text-muted-foreground">Manage all agents across the organization</p>
          </div>
          <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
            <DialogTrigger asChild>
              <Button data-testid="button-create-agent">
                <Plus className="h-4 w-4 mr-2" />
                Create Agent
              </Button>
            </DialogTrigger>
            <DialogContent data-testid="dialog-create-agent">
              <DialogHeader>
                <DialogTitle>Create New Agent</DialogTitle>
              </DialogHeader>
              <form onSubmit={handleSubmit} className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="email">Email *</Label>
                  <Input
                    id="email"
                    type="email"
                    data-testid="input-agent-email"
                    value={formData.email}
                    onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                    required
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="firstName">First Name *</Label>
                  <Input
                    id="firstName"
                    data-testid="input-first-name"
                    value={formData.firstName}
                    onChange={(e) => setFormData({ ...formData, firstName: e.target.value })}
                    required
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="lastName">Last Name *</Label>
                  <Input
                    id="lastName"
                    data-testid="input-last-name"
                    value={formData.lastName}
                    onChange={(e) => setFormData({ ...formData, lastName: e.target.value })}
                    required
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="brokerageId">Brokerage Assignment</Label>
                  <Select
                    value={formData.brokerageId}
                    onValueChange={(value) => setFormData({ ...formData, brokerageId: value })}
                  >
                    <SelectTrigger data-testid="select-brokerage">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="independent">Independent Agent</SelectItem>
                      {brokerages && brokerages.map((brokerage: any) => (
                        <SelectItem key={brokerage.id} value={brokerage.id}>
                          {brokerage.name}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
                <Button type="submit" className="w-full" disabled={createMutation.isPending} data-testid="button-submit-agent">
                  {createMutation.isPending ? "Creating..." : "Create Agent"}
                </Button>
              </form>
            </DialogContent>
          </Dialog>
        </div>

        <Card>
          <CardContent className="p-6">
            <div className="rounded-lg border">
              <table className="w-full">
                <thead className="bg-muted/50">
                  <tr>
                    <th className="text-left p-4 font-medium">Name</th>
                    <th className="text-left p-4 font-medium">Email</th>
                    <th className="text-left p-4 font-medium">Brokerage</th>
                    <th className="text-left p-4 font-medium">Clients</th>
                    <th className="text-left p-4 font-medium">Tours</th>
                    <th className="text-left p-4 font-medium">Offers</th>
                  </tr>
                </thead>
                <tbody>
                  {agents && agents.length > 0 ? (
                    agents.map((agent: any) => (
                      <tr key={agent.id} className="border-t" data-testid={`row-agent-${agent.id}`}>
                        <td className="p-4 font-medium">
                          {agent.firstName} {agent.lastName}
                        </td>
                        <td className="p-4 text-sm text-muted-foreground">{agent.email}</td>
                        <td className="p-4">
                          <span className={`flex items-center gap-1 text-sm ${
                            agent.brokerageName === 'Independent' ? 'text-muted-foreground' : ''
                          }`}>
                            <Building2 className="h-4 w-4" />
                            {agent.brokerageName}
                          </span>
                        </td>
                        <td className="p-4">
                          <span className="flex items-center gap-1">
                            <Users className="h-4 w-4" />
                            {agent.clientCount || 0}
                          </span>
                        </td>
                        <td className="p-4">
                          <span className="flex items-center gap-1">
                            <MapPin className="h-4 w-4" />
                            {agent.tourCount || 0}
                          </span>
                        </td>
                        <td className="p-4">
                          <span className="flex items-center gap-1">
                            <FileText className="h-4 w-4" />
                            {agent.offerCount || 0}
                          </span>
                        </td>
                      </tr>
                    ))
                  ) : (
                    <tr>
                      <td colSpan={6} className="text-center py-8 text-muted-foreground">
                        No agents found
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

client/src/components/ProductivityDashbo.content:
import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { useToast } from "@/hooks/use-toast";
import { 
  Calendar, 
  Users, 
  Clock, 
  MapPin, 
  TrendingUp, 
  Target,
  FileText,
  Download,
  Activity
} from "lucide-react";
import { format } from "date-fns";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";

interface ProductivityDashboardModalProps {
  isOpen: boolean;
  onClose: () => void;
}

function ProductivityDashboardModal({ isOpen, onClose }: ProductivityDashboardModalProps) {
  const { toast } = useToast();
  const [activeTab, setActiveTab] = useState("overview");

  // Fetch agent stats
  const { data: stats, isLoading, error } = useQuery<{
    todayTours: number;
    activeClients: number;
    pendingRequests: number;
    weeklyDistance: number;
    timeInvestedHours: number;
    offersPipeline: {
      pending: number;
      accepted: number;
      rejected: number;
      total: number;
    };
    avgScopeFitScore: number;
    exceptionsCount: number;
    recentChanges: number;
  }>({
    queryKey: ["/api/stats"],
    enabled: isOpen,
  });

  // Calculate conversion rates
  const conversionRate = stats?.offersPipeline?.total 
    ? (stats.offersPipeline.accepted / stats.offersPipeline.total) * 100 
    : 0;

  const offersPerClient = stats?.activeClients && stats?.offersPipeline?.total
    ? stats.offersPipeline.total / stats.activeClients 
    : 0;

  const avgDistancePerTour = stats?.weeklyDistance && stats?.todayTours
    ? stats.weeklyDistance / (stats.todayTours || 1)
    : 0;

  const handleExportPDF = () => {
    if (!stats) return;

    const doc = new jsPDF();

    // Add title
    doc.setFontSize(20);
    doc.text("Productivity Dashboard", 14, 20);

    // Add generation date
    doc.setFontSize(10);
    doc.text(`Generated: ${format(new Date(), "MMM dd, yyyy HH:mm")}`, 14, 28);

    // Add summary statistics
    let yPos = 40;
    doc.setFontSize(14);
    doc.text("Overview Metrics", 14, yPos);
    yPos += 10;
    doc.setFontSize(10);
    doc.text(`Today's Tours: ${stats.todayTours ?? 0}`, 14, yPos);
    doc.text(`Active Clients: ${stats.activeClients ?? 0}`, 70, yPos);
    doc.text(`Pending Requests: ${stats.pendingRequests ?? 0}`, 130, yPos);
    yPos += 6;
    doc.text(`Weekly Distance: ${(stats.weeklyDistance ?? 0).toFixed(1)} km`, 14, yPos);
    doc.text(`Time Invested: ${(stats.timeInvestedHours ?? 0).toFixed(1)}h`, 70, yPos);
    yPos += 6;
    doc.text(`Avg Scope Fit: ${((stats.avgScopeFitScore ?? 0) * 100).toFixed(1)}%`, 14, yPos);
    doc.text(`Exceptions: ${stats.exceptionsCount ?? 0}`, 70, yPos);
    doc.text(`Recent Changes: ${stats.recentChanges ?? 0}`, 130, yPos);
    yPos += 12;

    // Add offers pipeline section
    doc.setFontSize(14);
    doc.text("Offers Pipeline", 14, yPos);
    yPos += 7;

    const offersTableData = [
      ["Pending", String(stats.offersPipeline?.pending ?? 0)],
      ["Accepted", String(stats.offersPipeline?.accepted ?? 0)],
      ["Rejected", String(stats.offersPipeline?.rejected ?? 0)],
      ["Total", String(stats.offersPipeline?.total ?? 0)],
    ];

    autoTable(doc, {
      startY: yPos,
      head: [["Status", "Count"]],
      body: offersTableData,
      theme: "grid",
      styles: { fontSize: 10, cellPadding: 3 },
      headStyles: { fillColor: [59, 130, 246], textColor: [255, 255, 255] },
      columnStyles: {
        0: { cellWidth: 80 },
        1: { cellWidth: 50 },
      },
    });

    yPos = (doc as any).lastAutoTable.finalY + 12;

    // Add performance metrics section
    doc.setFontSize(14);
    doc.text("Performance Metrics", 14, yPos);
    yPos += 7;

    const performanceTableData = [
      ["Conversion Rate", `${conversionRate.toFixed(1)}%`],
      ["Offers per Client", offersPerClient.toFixed(2)],
      ["Avg Distance per Tour", `${avgDistancePerTour.toFixed(1)} km`],
      ["Avg Time per Client", `${((stats.timeInvestedHours || 0) / (stats.activeClients || 1)).toFixed(1)}h`],
    ];

    autoTable(doc, {
      startY: yPos,
      head: [["Metric", "Value"]],
      body: performanceTableData,
      theme: "grid",
      styles: { fontSize: 10, cellPadding: 3 },
      headStyles: { fillColor: [59, 130, 246], textColor: [255, 255, 255] },
      columnStyles: {
        0: { cellWidth: 80 },
        1: { cellWidth: 50 },
      },
    });

    // Save the PDF
    doc.save(`productivity-dashboard-${format(new Date(), "yyyy-MM-dd")}.pdf`);

    toast({
      title: "Export Complete",
      description: "Productivity metrics have been exported to PDF.",
    });
  };

  const handleExportCSV = () => {
    if (!stats) return;

    const csvData = [
      ["Metric", "Value"],
      ["Today's Tours", stats.todayTours],
      ["Active Clients", stats.activeClients],
      ["Pending Requests", stats.pendingRequests],
      ["Weekly Distance (km)", stats.weeklyDistance],
      ["Time Invested (hours)", stats.timeInvestedHours],
      ["Pending Offers", stats.offersPipeline?.pending ?? 0],
      ["Accepted Offers", stats.offersPipeline?.accepted ?? 0],
      ["Rejected Offers", stats.offersPipeline?.rejected ?? 0],
      ["Total Offers", stats.offersPipeline?.total ?? 0],
      ["Conversion Rate (%)", conversionRate.toFixed(2)],
      ["Offers per Client", offersPerClient.toFixed(2)],
      ["Avg Scope Fit Score (%)", (stats.avgScopeFitScore * 100).toFixed(2)],
      ["Exceptions Count", stats.exceptionsCount],
      ["Recent Changes", stats.recentChanges],
    ];

    const csvContent = csvData.map(row => row.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: "text/csv" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `productivity-dashboard-${format(new Date(), "yyyy-MM-dd")}.csv`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);

    toast({
      title: "Export Successful",
      description: "Productivity metrics exported to CSV",
    });
  };

  if (error) {
    return (
      <Dialog open={isOpen} onOpenChange={onClose}>
        <DialogContent data-testid="dialog-productivity-error">
          <DialogHeader>
            <DialogTitle>Error Loading Dashboard</DialogTitle>
          </DialogHeader>
          <p className="text-muted-foreground">Failed to load productivity metrics. Please try again.</p>
        </DialogContent>
      </Dialog>
    );
  }

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-6xl max-h-[90vh] overflow-y-auto" data-testid="dialog-productivity-dashboard">
        <DialogHeader>
          <div className="flex items-center justify-between">
            <DialogTitle className="flex items-center gap-2">
              <TrendingUp className="h-5 w-5" />
              Productivity Dashboard
            </DialogTitle>
            <div className="flex gap-2">
              <Button
                variant="outline"
                size="sm"
                onClick={handleExportPDF}
                disabled={isLoading || !stats}
                data-testid="button-export-pdf"
              >
                <FileText className="h-4 w-4 mr-2" />
                Export PDF
              </Button>
              <Button
                variant="outline"
                size="sm"
                onClick={handleExportCSV}
                disabled={isLoading || !stats}
                data-testid="button-export-csv"
              >
                <Download className="h-4 w-4 mr-2" />
                Export CSV
              </Button>
            </div>
          </div>
          <p className="text-sm text-muted-foreground">
            Comprehensive performance metrics and KPIs
          </p>
        </DialogHeader>

        {isLoading ? (
          <div className="flex items-center justify-center py-12">
            <div className="text-center space-y-2">
              <Activity className="h-8 w-8 animate-spin mx-auto text-primary" />
              <p className="text-muted-foreground">Loading metrics...</p>
            </div>
          </div>
        ) : (
          <Tabs value={activeTab} onValueChange={setActiveTab} className="space-y-6">
            <TabsList className="grid w-full grid-cols-3">
              <TabsTrigger value="overview" data-testid="tab-overview">Overview</TabsTrigger>
              <TabsTrigger value="performance" data-testid="tab-performance">Performance</TabsTrigger>
              <TabsTrigger value="efficiency" data-testid="tab-efficiency">Efficiency</TabsTrigger>
            </TabsList>

            {/* Overview Tab */}
            <TabsContent value="overview" className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                <Card>
                  <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                    <CardTitle className="text-sm font-medium">Today's Tours</CardTitle>
                    <Calendar className="h-4 w-4 text-muted-foreground" />
                  </CardHeader>
                  <CardContent>
                    <div className="text-2xl font-bold" data-testid="metric-today-tours">
                      {stats?.todayTours || 0}
                    </div>
                    <p className="text-xs text-muted-foreground mt-1">Scheduled for today</p>
                  </CardContent>
                </Card>

                <Card>
                  <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                    <CardTitle className="text-sm font-medium">Active Clients</CardTitle>
                    <Users className="h-4 w-4 text-muted-foreground" />
                  </CardHeader>
                  <CardContent>
                    <div className="text-2xl font-bold" data-testid="metric-active-clients">
                      {stats?.activeClients || 0}
                    </div>
                    <p className="text-xs text-muted-foreground mt-1">Currently engaged</p>
                  </CardContent>
                </Card>

                <Card>
                  <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                    <CardTitle className="text-sm font-medium">Pending Requests</CardTitle>
                    <Clock className="h-4 w-4 text-muted-foreground" />
                  </CardHeader>
                  <CardContent>
                    <div className="text-2xl font-bold" data-testid="metric-pending-requests">
                      {stats?.pendingRequests || 0}
                    </div>
                    <p className="text-xs text-muted-foreground mt-1">Awaiting response</p>
                  </CardContent>
                </Card>

                <Card>
                  <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                    <CardTitle className="text-sm font-medium">Weekly Distance</CardTitle>
                    <MapPin className="h-4 w-4 text-muted-foreground" />
                  </CardHeader>
                  <CardContent>
                    <div className="text-2xl font-bold" data-testid="metric-weekly-distance">
                      {stats?.weeklyDistance?.toFixed(1) || 0} km
                    </div>
                    <p className="text-xs text-muted-foreground mt-1">Last 7 days</p>
                  </CardContent>
                </Card>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <Card>
                  <CardHeader>
                    <CardTitle className="text-base flex items-center gap-2">
                      <Clock className="h-4 w-4" />
                      Time Investment
                    </CardTitle>
                  </CardHeader>
                  <CardContent className="space-y-4">
                    <div>
                      <p className="text-sm text-muted-foreground">Total Hours Invested</p>
                      <p className="text-3xl font-bold" data-testid="metric-time-invested">
                        {stats?.timeInvestedHours?.toFixed(1) || 0}h
                      </p>
                    </div>
                    <div className="pt-4 border-t">
                      <p className="text-sm text-muted-foreground">Recent Changes (7 days)</p>
                      <p className="text-2xl font-bold" data-testid="metric-recent-changes">
                        {stats?.recentChanges || 0}
                      </p>
                    </div>
                  </CardContent>
                </Card>

                <Card>
                  <CardHeader>
                    <CardTitle className="text-base flex items-center gap-2">
                      <Target className="h-4 w-4" />
                      Requirements Quality
                    </CardTitle>
                  </CardHeader>
                  <CardContent className="space-y-4">
                    <div>
                      <p className="text-sm text-muted-foreground">Avg Scope Fit Score</p>
                      <p className="text-3xl font-bold" data-testid="metric-scope-fit">
                        {((stats?.avgScopeFitScore || 0) * 100).toFixed(1)}%
                      </p>
                    </div>
                    <div className="pt-4 border-t">
                      <p className="text-sm text-muted-foreground">Exceptions Count</p>
                      <p className="text-2xl font-bold" data-testid="metric-exceptions">
                        {stats?.exceptionsCount || 0}
                      </p>
                    </div>
                  </CardContent>
                </Card>
              </div>
            </TabsContent>

            {/* Performance Tab */}
            <TabsContent value="performance" className="space-y-6">
              <Card>
                <CardHeader>
                  <CardTitle className="flex items-center gap-2">
                    <FileText className="h-5 w-5" />
                    Offers Pipeline
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                    <div className="text-center p-4 bg-blue-50 dark:bg-blue-950 rounded-lg">
                      <p className="text-sm text-muted-foreground">Pending</p>
                      <p className="text-3xl font-bold text-blue-600 dark:text-blue-400" data-testid="metric-offers-pending">
                        {stats?.offersPipeline?.pending ?? 0}
                      </p>
                    </div>
                    <div className="text-center p-4 bg-green-50 dark:bg-green-950 rounded-lg">
                      <p className="text-sm text-muted-foreground">Accepted</p>
                      <p className="text-3xl font-bold text-green-600 dark:text-green-400" data-testid="metric-offers-accepted">
                        {stats?.offersPipeline?.accepted ?? 0}
                      </p>
                    </div>
                    <div className="text-center p-4 bg-red-50 dark:bg-red-950 rounded-lg">
                      <p className="text-sm text-muted-foreground">Rejected</p>
                      <p className="text-3xl font-bold text-red-600 dark:text-red-400" data-testid="metric-offers-rejected">
                        {stats?.offersPipeline?.rejected ?? 0}
                      </p>
                    </div>
                    <div className="text-center p-4 bg-purple-50 dark:bg-purple-950 rounded-lg">
                      <p className="text-sm text-muted-foreground">Total</p>
                      <p className="text-3xl font-bold text-purple-600 dark:text-purple-400" data-testid="metric-offers-total">
                        {stats?.offersPipeline?.total ?? 0}
                      </p>
                    </div>
                  </div>
                </CardContent>
              </Card>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <Card>
                  <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                    <CardTitle className="text-sm font-medium">Conversion Rate</CardTitle>
                    <TrendingUp className="h-4 w-4 text-muted-foreground" />
                  </CardHeader>
                  <CardContent>
                    <div className="text-2xl font-bold" data-testid="metric-conversion-rate">
                      {conversionRate.toFixed(1)}%
                    </div>
                    <p className="text-xs text-muted-foreground mt-1">
                      Accepted / Total offers
                    </p>
                  </CardContent>
                </Card>

                <Card>
                  <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                    <CardTitle className="text-sm font-medium">Offers per Client</CardTitle>
                    <Users className="h-4 w-4 text-muted-foreground" />
                  </CardHeader>
                  <CardContent>
                    <div className="text-2xl font-bold" data-testid="metric-offers-per-client">
                      {offersPerClient.toFixed(2)}
                    </div>
                    <p className="text-xs text-muted-foreground mt-1">
                      Average per active client
                    </p>
                  </CardContent>
                </Card>

                <Card>
                  <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                    <CardTitle className="text-sm font-medium">Success Rate</CardTitle>
