import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { ChevronLeft, ChevronRight, Camera, Upload, X } from "lucide-react";
import PhotoUploadModal from "./PhotoUploadModal";

interface PhotoGalleryModalProps {
  isOpen: boolean;
  onClose: () => void;
  propertyId: string;
  canUpload?: boolean;
}

interface PropertyPhoto {
  id: string;
  url: string;
  caption?: string;
  filename: string;
  createdAt: string;
}

export default function PhotoGalleryModal({
  isOpen,
  onClose,
  propertyId,
  canUpload = false,
}: PhotoGalleryModalProps) {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [showUploadModal, setShowUploadModal] = useState(false);

  // Fetch photos for this property
  const { data: photos = [], isLoading } = useQuery<PropertyPhoto[]>({
    queryKey: [`/api/properties/${propertyId}/photos`],
    enabled: isOpen && !!propertyId,
    retry: false,
    throwOnError: false,
  });

  const currentPhoto = photos[currentIndex];

  const goToNext = () => {
    setCurrentIndex((prev) => (prev + 1) % photos.length);
  };

  const goToPrevious = () => {
    setCurrentIndex((prev) => (prev - 1 + photos.length) % photos.length);
  };

  if (!isOpen) return null;

  return (
    <>
      <Dialog open={isOpen} onOpenChange={onClose}>
        <DialogContent className="max-w-4xl max-h-[90vh] p-0">
          <DialogHeader className="p-6 pb-2">
            <div className="flex items-center justify-between">
              <DialogTitle className="flex items-center gap-2">
                <Camera className="h-5 w-5" />
                Property Photos
                {photos.length > 0 && (
                  <Badge variant="secondary">
                    {currentIndex + 1} of {photos.length}
                  </Badge>
                )}
              </DialogTitle>
              {canUpload && (
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => setShowUploadModal(true)}
                  className="ml-auto mr-2"
                >
                  <Upload className="h-4 w-4 mr-2" />
                  Add Photos
                </Button>
              )}
            </div>
          </DialogHeader>

          {isLoading ? (
            <div className="p-6 text-center">
              <div className="animate-pulse">
                <div className="w-full h-48 bg-muted rounded mb-4"></div>
                <div className="h-4 bg-muted rounded w-1/3 mx-auto"></div>
              </div>
            </div>
          ) : photos.length === 0 ? (
            <div className="p-6 text-center">
              <Camera className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
              <h3 className="text-lg font-medium mb-2">No photos yet</h3>
              <p className="text-muted-foreground mb-4">
                {canUpload 
                  ? "Upload some photos to showcase this property."
                  : "No photos have been uploaded for this property yet."
                }
              </p>
              {canUpload && (
                <Button onClick={() => setShowUploadModal(true)}>
                  <Upload className="h-4 w-4 mr-2" />
                  Upload Photos
                </Button>
              )}
            </div>
          ) : (
            <div className="relative">
              {/* Main Photo */}
              <div className="relative bg-black">
                <img
                  src={currentPhoto.url}
                  alt={currentPhoto.caption || currentPhoto.filename}
                  className="w-full max-h-[60vh] object-contain"
                />

                {/* Navigation arrows */}
                {photos.length > 1 && (
                  <>
                    <Button
                      variant="secondary"
                      size="icon"
                      className="absolute left-4 top-1/2 -translate-y-1/2 bg-black/50 text-white hover:bg-black/70"
                      onClick={goToPrevious}
                    >
                      <ChevronLeft className="h-4 w-4" />
                    </Button>
                    <Button
                      variant="secondary"
                      size="icon"
                      className="absolute right-4 top-1/2 -translate-y-1/2 bg-black/50 text-white hover:bg-black/70"
                      onClick={goToNext}
                    >
                      <ChevronRight className="h-4 w-4" />
                    </Button>
                  </>
                )}
              </div>

              {/* Photo Info */}
              {currentPhoto.caption && (
                <div className="p-4 bg-muted/50">
                  <p className="text-sm">{currentPhoto.caption}</p>
                </div>
              )}

              {/* Thumbnail Strip */}
              {photos.length > 1 && (
                <div className="p-4 bg-background border-t">
                  <div className="flex gap-2 overflow-x-auto pb-2">
                    {photos.map((photo, index) => (
                      <button
                        key={photo.id}
                        onClick={() => setCurrentIndex(index)}
                        className={`flex-shrink-0 relative rounded overflow-hidden ${
                          index === currentIndex ? "ring-2 ring-primary" : ""
                        }`}
                      >
                        <img
                          src={photo.url}
                          alt={photo.caption || photo.filename}
                          className="w-16 h-12 object-cover"
                        />
                        {index === currentIndex && (
                          <div className="absolute inset-0 bg-primary/20" />
                        )}
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}
        </DialogContent>
      </Dialog>

      {/* Photo Upload Modal */}
      <PhotoUploadModal
        isOpen={showUploadModal}
        onClose={() => setShowUploadModal(false)}
        propertyId={propertyId}
        onUploadSuccess={() => {
          // Photos will be refreshed automatically by React Query
        }}
      />
    </>
  );
}

