import { Switch, Route } from "wouter";
import { queryClient } from "./lib/queryClient";
import { QueryClientProvider } from "@tanstack/react-query";
import { Toaster } from "@/components/ui/toaster";
import { TooltipProvider } from "@/components/ui/tooltip";
import { useAuth } from "@/hooks/useAuth";
import { ViewModeProvider, useViewMode } from "@/contexts/ViewModeContext";
import NotFound from "@/pages/not-found";
import Auth from "@/pages/Auth";
import BrokerageAuth from "@/pages/BrokerageAuth";
import AdminAuth from "@/pages/AdminAuth";
import AgentDashboard from "@/pages/AgentDashboard";
import ClientDashboard from "@/pages/ClientDashboard";
import ClientsPage from "@/pages/ClientsPage";
import ToursPage from "@/pages/ToursPage";
import DocumentsPage from "@/pages/DocumentsPage";
import ReportsPage from "@/pages/ReportsPage";
import MediaPage from "@/pages/MediaPage";
import RequirementsHub from "@/pages/RequirementsHub";
import BrandingSettingsPage from "@/pages/BrandingSettingsPage";
import DirectoryPage from "@/pages/DirectoryPage";
import BrokerageDashboard from "@/pages/BrokerageDashboard";
import BrokerageAgentsPage from "@/pages/BrokerageAgentsPage";
import BrokerageClientsPage from "@/pages/BrokerageClientsPage";
import BrokerageReportsPage from "@/pages/BrokerageReportsPage";
import BrokerageSettingsPage from "@/pages/BrokerageSettingsPage";
import AdminDashboard from "@/pages/AdminDashboard";
import AdminBrokeragesPage from "@/pages/AdminBrokeragesPage";
import AdminAgentsPage from "@/pages/AdminAgentsPage";
import AdminClientsPage from "@/pages/AdminClientsPage";
import AdminReportsPage from "@/pages/AdminReportsPage";
import AdminSettingsPage from "@/pages/AdminSettingsPage";
import BrowseAllPropertiesPage from "@/pages/BrowseAllPropertiesPage";
import PropertyShortlistsPage from "@/pages/PropertyShortlistsPage";
import ClientToursPage from "@/pages/ClientToursPage";

function Router() {
  const { user, isAuthenticated, isLoading } = useAuth();
  const { effectiveMode } = useViewMode();

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="animate-spin rounded-full h-32 w-32 border-b-2 border-primary"></div>
      </div>
    );
  }

  // Determine which routes to render based on role
  const renderRoutes = () => {
    if (!isAuthenticated) {
      return <Route path="/" component={Auth} />;
    }

    if (effectiveMode === 'admin') {
      return [
        <Route key="admin-home" path="/" component={AdminDashboard} />,
        <Route key="admin-dash" path="/admin" component={AdminDashboard} />,
        <Route key="admin-brokerages" path="/admin/brokerages" component={AdminBrokeragesPage} />,
        <Route key="admin-agents" path="/admin/agents" component={AdminAgentsPage} />,
        <Route key="admin-clients" path="/admin/clients" component={AdminClientsPage} />,
        <Route key="admin-reports" path="/admin/reports" component={AdminReportsPage} />,
        <Route key="admin-settings" path="/admin/settings" component={AdminSettingsPage} />,
      ];
    }

    if (user?.role?.toLowerCase() === 'brokerage') {
      return [
        <Route key="brokerage-home" path="/" component={BrokerageDashboard} />,
        <Route key="brokerage-dash" path="/brokerage" component={BrokerageDashboard} />,
        <Route key="brokerage-agents" path="/brokerage/agents" component={BrokerageAgentsPage} />,
        <Route key="brokerage-clients" path="/brokerage/clients" component={BrokerageClientsPage} />,
        <Route key="brokerage-reports" path="/brokerage/reports" component={BrokerageReportsPage} />,
        <Route key="brokerage-settings" path="/brokerage/settings" component={BrokerageSettingsPage} />,
      ];
    }

    if (effectiveMode === 'agent') {
      return [
        <Route key="agent-home" path="/" component={AgentDashboard} />,
        <Route key="agent-clients" path="/clients" component={ClientsPage} />,
        <Route key="agent-directory" path="/directory" component={DirectoryPage} />,
        <Route key="agent-tours" path="/tours" component={ToursPage} />,
        <Route key="agent-documents" path="/documents" component={DocumentsPage} />,
        <Route key="agent-reports" path="/reports" component={ReportsPage} />,
        <Route key="agent-media" path="/media" component={MediaPage} />,
        <Route key="agent-requirements" path="/requirements" component={RequirementsHub} />,
        <Route key="agent-branding" path="/settings/branding" component={BrandingSettingsPage} />,
      ];
    }

    if (effectiveMode === 'client') {
      return [
        <Route key="client-home" path="/" component={ClientDashboard} />,
        <Route key="client-browse" path="/browse-properties" component={BrowseAllPropertiesPage} />,
        <Route key="client-shortlists" path="/shortlists" component={PropertyShortlistsPage} />,
        <Route key="client-tours" path="/tours" component={ClientToursPage} />,
      ];
    }

    return <Route path="/" component={Auth} />;
  };

  return (
    <Switch>
      {/* Auth routes - accessible when not authenticated */}
      <Route path="/brokerage/login" component={BrokerageAuth} />
      <Route path="/admin/login" component={AdminAuth} />

      {renderRoutes()}

      <Route component={NotFound} />
    </Switch>
  );
}

function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <TooltipProvider>
        <ViewModeProvider>
          <Toaster />
          <Router />
        </ViewModeProvider>
      </TooltipProvider>
    </QueryClientProvider>
  );
}

export default App;

