client/src/pages/AgentDashboard.tsx.content:
import { useEffect, useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { useLocation } from "wouter";
import { useAuth } from "@/hooks/useAuth";
import { useToast } from "@/hooks/use-toast";
import { useIsMobile } from "@/hooks/use-mobile";
import { isUnauthorizedError } from "@/lib/authUtils";
import { apiRequest, queryClient } from "@/lib/queryClient";
import type { Tour, ShowingRequest } from "@shared/schema";
import TopAppBar from "@/components/TopAppBar";
import AgentSidebar from "@/components/AgentSidebar";
import MobileNav from "@/components/MobileNav";
import { SidebarProvider, SidebarInset } from "@/components/ui/sidebar";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Calendar, Users, Clock, MapPin, CheckCircle, XCircle, Home, Camera, Plus, Route, Edit3, FileText, FolderOpen, Share2, BarChart3, Calendar as CalendarIcon, TrendingUp, AlertCircle, Target, Clock3 } from "lucide-react";
import PropertyPhoto from "@/components/PropertyPhoto";
import PropertyCreateModal from "@/components/PropertyCreateModal";
import TourPlannerModal from "@/components/TourPlannerModal";
import ScheduleEditModal from "@/components/ScheduleEditModal";
import TourRecapModal from "@/components/TourRecapModal";
import { ReminderSettingsModal } from "@/components/ReminderSettingsModal";
import { DocumentCenterModal } from "@/components/DocumentCenterModal";
import { LocationSharingModal } from "@/components/LocationSharingModal";
import { LocationAnalyticsModal } from "@/components/LocationAnalyticsModal";
import { PersonalCalendarModal } from "@/components/PersonalCalendarModal";
import TourWizardModal from "@/components/TourWizardModal";
import { TourCompletionModal } from "@/components/TourCompletionModal";

export default function AgentDashboard() {
  const { toast } = useToast();
  const { user, isAuthenticated, isLoading } = useAuth();
  const isMobile = useIsMobile();
  const [, setLocation] = useLocation();
  const [showPropertyCreateModal, setShowPropertyCreateModal] = useState(false);
  const [showTourPlannerModal, setShowTourPlannerModal] = useState(false);
  const [showScheduleEditModal, setShowScheduleEditModal] = useState(false);
  const [showTourRecapModal, setShowTourRecapModal] = useState(false);
  const [showReminderSettingsModal, setShowReminderSettingsModal] = useState(false);
  const [showDocumentCenterModal, setShowDocumentCenterModal] = useState(false);
  const [showLocationSharingModal, setShowLocationSharingModal] = useState(false);
  const [showLocationAnalyticsModal, setShowLocationAnalyticsModal] = useState(false);
  const [showPersonalCalendarModal, setShowPersonalCalendarModal] = useState(false);
  const [showTourWizardModal, setShowTourWizardModal] = useState(false);
  const [showTourCompletionModal, setShowTourCompletionModal] = useState(false);
  const [selectedTourForCompletion, setSelectedTourForCompletion] = useState<string | null>(null);
  const [selectedDate, setSelectedDate] = useState(new Date());
  const [activeSection, setActiveSection] = useState("dashboard");
  const [activeTab, setActiveTab] = useState("dashboard");

  // Redirect to home if not authenticated
  useEffect(() => {
    if (!isLoading && !isAuthenticated) {
      toast({
        title: "Unauthorized",
        description: "You are logged out. Logging in again...",
        variant: "destructive",
      });
      setTimeout(() => {
        window.location.href = "/api/login";
      }, 500);
      return;
    }
  }, [isAuthenticated, isLoading, toast]);

  // Fetch agent statistics
  const { data: stats, isLoading: statsLoading } = useQuery<{
    todayTours: number;
    activeClients: number;
    pendingRequests: number;
    weeklyDistance: number;
    timeInvestedHours: number;
    offersPipeline: {
      pending: number;
      accepted: number;
      rejected: number;
      total: number;
    };
    avgScopeFitScore: number;
    exceptionsCount: number;
    recentChanges: number;
  }>({
    queryKey: ["/api/stats"],
    enabled: isAuthenticated,
  });

  // Fetch today's tours
  const { data: tours = [], isLoading: toursLoading } = useQuery<Tour[]>({
    queryKey: ["/api/tours"],
    enabled: isAuthenticated,
  });

  // Fetch pending requests
  const { data: pendingRequests = [], isLoading: requestsLoading } = useQuery<ShowingRequest[]>({
    queryKey: ["/api/showing-requests"],
    enabled: isAuthenticated,
  });

  // Fetch agent's properties
  const { data: properties = [], isLoading: propertiesLoading } = useQuery<any[]>({
    queryKey: ["/api/properties"],
    enabled: isAuthenticated,
  });

  // Approve request mutation
  const approveRequestMutation = useMutation({
    mutationFn: async (requestId: string) => {
      await apiRequest("PATCH", `/api/showing-requests/${requestId}/status`, { status: "approved" });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/showing-requests"] });
      queryClient.invalidateQueries({ queryKey: ["/api/stats"] });
      toast({
        title: "Success",
        description: "Request approved successfully",
      });
    },
    onError: (error) => {
      if (isUnauthorizedError(error)) {
        toast({
          title: "Unauthorized",
          description: "You are logged out. Logging in again...",
          variant: "destructive",
        });
        setTimeout(() => {
          window.location.href = "/api/login";
        }, 500);
        return;
      }
      toast({
        title: "Error",
        description: "Failed to approve request",
        variant: "destructive",
      });
    },
  });

  // Reject request mutation
  const rejectRequestMutation = useMutation({
    mutationFn: async (requestId: string) => {
      await apiRequest("PATCH", `/api/showing-requests/${requestId}/status`, { status: "rejected" });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/showing-requests"] });
      queryClient.invalidateQueries({ queryKey: ["/api/stats"] });
      toast({
        title: "Success",
        description: "Request rejected",
      });
    },
    onError: (error) => {
      if (isUnauthorizedError(error)) {
        toast({
          title: "Unauthorized",
          description: "You are logged out. Logging in again...",
          variant: "destructive",
        });
        setTimeout(() => {
          window.location.href = "/api/login";
        }, 500);
        return;
      }
      toast({
        title: "Error",
        description: "Failed to reject request",
        variant: "destructive",
      });
    },
  });

  const todayTours = tours.filter((tour: any) => {
    const today = new Date().toDateString();
    const tourDate = new Date(tour.scheduledDate).toDateString();
    return today === tourDate;
  });

  const pendingOnly = pendingRequests.filter((req: any) => req.status === "pending");

  if (!isAuthenticated || isLoading) {
    return null;
  }

  const handleQuickActions = {
    createTour: () => setShowTourPlannerModal(true),
    approveRequests: () => {
      // Handle bulk approval logic here
      toast({
        title: "Feature Available",
        description: "Bulk request approval will be available in the requests section.",
      });
    },
    requestDocs: () => setShowDocumentCenterModal(true),
    startIntake: () => {
      toast({
        title: "Feature Available", 
        description: "Client intake forms will be available in the clients section.",
      });
    },
    showBranding: () => {
      toast({
        title: "Coming Soon",
        description: "Branding settings will be available soon.",
      });
    },
    showIntegrations: () => {
      toast({
        title: "Coming Soon",
        description: "Integration settings will be available soon.",
      });
    },
    showNotifications: () => {
      toast({
        title: "Coming Soon",
        description: "Notification settings will be available soon.",
      });
    },
  };

  return (
    <SidebarProvider>
      <div className="min-h-screen flex w-full bg-background">
        {/* Sidebar - Only rendered on larger screens, completely hidden on mobile */}
        {!isMobile && (
          <AgentSidebar 
            activeSection={activeSection}
            onSectionChange={setActiveSection}
            pendingRequests={pendingOnly.length}
            upcomingTours={todayTours.length}
          />
        )}

        <SidebarInset className="flex-1 flex flex-col w-full">
          <TopAppBar 
            userRole="agent"
            onCreateTour={handleQuickActions.createTour}
            onApproveRequests={handleQuickActions.approveRequests}
            onRequestDocs={handleQuickActions.requestDocs}
            onStartIntake={handleQuickActions.startIntake}
            onShowBranding={handleQuickActions.showBranding}
            onShowIntegrations={handleQuickActions.showIntegrations}
            onShowNotifications={handleQuickActions.showNotifications}
            pendingRequests={pendingOnly.length}
            upcomingTours={todayTours.length}
          />

          <main className="flex-1 overflow-auto">
            <div className="max-w-7xl mx-auto px-3 sm:px-4 lg:px-8 py-4 sm:py-6 lg:py-8">

          {/* Statistics Overview */}
          <div className="grid grid-cols-2 sm:grid-cols-2 lg:grid-cols-4 gap-3 sm:gap-4 lg:gap-6 mb-4 sm:mb-6">
            <Card data-testid="card-today-tours">
              <CardContent className="p-3 sm:p-4 lg:p-6">
                <div className="flex items-center">
                  <div className="p-2 sm:p-3 bg-primary/10 rounded-lg">
                    <Calendar className="h-5 w-5 sm:h-6 sm:w-6 text-primary" />
                  </div>
                  <div className="ml-2 sm:ml-4 min-w-0">
                    <p className="text-xs sm:text-sm font-medium text-muted-foreground truncate">Today's Tours</p>
                    <p className="text-xl sm:text-2xl font-bold" data-testid="text-today-tours">
                      {statsLoading ? "..." : stats?.todayTours || 0}
                    </p>
                  </div>
                </div>
              </CardContent>
            </Card>

            <Card data-testid="card-active-clients">
              <CardContent className="p-3 sm:p-4 lg:p-6">
                <div className="flex items-center">
                  <div className="p-2 sm:p-3 bg-accent/10 rounded-lg">
                    <Users className="h-5 w-5 sm:h-6 sm:w-6 text-accent" />
                  </div>
                  <div className="ml-2 sm:ml-4 min-w-0">
                    <p className="text-xs sm:text-sm font-medium text-muted-foreground truncate">Active Clients</p>
                    <p className="text-xl sm:text-2xl font-bold" data-testid="text-active-clients">
                      {statsLoading ? "..." : stats?.activeClients || 0}
                    </p>
                  </div>
                </div>
              </CardContent>
            </Card>

            <Card data-testid="card-pending-requests">
              <CardContent className="p-3 sm:p-4 lg:p-6">
                <div className="flex items-center">
                  <div className="p-2 sm:p-3 bg-yellow-100 rounded-lg">
                    <Clock className="h-5 w-5 sm:h-6 sm:w-6 text-yellow-600" />
                  </div>
                  <div className="ml-2 sm:ml-4 min-w-0">
                    <p className="text-xs sm:text-sm font-medium text-muted-foreground truncate">Pending</p>
                    <p className="text-xl sm:text-2xl font-bold" data-testid="text-pending-requests">
                      {statsLoading ? "..." : stats?.pendingRequests || 0}
                    </p>
                  </div>
                </div>
              </CardContent>
            </Card>

            <Card data-testid="card-weekly-distance">
              <CardContent className="p-3 sm:p-4 lg:p-6">
                <div className="flex items-center">
                  <div className="p-2 sm:p-3 bg-secondary/10 rounded-lg">
                    <MapPin className="h-5 w-5 sm:h-6 sm:w-6 text-secondary" />
                  </div>
                  <div className="ml-2 sm:ml-4 min-w-0">
                    <p className="text-xs sm:text-sm font-medium text-muted-foreground truncate">Weekly (km)</p>
                    <p className="text-xl sm:text-2xl font-bold" data-testid="text-weekly-distance">
                      {statsLoading ? "..." : Math.round(stats?.weeklyDistance || 0)}
                    </p>
                  </div>
                </div>
              </CardContent>
            </Card>
          </div>

          {/* Enhanced KPIs - Stack on mobile */}
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-3 sm:gap-4 lg:gap-6 mb-6 sm:mb-8">
            <Card data-testid="card-time-invested">
              <CardContent className="p-3 sm:p-4 lg:p-6">
                <div className="flex items-center">
                  <div className="p-2 sm:p-3 bg-blue-100 rounded-lg">
                    <Clock3 className="h-5 w-5 sm:h-6 sm:w-6 text-blue-600" />
                  </div>
                  <div className="ml-2 sm:ml-4 min-w-0">
                    <p className="text-xs sm:text-sm font-medium text-muted-foreground truncate">Time Invested</p>
                    <p className="text-lg sm:text-2xl font-bold" data-testid="text-time-invested">
                      {statsLoading ? "..." : `${stats?.timeInvestedHours || 0}h`}
                    </p>
                  </div>
                </div>
              </CardContent>
            </Card>

            <Card data-testid="card-offers-pipeline">
              <CardContent className="p-3 sm:p-4 lg:p-6">
                <div className="flex items-center">
                  <div className="p-2 sm:p-3 bg-green-100 rounded-lg">
                    <TrendingUp className="h-5 w-5 sm:h-6 sm:w-6 text-green-600" />
                  </div>
                  <div className="ml-2 sm:ml-4 min-w-0">
                    <p className="text-xs sm:text-sm font-medium text-muted-foreground truncate">Offers</p>
                    <p className="text-lg sm:text-2xl font-bold" data-testid="text-offers-total">
                      {statsLoading ? "..." : stats?.offersPipeline?.total || 0}
                    </p>
                    <p className="text-xs text-muted-foreground">
                      {statsLoading ? "" : `${stats?.offersPipeline?.pending || 0} pend`}
                    </p>
                  </div>
                </div>
              </CardContent>
            </Card>

            <Card data-testid="card-scope-fit">
              <CardContent className="p-3 sm:p-4 lg:p-6">
                <div className="flex items-center">
                  <div className="p-2 sm:p-3 bg-purple-100 rounded-lg">
                    <Target className="h-5 w-5 sm:h-6 sm:w-6 text-purple-600" />
                  </div>
                  <div className="ml-2 sm:ml-4 min-w-0">
                    <p className="text-xs sm:text-sm font-medium text-muted-foreground truncate">Scope Fit</p>
                    <p className="text-lg sm:text-2xl font-bold" data-testid="text-scope-fit">
                      {statsLoading ? "..." : `${Math.round((stats?.avgScopeFitScore || 0) * 100)}%`}
                    </p>
                  </div>
                </div>
              </CardContent>
            </Card>

            <Card data-testid="card-exceptions">
              <CardContent className="p-3 sm:p-4 lg:p-6">
                <div className="flex items-center">
                  <div className="p-2 sm:p-3 bg-orange-100 rounded-lg">
                    <AlertCircle className="h-5 w-5 sm:h-6 sm:w-6 text-orange-600" />
                  </div>
                  <div className="ml-2 sm:ml-4 min-w-0">
                    <p className="text-xs sm:text-sm font-medium text-muted-foreground truncate">Exceptions</p>
                    <p className="text-lg sm:text-2xl font-bold" data-testid="text-exceptions">
                      {statsLoading ? "..." : stats?.exceptionsCount || 0}
                    </p>
                  </div>
                </div>
              </CardContent>
            </Card>

            <Card data-testid="card-recent-changes">
              <CardContent className="p-3 sm:p-4 lg:p-6">
                <div className="flex items-center">
                  <div className="p-2 sm:p-3 bg-indigo-100 rounded-lg">
                    <FileText className="h-5 w-5 sm:h-6 sm:w-6 text-indigo-600" />
                  </div>
                  <div className="ml-2 sm:ml-4 min-w-0">
                    <p className="text-xs sm:text-sm font-medium text-muted-foreground truncate">Recent</p>
                    <p className="text-lg sm:text-2xl font-bold" data-testid="text-recent-changes">
                      {statsLoading ? "..." : stats?.recentChanges || 0}
                    </p>
                    <p className="text-xs text-muted-foreground">Last 7d</p>
                  </div>
                </div>
              </CardContent>
            </Card>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-3 gap-4 sm:gap-6 lg:gap-8">

            {/* Today's Schedule */}
            <div className="lg:col-span-2 order-1">
              <Card>
                <div className="p-3 sm:p-4 lg:p-6 border-b border-border">
                  <div className="flex flex-col gap-3 sm:gap-4">
                    <h2 className="text-lg sm:text-xl font-semibold">Today's Schedule</h2>
                    <div className="flex flex-wrap gap-2">
                      <Button 
                        variant="outline"
                        size="sm"
                        onClick={() => setShowTourPlannerModal(true)}
                        data-testid="button-route-planner"
                      >
                        <Route className="h-4 w-4 mr-2" />
                        Route Planner
                      </Button>
                      <Button 
                        variant="outline"
                        size="sm"
                        onClick={() => setShowScheduleEditModal(true)}
                        data-testid="button-edit-schedules"
                      >
                        <Edit3 className="h-4 w-4 mr-2" />
                        Edit Schedules
                      </Button>
                      <Button 
                        variant="outline"
                        size="sm"
                        onClick={() => setShowTourRecapModal(true)}
                        data-testid="button-tour-recap"
                      >
                        <FileText className="h-4 w-4 mr-2" />
                        Tour Recap
                      </Button>
                      <Button 
                        variant="outline"
                        size="sm"
                        onClick={() => setShowReminderSettingsModal(true)}
                        data-testid="button-reminder-settings"
                      >
                        <Clock className="h-4 w-4 mr-2" />
                        Reminder Settings
                      </Button>
                      <Button 
                        variant="outline"
                        size="sm"
                        onClick={() => setShowDocumentCenterModal(true)}
                        data-testid="button-document-center"
                      >
                        <FolderOpen className="h-4 w-4 mr-2" />
                        Document Center
                      </Button>
                      <Button 
                        variant="outline"
                        size="sm"
                        onClick={() => setShowLocationSharingModal(true)}
                        data-testid="button-location-sharing"
                      >
                        <Share2 className="h-4 w-4 mr-2" />
                        Location Sharing
                      </Button>
                      <Button 
                        variant="outline"
                        size="sm"
                        onClick={() => setShowLocationAnalyticsModal(true)}
                        data-testid="button-location-analytics"
                      >
                        <BarChart3 className="h-4 w-4 mr-2" />
                        Location Analytics
                      </Button>
                      <Button 
                        size="sm"
                        className="bg-primary text-primary-foreground hover:bg-primary/90"
                        onClick={() => setShowTourWizardModal(true)}
                        data-testid="button-new-tour"
                      >
                        <Calendar className="h-4 w-4 mr-2" />
                        New Tour
                      </Button>
                    </div>
                  </div>
                </div>

                <CardContent className="p-6">
                  {toursLoading ? (
                    <div className="space-y-4">
                      {[1, 2, 3].map((i) => (
                        <div key={i} className="animate-pulse border border-border rounded-lg p-4">
                          <div className="h-4 bg-muted rounded w-1/3 mb-2"></div>
                          <div className="h-3 bg-muted rounded w-1/2"></div>
                        </div>
                      ))}
                    </div>
                  ) : todayTours.length === 0 ? (
                    <div className="text-center py-8">
                      <Calendar className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
                      <p className="text-muted-foreground">No tours scheduled for today</p>
                    </div>
                  ) : (
                    <div className="space-y-4">
                      {todayTours.map((tour: any) => (
                        <div 
                          key={tour.id} 
                          className="border border-border rounded-lg p-4 hover:bg-muted/50 transition-colors"
                          data-testid={`tour-${tour.id}`}
                        >
                          <div className="flex items-start justify-between mb-3">
                            <div className="flex-1">
                              <div className="flex items-center space-x-2 mb-2">
                                <span className="font-medium">Tour #{tour.id.slice(0, 8)}</span>
                                <Badge 
                                  variant={tour.status === "in_progress" ? "default" : "secondary"}
                                  data-testid={`badge-${tour.status}`}
                                >
                                  {tour.status === "in_progress" ? "In Progress" : 
                                   tour.status === "scheduled" ? "Scheduled" : tour.status}
                                </Badge>
                              </div>
                              <p className="text-sm text-muted-foreground mb-2">
                                {tour.scheduledDate ? new Date(tour.scheduledDate).toLocaleTimeString([], {
                                  hour: '2-digit',
                                  minute: '2-digit'
                                }) : "Time TBD"}
                              </p>
                              <p className="text-sm">
                                {tour.totalDistance ? `${tour.totalDistance} km` : "Distance TBD"} • 
                                {tour.estimatedDuration ? ` ${tour.estimatedDuration} min` : " Duration TBD"}
                              </p>
                            </div>
                          </div>
                          {tour.status !== "completed" && (
                            <div className="pt-3 border-t border-border">
                              <Button
                                size="sm"
                                className="bg-primary text-primary-foreground hover:bg-primary/90"
                                onClick={() => {
                                  setSelectedTourForCompletion(tour.id);
                                  setShowTourCompletionModal(true);
                                }}
                                data-testid={`button-complete-tour-${tour.id}`}
                              >
                                Mark as Done
                              </Button>
                            </div>
                          )}
                        </div>
                      ))}
                    </div>
                  )}
                </CardContent>
              </Card>
            </div>

            {/* Pending Requests */}
            <div className="space-y-6 order-3 lg:order-3">
              <Card>
                <div className="p-3 sm:p-4 lg:p-6 border-b border-border">
                  <h3 className="text-base sm:text-lg font-semibold">Pending Requests</h3>
                </div>
                <CardContent className="p-3 sm:p-4 lg:p-6">
                  {requestsLoading ? (
                    <div className="space-y-4">
                      {[1, 2].map((i) => (
                        <div key={i} className="animate-pulse border-l-4 border-yellow-400 pl-4 py-2">
                          <div className="h-4 bg-muted rounded w-2/3 mb-2"></div>
                          <div className="h-3 bg-muted rounded w-1/2"></div>
                        </div>
                      ))}
                    </div>
                  ) : pendingOnly.length === 0 ? (
                    <div className="text-center py-8">
                      <CheckCircle className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
                      <p className="text-muted-foreground">No pending requests</p>
                    </div>
                  ) : (
                    <div className="space-y-4">
                      {pendingOnly.map((request: any) => (
                        <div 
                          key={request.id} 
                          className="border-l-4 border-yellow-400 pl-4 py-2"
                          data-testid={`request-${request.id}`}
                        >
                          <div className="flex items-start justify-between">
                            <div>
                              <p className="font-medium text-sm">Request #{request.id.slice(0, 8)}</p>
                              <p className="text-xs text-muted-foreground">
                                {new Date(request.createdAt).toLocaleDateString()}
                              </p>
                              <p className="text-sm mt-1">
                                {request.preferredDate ? 
                                  `Preferred: ${new Date(request.preferredDate).toLocaleDateString()}` : 
                                  "Date flexible"
                                }
                              </p>
                            </div>
                            <div className="flex space-x-1">
                              <Button
                                size="sm"
                                variant="ghost"
                                className="p-1 h-8 w-8 hover:bg-accent/10"
                                onClick={() => approveRequestMutation.mutate(request.id)}
                                disabled={approveRequestMutation.isPending}
                                data-testid={`button-approve-${request.id}`}
                              >
                                <CheckCircle className="h-4 w-4 text-accent" />
                              </Button>
                              <Button
                                size="sm"
                                variant="ghost"
                                className="p-1 h-8 w-8 hover:bg-destructive/10"
                                onClick={() => rejectRequestMutation.mutate(request.id)}
                                disabled={rejectRequestMutation.isPending}
                                data-testid={`button-reject-${request.id}`}
                              >
                                <XCircle className="h-4 w-4 text-destructive" />
                              </Button>
                            </div>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </CardContent>
              </Card>

              {/* My Properties */}
              <Card>
                <div className="p-6 border-b border-border">
                  <div className="flex items-center justify-between">
                    <h3 className="text-lg font-semibold">My Properties</h3>
                    <Button 
                      size="sm" 
                      variant="outline"
                      onClick={() => setShowPropertyCreateModal(true)}
                      data-testid="button-add-property"
                    >
                      <Plus className="h-4 w-4 mr-2" />
                      Add
                    </Button>
                  </div>
                </div>
                <CardContent className="p-6">
                  {propertiesLoading ? (
                    <div className="space-y-4">
                      {[1, 2].map((i) => (
                        <div key={i} className="animate-pulse flex items-start space-x-3">
                          <div className="w-16 h-12 bg-muted rounded"></div>
                          <div className="flex-1">
                            <div className="h-4 bg-muted rounded w-3/4 mb-2"></div>
                            <div className="h-3 bg-muted rounded w-1/2"></div>
                          </div>
                        </div>
                      ))}
                    </div>
                  ) : properties.length === 0 ? (
                    <div className="text-center py-8">
                      <Home className="h-10 w-10 text-muted-foreground mx-auto mb-3" />
                      <p className="text-sm text-muted-foreground mb-3">No properties added yet</p>
                      <Button 
                        size="sm" 
                        onClick={() => setShowPropertyCreateModal(true)}
                        data-testid="button-add-first-property"
                      >
                        <Plus className="h-4 w-4 mr-2" />
                        Add Your First Property
                      </Button>
                    </div>
                  ) : (
                    <div className="space-y-4 max-h-64 overflow-y-auto">
                      {properties.slice(0, 4).map((property: any) => (
                        <div 
                          key={property.id} 
                          className="flex items-start space-x-3 p-3 hover:bg-muted/50 rounded-lg transition-colors cursor-pointer"
                          data-testid={`agent-property-${property.id}`}
                        >
                          <PropertyPhoto
                            propertyId={property.id}
                            className="w-16 h-12 flex-shrink-0"
                            showPhotoCount={true}
                            userRole="agent"
                          />
                          <div className="flex-1 min-w-0">
                            <h4 className="font-medium text-sm truncate">{property.address}</h4>
                            <p className="text-xs text-muted-foreground">
                              {property.bedrooms} bed, {property.bathrooms} bath
                            </p>
                            <p className="text-xs font-medium text-primary">
                              ${Number(property.price).toLocaleString()}
                            </p>
                          </div>
                          <div className="flex flex-col space-y-1">
                            <Button
                              size="sm"
                              variant="ghost"
                              className="h-6 px-2 text-xs"
                              data-testid={`button-manage-photos-${property.id}`}
                            >
                              <Camera className="h-3 w-3" />
                            </Button>
                          </div>
                        </div>
                      ))}
                      {properties.length > 4 && (
                        <Button variant="ghost" size="sm" className="w-full text-xs">
                          View all {properties.length} properties
                        </Button>
                      )}
                    </div>
                  )}
                </CardContent>
              </Card>

              {/* Quick Actions */}
              <Card>
                <div className="p-6 border-b border-border">
                  <h3 className="text-lg font-semibold">Quick Actions</h3>
                </div>
                <CardContent className="p-6 space-y-3">
                  <Button 
                    variant="ghost" 
                    className="w-full justify-start"
                    onClick={() => setLocation("/clients")}
                    data-testid="button-manage-clients"
                  >
                    <Users className="h-4 w-4 mr-3" />
                    Manage Clients
                  </Button>
                  <Button 
                    variant="ghost" 
                    className="w-full justify-start"
                    onClick={() => setLocation("/reports")}
                    data-testid="button-generate-reports"
                  >
                    <Clock className="h-4 w-4 mr-3" />
                    Generate Reports
                  </Button>
                  <Button 
                    variant="ghost" 
                    className="w-full justify-start"
                    onClick={() => setShowPersonalCalendarModal(true)}
                    data-testid="button-personal-calendar"
                  >
                    <CalendarIcon className="h-4 w-4 mr-3" />
                    Personal Calendar
                  </Button>
                  <Button 
                    variant="ghost" 
                    className="w-full justify-start"
                    onClick={() => setLocation("/reports")}
                    data-testid="button-view-statistics"
                  >
                    <BarChart3 className="h-4 w-4 mr-3" />
                    View Statistics
                  </Button>
                </CardContent>
              </Card>
            </div>
          </div>
            </div>
          </main>
        </SidebarInset>
      </div>

      <MobileNav 
        userRole="agent" 
        activeTab={activeTab}
        onTabChange={setActiveTab}
        upcomingTours={todayTours.length}
      />

      <PropertyCreateModal 
        isOpen={showPropertyCreateModal} 
        onClose={() => setShowPropertyCreateModal(false)} 
      />

      {/* Tour Planning Modals */}
      <TourPlannerModal 
        isOpen={showTourPlannerModal}
        onClose={() => setShowTourPlannerModal(false)}
        selectedDate={selectedDate}
      />

      <TourWizardModal 
        isOpen={showTourWizardModal}
        onClose={() => setShowTourWizardModal(false)}
      />

      <ScheduleEditModal 
        isOpen={showScheduleEditModal}
        onClose={() => setShowScheduleEditModal(false)}
        selectedDate={selectedDate}
      />

      <TourRecapModal 
        isOpen={showTourRecapModal}
        onClose={() => setShowTourRecapModal(false)}
        selectedDate={selectedDate}
      />

      <ReminderSettingsModal 
        isOpen={showReminderSettingsModal}
        onClose={() => setShowReminderSettingsModal(false)}
        userId={user?.id || ""}
      />

      <DocumentCenterModal 
        isOpen={showDocumentCenterModal}
        onClose={() => setShowDocumentCenterModal(false)}
        userId={user?.id || ""}
      />

      <LocationSharingModal 
        isOpen={showLocationSharingModal}
        onClose={() => setShowLocationSharingModal(false)}
        userId={user?.id || ""}
      />

      <LocationAnalyticsModal 
        isOpen={showLocationAnalyticsModal}
        onClose={() => setShowLocationAnalyticsModal(false)}
        userId={user?.id || ""}
      />

      <PersonalCalendarModal 
        isOpen={showPersonalCalendarModal}
        onClose={() => setShowPersonalCalendarModal(false)}
        userId={user?.id || ""}
      />

      <TourCompletionModal
        isOpen={showTourCompletionModal}
        onClose={() => {
          setShowTourCompletionModal(false);
          setSelectedTourForCompletion(null);
        }}
        tourId={selectedTourForCompletion || ""}
      />
    </SidebarProvider>
  );
}

