import { useState } from "react";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";
import type { TourReminder, InsertTourReminder } from "@shared/schema";

interface ReminderSettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
  userId: string;
}

export function ReminderSettingsModal({ isOpen, onClose, userId }: ReminderSettingsModalProps) {
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const [reminderType, setReminderType] = useState<"first_trip" | "before_tour" | "follow_up">("first_trip");
  const [reminderDays, setReminderDays] = useState(1);
  const [reminderHours, setReminderHours] = useState(2);
  const [isEnabled, setIsEnabled] = useState(true);

  // Fetch existing reminders
  const { data: reminders, isLoading } = useQuery<TourReminder[]>({
    queryKey: ["/api/reminders", userId],
    queryFn: async () => {
      const response = await apiRequest("GET", `/api/reminders/${userId}`);
      return response.json();
    },
    enabled: isOpen && !!userId,
  });

  // Create reminder mutation
  const createReminderMutation = useMutation({
    mutationFn: async (data: InsertTourReminder) => {
      const response = await apiRequest("POST", "/api/reminders", data);
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/reminders", userId] });
      toast({
        title: "Reminder Created",
        description: "Your reminder settings have been saved successfully.",
      });
      resetForm();
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to create reminder. Please try again.",
        variant: "destructive",
      });
    },
  });

  // Update reminder mutation
  const updateReminderMutation = useMutation({
    mutationFn: async ({ id, data }: { id: string; data: Partial<TourReminder> }) => {
      const response = await apiRequest("PUT", `/api/reminders/${id}`, data);
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/reminders", userId] });
      toast({
        title: "Reminder Updated",
        description: "Your reminder settings have been updated successfully.",
      });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to update reminder. Please try again.",
        variant: "destructive",
      });
    },
  });

  // Delete reminder mutation
  const deleteReminderMutation = useMutation({
    mutationFn: async (id: string) => {
      await apiRequest("DELETE", `/api/reminders/${id}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/reminders", userId] });
      toast({
        title: "Reminder Deleted",
        description: "The reminder has been deleted successfully.",
      });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to delete reminder. Please try again.",
        variant: "destructive",
      });
    },
  });

  const resetForm = () => {
    setReminderType("first_trip");
    setReminderDays(1);
    setReminderHours(2);
    setIsEnabled(true);
  };

  const handleCreateReminder = () => {
    createReminderMutation.mutate({
      userId,
      reminderType,
      reminderDays,
      reminderHours,
      isEnabled,
    });
  };

  const handleToggleReminder = (reminder: TourReminder) => {
    updateReminderMutation.mutate({
      id: reminder.id,
      data: { isEnabled: !reminder.isEnabled },
    });
  };

  const handleDeleteReminder = (id: string) => {
    deleteReminderMutation.mutate(id);
  };

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-2xl max-h-[80vh] overflow-y-auto" data-testid="dialog-reminder-settings">
        <DialogHeader>
          <DialogTitle>Tour Reminder Settings</DialogTitle>
        </DialogHeader>

        <div className="space-y-6">
          {/* Existing Reminders */}
          <div>
            <h3 className="text-lg font-semibold mb-4">Current Reminders</h3>
            {isLoading ? (
              <div className="text-center py-4">Loading reminders...</div>
            ) : reminders && reminders.length > 0 ? (
              <div className="space-y-3">
                {reminders.map((reminder) => (
                  <div
                    key={reminder.id}
                    className="flex items-center justify-between p-4 border rounded-lg"
                    data-testid={`reminder-item-${reminder.id}`}
                  >
                    <div className="flex-1">
                      <div className="font-medium capitalize">
                        {reminder.reminderType?.replace("_", " ") || "Unknown"}
                      </div>
                      <div className="text-sm text-muted-foreground">
                        {reminder.reminderDays || 0} day(s) and {reminder.reminderHours || 0} hour(s) before
                      </div>
                    </div>
                    <div className="flex items-center gap-2">
                      <Switch
                        checked={reminder.isEnabled || false}
                        onCheckedChange={() => handleToggleReminder(reminder)}
                        data-testid={`switch-reminder-${reminder.id}`}
                      />
                      <Button
                        variant="destructive"
                        size="sm"
                        onClick={() => handleDeleteReminder(reminder.id)}
                        data-testid={`button-delete-reminder-${reminder.id}`}
                      >
                        Delete
                      </Button>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="text-center py-4 text-muted-foreground">
                No reminders configured yet
              </div>
            )}
          </div>

          {/* Create New Reminder */}
          <div className="border-t pt-6">
            <h3 className="text-lg font-semibold mb-4">Add New Reminder</h3>
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label htmlFor="reminder-type">Reminder Type</Label>
                  <Select value={reminderType} onValueChange={(value: any) => setReminderType(value)}>
                    <SelectTrigger data-testid="select-reminder-type">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="first_trip">First Trip of Day</SelectItem>
                      <SelectItem value="before_tour">Before Each Tour</SelectItem>
                      <SelectItem value="follow_up">Follow Up Reminder</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                <div>
                  <Label htmlFor="enabled">Enable Reminder</Label>
                  <div className="flex items-center mt-2">
                    <Switch
                      checked={isEnabled}
                      onCheckedChange={setIsEnabled}
                      data-testid="switch-new-reminder-enabled"
                    />
                    <span className="ml-2 text-sm">{isEnabled ? "Enabled" : "Disabled"}</span>
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label htmlFor="reminder-days">Days Before</Label>
                  <Input
                    type="number"
                    min="0"
                    max="30"
                    value={reminderDays}
                    onChange={(e) => setReminderDays(parseInt(e.target.value) || 0)}
                    data-testid="input-reminder-days"
                  />
                </div>

                <div>
                  <Label htmlFor="reminder-hours">Hours Before</Label>
                  <Input
                    type="number"
                    min="0"
                    max="24"
                    value={reminderHours}
                    onChange={(e) => setReminderHours(parseInt(e.target.value) || 0)}
                    data-testid="input-reminder-hours"
                  />
                </div>
              </div>

              <div className="flex gap-2">
                <Button
                  onClick={handleCreateReminder}
                  disabled={createReminderMutation.isPending}
                  data-testid="button-create-reminder"
                >
                  {createReminderMutation.isPending ? "Creating..." : "Create Reminder"}
                </Button>
                <Button variant="outline" onClick={resetForm} data-testid="button-reset-form">
                  Reset
                </Button>
              </div>
            </div>
          </div>
        </div>

        <div className="flex justify-end">
          <Button variant="outline" onClick={onClose} data-testid="button-close-reminder-settings">
            Close
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
}

client/src/components/ScheduleEditModal..content:
import { useState, useEffect } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { useMutation, useQuery } from "@tanstack/react-query";
import { useToast } from "@/hooks/use-toast";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { z } from "zod";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent } from "@/components/ui/card";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { 
  Calendar,
  Clock,
  MapPin,
  Users,
  Edit3,
  Save,
  X,
  Trash2
} from "lucide-react";

interface ScheduleEditModalProps {
  isOpen: boolean;
  onClose: () => void;
  selectedDate: Date;
}

const scheduleEditSchema = z.object({
  tourId: z.string().min(1, "Tour is required"),
  scheduledDate: z.string().min(1, "Date is required"),
  startTime: z.string().min(1, "Start time is required"),
  estimatedDuration: z.number().min(15, "Duration must be at least 15 minutes"),
  notes: z.string().optional(),
  status: z.enum(["scheduled", "confirmed", "in_progress", "completed", "cancelled"]),
});

type ScheduleEditData = z.infer<typeof scheduleEditSchema>;

interface ScheduleItem {
  id: string;
  tourId: string;
  property: {
    id: string;
    address: string;
    listingPrice: number;
  };
  client: {
    id: string;
    firstName: string;
    lastName: string;
    email: string;
  };
  scheduledDate: string;
  startTime: string;
  estimatedDuration: number;
  status: string;
  notes?: string;
}

export default function ScheduleEditModal({ 
  isOpen, 
  onClose, 
  selectedDate 
}: ScheduleEditModalProps) {
  const { toast } = useToast();
  const [editingSchedule, setEditingSchedule] = useState<ScheduleItem | null>(null);

  // Fetch schedules for the selected date
  const { data: schedules = [], isLoading, refetch } = useQuery<ScheduleItem[]>({
    queryKey: ["/api/schedules/date", selectedDate.toISOString().split('T')[0]],
    enabled: isOpen,
  });

  const form = useForm<ScheduleEditData>({
    resolver: zodResolver(scheduleEditSchema),
    defaultValues: {
      tourId: "",
      scheduledDate: selectedDate.toISOString().split('T')[0],
      startTime: "",
      estimatedDuration: 30,
      notes: "",
      status: "scheduled",
    },
  });

  // Update schedule mutation
  const updateScheduleMutation = useMutation({
    mutationFn: async (data: ScheduleEditData & { scheduleId: string }) => {
      return apiRequest("PATCH", `/api/schedules/${data.scheduleId}`, data);
    },
    onSuccess: () => {
      toast({
        title: "Schedule Updated",
        description: "The showing schedule has been updated successfully.",
      });
      setEditingSchedule(null);
      form.reset();
      queryClient.invalidateQueries({ queryKey: ["/api/schedules/date"] });
      refetch();
    },
    onError: () => {
      toast({
        title: "Update Failed",
        description: "Could not update the schedule. Please try again.",
        variant: "destructive",
      });
    },
  });

  // Delete schedule mutation
  const deleteScheduleMutation = useMutation({
    mutationFn: async (scheduleId: string) => {
      return apiRequest("DELETE", `/api/schedules/${scheduleId}`);
    },
    onSuccess: () => {
      toast({
        title: "Schedule Deleted",
        description: "The showing schedule has been deleted.",
      });
      setEditingSchedule(null);
      queryClient.invalidateQueries({ queryKey: ["/api/schedules/date"] });
      refetch();
    },
    onError: () => {
      toast({
        title: "Delete Failed",
        description: "Could not delete the schedule. Please try again.",
        variant: "destructive",
      });
    },
  });

  const handleEditSchedule = (schedule: ScheduleItem) => {
    setEditingSchedule(schedule);
    form.reset({
      tourId: schedule.tourId,
      scheduledDate: schedule.scheduledDate,
      startTime: schedule.startTime,
      estimatedDuration: schedule.estimatedDuration,
      notes: schedule.notes || "",
      status: schedule.status as any,
    });
  };

  const handleSaveSchedule = async (data: ScheduleEditData) => {
    if (!editingSchedule) return;

    updateScheduleMutation.mutate({
      ...data,
      scheduleId: editingSchedule.id,
    });
  };

  const handleDeleteSchedule = (scheduleId: string) => {
    if (confirm("Are you sure you want to delete this showing schedule?")) {
      deleteScheduleMutation.mutate(scheduleId);
    }
  };

  const formatTime = (timeString: string) => {
    return new Date(timeString).toLocaleTimeString("en-US", {
      hour: "numeric",
      minute: "2-digit",
      hour12: true,
    });
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case "scheduled":
        return "bg-blue-100 text-blue-800";
      case "confirmed":
        return "bg-green-100 text-green-800";
      case "in_progress":
        return "bg-yellow-100 text-yellow-800";
      case "completed":
        return "bg-gray-100 text-gray-800";
      case "cancelled":
        return "bg-red-100 text-red-800";
      default:
        return "bg-gray-100 text-gray-800";
    }
  };

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Edit3 className="h-5 w-5" />
            Edit Showing Schedules - {selectedDate.toLocaleDateString()}
          </DialogTitle>
        </DialogHeader>

        <div className="space-y-6">
          {/* Schedules List */}
          <Card>
            <CardContent className="p-4">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-2">
                  <Calendar className="h-4 w-4 text-primary" />
                  <h3 className="font-medium">Scheduled Showings</h3>
                  <Badge variant="secondary">{schedules.length} showings</Badge>
                </div>
              </div>

              {isLoading ? (
                <div className="space-y-3">
                  {[1, 2, 3].map((i) => (
                    <div key={i} className="animate-pulse border rounded-lg p-4">
                      <div className="h-4 bg-muted rounded w-1/3 mb-2"></div>
                      <div className="h-3 bg-muted rounded w-1/2"></div>
                    </div>
                  ))}
                </div>
              ) : schedules.length === 0 ? (
                <div className="text-center py-8">
                  <Calendar className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
                  <p className="text-muted-foreground">No showings scheduled for this date</p>
                </div>
              ) : (
                <div className="space-y-3">
                  {schedules.map((schedule) => (
                    <div key={schedule.id} className="border rounded-lg p-4 hover:bg-muted/50 transition-colors">
                      <div className="flex items-start justify-between">
                        <div className="flex-1">
                          <div className="flex items-center gap-2 mb-2">
                            <MapPin className="h-4 w-4 text-muted-foreground" />
                            <p className="font-medium">{schedule.property.address}</p>
                            <Badge className={getStatusColor(schedule.status)}>
                              {schedule.status}
                            </Badge>
                          </div>
                          <div className="flex items-center gap-2 mb-1">
                            <Users className="h-4 w-4 text-muted-foreground" />
                            <p className="text-sm text-muted-foreground">
                              Client: {schedule.client.firstName} {schedule.client.lastName}
                            </p>
                          </div>
                          <div className="flex items-center gap-2">
                            <Clock className="h-4 w-4 text-muted-foreground" />
                            <p className="text-sm text-muted-foreground">
                              {formatTime(schedule.startTime)} ({schedule.estimatedDuration} min)
                            </p>
                          </div>
                          {schedule.notes && (
                            <p className="text-sm text-muted-foreground mt-2">
                              Notes: {schedule.notes}
                            </p>
                          )}
                        </div>
                        <div className="flex gap-2">
                          <Button
                            size="sm"
                            variant="outline"
                            onClick={() => handleEditSchedule(schedule)}
                            data-testid={`button-edit-schedule-${schedule.id}`}
                          >
                            <Edit3 className="h-4 w-4" />
                          </Button>
                          <Button
                            size="sm"
                            variant="outline"
                            onClick={() => handleDeleteSchedule(schedule.id)}
                            data-testid={`button-delete-schedule-${schedule.id}`}
                          >
                            <Trash2 className="h-4 w-4 text-red-600" />
                          </Button>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </CardContent>
          </Card>

          {/* Edit Form */}
          {editingSchedule && (
            <Card>
              <CardContent className="p-4">
                <div className="flex items-center gap-2 mb-4">
                  <Edit3 className="h-4 w-4 text-primary" />
                  <h3 className="font-medium">Edit Schedule</h3>
                </div>
                <Form {...form}>
                  <form onSubmit={form.handleSubmit(handleSaveSchedule)} className="space-y-4">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      <FormField
                        control={form.control}
                        name="scheduledDate"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Date</FormLabel>
                            <FormControl>
                              <Input
                                type="date"
                                {...field}
                                data-testid="input-scheduled-date"
                              />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                      <FormField
                        control={form.control}
                        name="startTime"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Start Time</FormLabel>
                            <FormControl>
                              <Input
                                type="time"
                                {...field}
                                data-testid="input-start-time"
                              />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                      <FormField
                        control={form.control}
                        name="estimatedDuration"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Duration (minutes)</FormLabel>
                            <FormControl>
                              <Input
                                type="number"
                                min="15"
                                max="240"
                                {...field}
                                onChange={(e) => field.onChange(parseInt(e.target.value))}
                                data-testid="input-duration"
                              />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                      <FormField
                        control={form.control}
                        name="status"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Status</FormLabel>
                            <Select value={field.value} onValueChange={field.onChange}>
                              <FormControl>
                                <SelectTrigger data-testid="select-status">
                                  <SelectValue placeholder="Select status" />
                                </SelectTrigger>
                              </FormControl>
                              <SelectContent>
                                <SelectItem value="scheduled">Scheduled</SelectItem>
                                <SelectItem value="confirmed">Confirmed</SelectItem>
                                <SelectItem value="in_progress">In Progress</SelectItem>
                                <SelectItem value="completed">Completed</SelectItem>
                                <SelectItem value="cancelled">Cancelled</SelectItem>
                              </SelectContent>
                            </Select>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                    </div>
                    <FormField
                      control={form.control}
                      name="notes"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Notes</FormLabel>
                          <FormControl>
                            <Textarea
                              placeholder="Add any notes about this showing..."
                              {...field}
                              data-testid="input-notes"
                            />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                    <div className="flex justify-end gap-3">
                      <Button
                        type="button"
                        variant="outline"
                        onClick={() => setEditingSchedule(null)}
                      >
                        <X className="h-4 w-4 mr-2" />
                        Cancel
                      </Button>
                      <Button
                        type="submit"
                        disabled={updateScheduleMutation.isPending}
                        data-testid="button-save-schedule"
                      >
                        {updateScheduleMutation.isPending ? (
                          <>
                            <Save className="h-4 w-4 mr-2 animate-spin" />
                            Saving...
                          </>
                        ) : (
                          <>
                            <Save className="h-4 w-4 mr-2" />
                            Save Changes
                          </>
                        )}
                      </Button>
                    </div>
                  </form>
                </Form>
              </CardContent>
            </Card>
          )}

          {/* Close Button */}
          {!editingSchedule && (
            <div className="flex justify-end">
              <Button variant="outline" onClick={onClose}>
                Close
              </Button>
            </div>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}

client/src/components/TourRequestModal.t.content:
import { useState } from "react";
import { useMutation, useQuery } from "@tanstack/react-query";
import { useToast } from "@/hooks/use-toast";
import { isUnauthorizedError } from "@/lib/authUtils";
import { apiRequest, queryClient } from "@/lib/queryClient";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { Checkbox } from "@/components/ui/checkbox";
import { Card, CardContent } from "@/components/ui/card";
import { Separator } from "@/components/ui/separator";
import { Home, Plus } from "lucide-react";

interface TourRequestModalProps {
  isOpen: boolean;
  onClose: () => void;
}

interface FormData {
  preferredDate: string;
  preferredTime: string;
  notes: string;
  propertyIds: string[];
}

interface CustomProperty {
  address: string;
  mlsNumber: string;
  notes: string;
}

export default function TourRequestModal({ isOpen, onClose }: TourRequestModalProps) {
  const { toast } = useToast();
  const [formData, setFormData] = useState<FormData>({
    preferredDate: "",
    preferredTime: "",
    notes: "",
    propertyIds: [],
  });

  const [customProperty, setCustomProperty] = useState<CustomProperty>({
    address: "",
    mlsNumber: "",
    notes: "",
  });

  // Fetch available properties
  const { data: properties = [], isLoading: propertiesLoading } = useQuery({
    queryKey: ["/api/properties"],
    enabled: isOpen,
  });

  // Submit tour request mutation
  const submitRequestMutation = useMutation({
    mutationFn: async (data: FormData) => {
      const requestData = {
        preferredDate: data.preferredDate ? new Date(data.preferredDate + 'T' + data.preferredTime) : null,
        preferredTime: data.preferredTime,
        notes: data.notes,
        propertyIds: data.propertyIds,
      };
      await apiRequest("POST", "/api/showing-requests", requestData);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/showing-requests"] });
      queryClient.invalidateQueries({ queryKey: ["/api/tours"] });
      toast({
        title: "Success",
        description: "Tour request submitted successfully!",
      });
      onClose();
      resetForm();
    },
    onError: (error) => {
      if (isUnauthorizedError(error)) {
        toast({
          title: "Unauthorized",
          description: "You are logged out. Logging in again...",
          variant: "destructive",
        });
        setTimeout(() => {
          window.location.href = "/api/login";
        }, 500);
        return;
      }
      toast({
        title: "Error",
        description: "Failed to submit tour request",
        variant: "destructive",
      });
    },
  });

  const resetForm = () => {
    setFormData({
      preferredDate: "",
      preferredTime: "",
      notes: "",
      propertyIds: [],
    });
    setCustomProperty({
      address: "",
      mlsNumber: "",
      notes: "",
    });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    const hasSelectedProperties = formData.propertyIds.length > 0;
    const hasCustomProperty = customProperty.address && customProperty.mlsNumber;

    if (!hasSelectedProperties && !hasCustomProperty) {
      toast({
        title: "Error",
        description: "Please select at least one property or suggest a custom property",
        variant: "destructive",
      });
      return;
    }

    // Submit custom property suggestion first if provided
    if (hasCustomProperty) {
      try {
        await apiRequest("POST", "/api/property-suggestions", {
          address: customProperty.address,
          mlsNumber: customProperty.mlsNumber,
          notes: customProperty.notes,
          preferredDate: formData.preferredDate ? new Date(formData.preferredDate + 'T' + formData.preferredTime) : null,
          preferredTime: formData.preferredTime,
        });
        toast({
          title: "Success",
          description: "Property suggestion submitted to your agent!",
        });
      } catch (error) {
        if (!isUnauthorizedError(error as Error)) {
          toast({
            title: "Warning",
            description: "Failed to submit property suggestion, but continuing with tour request",
            variant: "destructive",
          });
        }
      }
    }

    // Submit tour request if properties selected
    if (hasSelectedProperties) {
      submitRequestMutation.mutate(formData);
    } else {
      // If only custom property, close modal
      queryClient.invalidateQueries({ queryKey: ["/api/property-suggestions"] });
      onClose();
      resetForm();
    }
  };

  const handlePropertyToggle = (propertyId: string) => {
    setFormData(prev => ({
      ...prev,
      propertyIds: prev.propertyIds.includes(propertyId)
        ? prev.propertyIds.filter(id => id !== propertyId)
        : [...prev.propertyIds, propertyId],
    }));
  };

  const handleClose = () => {
    onClose();
    resetForm();
  };

  return (
    <Dialog open={isOpen} onOpenChange={handleClose}>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-hidden" data-testid="modal-tour-request">
        <DialogHeader>
          <DialogTitle>Request New Tour</DialogTitle>
        </DialogHeader>

        <div className="overflow-y-auto max-h-[calc(90vh-120px)]">
          <form onSubmit={handleSubmit} className="space-y-6" data-testid="form-tour-request">
            <div>
              <Label htmlFor="preferredDate" className="text-sm font-medium">
                Preferred Date & Time
              </Label>
              <div className="grid grid-cols-2 gap-4 mt-2">
                <Input
                  id="preferredDate"
                  type="date"
                  value={formData.preferredDate}
                  onChange={(e) => setFormData(prev => ({ ...prev, preferredDate: e.target.value }))}
                  data-testid="input-preferred-date"
                />
                <Input
                  id="preferredTime"
                  type="time"
                  value={formData.preferredTime}
                  onChange={(e) => setFormData(prev => ({ ...prev, preferredTime: e.target.value }))}
                  data-testid="input-preferred-time"
                />
              </div>
            </div>

            <div>
              <Label className="text-sm font-medium mb-2 block">
                Select Properties
              </Label>
              <div className="space-y-3 max-h-64 overflow-y-auto border border-border rounded-md p-3">
                {propertiesLoading ? (
                  <div className="space-y-3">
                    {[1, 2, 3].map((i) => (
                      <div key={i} className="animate-pulse border border-border rounded-lg p-4">
                        <div className="flex items-start space-x-3">
                          <div className="w-4 h-4 bg-muted rounded"></div>
                          <div className="w-20 h-15 bg-muted rounded-md"></div>
                          <div className="flex-1">
                            <div className="h-4 bg-muted rounded w-1/3 mb-2"></div>
                            <div className="h-3 bg-muted rounded w-1/2"></div>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                ) : properties.length === 0 ? (
                  <div className="text-center py-8">
                    <Home className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
                    <p className="text-muted-foreground">No properties available</p>
                  </div>
                ) : (
                  properties.map((property: any) => (
                    <Card 
                      key={property.id} 
                      className="cursor-pointer hover:bg-muted/50 transition-colors"
                      data-testid={`property-option-${property.id}`}
                    >
                      <CardContent className="p-4">
                        <div className="flex items-start space-x-3">
                          <Checkbox
                            checked={formData.propertyIds.includes(property.id)}
                            onChange={() => handlePropertyToggle(property.id)}
                            data-testid={`checkbox-${property.id}`}
                          />
                          <div className="w-20 h-15 bg-muted rounded-md flex items-center justify-center">
                            <Home className="h-8 w-8 text-muted-foreground" />
                          </div>
                          <div className="flex-1">
                            <h4 className="font-medium">{property.address}</h4>
                            <p className="text-sm text-muted-foreground">
                              {property.bedrooms} bed, {property.bathrooms} bath • ${Number(property.price).toLocaleString()}
                            </p>
                            <p className="text-sm text-muted-foreground">
                              {property.area || "Area not specified"}
                            </p>
                          </div>
                        </div>
                      </CardContent>
                    </Card>
                  ))
                )}
              </div>
            </div>

            <div className="my-6">
              <div className="relative flex items-center justify-center">
                <Separator className="absolute w-full" />
                <span className="relative bg-background px-4 text-sm text-muted-foreground">
                  OR Suggest Your Own Property
                </span>
              </div>
            </div>

            <div className="space-y-4 border border-border rounded-lg p-4 bg-muted/30">
              <div className="flex items-center gap-2 text-sm font-medium mb-2">
                <Plus className="h-4 w-4" />
                <span>Custom Property Suggestion</span>
              </div>

              <div>
                <Label htmlFor="customAddress" className="text-sm font-medium">
                  Property Address
                </Label>
                <Input
                  id="customAddress"
                  className="mt-2"
                  placeholder="Enter full property address..."
                  value={customProperty.address}
                  onChange={(e) => setCustomProperty(prev => ({ ...prev, address: e.target.value }))}
                  data-testid="input-custom-address"
                />
              </div>

              <div>
                <Label htmlFor="customMLS" className="text-sm font-medium">
                  MLS Number
                </Label>
                <Input
                  id="customMLS"
                  className="mt-2"
                  placeholder="Enter MLS number..."
                  value={customProperty.mlsNumber}
                  onChange={(e) => setCustomProperty(prev => ({ ...prev, mlsNumber: e.target.value }))}
                  data-testid="input-custom-mls"
                />
              </div>

              <div>
                <Label htmlFor="customNotes" className="text-sm font-medium">
                  Notes (Optional)
                </Label>
                <Textarea
                  id="customNotes"
                  className="mt-2 h-20"
                  placeholder="Why are you interested in this property?..."
                  value={customProperty.notes}
                  onChange={(e) => setCustomProperty(prev => ({ ...prev, notes: e.target.value }))}
                  data-testid="textarea-custom-notes"
                />
              </div>
            </div>

            <div>
              <Label htmlFor="notes" className="text-sm font-medium">
                Additional Notes
              </Label>
              <Textarea
                id="notes"
                className="mt-2 h-24"
                placeholder="Any specific requirements or preferences..."
                value={formData.notes}
                onChange={(e) => setFormData(prev => ({ ...prev, notes: e.target.value }))}
                data-testid="textarea-notes"
              />
            </div>

            <div className="flex space-x-3">
              <Button 
                type="submit" 
                className="flex-1 bg-primary text-primary-foreground hover:bg-primary/90"
                disabled={submitRequestMutation.isPending}
                data-testid="button-submit-request"
              >
                {submitRequestMutation.isPending ? "Submitting..." : "Submit Request"}
              </Button>
              <Button 
                type="button" 
                variant="outline" 
                onClick={handleClose}
                data-testid="button-cancel-request"
              >
                Cancel
              </Button>
            </div>
          </form>
        </div>
      </DialogContent>
    </Dialog>
  );
}

shared/schema.ts.content:
import { sql } from 'drizzle-orm';
import {
  index,
  jsonb,
  pgTable,
  timestamp,
  varchar,
  text,
  integer,
  decimal,
  boolean,
  uuid,
} from "drizzle-orm/pg-core";
import { relations } from "drizzle-orm";
import { createInsertSchema } from "drizzle-zod";
import { z } from "zod";

// Session storage table (required for Replit Auth)
export const sessions = pgTable(
  "sessions",
  {
    sid: varchar("sid").primaryKey(),
    sess: jsonb("sess").notNull(),
    expire: timestamp("expire").notNull(),
  },
  (table) => [index("IDX_session_expire").on(table.expire)],
);

// User storage table (required for Replit Auth)
export const users = pgTable("users", {
  id: varchar("id").primaryKey().default(sql`gen_random_uuid()`),
  email: varchar("email").unique(),
  firstName: varchar("first_name"),
  lastName: varchar("last_name"),
  profileImageUrl: varchar("profile_image_url"),
  passwordHash: varchar("password_hash"), // Hashed password for client accounts
  role: varchar("role", { enum: ["agent", "client", "brokerage", "superadmin"] }).notNull().default("client"),
  clientType: varchar("client_type", { enum: ["buyer", "renter"] }), // Only for clients
  agentId: varchar("agent_id"),
  driveFolderUrl: varchar("drive_folder_url"), // Manual Google Drive folder URL (simplified integration)
  createdAt: timestamp("created_at").defaultNow(),
  updatedAt: timestamp("updated_at").defaultNow(),
});

// Rental profiles for renter clients
// Enhanced Requirements System for comprehensive client management

// Core requirements table with versioning and validation
export const clientRequirements = pgTable("client_requirements", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  userId: varchar("user_id").notNull().references(() => users.id),
  clientType: varchar("client_type", { enum: ["buyer", "renter"] }).notNull(),
  version: integer("version").notNull().default(1),
  status: varchar("status", { 
    enum: ["incomplete", "pending_validation", "validated", "needs_review", "approved", "expired"] 
  }).default("incomplete"),

  // Validation tracking
  validationScore: decimal("validation_score", { precision: 3, scale: 2 }).default("0"), // 0-1 completeness score
  lastValidatedAt: timestamp("last_validated_at"),
  validatedBy: varchar("validated_by").references(() => users.id),

  // Common fields for all client types
  budgetMin: decimal("budget_min", { precision: 12, scale: 2 }),
  budgetMax: decimal("budget_max", { precision: 12, scale: 2 }),
  preferredAreas: text("preferred_areas").array(),
  propertyTypes: text("property_types").array(),
  bedrooms: integer("bedrooms"),
  bathrooms: decimal("bathrooms", { precision: 3, scale: 1 }),
  parkingRequired: boolean("parking_required").default(false),
  parkingSpots: integer("parking_spots").default(0),

  // Buyer-specific fields
  preApprovalAmount: decimal("pre_approval_amount", { precision: 12, scale: 2 }),
  downPaymentAmount: decimal("down_payment_amount", { precision: 12, scale: 2 }),
  mortgagePreApprovalExpiry: timestamp("mortgage_pre_approval_expiry"),
  firstTimeBuyer: boolean("first_time_buyer").default(false),
  desiredClosingDate: timestamp("desired_closing_date"),

  // Renter-specific fields  
  monthlyIncomeVerified: boolean("monthly_income_verified").default(false),
  combinedFamilyIncome: decimal("combined_family_income", { precision: 12, scale: 2 }),
  preferredMoveInDate: timestamp("preferred_move_in_date"),
  willingToPrepayRent: boolean("willing_to_prepay_rent").default(false),
  prepayMonths: integer("prepay_months").default(0),

  // Timeline and urgency
  urgencyLevel: varchar("urgency_level", { enum: ["low", "medium", "high", "urgent"] }).default("medium"),
  timeframe: varchar("timeframe", { enum: ["asap", "1_month", "3_months", "6_months", "flexible"] }),

  // Metadata
  notes: text("notes"),
  agentId: varchar("agent_id").references(() => users.id),
  createdAt: timestamp("created_at").defaultNow(),
  updatedAt: timestamp("updated_at").defaultNow(),
  isActive: boolean("is_active").default(true),
});

// Requirements versioning for audit trail
export const requirementsVersions = pgTable("requirements_versions", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  requirementId: uuid("requirement_id").notNull().references(() => clientRequirements.id),
  version: integer("version").notNull(),
  changeType: varchar("change_type", { enum: ["created", "updated", "validated", "approved"] }).notNull(),
  changes: jsonb("changes"), // Store diff of what changed
  changedBy: varchar("changed_by").notNull().references(() => users.id),
  changeReason: text("change_reason"),
  createdAt: timestamp("created_at").defaultNow(),
});

// Exceptions and special cases register
export const requirementsExceptions = pgTable("requirements_exceptions", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  requirementId: uuid("requirement_id").notNull().references(() => clientRequirements.id),
  exceptionType: varchar("exception_type", { 
    enum: ["budget_override", "area_expansion", "criteria_waiver", "timeline_extension", "special_circumstance"] 
  }).notNull(),
  description: text("description").notNull(),
  justification: text("justification").notNull(),
  approvedBy: varchar("approved_by").references(() => users.id),
  approvedAt: timestamp("approved_at"),
  status: varchar("status", { enum: ["pending", "approved", "rejected", "expired"] }).default("pending"),
  expiresAt: timestamp("expires_at"),
  createdAt: timestamp("created_at").defaultNow(),
});

// Scope fit scoring for properties
export const propertyMatches = pgTable("property_matches", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  requirementId: uuid("requirement_id").notNull().references(() => clientRequirements.id),
  propertyId: uuid("property_id").notNull().references(() => properties.id),
  overallScore: decimal("overall_score", { precision: 3, scale: 2 }).notNull(), // 0-1 match score

  // Individual scoring components
  budgetScore: decimal("budget_score", { precision: 3, scale: 2 }),
  locationScore: decimal("location_score", { precision: 3, scale: 2 }),
  sizeScore: decimal("size_score", { precision: 3, scale: 2 }),
  typeScore: decimal("type_score", { precision: 3, scale: 2 }),
  amenityScore: decimal("amenity_score", { precision: 3, scale: 2 }),
  timelineScore: decimal("timeline_score", { precision: 3, scale: 2 }),

  // Match metadata
  matchReason: text("match_reason"), // Explanation of why it's a good match
  dealBreakers: text("deal_breakers").array(), // What doesn't match
  highlights: text("highlights").array(), // What matches really well

  calculatedAt: timestamp("calculated_at").defaultNow(),
  agentReview: varchar("agent_review", { enum: ["pending", "approved", "rejected"] }),
  agentNotes: text("agent_notes"),
});

// Legacy rental profiles table (keeping for backward compatibility)
export const rentalProfiles = pgTable("rental_profiles", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  userId: varchar("user_id").notNull().unique().references(() => users.id),
  bedrooms: integer("bedrooms").notNull(),
  bathrooms: decimal("bathrooms", { precision: 3, scale: 1 }).notNull(),
  parkingRequired: boolean("parking_required").default(false),
  parkingSpots: integer("parking_spots").default(0),
  numberOfOccupants: integer("number_of_occupants").notNull(),
  monthlyBudget: decimal("monthly_budget", { precision: 10, scale: 2 }).notNull(), // CAD
  preferredAreas: text("preferred_areas").array(), // Array of cities/areas
  propertyType: varchar("property_type", { 
    enum: ["condo", "townhouse", "detached", "apartment", "basement", "duplex", "other"] 
  }).notNull(),
  preferredMoveInDate: timestamp("preferred_move_in_date"),
  combinedFamilyIncome: decimal("combined_family_income", { precision: 12, scale: 2 }).notNull(), // CAD annually
  willingToPrepayRent: boolean("willing_to_prepay_rent").default(false),
  prepayMonths: integer("prepay_months").default(0), // How many months willing to prepay
  createdAt: timestamp("created_at").defaultNow(),
  updatedAt: timestamp("updated_at").defaultNow(),
});

// OREA Form 410 Rental Application tables
export const rentalApplications = pgTable("rental_applications", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  userId: varchar("user_id").notNull().references(() => users.id),
  propertyId: uuid("property_id").notNull().references(() => properties.id),
  agentId: varchar("agent_id").notNull().references(() => users.id),
  applicationNumber: varchar("application_number").notNull().unique(),
  // Property & Lease Information
  intendedStartDate: timestamp("intended_start_date").notNull(),
  monthlyRent: decimal("monthly_rent", { precision: 10, scale: 2 }).notNull(),
  rentDueDate: integer("rent_due_date").notNull(), // Day of month (1-31)
  // Personal Information
  dateOfBirth: timestamp("date_of_birth").notNull(),
  socialInsuranceNumber: varchar("social_insurance_number"), // Optional
  driversLicenseNumber: varchar("drivers_license_number"),
  phoneNumber: varchar("phone_number").notNull(),
  occupation: varchar("occupation"),
  // Vehicle Information
  vehicleMake: varchar("vehicle_make"),
  vehicleModel: varchar("vehicle_model"),
  vehicleYear: integer("vehicle_year"),
  vehicleLicensePlate: varchar("vehicle_license_plate"),
  // Pet Information
  hasPets: boolean("has_pets").default(false),
  petDetails: text("pet_details"), // Type, breed, age, etc.
  // Additional Occupants
  additionalOccupants: jsonb("additional_occupants"), // Array of {name, relationship, age}
  // Application Status
  status: varchar("status", { 
    enum: ["draft", "submitted", "under_review", "approved", "rejected", "withdrawn"] 
  }).default("draft"),
  submittedAt: timestamp("submitted_at"),
  reviewedAt: timestamp("reviewed_at"),
  reviewNotes: text("review_notes"),
  // Consent and Signatures
  consentBackgroundCheck: boolean("consent_background_check").default(false),
  consentCreditCheck: boolean("consent_credit_check").default(false),
  consentReferenceCheck: boolean("consent_reference_check").default(false),
  applicationSignedAt: timestamp("application_signed_at"),
  createdAt: timestamp("created_at").defaultNow(),
  updatedAt: timestamp("updated_at").defaultNow(),
});

export const employmentHistory = pgTable("employment_history", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  applicationId: uuid("application_id").notNull().references(() => rentalApplications.id),
  isCurrent: boolean("is_current").notNull(),
  employerName: varchar("employer_name").notNull(),
  businessAddress: text("business_address").notNull(),
  businessPhone: varchar("business_phone").notNull(),
  position: varchar("position").notNull(),
  startDate: timestamp("start_date").notNull(),
  endDate: timestamp("end_date"), // NULL for current employment
  supervisorName: varchar("supervisor_name"),
  monthlySalary: decimal("monthly_salary", { precision: 10, scale: 2 }).notNull(),
  salaryType: varchar("salary_type", { enum: ["hourly", "salary", "commission", "contract"] }).notNull(),
  createdAt: timestamp("created_at").defaultNow(),
});

export const financialInformation = pgTable("financial_information", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  applicationId: uuid("application_id").notNull().references(() => rentalApplications.id),
  bankName: varchar("bank_name").notNull(),
  branchAddress: text("branch_address").notNull(),
  accountType: varchar("account_type", { enum: ["checking", "savings", "credit"] }).notNull(),
  accountNumber: varchar("account_number").notNull(), // Encrypted in practice
  monthlyIncome: decimal("monthly_income", { precision: 12, scale: 2 }).notNull(),
  otherIncome: decimal("other_income", { precision: 12, scale: 2 }).default("0"),
  otherIncomeSource: text("other_income_source"),
  monthlyDebts: decimal("monthly_debts", { precision: 10, scale: 2 }).default("0"),
  debtDetails: text("debt_details"), // Credit cards, loans, etc.
  bankruptcyHistory: boolean("bankruptcy_history").default(false),
  bankruptcyDetails: text("bankruptcy_details"),
  createdAt: timestamp("created_at").defaultNow(),
});

export const rentalHistory = pgTable("rental_history", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  applicationId: uuid("application_id").notNull().references(() => rentalApplications.id),
  address: text("address").notNull(),
  landlordName: varchar("landlord_name").notNull(),
  landlordPhone: varchar("landlord_phone").notNull(),
  landlordEmail: varchar("landlord_email"),
  monthlyRent: decimal("monthly_rent", { precision: 10, scale: 2 }).notNull(),
  startDate: timestamp("start_date").notNull(),
  endDate: timestamp("end_date"), // NULL for current rental
  reasonForLeaving: text("reason_for_leaving"),
  wasEvicted: boolean("was_evicted").default(false),
  latePayments: boolean("late_payments").default(false),
  createdAt: timestamp("created_at").defaultNow(),
});

export const personalReferences = pgTable("personal_references", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  applicationId: uuid("application_id").notNull().references(() => rentalApplications.id),
  name: varchar("name").notNull(),
  relationship: varchar("relationship").notNull(), // Friend, colleague, etc.
  phoneNumber: varchar("phone_number").notNull(),
  email: varchar("email"),
  yearsKnown: integer("years_known").notNull(),
  createdAt: timestamp("created_at").defaultNow(),
});

export const applicationDocuments = pgTable("application_documents", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  applicationId: uuid("application_id").notNull().references(() => rentalApplications.id),
  documentType: varchar("document_type", { 
    enum: ["pay_stub", "bank_statement", "employment_letter", "tax_return", "reference_letter", "id_document", "other"] 
  }).notNull(),
  documentName: varchar("document_name").notNull(),
  fileName: varchar("file_name").notNull(),
  originalName: varchar("original_name").notNull(),
  filePath: varchar("file_path").notNull(),
  mimeType: varchar("mime_type").notNull(),
  fileSize: integer("file_size").notNull(),
  isRequired: boolean("is_required").default(true),
  uploadedAt: timestamp("uploaded_at").defaultNow(),
});

export const agentBrandingSettings = pgTable("agent_branding_settings", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  agentId: varchar("agent_id").notNull().references(() => users.id),
  logoUrl: text("logo_url").notNull(),
  agentName: varchar("agent_name", { length: 120 }).notNull(),
  agentEmail: varchar("agent_email", { length: 120 }).notNull(),
  brokerageName: varchar("brokerage_name", { length: 120 }).notNull(),
  updatedAt: timestamp("updated_at").defaultNow(),
  updatedBy: varchar("updated_by").notNull().references(() => users.id),
});

export const settingsVersions = pgTable("settings_versions", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  agentId: varchar("agent_id").notNull().references(() => users.id),
  tab: varchar("tab", { enum: ["branding", "general", "notifications"] }).notNull(),
  diff: jsonb("diff"),
  updatedAt: timestamp("updated_at").defaultNow(),
  updatedBy: varchar("updated_by").notNull().references(() => users.id),
});

export const properties = pgTable("properties", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  mlsNumber: integer("mls_number").notNull().unique(),
  address: text("address").notNull(),
  city: varchar("city"),
  province: varchar("province"),
  postalCode: varchar("postal_code"),
  propertyType: varchar("property_type", { enum: ["detached", "semi-detached", "townhouse", "condo", "apartment"] }),
  bedrooms: integer("bedrooms").notNull(),
  bathrooms: decimal("bathrooms", { precision: 3, scale: 1 }).notNull(),
  price: decimal("price", { precision: 12, scale: 2 }).notNull(),
  area: varchar("area"),
  description: text("description"),
  imageUrl: varchar("image_url"),
  isActive: boolean("is_active").default(true),
  agentId: varchar("agent_id").notNull().references(() => users.id),
  createdAt: timestamp("created_at").defaultNow(),
});

export const propertyShortlists = pgTable("property_shortlists", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  propertyId: uuid("property_id").notNull().references(() => properties.id),
  userId: varchar("user_id").notNull().references(() => users.id),
  createdAt: timestamp("created_at").defaultNow(),
}, (table) => ({
  userPropertyIdx: sql`CREATE UNIQUE INDEX user_property_idx ON ${table} (user_id, property_id)`,
}));

export const clientGroups = pgTable("client_groups", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  name: varchar("name").notNull(),
  createdById: varchar("created_by_id").notNull().references(() => users.id),
  createdAt: timestamp("created_at").defaultNow(),
});

export const groupMembers = pgTable("group_members", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  groupId: uuid("group_id").notNull().references(() => clientGroups.id),
  userId: varchar("user_id").notNull().references(() => users.id),
  joinedAt: timestamp("joined_at").defaultNow(),
});

export const groupMessages = pgTable("group_messages", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  groupId: uuid("group_id").notNull().references(() => clientGroups.id),
  userId: varchar("user_id").notNull().references(() => users.id),
  message: text("message").notNull(),
  createdAt: timestamp("created_at").defaultNow(),
});

export const tours = pgTable("tours", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  agentId: varchar("agent_id").notNull().references(() => users.id),
  clientId: varchar("client_id").notNull().references(() => users.id),
  groupId: uuid("group_id").references(() => clientGroups.id),
  scheduledDate: timestamp("scheduled_date"),
  startTime: timestamp("start_time"),
  endTime: timestamp("end_time"),
  status: varchar("status", { enum: ["requested", "scheduled", "in_progress", "completed", "cancelled"] }).default("requested"),
  totalDistance: decimal("total_distance", { precision: 8, scale: 2 }),
  estimatedDuration: integer("estimated_duration_minutes"),
  actualDuration: integer("actual_duration_minutes"),
  notes: text("notes"),
  createdAt: timestamp("created_at").defaultNow(),
  updatedAt: timestamp("updated_at").defaultNow(),
});

export const tourProperties = pgTable("tour_properties", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  tourId: uuid("tour_id").notNull().references(() => tours.id),
  propertyId: uuid("property_id").notNull().references(() => properties.id),
  order: integer("order").notNull(),
  scheduledTime: timestamp("scheduled_time"),
  visitedAt: timestamp("visited_at"),
  status: varchar("status", { enum: ["scheduled", "viewed", "liked", "rejected", "offer_made"] }).default("scheduled"),
  rejectionReason: text("rejection_reason"),
  notes: text("notes"),
});

export const propertyRatings = pgTable("property_ratings", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  propertyId: uuid("property_id").notNull().references(() => properties.id),
  tourId: uuid("tour_id").notNull().references(() => tours.id),
  clientId: varchar("client_id").notNull().references(() => users.id),
  rating: integer("rating").notNull(), // 1-5 stars
  feedbackCategory: varchar("feedback_category", { 
    enum: ["offer_now", "hold_later", "reject"] 
  }).notNull(),
  reason: text("reason").notNull(),
  notes: text("notes"),
  remindLater: boolean("remind_later").default(false),
  remindedAt: timestamp("reminded_at"),
  createdAt: timestamp("created_at").defaultNow(),
  updatedAt: timestamp("updated_at").defaultNow(),
});

export const propertyPhotos = pgTable("property_photos", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  propertyId: uuid("property_id").notNull().references(() => properties.id),
  tourId: uuid("tour_id").references(() => tours.id),
  clientId: varchar("client_id").references(() => users.id),
  uploadedBy: varchar("uploaded_by").notNull().references(() => users.id),
  filename: varchar("filename").notNull(),
  originalName: varchar("original_name").notNull(),
  url: varchar("url").notNull(),
  mimeType: varchar("mime_type").notNull(),
  size: integer("size").notNull(),
  caption: text("caption"),
  createdAt: timestamp("created_at").defaultNow(),
});

// Property media for comprehensive viewing documentation (photos, videos, documents)
export const propertyMedia = pgTable("property_media", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  propertyId: uuid("property_id").notNull().references(() => properties.id),
  tourId: uuid("tour_id").notNull().references(() => tours.id),
  uploadedBy: varchar("uploaded_by").notNull().references(() => users.id),
  mediaType: varchar("media_type", { 
    enum: ["photo", "video", "document"] 
  }).notNull(),
  documentType: varchar("document_type", {
    enum: ["offer", "inspection", "appraisal", "floor_plan", "listing", "other"]
  }),
  filename: varchar("filename").notNull(),
  originalName: varchar("original_name").notNull(),
  url: varchar("url").notNull(),
  mimeType: varchar("mime_type").notNull(),
  size: integer("size").notNull(),
  caption: text("caption"),
  description: text("description"),
  createdAt: timestamp("created_at").defaultNow(),
});

export const offers = pgTable("offers", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  propertyId: uuid("property_id").notNull().references(() => properties.id),
  clientId: varchar("client_id").notNull().references(() => users.id),
  agentId: varchar("agent_id").notNull().references(() => users.id),
  amount: decimal("amount", { precision: 12, scale: 2 }).notNull(),
  status: varchar("status", { enum: ["pending", "accepted", "rejected", "withdrawn"] }).default("pending"),
  rejectionReason: text("rejection_reason"),
  submittedAt: timestamp("submitted_at").defaultNow(),
  respondedAt: timestamp("responded_at"),
  notes: text("notes"),
});

export const showingRequests = pgTable("showing_requests", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  clientId: varchar("client_id").notNull().references(() => users.id),
  agentId: varchar("agent_id").notNull().references(() => users.id),
  groupId: uuid("group_id").references(() => clientGroups.id),
  preferredDate: timestamp("preferred_date"),
  preferredTime: varchar("preferred_time"),
  status: varchar("status", { enum: ["pending", "approved", "rejected"] }).default("pending"),
  notes: text("notes"),
  createdAt: timestamp("created_at").defaultNow(),
  updatedAt: timestamp("updated_at").defaultNow(),
});

export const requestedProperties = pgTable("requested_properties", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  requestId: uuid("request_id").notNull().references(() => showingRequests.id),
  propertyId: uuid("property_id").notNull().references(() => properties.id),
});

// Tour recaps for end-of-day summaries
export const tourRecaps = pgTable("tour_recaps", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  agentId: varchar("agent_id").notNull().references(() => users.id),
  tourDate: timestamp("tour_date").notNull(),
  totalDistance: varchar("total_distance"),
  totalDuration: varchar("total_duration"),
  showingsCompleted: integer("showings_completed").notNull().default(0),
  clientsSatisfaction: integer("clients_satisfaction").notNull().default(5),
  keyInsights: text("key_insights"),
  challengesFaced: text("challenges_faced"),
  opportunitiesIdentified: text("opportunities_identified"),
  followUpActions: text("follow_up_actions"),
  overallNotes: text("overall_notes"),
  createdAt: timestamp("created_at").defaultNow(),
  updatedAt: timestamp("updated_at").defaultNow(),
});

// Showing schedules for detailed schedule management
export const showingSchedules = pgTable("showing_schedules", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  tourId: uuid("tour_id").notNull().references(() => tours.id),
  propertyId: uuid("property_id").notNull().references(() => properties.id),
  scheduledDate: timestamp("scheduled_date").notNull(),
  startTime: varchar("start_time").notNull(),
  estimatedDuration: integer("estimated_duration").notNull().default(30),
  status: varchar("status", { enum: ["scheduled", "confirmed", "in_progress", "completed", "cancelled"] }).default("scheduled"),
  notes: text("notes"),
  createdAt: timestamp("created_at").defaultNow(),
  updatedAt: timestamp("updated_at").defaultNow(),
});

// Tour reminders for notifications before tours
export const tourReminders = pgTable("tour_reminders", {
  id: uuid("id").primaryKey().default(sql`gen_random_uuid()`),
  userId: varchar("user_id").notNull().references(() => users.id),
  tourId: uuid("tour_id").notNull().references(() => tours.id),
  method: varchar("method", { enum: ["notification", "email", "sms"] }).notNull(),
  intervalValue: integer("interval_value").notNull().default(1),
  intervalUnit: varchar("interval_unit", { enum: ["minutes", "hours", "days", "weeks"] }).notNull().default("days"),
  timing: varchar("timing").notNull().default("09:00"),
  isEnabled: boolean("is_enabled").default(true),
  lastSent: timestamp("last_sent"),
