import { useAuth } from "@/hooks/useAuth";
import { useQuery } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import { ViewModeSwitcher } from "@/components/ViewModeSwitcher";
import HamburgerMenu from "@/components/HamburgerMenu";
import { LogOut, User, Mail } from "lucide-react";

interface HeaderProps {
  userRole: "agent" | "client";
  upcomingTours?: number;
  shortlistCount?: number;
}

interface AgentBranding {
  logoUrl: string;
  agentName: string;
  agentEmail: string;
  brokerageName: string;
}

export default function Header({ userRole, upcomingTours = 0, shortlistCount = 0 }: HeaderProps) {
  const { user } = useAuth();

  const { data: agentBranding } = useQuery<AgentBranding | null>({
    queryKey: ["/api/settings/branding/my-agent"],
    enabled: !!user && userRole === "client",
  });

  const handleLogout = () => {
    localStorage.removeItem("authToken");
    window.location.href = "/api/logout";
  };

  const getInitials = () => {
    if (user?.firstName && user?.lastName) {
      return user.firstName[0] + user.lastName[0];
    }
    return user?.email?.[0]?.toUpperCase() || "U";
  };

  const getDisplayName = () => {
    if (user?.firstName && user?.lastName) {
      return `${user.firstName} ${user.lastName}`;
    }
    return user?.email || "User";
  };

  if (userRole === "client") {
    return (
      <header className="bg-card shadow-sm border-b border-border sticky top-0 z-50" data-testid="header">
        <div className="max-w-7xl mx-auto px-3 sm:px-4 lg:px-8">
          <div className="flex justify-between items-center py-3 sm:py-4 gap-2">
            {/* Left - Hamburger + Branding */}
            <div className="flex items-center gap-2 sm:gap-4">
              <HamburgerMenu
                userRole="client"
                upcomingTours={upcomingTours}
                shortlistCount={shortlistCount}
              />

              {agentBranding?.logoUrl ? (
                <img
                  src={agentBranding.logoUrl}
                  alt="Agent Logo"
                  className="h-8 w-8 sm:h-10 sm:w-10 lg:h-12 lg:w-12 rounded object-cover border"
                  data-testid="img-agent-logo"
                />
              ) : (
                <Avatar className="h-8 w-8 sm:h-10 sm:w-10">
                  <AvatarFallback className="bg-muted text-muted-foreground">
                    <User className="h-4 w-4 sm:h-5 sm:w-5" />
                  </AvatarFallback>
                </Avatar>
              )}

              <div className="hidden sm:block">
                <div className="text-sm sm:text-base lg:text-lg font-semibold truncate max-w-[150px] sm:max-w-none" data-testid="text-agent-name">
                  {agentBranding?.agentName || "Your Agent"}
                </div>
                <div className="text-xs sm:text-sm text-muted-foreground truncate max-w-[150px] sm:max-w-none" data-testid="text-brokerage-name">
                  {agentBranding?.brokerageName || "Your Brokerage"}
                </div>
              </div>

              <Badge 
                variant="secondary"
                className="bg-accent/10 text-accent hidden sm:inline-flex"
                data-testid="badge-role-client"
              >
                Client
              </Badge>
            </div>

            {/* Right - Actions */}
            <div className="flex items-center gap-2 sm:gap-4">
              <div className="hidden lg:block">
                <ViewModeSwitcher />
              </div>

              {agentBranding?.agentEmail && (
                <a
                  href={`mailto:${agentBranding.agentEmail}`}
                  className="hidden md:flex items-center gap-2 text-sm text-primary hover:underline"
                  data-testid="link-contact-agent"
                >
                  <Mail className="h-4 w-4" />
                  <span className="hidden lg:inline">Contact Agent</span>
                </a>
              )}

              <div className="hidden md:flex items-center gap-2">
                <Avatar className="h-8 w-8">
                  <AvatarFallback className="bg-muted text-muted-foreground text-sm">
                    {getInitials()}
                  </AvatarFallback>
                </Avatar>
                <span className="text-sm font-medium hidden lg:block" data-testid="user-name">
                  {getDisplayName()}
                </span>
              </div>

              <Button 
                variant="ghost" 
                size="sm"
                onClick={handleLogout}
                className="p-2 hover:bg-muted rounded-full"
                data-testid="button-logout"
              >
                <LogOut className="h-4 w-4" />
              </Button>
            </div>
          </div>
        </div>
      </header>
    );
  }

  return (
    <header className="bg-card shadow-sm border-b border-border sticky top-0 z-50" data-testid="header">
      <div className="max-w-7xl mx-auto px-3 sm:px-4 lg:px-8">
        <div className="flex justify-between items-center py-3 sm:py-4 gap-2">
          <div className="flex items-center gap-2 sm:gap-4">
            <HamburgerMenu userRole="agent" />

            <h1 className="text-lg sm:text-xl lg:text-2xl font-bold text-primary" data-testid="app-title">
              Estate Vista
            </h1>
            <Badge 
              variant="default"
              className="bg-primary/10 text-primary hidden sm:inline-flex"
              data-testid="badge-role-agent"
            >
              Agent
            </Badge>
          </div>

          <div className="flex items-center gap-2 sm:gap-4">
            <div className="hidden md:flex items-center gap-2">
              <Avatar className="h-8 w-8">
                <AvatarFallback className="bg-muted text-muted-foreground text-sm">
                  {getInitials()}
                </AvatarFallback>
              </Avatar>
              <span className="text-sm font-medium hidden lg:block" data-testid="user-name">
                {getDisplayName()}
              </span>
            </div>
            <Button 
              variant="ghost" 
              size="sm"
              onClick={handleLogout}
              className="p-2 hover:bg-muted rounded-full"
              data-testid="button-logout"
            >
              <LogOut className="h-4 w-4" />
            </Button>
          </div>
        </div>
      </div>
    </header>
  );
}

