import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { useAuth } from "@/hooks/useAuth";
import { useViewMode } from "@/contexts/ViewModeContext";
import Header from "@/components/Header";
import AgentSidebar from "@/components/AgentSidebar";
import { SidebarProvider, SidebarInset } from "@/components/ui/sidebar";
import DocumentCenterModal from "@/components/DocumentCenterModal";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { FileText, Upload, Download, Folder, Users } from "lucide-react";

export default function DocumentsPage() {
  const { user } = useAuth();
  const { effectiveMode } = useViewMode();
  const [showDocumentCenter, setShowDocumentCenter] = useState(false);
  const [selectedClient, setSelectedClient] = useState<string>("all");

  // Fetch documents for the agent
  const { data: documents = [], isLoading } = useQuery<any[]>({
    queryKey: ["/api/documents", selectedClient],
    queryFn: async () => {
      let url = "/api/documents";
      if (selectedClient !== "all") {
        const clientId = selectedClient === "no-client" ? "null" : selectedClient;
        url += `?clientId=${clientId}`;
      }
      const res = await fetch(url);
      if (!res.ok) throw new Error("Failed to fetch documents");
      return res.json();
    },
    enabled: !!user && effectiveMode === 'agent',
  });

  // Fetch clients for the filter dropdown
  const { data: clients = [] } = useQuery<any[]>({
    queryKey: ["/api/clients"],
    enabled: !!user && effectiveMode === 'agent',
  });

  const getDocumentTypeColor = (type: string) => {
    switch (type) {
      case 'offer_placed': return 'bg-green-100 text-green-800';
      case 'offer_received': return 'bg-blue-100 text-blue-800';
      case 'representative_agreement': return 'bg-purple-100 text-purple-800';
      case 'client_id': return 'bg-yellow-100 text-yellow-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  // Group documents by client
  const groupedDocuments = documents.reduce((acc, doc) => {
    const key = doc.clientId || 'no-client';
    if (!acc[key]) {
      acc[key] = {
        clientId: doc.clientId,
        clientName: doc.clientName || 'General Documents',
        documents: [],
      };
    }
    acc[key].documents.push(doc);
    return acc;
  }, {} as Record<string, { clientId: string | null; clientName: string; documents: any[] }>);

  if (!user) {
    return <div>Loading...</div>;
  }

  return (
    <SidebarProvider>
      <div className="min-h-screen bg-background">
        <Header userRole="agent" />
        <div className="flex">
          <AgentSidebar />
          <SidebarInset>
            <main className="flex-1 p-4 md:p-6">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-4 md:mb-6 gap-4">
            <div>
              <h1 className="text-2xl md:text-3xl font-bold">Documents</h1>
              <p className="text-sm md:text-base text-muted-foreground">Manage client documents and forms</p>
            </div>
            <Button 
              onClick={() => setShowDocumentCenter(true)}
              className="gap-2"
              data-testid="button-upload-document"
            >
              <Upload className="h-4 w-4" />
              Upload Document
            </Button>
          </div>

          {/* Client Filter */}
          <div className="mb-6">
            <label className="text-sm font-medium mb-2 block">Filter by Client</label>
            <Select value={selectedClient} onValueChange={setSelectedClient}>
              <SelectTrigger className="w-[300px]" data-testid="select-client-filter">
                <SelectValue placeholder="All Clients" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all" data-testid="option-all-clients">All Clients</SelectItem>
                <SelectItem value="no-client" data-testid="option-general-documents">General Documents</SelectItem>
                {clients.map((client) => (
                  <SelectItem 
                    key={client.id} 
                    value={client.id}
                    data-testid={`option-client-${client.id}`}
                  >
                    {client.firstName} {client.lastName}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          {isLoading ? (
            <div className="flex items-center justify-center py-12">
              <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
            </div>
          ) : documents.length === 0 ? (
            <Card>
              <CardContent className="flex flex-col items-center justify-center py-12">
                <FileText className="h-12 w-12 text-muted-foreground mb-4" />
                <h3 className="text-lg font-semibold mb-2">No documents uploaded</h3>
                <p className="text-muted-foreground text-center mb-4">
                  Upload client documents, forms, and agreements to get started.
                </p>
                <Button 
                  onClick={() => setShowDocumentCenter(true)}
                  className="gap-2"
                >
                  <Upload className="h-4 w-4" />
                  Upload First Document
                </Button>
              </CardContent>
            </Card>
          ) : (
            <div className="space-y-6">
              {Object.values(groupedDocuments).map((group: any) => (
                <Card key={group.clientId || 'no-client'} data-testid={`client-group-${group.clientId || 'no-client'}`}>
                  <CardHeader>
                    <CardTitle className="flex items-center gap-2">
                      {group.clientId ? (
                        <>
                          <Users className="h-5 w-5" />
                          {group.clientName}
                        </>
                      ) : (
                        <>
                          <Folder className="h-5 w-5" />
                          General Documents
                        </>
                      )}
                      <Badge variant="secondary" className="ml-2">
                        {group.documents.length} {group.documents.length === 1 ? 'document' : 'documents'}
                      </Badge>
                    </CardTitle>
                  </CardHeader>
                  <CardContent>
                    <div className="space-y-3">
                      {group.documents.map((doc: any) => (
                        <div 
                          key={doc.id} 
                          className="flex items-center justify-between p-3 border rounded-lg hover:bg-muted/50 transition-colors"
                          data-testid={`document-${doc.id}`}
                        >
                          <div className="flex items-center gap-3">
                            <FileText className="h-6 w-6 text-muted-foreground" />
                            <div>
                              <h4 className="font-medium">{doc.title || doc.filename}</h4>
                              <p className="text-sm text-muted-foreground">
                                {doc.description || 'No description'}
                              </p>
                              {doc.tags && doc.tags.length > 0 && (
                                <div className="flex gap-1 mt-1">
                                  {doc.tags.map((tag: string, idx: number) => (
                                    <Badge key={idx} variant="outline" className="text-xs">
                                      {tag}
                                    </Badge>
                                  ))}
                                </div>
                              )}
                            </div>
                          </div>
                          <div className="flex items-center gap-2">
                            <Badge className={getDocumentTypeColor(doc.documentType)}>
                              {doc.documentType.replace(/_/g, ' ')}
                            </Badge>
                            <Button 
                              variant="outline" 
                              size="sm"
                              data-testid={`button-download-${doc.id}`}
                            >
                              <Download className="h-4 w-4" />
                            </Button>
                          </div>
                        </div>
                      ))}
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          )}

            </main>
          </SidebarInset>
        </div>
      </div>

      <DocumentCenterModal
        isOpen={showDocumentCenter}
        onClose={() => setShowDocumentCenter(false)}
        userId={user.id}
      />
    </SidebarProvider>
  );
}

