import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { Users, User, Shield, ChevronDown } from "lucide-react";
import { useLocation } from "wouter";
import { useViewMode } from "@/contexts/ViewModeContext";
import { useAuth } from "@/hooks/useAuth";

export function ViewModeSwitcher() {
  const [, setLocation] = useLocation();
  const { effectiveMode, setViewMode } = useViewMode();
  const { user } = useAuth();

  const userRole = user?.role?.toLowerCase();

  // Only agents and superadmins can switch views
  if (userRole !== 'agent' && userRole !== 'superadmin') {
    return null;
  }

  const handleSwitch = (mode: 'admin' | 'agent' | 'client') => {
    setViewMode(mode);
    setLocation('/');
  };

  // For agents: simple toggle button
  if (userRole === 'agent') {
    const handleToggle = () => {
      const newMode = effectiveMode === 'agent' ? 'client' : 'agent';
      handleSwitch(newMode);
    };

    return (
      <Button
        variant="outline"
        size="sm"
        onClick={handleToggle}
        className="gap-2"
        data-testid="button-switch-view-mode"
      >
        {effectiveMode === 'agent' ? (
          <>
            <User className="h-4 w-4" />
            Switch to Client View
          </>
        ) : (
          <>
            <Users className="h-4 w-4" />
            Switch to Agent View
          </>
        )}
      </Button>
    );
  }

  // For superadmins: dropdown menu with all options
  const viewLabels = {
    admin: 'Admin',
    agent: 'Agent',
    client: 'Client'
  };

  const viewIcons = {
    admin: Shield,
    agent: Users,
    client: User
  };

  const CurrentIcon = effectiveMode ? viewIcons[effectiveMode] : Shield;

  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button
          variant="outline"
          size="sm"
          className="gap-2"
          data-testid="button-view-mode-dropdown"
        >
          <CurrentIcon className="h-4 w-4" />
          {effectiveMode ? viewLabels[effectiveMode] : 'Admin'} View
          <ChevronDown className="h-4 w-4" />
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="end">
        <DropdownMenuItem 
          onClick={() => handleSwitch('admin')}
          data-testid="menu-item-admin-view"
        >
          <Shield className="h-4 w-4 mr-2" />
          Admin View
        </DropdownMenuItem>
        <DropdownMenuItem 
          onClick={() => handleSwitch('agent')}
          data-testid="menu-item-agent-view"
        >
          <Users className="h-4 w-4 mr-2" />
          Agent View
        </DropdownMenuItem>
        <DropdownMenuItem 
          onClick={() => handleSwitch('client')}
          data-testid="menu-item-client-view"
        >
          <User className="h-4 w-4 mr-2" />
          Client View
        </DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

