import { createContext, useContext, useState, useEffect } from "react";
import { useAuth } from "@/hooks/useAuth";

type ViewMode = "admin" | "agent" | "client" | "auto";

interface ViewModeContextType {
  viewMode: ViewMode;
  setViewMode: (mode: ViewMode) => void;
  effectiveMode: "admin" | "agent" | "client" | null;
}

const ViewModeContext = createContext<ViewModeContextType | undefined>(
  undefined,
);

export function useViewMode() {
  const context = useContext(ViewModeContext);
  if (!context) {
    throw new Error("useViewMode must be used within ViewModeProvider");
  }
  return context;
}

export function ViewModeProvider({ children }: { children: React.ReactNode }) {
  const { user, isLoading } = useAuth();
  const [viewMode, setViewMode] = useState<ViewMode>(() => {
    const saved = localStorage.getItem("estate-vista-view-mode");
    return (saved as ViewMode) || "auto";
  });

  useEffect(() => {
    localStorage.setItem("estate-vista-view-mode", viewMode);
  }, [viewMode]);

  // Don't calculate effectiveMode until user is loaded
  const userRole = user?.role?.toLowerCase();

  // Calculate effective mode:
  // - If still loading: return null to prevent premature routing
  // - If auto: use actual user role
  // - If manual override: allow based on permissions
  const effectiveMode =
    isLoading || !user
      ? null
      : viewMode === "auto"
        ? userRole === "superadmin"
          ? "admin"
          : userRole === "agent"
            ? "agent"
            : userRole === "client"
              ? "client"
              : null // Note: brokerage doesn't have an effectiveMode, routed directly
        : viewMode === "admin" && userRole === "superadmin"
          ? "admin" // Superadmin can stay in admin view
          : viewMode === "agent" &&
              (userRole === "superadmin" || userRole === "agent")
            ? "agent" // Superadmin or agent can access agent view
            : viewMode === "client" &&
                (userRole === "superadmin" || userRole === "agent")
              ? "client" // Superadmin or agent can access client view
              : userRole === "client"
                ? "client" // Clients always stay in client view
                : null;


  return (
    <ViewModeContext.Provider value={{ viewMode, setViewMode, effectiveMode }}>
      {children}
    </ViewModeContext.Provider>
  );
}

