import { Building2, LayoutDashboard, Users, UserCheck, BarChart3, Settings, LogOut, Menu } from "lucide-react";
import { Link, useLocation } from "wouter";
import { Button } from "@/components/ui/button";
import { Sheet, SheetContent, SheetTrigger } from "@/components/ui/sheet";
import { useState } from "react";

const menuItems = [
  { icon: LayoutDashboard, label: "Dashboard", path: "/brokerage" },
  { icon: Users, label: "Agents", path: "/brokerage/agents" },
  { icon: UserCheck, label: "Clients", path: "/brokerage/clients" },
  { icon: BarChart3, label: "Reports", path: "/brokerage/reports" },
  { icon: Settings, label: "Settings", path: "/brokerage/settings" },
];

function SidebarContent({ onNavigate }: { onNavigate?: () => void }) {
  const [location] = useLocation();

  const handleLogout = () => {
    localStorage.removeItem("accessToken");
    window.location.href = "/api/logout";
  };

  return (
    <div className="flex flex-col h-full">
      <div className="p-4 md:p-6 border-b border-gray-200 dark:border-gray-800">
        <div className="flex items-center gap-3">
          <Building2 className="h-7 w-7 md:h-8 md:w-8 text-blue-600" />
          <div>
            <h1 className="text-lg md:text-xl font-bold">Brokerage Portal</h1>
            <p className="text-xs text-muted-foreground">Premier Realty Group</p>
          </div>
        </div>
      </div>

      <nav className="flex-1 p-3 md:p-4 space-y-1 md:space-y-2">
        {menuItems.map((item) => {
          const Icon = item.icon;
          const isActive = location === item.path;

          return (
            <Link 
              key={item.path} 
              href={item.path}
              onClick={onNavigate}
              data-testid={`nav-${item.label.toLowerCase().replace(/\s+/g, '-')}`}
              className={`
                flex items-center gap-3 px-3 md:px-4 py-3 rounded-lg transition-colors
                ${isActive 
                  ? 'bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400' 
                  : 'text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-800'
                }
              `}
            >
              <Icon className="h-5 w-5" />
              <span className="font-medium">{item.label}</span>
            </Link>
          );
        })}
      </nav>

      <div className="p-3 md:p-4 border-t border-gray-200 dark:border-gray-800 space-y-3">
        <div className="p-3 bg-blue-50 dark:bg-blue-900/20 rounded-lg">
          <p className="text-sm font-medium text-blue-900 dark:text-blue-200">Read-Only Access</p>
          <p className="text-xs text-blue-700 dark:text-blue-400">Monitoring agent activities</p>
        </div>
        <Button 
          variant="outline" 
          className="w-full gap-2" 
          onClick={handleLogout}
          data-testid="button-logout"
        >
          <LogOut className="h-4 w-4" />
          Sign Out
        </Button>
      </div>
    </div>
  );
}

export function BrokerageMobileHeader() {
  const [open, setOpen] = useState(false);

  return (
    <div className="md:hidden fixed top-0 left-0 right-0 z-50 bg-white dark:bg-gray-900 border-b border-gray-200 dark:border-gray-800 px-4 py-3">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <Building2 className="h-6 w-6 text-blue-600" />
          <span className="font-bold">Brokerage</span>
        </div>
        <Sheet open={open} onOpenChange={setOpen}>
          <SheetTrigger asChild>
            <Button variant="ghost" size="icon" data-testid="button-mobile-menu">
              <Menu className="h-6 w-6" />
            </Button>
          </SheetTrigger>
          <SheetContent side="left" className="p-0 w-72">
            <SidebarContent onNavigate={() => setOpen(false)} />
          </SheetContent>
        </Sheet>
      </div>
    </div>
  );
}

export default function BrokerageSidebar() {
  return (
    <div className="hidden md:flex w-64 min-h-screen border-r border-gray-200 dark:border-gray-800 bg-white dark:bg-gray-900 flex-col">
      <SidebarContent />
    </div>
  );
}

