"use client"

import * as React from "react"
import * as TooltipPrimitive from "@radix-ui/react-tooltip"

import { cn } from "@/lib/utils"

const TooltipProvider = TooltipPrimitive.Provider

const Tooltip = TooltipPrimitive.Root

const TooltipTrigger = TooltipPrimitive.Trigger

const TooltipContent = React.forwardRef<
  React.ElementRef<typeof TooltipPrimitive.Content>,
  React.ComponentPropsWithoutRef<typeof TooltipPrimitive.Content>
>(({ className, sideOffset = 4, ...props }, ref) => (
  <TooltipPrimitive.Content
    ref={ref}
    sideOffset={sideOffset}
    className={cn(
      "z-50 overflow-hidden rounded-md border bg-popover px-3 py-1.5 text-sm text-popover-foreground shadow-md animate-in fade-in-0 zoom-in-95 data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=closed]:zoom-out-95 data-[side=bottom]:slide-in-from-top-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2 origin-[--radix-tooltip-content-transform-origin]",
      className
    )}
    {...props}
  />
))
TooltipContent.displayName = TooltipPrimitive.Content.displayName

export { Tooltip, TooltipTrigger, TooltipContent, TooltipProvider }

client/src/pages/ReportsPage.tsx.content:
import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { useAuth } from "@/hooks/useAuth";
import { useViewMode } from "@/contexts/ViewModeContext";
import Header from "@/components/Header";
import AgentSidebar from "@/components/AgentSidebar";
import { SidebarProvider, SidebarInset } from "@/components/ui/sidebar";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { BarChart, Download, TrendingUp, Users, Calendar, MapPin } from "lucide-react";
import { TourReportModal } from "@/components/TourReportModal";
import ClientHistoryModal from "@/components/ClientHistoryModal";
import ProductivityDashboardModal from "@/components/ProductivityDashboardModal";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs";

export default function ReportsPage() {
  const { user } = useAuth();
  const { effectiveMode } = useViewMode();
  const [showTourReport, setShowTourReport] = useState(false);
  const [showClientHistory, setShowClientHistory] = useState(false);
  const [showProductivityDashboard, setShowProductivityDashboard] = useState(false);
  const [selectedClientId, setSelectedClientId] = useState<string | null>(null);
  const [period, setPeriod] = useState<'week' | 'month' | 'year' | 'all'>('month');
  const [reportType, setReportType] = useState<'all' | 'client'>('all');
  const [filterClientId, setFilterClientId] = useState<string | null>(null);

  // Fetch clients for client history selection
  const { data: clients = [] } = useQuery<any[]>({
    queryKey: ["/api/clients"],
    enabled: !!user && effectiveMode === 'agent',
  });

  // Fetch reports summary with period and client filtering
  const clientIdParam = reportType === 'client' ? filterClientId : null;
  const queryParams = new URLSearchParams({ period });
  if (clientIdParam) {
    queryParams.append('clientId', clientIdParam);
  }

  const { data: summary, isLoading } = useQuery<{
    period: string;
    clientId: string | null;
    totalTours: number;
    completedTours: number;
    activeClients: number;
    distanceTraveled: number;
    hoursInvested: number;
    offers: {
      total: number;
      pending: number;
      accepted: number;
      rejected: number;
      withdrawn: number;
    };
    rejectionReasons: Record<string, number>;
    todayTours: number;
    pendingRequests: number;
    weeklyDistance: number;
  }>({
    queryKey: [`/api/reports/summary?${queryParams.toString()}`, period, clientIdParam],
    enabled: !!user && effectiveMode === 'agent',
  });

  const reportTypes = [
    {
      title: "Tour Report",
      description: "Post-tour performance and client feedback",
      icon: Calendar,
      action: "Generate",
      available: true
    },
    {
      title: "Client History Ledger",
      description: "Complete client interaction timeline",
      icon: Users,
      action: "Export",
      available: true
    },
    {
      title: "Productivity Dashboard",
      description: "Agent performance metrics and KPIs",
      icon: TrendingUp,
      action: "View",
      available: true
    },
    {
      title: "Scope Fit Over Time",
      description: "Property matching accuracy trends",
      icon: BarChart,
      action: "Analyze",
      available: false
    },
    {
      title: "Location Analytics",
      description: "Geographic tour patterns and efficiency",
      icon: MapPin,
      action: "Generate",
      available: false
    }
  ];

  if (!user) {
    return <div>Loading...</div>;
  }

  return (
    <SidebarProvider>
      <div className="min-h-screen bg-background">
        <Header userRole="agent" />
        <div className="flex">
          <AgentSidebar />
          <SidebarInset>
            <main className="flex-1 p-4 md:p-6">
          <div className="mb-4 md:mb-6">
            <div className="flex flex-col md:flex-row md:justify-between md:items-center mb-4">
              <div>
                <h1 className="text-2xl md:text-3xl font-bold">Reports</h1>
                <p className="text-sm md:text-base text-muted-foreground">Generate insights and export data</p>
              </div>
            </div>

            {/* Report Type and Filters */}
            <div className="flex flex-wrap items-center gap-4 p-4 bg-muted/30 rounded-lg border">
              <div className="flex items-center gap-2">
                <span className="text-sm font-medium text-muted-foreground">Report Type:</span>
                <Tabs value={reportType} onValueChange={(val: any) => {
                  setReportType(val);
                  if (val === 'all') {
                    setFilterClientId(null);
                  }
                }} data-testid="tabs-report-type">
                  <TabsList>
                    <TabsTrigger value="all" data-testid="report-type-all">All Clients</TabsTrigger>
                    <TabsTrigger value="client" data-testid="report-type-client">Client Specific</TabsTrigger>
                  </TabsList>
                </Tabs>
              </div>

              {reportType === 'client' && (
                <div className="flex items-center gap-2">
                  <span className="text-sm font-medium text-muted-foreground">Client:</span>
                  <Select
                    value={filterClientId || ""}
                    onValueChange={setFilterClientId}
                    data-testid="select-filter-client"
                  >
                    <SelectTrigger className="w-[200px]">
                      <SelectValue placeholder="Select client" />
                    </SelectTrigger>
                    <SelectContent>
                      {clients.map((client: any) => (
                        <SelectItem key={client.id} value={client.id} data-testid={`filter-client-${client.id}`}>
                          {client.firstName} {client.lastName}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              )}

              <div className="flex items-center gap-2 ml-auto">
                <span className="text-sm font-medium text-muted-foreground">Time Period:</span>
                <Select value={period} onValueChange={(val: any) => setPeriod(val)}>
                  <SelectTrigger className="w-[180px]" data-testid="select-period">
                    <SelectValue placeholder="Select period" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="week" data-testid="period-week">Last 7 Days</SelectItem>
                    <SelectItem value="month" data-testid="period-month">Last 30 Days</SelectItem>
                    <SelectItem value="year" data-testid="period-year">Last Year</SelectItem>
                    <SelectItem value="all" data-testid="period-all">All Time</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>
          </div>

          {/* Quick Stats */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
            <Card data-testid="card-tours">
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">Total Tours</CardTitle>
                <Calendar className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold" data-testid="value-total-tours">{summary?.totalTours || 0}</div>
                <p className="text-xs text-muted-foreground mt-1">
                  {summary?.completedTours || 0} completed
                </p>
              </CardContent>
            </Card>

            <Card data-testid="card-clients">
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">Active Clients</CardTitle>
                <Users className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold" data-testid="value-active-clients">{summary?.activeClients || 0}</div>
              </CardContent>
            </Card>

            <Card data-testid="card-distance">
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">Distance Traveled</CardTitle>
                <MapPin className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold" data-testid="value-distance">{summary?.distanceTraveled || 0} km</div>
              </CardContent>
            </Card>

            <Card data-testid="card-hours">
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">Hours Invested</CardTitle>
                <TrendingUp className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold" data-testid="value-hours">{summary?.hoursInvested || 0}h</div>
              </CardContent>
            </Card>
          </div>

          {/* Offer Analytics */}
          <div className="grid md:grid-cols-2 gap-6 mb-8">
            <Card data-testid="card-offers-analytics">
              <CardHeader>
                <CardTitle>Offer Analytics</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-4">
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <p className="text-sm text-muted-foreground">Total Offers</p>
                      <p className="text-2xl font-bold" data-testid="value-offers-total">{summary?.offers?.total || 0}</p>
                    </div>
                    <div>
                      <p className="text-sm text-muted-foreground">Accepted</p>
                      <p className="text-2xl font-bold text-green-600" data-testid="value-offers-accepted">{summary?.offers?.accepted || 0}</p>
                    </div>
                    <div>
                      <p className="text-sm text-muted-foreground">Pending</p>
                      <p className="text-2xl font-bold text-blue-600" data-testid="value-offers-pending">{summary?.offers?.pending || 0}</p>
                    </div>
                    <div>
                      <p className="text-sm text-muted-foreground">Rejected</p>
                      <p className="text-2xl font-bold text-red-600" data-testid="value-offers-rejected">{summary?.offers?.rejected || 0}</p>
                    </div>
                  </div>
                  {summary?.offers && summary.offers.total > 0 && (
                    <div className="pt-4 border-t">
                      <p className="text-sm font-medium mb-2">Success Rate</p>
                      <div className="flex items-center gap-2">
                        <div className="flex-1 bg-gray-200 rounded-full h-2">
                          <div 
                            className="bg-green-600 h-2 rounded-full" 
                            style={{ width: `${(summary.offers.accepted / summary.offers.total) * 100}%` }}
                          />
                        </div>
                        <span className="text-sm font-medium" data-testid="value-success-rate">
                          {Math.round((summary.offers.accepted / summary.offers.total) * 100)}%
                        </span>
                      </div>
                    </div>
                  )}
                </div>
              </CardContent>
            </Card>

            <Card data-testid="card-rejection-reasons">
              <CardHeader>
                <CardTitle>Top Rejection Reasons</CardTitle>
              </CardHeader>
              <CardContent>
                {summary?.rejectionReasons && Object.keys(summary.rejectionReasons).length > 0 ? (
                  <div className="space-y-3">
                    {Object.entries(summary.rejectionReasons)
                      .sort(([, a], [, b]) => b - a)
                      .slice(0, 5)
                      .map(([reason, count]) => (
                        <div key={reason} className="flex items-center justify-between">
                          <p className="text-sm flex-1 truncate" data-testid={`reason-${reason}`}>{reason}</p>
                          <Badge variant="secondary" data-testid={`count-${reason}`}>{count}</Badge>
                        </div>
                      ))}
                  </div>
                ) : (
                  <p className="text-sm text-muted-foreground">No rejection data available</p>
                )}
              </CardContent>
            </Card>
          </div>

          {/* Report Types */}
          <div className="grid gap-6">
            <h2 className="text-xl font-semibold">Available Reports</h2>
            <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
              {reportTypes.map((report) => {
                // Special rendering for Client History Ledger
                if (report.title === "Client History Ledger") {
                  return (
                    <Card key={report.title} className="hover:shadow-md transition-shadow">
                      <CardHeader>
                        <CardTitle className="flex items-center gap-3">
                          <report.icon className="h-5 w-5" />
                          {report.title}
                        </CardTitle>
                      </CardHeader>
                      <CardContent className="space-y-4">
                        <p className="text-muted-foreground">{report.description}</p>
                        <div className="space-y-2">
                          <label className="text-sm font-medium">Select Client</label>
                          <Select
                            value={selectedClientId || ""}
                            onValueChange={setSelectedClientId}
                            data-testid="select-client-for-history"
                          >
                            <SelectTrigger>
                              <SelectValue placeholder="Choose a client" />
                            </SelectTrigger>
                            <SelectContent>
                              {clients.map((client: any) => (
                                <SelectItem key={client.id} value={client.id}>
                                  {client.firstName} {client.lastName}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                        </div>
                        <Button 
                          disabled={!selectedClientId}
                          onClick={() => setShowClientHistory(true)}
                          className="w-full gap-2"
                          data-testid="button-client-history-ledger"
                        >
                          <Download className="h-4 w-4" />
                          {report.action} Report
                        </Button>
                      </CardContent>
                    </Card>
                  );
                }

                // Standard rendering for other reports
                return (
                  <Card key={report.title} className="hover:shadow-md transition-shadow">
                    <CardHeader>
                      <CardTitle className="flex items-center gap-3">
                        <report.icon className="h-5 w-5" />
                        {report.title}
                      </CardTitle>
                    </CardHeader>
                    <CardContent>
                      <p className="text-muted-foreground mb-4">{report.description}</p>
                      <Button 
                        disabled={!report.available}
                        onClick={() => {
                          if (report.title === "Tour Report") {
                            setShowTourReport(true);
                          } else if (report.title === "Productivity Dashboard") {
                            setShowProductivityDashboard(true);
                          }
                        }}
                        className="w-full gap-2"
                        data-testid={`button-${report.title.toLowerCase().replace(/\s+/g, '-')}`}
                      >
                        <Download className="h-4 w-4" />
                        {report.action} Report
                      </Button>
                      {!report.available && (
                        <Badge variant="secondary" className="mt-2">
                          Coming Soon
                        </Badge>
                      )}
                    </CardContent>
                  </Card>
                );
              })}
            </div>
          </div>

          {/* Modals */}
          <TourReportModal 
            isOpen={showTourReport} 
            onClose={() => setShowTourReport(false)} 
          />
          <ClientHistoryModal
            isOpen={showClientHistory}
            onClose={() => setShowClientHistory(false)}
            selectedClientId={selectedClientId}
          />
          <ProductivityDashboardModal
            isOpen={showProductivityDashboard}
            onClose={() => setShowProductivityDashboard(false)}
          />
            </main>
          </SidebarInset>
        </div>
      </div>
    </SidebarProvider>
  );
}

client/src/components/TopAppBar.tsx.content:
import { useState } from "react";
import { useAuth } from "@/hooks/useAuth";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import HamburgerMenu from "@/components/HamburgerMenu";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
  Command,
  CommandEmpty,
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
} from "@/components/ui/command";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import {
  LogOut,
  Search,
  Plus,
  CheckCircle,
  FileText,
  UserPlus,
  Settings,
  Palette,
  Bell,
  ChevronDown
} from "lucide-react";

interface TopAppBarProps {
  userRole: "agent" | "client";
  onCreateTour?: () => void;
  onApproveRequests?: () => void;
  onRequestDocs?: () => void;
  onStartIntake?: () => void;
  onShowBranding?: () => void;
  onShowIntegrations?: () => void;
  onShowNotifications?: () => void;
  pendingRequests?: number;
  upcomingTours?: number;
}

export default function TopAppBar({ 
  userRole, 
  onCreateTour, 
  onApproveRequests, 
  onRequestDocs, 
  onStartIntake,
  onShowBranding,
  onShowIntegrations,
  onShowNotifications,
  pendingRequests = 0,
  upcomingTours = 0,
}: TopAppBarProps) {
  const { user } = useAuth();
  const [searchOpen, setSearchOpen] = useState(false);
  const [searchValue, setSearchValue] = useState("");

  const handleLogout = () => {
    localStorage.removeItem("authToken");
    window.location.href = "/api/logout";
  };

  const getInitials = () => {
    if (user?.firstName && user?.lastName) {
      return user.firstName[0] + user.lastName[0];
    }
    return user?.email?.[0]?.toUpperCase() || "U";
  };

  const getDisplayName = () => {
    if (user?.firstName && user?.lastName) {
      return `${user.firstName} ${user.lastName}`;
    }
    return user?.email || "User";
  };

  const searchResults = [
    { type: "client", name: "John Doe", email: "john@example.com", id: "1" },
    { type: "property", address: "123 Main St", price: "$450,000", id: "2" },
    { type: "mls", number: "C5123456", address: "456 Oak Ave", id: "3" },
  ];

  const filteredResults = searchResults.filter(item =>
    item.name?.toLowerCase().includes(searchValue.toLowerCase()) ||
    item.address?.toLowerCase().includes(searchValue.toLowerCase()) ||
    item.number?.toLowerCase().includes(searchValue.toLowerCase())
  );

  return (
    <header className="bg-card shadow-sm border-b border-border sticky top-0 z-50" data-testid="top-app-bar">
      <div className="max-w-7xl mx-auto px-3 sm:px-4 lg:px-8">
        <div className="flex justify-between items-center py-3 gap-2">
          {/* Left Section - Hamburger + Logo */}
          <div className="flex items-center gap-2 sm:gap-4">
            {/* Hamburger Menu for Mobile */}
            <HamburgerMenu
              userRole={userRole}
              pendingRequests={pendingRequests}
              upcomingTours={upcomingTours}
            />

            <div className="flex items-center gap-2 sm:gap-3">
              <h1 className="text-lg sm:text-xl font-bold text-primary" data-testid="app-title">
                Estate Vista
              </h1>
              <Badge 
                variant="default"
                className="bg-primary/10 text-primary hidden sm:inline-flex"
                data-testid="badge-role"
              >
                {userRole === "agent" ? "Agent" : "Client"}
              </Badge>
            </div>

            {/* Global Search - Hidden on mobile */}
            {userRole === "agent" && (
              <div className="hidden lg:block">
                <Popover open={searchOpen} onOpenChange={setSearchOpen}>
                  <PopoverTrigger asChild>
                    <Button
                      variant="outline"
                      role="combobox"
                      aria-expanded={searchOpen}
                      className="w-64 xl:w-80 justify-start text-muted-foreground"
                      data-testid="global-search-trigger"
                    >
                      <Search className="mr-2 h-4 w-4" />
                      <span className="truncate">Search clients, properties...</span>
                    </Button>
                  </PopoverTrigger>
                  <PopoverContent className="w-80 p-0" align="start">
                    <Command>
                      <CommandInput 
                        placeholder="Search clients, properties, MLS#..." 
                        value={searchValue}
                        onValueChange={setSearchValue}
                        data-testid="global-search-input"
                      />
                      <CommandList>
                        <CommandEmpty>No results found.</CommandEmpty>
                        {filteredResults.length > 0 && (
                          <>
                            <CommandGroup heading="Clients">
                              {filteredResults
                                .filter(item => item.type === "client")
                                .map((client) => (
                                  <CommandItem key={client.id} data-testid={`search-result-client-${client.id}`}>
                                    <div>
                                      <div className="font-medium">{client.name}</div>
                                      <div className="text-sm text-muted-foreground">{client.email}</div>
                                    </div>
                                  </CommandItem>
                                ))}
                            </CommandGroup>
                            <CommandGroup heading="Properties">
                              {filteredResults
                                .filter(item => item.type === "property")
                                .map((property) => (
                                  <CommandItem key={property.id} data-testid={`search-result-property-${property.id}`}>
                                    <div>
                                      <div className="font-medium">{property.address}</div>
                                      <div className="text-sm text-muted-foreground">{property.price}</div>
                                    </div>
                                  </CommandItem>
                                ))}
                            </CommandGroup>
                            <CommandGroup heading="MLS Listings">
                              {filteredResults
                                .filter(item => item.type === "mls")
                                .map((listing) => (
                                  <CommandItem key={listing.id} data-testid={`search-result-mls-${listing.id}`}>
                                    <div>
                                      <div className="font-medium">MLS# {listing.number}</div>
                                      <div className="text-sm text-muted-foreground">{listing.address}</div>
                                    </div>
                                  </CommandItem>
                                ))}
                            </CommandGroup>
                          </>
                        )}
                      </CommandList>
                    </Command>
                  </PopoverContent>
                </Popover>
              </div>
            )}
          </div>

          {/* Center Section - Quick Actions (Desktop only for agents) */}
          {userRole === "agent" && (
            <div className="hidden xl:flex items-center gap-2">
              <Button 
                variant="outline" 
                size="sm"
                onClick={onCreateTour}
                className="flex items-center gap-2"
                data-testid="quick-action-create-tour"
              >
                <Plus className="h-4 w-4" />
                <span className="hidden 2xl:inline">Create Tour</span>
              </Button>
              <Button 
                variant="outline" 
                size="sm"
                onClick={onApproveRequests}
                className="flex items-center gap-2"
                data-testid="quick-action-approve-requests"
              >
                <CheckCircle className="h-4 w-4" />
                <span className="hidden 2xl:inline">Approve</span>
              </Button>
              <Button 
                variant="outline" 
                size="sm"
                onClick={onRequestDocs}
                className="flex items-center gap-2"
                data-testid="quick-action-request-docs"
              >
                <FileText className="h-4 w-4" />
                <span className="hidden 2xl:inline">Docs</span>
              </Button>
              <Button 
                variant="outline" 
                size="sm"
                onClick={onStartIntake}
                className="flex items-center gap-2"
                data-testid="quick-action-start-intake"
              >
                <UserPlus className="h-4 w-4" />
                <span className="hidden 2xl:inline">Intake</span>
              </Button>
            </div>
          )}

          {/* Right Section - Profile */}
          <div className="flex items-center gap-2 sm:gap-4">
            {/* Search icon for tablet */}
            {userRole === "agent" && (
              <Button
                variant="ghost"
                size="icon"
                className="hidden sm:flex lg:hidden"
                onClick={() => setSearchOpen(true)}
                data-testid="mobile-search-trigger"
              >
                <Search className="h-5 w-5" />
              </Button>
            )}

            {/* User info - Hidden on small screens */}
            <div className="hidden md:flex items-center gap-2">
              <Avatar className="h-8 w-8">
                <AvatarFallback className="bg-muted text-muted-foreground text-sm">
                  {getInitials()}
                </AvatarFallback>
              </Avatar>
              <span className="text-sm font-medium hidden lg:block" data-testid="user-name">
                {getDisplayName()}
              </span>
            </div>

            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button 
                  variant="ghost" 
                  size="sm"
                  className="p-2 hover:bg-muted rounded-full"
                  data-testid="profile-menu-trigger"
                >
                  <ChevronDown className="h-4 w-4" />
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent align="end" className="w-56">
                {/* Show user info on mobile */}
                <div className="md:hidden px-2 py-2 border-b mb-2">
                  <div className="flex items-center gap-2">
                    <Avatar className="h-8 w-8">
                      <AvatarFallback className="bg-muted text-muted-foreground text-sm">
                        {getInitials()}
                      </AvatarFallback>
                    </Avatar>
                    <div>
                      <p className="text-sm font-medium">{getDisplayName()}</p>
                      <p className="text-xs text-muted-foreground">{user?.email}</p>
                    </div>
                  </div>
                </div>

                <DropdownMenuLabel>
                  {userRole === "agent" ? "Agent Tools" : "Settings"}
                </DropdownMenuLabel>
                <DropdownMenuSeparator />

                {userRole === "agent" && (
                  <>
                    <DropdownMenuItem 
                      onClick={onShowBranding}
                      data-testid="menu-branding"
                    >
                      <Palette className="mr-2 h-4 w-4" />
                      Branding
                    </DropdownMenuItem>
                    <DropdownMenuItem 
                      onClick={onShowIntegrations}
                      data-testid="menu-integrations"
                    >
                      <Settings className="mr-2 h-4 w-4" />
                      Integrations
                    </DropdownMenuItem>
                    <DropdownMenuItem 
                      onClick={onShowNotifications}
                      data-testid="menu-notifications"
                    >
                      <Bell className="mr-2 h-4 w-4" />
                      Notifications
                    </DropdownMenuItem>
                    <DropdownMenuSeparator />
                  </>
                )}

                <DropdownMenuItem 
                  onClick={handleLogout}
                  className="text-destructive focus:text-destructive"
                  data-testid="menu-logout"
                >
                  <LogOut className="mr-2 h-4 w-4" />
                  Logout
                </DropdownMenuItem>
              </DropdownMenuContent>
            </DropdownMenu>
          </div>
        </div>
      </div>
    </header>
  );
}

