import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";
import { Download, FileText, Calendar, MapPin, Clock, Star, TrendingUp } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { format } from "date-fns";
import type { Tour, Property, User } from "@shared/schema";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";

interface TourReportModalProps {
  isOpen: boolean;
  onClose: () => void;
}

interface TourWithDetails extends Tour {
  client?: User;
  properties?: Property[];
  totalRatings?: number;
  averageRating?: number;
}

export function TourReportModal({ isOpen, onClose }: TourReportModalProps) {
  const { toast } = useToast();
  const [startDate, setStartDate] = useState("");
  const [endDate, setEndDate] = useState("");
  const [clientFilter, setClientFilter] = useState("");
  const [statusFilter, setStatusFilter] = useState<"all" | "completed" | "scheduled" | "cancelled">("all");

  // Fetch tour data
  const { data: tours = [], isLoading } = useQuery<TourWithDetails[]>({
    queryKey: ["/api/tours/report", startDate, endDate, clientFilter, statusFilter],
    queryFn: async () => {
      const params = new URLSearchParams();
      if (startDate) params.append("startDate", startDate);
      if (endDate) params.append("endDate", endDate);
      if (clientFilter) params.append("clientFilter", clientFilter);
      if (statusFilter) params.append("statusFilter", statusFilter);

      const url = `/api/tours/report${params.toString() ? `?${params.toString()}` : ""}`;
      const response = await fetch(url, { credentials: "include" });
      if (!response.ok) throw new Error("Failed to fetch tours");
      return response.json();
    },
    enabled: isOpen,
  });

  const handleExportPDF = () => {
    if (!tours || tours.length === 0) {
      toast({
        title: "No Data",
        description: "There are no tours to export.",
        variant: "destructive",
      });
      return;
    }

    const doc = new jsPDF();

    // Add title
    doc.setFontSize(20);
    doc.text("Tour Report", 14, 20);

    // Add generation date
    doc.setFontSize(10);
    doc.text(`Generated: ${format(new Date(), "MMM dd, yyyy HH:mm")}`, 14, 28);

    // Add filter information if any
    let yPos = 35;
    if (startDate || endDate) {
      doc.text(`Date Range: ${startDate || "Any"} to ${endDate || "Any"}`, 14, yPos);
      yPos += 5;
    }
    if (clientFilter) {
      doc.text(`Client Filter: ${clientFilter}`, 14, yPos);
      yPos += 5;
    }
    if (statusFilter !== "all") {
      doc.text(`Status Filter: ${statusFilter}`, 14, yPos);
      yPos += 5;
    }

    // Add summary statistics
    yPos += 5;
    doc.setFontSize(12);
    doc.text("Summary Statistics", 14, yPos);
    yPos += 7;
    doc.setFontSize(10);
    doc.text(`Total Tours: ${totalTours}`, 14, yPos);
    doc.text(`Completed: ${completedTours}`, 80, yPos);
    doc.text(`Properties: ${totalProperties}`, 140, yPos);
    yPos += 5;
    doc.text(`Total Distance: ${(totalDistance / 1000).toFixed(2)} km`, 14, yPos);
    doc.text(`Avg Rating: ${Number(averageRating).toFixed(1)}`, 80, yPos);
    yPos += 10;

    // Add tours table
    const tableData = tours.map(tour => [
      tour.scheduledDate ? format(new Date(tour.scheduledDate), "MMM dd, yyyy") : "N/A",
      tour.client ? `${tour.client.firstName || ""} ${tour.client.lastName || ""}`.trim() || "N/A" : "N/A",
      String(tour.properties?.length || 0),
      tour.estimatedDuration ? `${tour.estimatedDuration}min` : "N/A",
      tour.totalDistance ? `${(Number(tour.totalDistance) / 1000).toFixed(1)}km` : "N/A",
      tour.status || "N/A",
      tour.averageRating ? tour.averageRating.toFixed(1) : "N/A",
    ]);

    autoTable(doc, {
      startY: yPos,
      head: [["Date", "Client", "Props", "Duration", "Distance", "Status", "Rating"]],
      body: tableData,
      theme: "grid",
      styles: { fontSize: 8, cellPadding: 2 },
      headStyles: { fillColor: [59, 130, 246], textColor: [255, 255, 255] },
      columnStyles: {
        0: { cellWidth: 28 },
        1: { cellWidth: 35 },
        2: { cellWidth: 15 },
        3: { cellWidth: 22 },
        4: { cellWidth: 22 },
        5: { cellWidth: 25 },
        6: { cellWidth: 18 },
      },
    });

    // Save the PDF
    doc.save(`tour-report-${format(new Date(), "yyyy-MM-dd")}.pdf`);

    toast({
      title: "Export Complete",
      description: "Tour report has been exported to PDF.",
    });
  };

  const handleExportCSV = () => {
    if (!tours || tours.length === 0) {
      toast({
        title: "No Data",
        description: "There are no tours to export.",
        variant: "destructive",
      });
      return;
    }

    // Generate CSV content
    const headers = ["Date", "Client", "Properties", "Duration", "Distance", "Status", "Avg Rating"];
    const rows = tours.map(tour => [
      tour.scheduledDate ? format(new Date(tour.scheduledDate), "yyyy-MM-dd") : "N/A",
      tour.client ? `${tour.client.firstName || ""} ${tour.client.lastName || ""}`.trim() || "N/A" : "N/A",
      tour.properties?.length || 0,
      tour.estimatedDuration || "N/A",
      tour.totalDistance ? `${(Number(tour.totalDistance) / 1000).toFixed(2)} km` : "N/A",
      tour.status || "N/A",
      tour.averageRating ? tour.averageRating.toFixed(1) : "N/A",
    ]);

    const csvContent = [
      headers.join(","),
      ...rows.map(row => row.join(","))
    ].join("\n");

    // Download CSV
    const blob = new Blob([csvContent], { type: "text/csv" });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `tour-report-${format(new Date(), "yyyy-MM-dd")}.csv`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    window.URL.revokeObjectURL(url);

    toast({
      title: "Export Complete",
      description: "Tour report has been exported to CSV.",
    });
  };

  // Calculate summary statistics
  const totalTours = tours.length;
  const completedTours = tours.filter(t => t.status === "completed").length;
  const totalProperties = tours.reduce((sum, t) => sum + (t.properties?.length || 0), 0);
  const totalDistance = tours.reduce((sum, t) => sum + (Number(t.totalDistance) || 0), 0);
  const averageRating = tours.filter(t => t.averageRating).length > 0
    ? tours.reduce((sum, t) => sum + (t.averageRating || 0), 0) / tours.filter(t => t.averageRating).length
    : 0;

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-5xl max-h-[90vh] overflow-y-auto" data-testid="dialog-tour-report">
        <DialogHeader>
          <DialogTitle>Tour Report</DialogTitle>
        </DialogHeader>

        <div className="space-y-6">
          {/* Filters */}
          <Card>
            <CardHeader>
              <CardTitle className="text-lg">Filters</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                <div>
                  <Label htmlFor="start-date">Start Date</Label>
                  <Input
                    id="start-date"
                    type="date"
                    value={startDate}
                    onChange={(e) => setStartDate(e.target.value)}
                    data-testid="input-start-date"
                  />
                </div>
                <div>
                  <Label htmlFor="end-date">End Date</Label>
                  <Input
                    id="end-date"
                    type="date"
                    value={endDate}
                    onChange={(e) => setEndDate(e.target.value)}
                    data-testid="input-end-date"
                  />
                </div>
                <div>
                  <Label htmlFor="client-filter">Client</Label>
                  <Input
                    id="client-filter"
                    placeholder="Search client..."
                    value={clientFilter}
                    onChange={(e) => setClientFilter(e.target.value)}
                    data-testid="input-client-filter"
                  />
                </div>
                <div>
                  <Label htmlFor="status-filter">Status</Label>
                  <Select value={statusFilter} onValueChange={(value: any) => setStatusFilter(value)}>
                    <SelectTrigger data-testid="select-status-filter">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="all">All Status</SelectItem>
                      <SelectItem value="completed">Completed</SelectItem>
                      <SelectItem value="scheduled">Scheduled</SelectItem>
                      <SelectItem value="cancelled">Cancelled</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Summary Statistics */}
          <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">Total Tours</CardTitle>
                <Calendar className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold" data-testid="stat-total-tours">{totalTours}</div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">Completed</CardTitle>
                <TrendingUp className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold" data-testid="stat-completed-tours">{completedTours}</div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">Properties</CardTitle>
                <FileText className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold" data-testid="stat-total-properties">{totalProperties}</div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">Distance</CardTitle>
                <MapPin className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold" data-testid="stat-total-distance">
                  {(totalDistance / 1000).toFixed(1)} km
                </div>
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-sm font-medium">Avg Rating</CardTitle>
                <Star className="h-4 w-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold" data-testid="stat-average-rating">
                  {averageRating > 0 ? averageRating.toFixed(1) : "N/A"}
                </div>
              </CardContent>
            </Card>
          </div>

          {/* Tour List */}
          <Card>
            <CardHeader>
              <CardTitle className="text-lg">Tours</CardTitle>
            </CardHeader>
            <CardContent>
              {isLoading ? (
                <div className="text-center py-8 text-muted-foreground">Loading tours...</div>
              ) : tours.length === 0 ? (
                <div className="text-center py-8 text-muted-foreground">
                  No tours found for the selected filters.
                </div>
              ) : (
                <div className="space-y-4">
                  {tours.map((tour) => (
                    <Card key={tour.id} className="border-l-4 border-l-primary">
                      <CardContent className="pt-6">
                        <div className="flex justify-between items-start mb-2">
                          <div>
                            <div className="flex items-center gap-2">
                              <h3 className="font-semibold">
                                {tour.client ? `${tour.client.firstName || ""} ${tour.client.lastName || ""}`.trim() || "Unknown Client" : "Unknown Client"}
                              </h3>
                              <Badge variant={tour.status === "completed" ? "default" : "secondary"}>
                                {tour.status || "scheduled"}
                              </Badge>
                            </div>
                            <div className="flex items-center gap-4 text-sm text-muted-foreground mt-1">
                              <span className="flex items-center gap-1">
                                <Calendar className="h-3 w-3" />
                                {tour.scheduledDate ? format(new Date(tour.scheduledDate), "MMM dd, yyyy") : "N/A"}
                              </span>
                              {tour.estimatedDuration && (
                                <span className="flex items-center gap-1">
                                  <Clock className="h-3 w-3" />
                                  {tour.estimatedDuration}
                                </span>
                              )}
                              {tour.totalDistance && (
                                <span className="flex items-center gap-1">
                                  <MapPin className="h-3 w-3" />
                                  {(Number(tour.totalDistance) / 1000).toFixed(2)} km
                                </span>
                              )}
                              {tour.averageRating && (
                                <span className="flex items-center gap-1">
                                  <Star className="h-3 w-3 fill-yellow-400 text-yellow-400" />
                                  {tour.averageRating.toFixed(1)}
                                </span>
                              )}
                            </div>
                          </div>
                        </div>
                        <Separator className="my-2" />
                        <div className="text-sm">
                          <span className="font-medium">{tour.properties?.length || 0} properties</span>
                          {tour.totalRatings && tour.totalRatings > 0 && (
                            <span className="text-muted-foreground ml-2">
                              • {tour.totalRatings} rating{tour.totalRatings !== 1 ? "s" : ""}
                            </span>
                          )}
                        </div>
                      </CardContent>
                    </Card>
                  ))}
                </div>
              )}
            </CardContent>
          </Card>

          {/* Export Actions */}
          <div className="flex gap-2">
            <Button onClick={handleExportPDF} className="flex-1" data-testid="button-export-pdf">
              <Download className="mr-2 h-4 w-4" />
              Export PDF
            </Button>
            <Button onClick={handleExportCSV} variant="outline" className="flex-1" data-testid="button-export-csv">
              <Download className="mr-2 h-4 w-4" />
              Export CSV
            </Button>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

