import { useState } from "react";
import { useLocation, Link } from "wouter";
import { useAuth } from "@/hooks/useAuth";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import { Separator } from "@/components/ui/separator";
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetTrigger,
} from "@/components/ui/sheet";
import {
  Menu,
  LayoutDashboard,
  Users,
  Calendar,
  FileText,
  BarChart3,
  Camera,
  Settings,
  Palette,
  LogOut,
  Home,
  Heart,
  MessageCircle,
  BookUser,
  X,
} from "lucide-react";

interface HamburgerMenuProps {
  userRole: "agent" | "client";
  pendingRequests?: number;
  upcomingTours?: number;
  shortlistCount?: number;
  onNavigate?: (path: string) => void;
}

export default function HamburgerMenu({
  userRole,
  pendingRequests = 0,
  upcomingTours = 0,
  shortlistCount = 0,
  onNavigate,
}: HamburgerMenuProps) {
  const [isOpen, setIsOpen] = useState(false);
  const { user } = useAuth();
  const [location, setLocation] = useLocation();

  const handleLogout = () => {
    localStorage.removeItem("authToken");
    window.location.href = "/api/logout";
  };

  const getInitials = () => {
    if (user?.firstName && user?.lastName) {
      return user.firstName[0] + user.lastName[0];
    }
    return user?.email?.[0]?.toUpperCase() || "U";
  };

  const getDisplayName = () => {
    if (user?.firstName && user?.lastName) {
      return `${user.firstName} ${user.lastName}`;
    }
    return user?.email || "User";
  };

  const handleNavigation = (path: string) => {
    setLocation(path);
    setIsOpen(false);
    onNavigate?.(path);
  };

  const agentMenuItems = [
    { icon: LayoutDashboard, label: "Dashboard", path: "/", badge: null },
    { icon: Users, label: "Clients", path: "/clients", badge: null },
    { icon: BookUser, label: "Directory", path: "/directory", badge: null },
    { icon: Calendar, label: "Tours", path: "/tours", badge: upcomingTours > 0 ? upcomingTours : null },
    { icon: FileText, label: "Documents", path: "/documents", badge: pendingRequests > 0 ? pendingRequests : null },
    { icon: BarChart3, label: "Reports", path: "/reports", badge: null },
    { icon: Camera, label: "Media", path: "/media", badge: null },
  ];

  const clientMenuItems = [
    { icon: Home, label: "Home", path: "/", badge: null },
    { icon: Calendar, label: "My Tours", path: "/tours", badge: upcomingTours > 0 ? upcomingTours : null },
    { icon: Heart, label: "Shortlist", path: "/shortlist", badge: shortlistCount > 0 ? shortlistCount : null },
    { icon: FileText, label: "Documents", path: "/documents", badge: null },
    { icon: MessageCircle, label: "Messages", path: "/messages", badge: null },
  ];

  const menuItems = userRole === "agent" ? agentMenuItems : clientMenuItems;

  return (
    <Sheet open={isOpen} onOpenChange={setIsOpen}>
      <SheetTrigger asChild>
        <Button
          variant="ghost"
          size="icon"
          className="md:hidden"
          data-testid="hamburger-menu-trigger"
        >
          <Menu className="h-6 w-6" />
          <span className="sr-only">Open menu</span>
        </Button>
      </SheetTrigger>
      <SheetContent side="left" className="w-[280px] p-0">
        <SheetHeader className="p-4 border-b">
          <SheetTitle className="flex items-center gap-3">
            <span className="text-xl font-bold text-primary">Estate Vista</span>
            <Badge variant="secondary" className="text-xs">
              {userRole === "agent" ? "Agent" : "Client"}
            </Badge>
          </SheetTitle>
        </SheetHeader>

        <div className="flex flex-col h-[calc(100%-80px)]">
          <div className="p-4 border-b bg-muted/30">
            <div className="flex items-center gap-3">
              <Avatar className="h-10 w-10">
                <AvatarFallback className="bg-primary text-primary-foreground">
                  {getInitials()}
                </AvatarFallback>
              </Avatar>
              <div className="flex-1 min-w-0">
                <p className="text-sm font-medium truncate" data-testid="menu-user-name">
                  {getDisplayName()}
                </p>
                <p className="text-xs text-muted-foreground truncate">
                  {user?.email}
                </p>
              </div>
            </div>
          </div>

          <nav className="flex-1 overflow-y-auto p-2">
            <div className="space-y-1">
              {menuItems.map((item) => {
                const Icon = item.icon;
                const isActive = location === item.path || (item.path === "/" && location === "");

                return (
                  <Button
                    key={item.path}
                    variant={isActive ? "secondary" : "ghost"}
                    className="w-full justify-start gap-3 h-12"
                    onClick={() => handleNavigation(item.path)}
                    data-testid={`menu-item-${item.label.toLowerCase().replace(/\s/g, '-')}`}
                  >
                    <Icon className="h-5 w-5" />
                    <span className="flex-1 text-left">{item.label}</span>
                    {item.badge && (
                      <Badge variant="destructive" className="h-5 min-w-[20px] px-1.5">
                        {item.badge > 9 ? "9+" : item.badge}
                      </Badge>
                    )}
                  </Button>
                );
              })}
            </div>

            <Separator className="my-4" />

            {userRole === "agent" && (
              <div className="space-y-1">
                <p className="px-3 text-xs font-medium text-muted-foreground uppercase tracking-wider mb-2">
                  Settings
                </p>
                <Button
                  variant="ghost"
                  className="w-full justify-start gap-3 h-12"
                  onClick={() => handleNavigation("/settings/branding")}
                  data-testid="menu-item-branding"
                >
                  <Palette className="h-5 w-5" />
                  <span>Branding</span>
                </Button>
                <Button
                  variant="ghost"
                  className="w-full justify-start gap-3 h-12"
                  onClick={() => handleNavigation("/settings")}
                  data-testid="menu-item-settings"
                >
                  <Settings className="h-5 w-5" />
                  <span>Settings</span>
                </Button>
              </div>
            )}
          </nav>

          <div className="p-4 border-t mt-auto">
            <Button
              variant="outline"
              className="w-full justify-start gap-3 text-destructive hover:text-destructive hover:bg-destructive/10"
              onClick={handleLogout}
              data-testid="menu-logout"
            >
              <LogOut className="h-5 w-5" />
              <span>Log out</span>
            </Button>
          </div>
        </div>
      </SheetContent>
    </Sheet>
  );
}

client/src/hooks/use-mobile.tsx.content:
import * as React from "react"

const MOBILE_BREAKPOINT = 768

function getInitialIsMobile(): boolean {
  if (typeof window !== "undefined") {
    return window.innerWidth < MOBILE_BREAKPOINT
  }
  return false
}

export function useIsMobile() {
  const [isMobile, setIsMobile] = React.useState<boolean>(getInitialIsMobile)

  React.useEffect(() => {
    const mql = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT - 1}px)`)
    const onChange = () => {
      setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    }
    mql.addEventListener("change", onChange)
    setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    return () => mql.removeEventListener("change", onChange)
  }, [])

  return isMobile
}

