import { useQuery, useMutation } from "@tanstack/react-query";
import AdminSidebar from "@/components/AdminSidebar";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useState } from "react";
import { Plus, Building2, Users, MapPin } from "lucide-react";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";

export default function AdminBrokeragesPage() {
  const { toast } = useToast();
  const [dialogOpen, setDialogOpen] = useState(false);
  const [formData, setFormData] = useState({
    name: "",
    contactEmail: "",
    contactPhone: "",
    website: ""
  });

  const { data: brokerages, isLoading, isError, error } = useQuery({
    queryKey: ['/api/admin/brokerages'],
  });

  const createMutation = useMutation({
    mutationFn: async (data: any) => {
      return await apiRequest('/api/admin/brokerages', 'POST', data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/admin/brokerages'] });
      queryClient.invalidateQueries({ queryKey: ['/api/admin/kpis'] });
      setDialogOpen(false);
      setFormData({ name: "", contactEmail: "", contactPhone: "", website: "" });
      toast({ title: "Success", description: "Brokerage created successfully" });
    },
    onError: () => {
      toast({ title: "Error", description: "Failed to create brokerage", variant: "destructive" });
    }
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    createMutation.mutate(formData);
  };

  if (isLoading) {
    return (
      <div className="flex">
        <AdminSidebar />
        <div className="flex-1 p-8">
          <div className="animate-pulse space-y-4">
            <div className="h-8 bg-muted rounded w-1/3"></div>
            <div className="h-64 bg-muted rounded"></div>
          </div>
        </div>
      </div>
    );
  }

  if (isError) {
    return (
      <div className="flex">
        <AdminSidebar />
        <div className="flex-1 p-8">
          <Card className="border-red-200 bg-red-50" data-testid="error-brokerages">
            <CardContent className="p-6">
              <h3 className="text-lg font-semibold text-red-900 mb-2">Failed to load brokerages</h3>
              <p className="text-red-700">{error?.message || "An error occurred while loading brokerages. Please try again."}</p>
            </CardContent>
          </Card>
        </div>
      </div>
    );
  }

  return (
    <div className="flex">
      <AdminSidebar />
      <div className="flex-1 p-8 space-y-6" data-testid="admin-brokerages-page">
        <div className="flex justify-between items-center">
          <div>
            <h1 className="text-3xl font-bold" data-testid="heading-brokerages">Brokerages</h1>
            <p className="text-muted-foreground">Manage all brokerages in the organization</p>
          </div>
          <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
            <DialogTrigger asChild>
              <Button data-testid="button-create-brokerage">
                <Plus className="h-4 w-4 mr-2" />
                Create Brokerage
              </Button>
            </DialogTrigger>
            <DialogContent data-testid="dialog-create-brokerage">
              <DialogHeader>
                <DialogTitle>Create New Brokerage</DialogTitle>
              </DialogHeader>
              <form onSubmit={handleSubmit} className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="name">Brokerage Name *</Label>
                  <Input
                    id="name"
                    data-testid="input-brokerage-name"
                    value={formData.name}
                    onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                    required
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="contactEmail">Contact Email</Label>
                  <Input
                    id="contactEmail"
                    type="email"
                    data-testid="input-contact-email"
                    value={formData.contactEmail}
                    onChange={(e) => setFormData({ ...formData, contactEmail: e.target.value })}
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="contactPhone">Contact Phone</Label>
                  <Input
                    id="contactPhone"
                    data-testid="input-contact-phone"
                    value={formData.contactPhone}
                    onChange={(e) => setFormData({ ...formData, contactPhone: e.target.value })}
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="website">Website</Label>
                  <Input
                    id="website"
                    data-testid="input-website"
                    value={formData.website}
                    onChange={(e) => setFormData({ ...formData, website: e.target.value })}
                  />
                </div>
                <Button type="submit" className="w-full" disabled={createMutation.isPending} data-testid="button-submit-brokerage">
                  {createMutation.isPending ? "Creating..." : "Create Brokerage"}
                </Button>
              </form>
            </DialogContent>
          </Dialog>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {brokerages && brokerages.length > 0 ? (
            brokerages.map((brokerage: any) => (
              <Card key={brokerage.id} data-testid={`card-brokerage-${brokerage.id}`}>
                <CardHeader>
                  <CardTitle className="flex items-center gap-2">
                    <Building2 className="h-5 w-5" />
                    {brokerage.name}
                  </CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                  <div className="space-y-2">
                    <div className="flex justify-between text-sm">
                      <span className="text-muted-foreground">Agents:</span>
                      <span className="font-medium flex items-center gap-1">
                        <Users className="h-4 w-4" />
                        {brokerage.agentCount || 0}
                      </span>
                    </div>
                    <div className="flex justify-between text-sm">
                      <span className="text-muted-foreground">Clients:</span>
                      <span className="font-medium">{brokerage.clientCount || 0}</span>
                    </div>
                    <div className="flex justify-between text-sm">
                      <span className="text-muted-foreground">Tours:</span>
                      <span className="font-medium flex items-center gap-1">
                        <MapPin className="h-4 w-4" />
                        {brokerage.tourCount || 0}
                      </span>
                    </div>
                  </div>
                  <div className="pt-2 border-t">
                    <span className={`px-2 py-1 rounded-full text-xs ${
                      brokerage.status === 'active' 
                        ? 'bg-green-100 text-green-800' 
                        : 'bg-red-100 text-red-800'
                    }`}>
                      {brokerage.status}
                    </span>
                  </div>
                  {brokerage.contactEmail && (
                    <div className="text-sm text-muted-foreground">
                      {brokerage.contactEmail}
                    </div>
                  )}
                </CardContent>
              </Card>
            ))
          ) : (
            <div className="col-span-full text-center py-12 text-muted-foreground">
              No brokerages found. Create one to get started.
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

client/src/pages/BrandingSettingsPage.ts.content:
import { useState, useEffect } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { useAuth } from "@/hooks/useAuth";
import { useViewMode } from "@/contexts/ViewModeContext";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { useToast } from "@/hooks/use-toast";
import Header from "@/components/Header";
import AgentSidebar from "@/components/AgentSidebar";
import { SidebarProvider, SidebarInset } from "@/components/ui/sidebar";
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Form, FormControl, FormDescription, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Loader2, Upload, Mail, Building2, User } from "lucide-react";
import { apiRequest, queryClient } from "@/lib/queryClient";

const brandingSchema = z.object({
  logoUrl: z.string().min(1, "Agent logo is required"),
  agentName: z.string().min(1, "Agent name is required").max(120, "Agent name must be less than 120 characters"),
  agentEmail: z.string().email("Invalid email address").max(120, "Email must be less than 120 characters"),
  brokerageName: z.string().min(1, "Brokerage name is required").max(120, "Brokerage name must be less than 120 characters"),
});

type BrandingFormData = z.infer<typeof brandingSchema>;

export default function BrandingSettingsPage() {
  const { user } = useAuth();
  const { effectiveMode } = useViewMode();
  const { toast } = useToast();
  const [isUploading, setIsUploading] = useState(false);
  const [previewLogoUrl, setPreviewLogoUrl] = useState("");

  const { data: settings, isLoading } = useQuery<BrandingFormData | null>({
    queryKey: ["/api/settings/branding"],
    enabled: !!user && effectiveMode === 'agent',
  });

  const form = useForm<BrandingFormData>({
    resolver: zodResolver(brandingSchema),
    defaultValues: {
      logoUrl: "",
      agentName: "",
      agentEmail: "",
      brokerageName: "",
    },
  });

  useEffect(() => {
    if (settings) {
      form.reset(settings);
      setPreviewLogoUrl(settings.logoUrl);
    }
  }, [settings, form]);

  const saveMutation = useMutation({
    mutationFn: async (data: BrandingFormData) => {
      return await apiRequest("/api/settings/branding", "PUT", data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/settings/branding"] });
      toast({
        title: "Success",
        description: "Branding settings saved successfully",
      });
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to save branding settings",
        variant: "destructive",
      });
    },
  });

  const handleLogoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Validate file type
    if (!file.type.match(/^image\/(png|svg\+xml)$/)) {
      toast({
        title: "Invalid file type",
        description: "Please upload a PNG or SVG file",
        variant: "destructive",
      });
      return;
    }

    // Validate file size (max 1MB)
    if (file.size > 1024 * 1024) {
      toast({
        title: "File too large",
        description: "Please upload a file smaller than 1MB",
        variant: "destructive",
      });
      return;
    }

    // Validate dimensions (must be square and at least 256px)
    const img = new Image();
    const reader = new FileReader();

    reader.onload = (event) => {
      img.onload = async () => {
        if (img.width < 256 || img.height < 256) {
          toast({
            title: "Image too small",
            description: "Please upload an image at least 256x256 pixels",
            variant: "destructive",
          });
          return;
        }

        if (img.width !== img.height) {
          toast({
            title: "Image not square",
            description: "Please upload a square image (same width and height)",
            variant: "destructive",
          });
          return;
        }

        // All validations passed, upload the file
        try {
          setIsUploading(true);

          // Get upload URL
          const { url } = await apiRequest("/api/uploads/agent-logo", "POST", {});

          // Upload file directly to object storage
          await fetch(url, {
            method: "PUT",
            body: file,
            headers: {
              "Content-Type": file.type,
            },
          });

          // Set the logo URL in the form
          form.setValue("logoUrl", url.split("?")[0]); // Remove query params
          setPreviewLogoUrl(url.split("?")[0]);

          toast({
            title: "Logo uploaded",
            description: "Logo uploaded successfully. Don't forget to save!",
          });
        } catch (error: any) {
          toast({
            title: "Upload failed",
            description: error.message || "Failed to upload logo",
            variant: "destructive",
          });
        } finally {
          setIsUploading(false);
        }
      };
      img.src = event.target?.result as string;
    };
    reader.readAsDataURL(file);
  };

  const handleReset = () => {
    if (settings) {
      form.reset(settings);
      setPreviewLogoUrl(settings.logoUrl);
      toast({
        title: "Form reset",
        description: "Branding settings have been reset to last saved values",
      });
    }
  };

  const onSubmit = (data: BrandingFormData) => {
    saveMutation.mutate(data);
  };

  // Watch form values for live preview
  const watchedValues = form.watch();

  if (isLoading) {
    return (
      <SidebarProvider>
        <AgentSidebar />
        <SidebarInset>
          <Header userRole="agent" />
          <div className="flex items-center justify-center h-[80vh]">
            <Loader2 className="h-8 w-8 animate-spin text-primary" />
          </div>
        </SidebarInset>
      </SidebarProvider>
    );
  }

  return (
    <SidebarProvider>
      <AgentSidebar />
      <SidebarInset>
        <Header userRole="agent" />
        <div className="flex-1 space-y-4 p-4 md:p-8 pt-6">
          <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4">
            <div>
              <h2 className="text-2xl md:text-3xl font-bold tracking-tight">Branding & Settings</h2>
              <p className="text-sm md:text-base text-muted-foreground">
                Customize your agent branding for the client portal
              </p>
            </div>
          </div>

          <div className="grid gap-4 md:gap-6 md:grid-cols-2">
            {/* Left: Form Card */}
            <Card data-testid="card-branding-form">
              <CardHeader>
                <CardTitle>Agent Branding</CardTitle>
                <CardDescription>
                  Configure your branding settings. All fields are required.
                </CardDescription>
              </CardHeader>
              <CardContent>
                <Form {...form}>
                  <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
                    {/* Agent Logo Upload */}
                    <div className="space-y-2">
                      <Label htmlFor="logo-upload">Agent Logo</Label>
                      <div className="flex items-center gap-4">
                        {previewLogoUrl && (
                          <img
                            src={previewLogoUrl}
                            alt="Logo preview"
                            className="h-16 w-16 rounded object-cover border"
                            data-testid="img-logo-preview"
                          />
                        )}
                        <div className="flex-1">
                          <Input
                            id="logo-upload"
                            type="file"
                            accept=".png,.svg"
                            onChange={handleLogoUpload}
                            disabled={isUploading}
                            className="cursor-pointer"
                            data-testid="input-logo-upload"
                          />
                          <p className="text-xs text-muted-foreground mt-1">
                            PNG/SVG, square, min 256px, max 1MB
                          </p>
                        </div>
                      </div>
                      {isUploading && (
                        <div className="flex items-center gap-2 text-sm text-muted-foreground">
                          <Loader2 className="h-4 w-4 animate-spin" />
                          Uploading logo...
                        </div>
                      )}
                    </div>

                    {/* Agent Name */}
                    <FormField
                      control={form.control}
                      name="agentName"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel className="flex items-center gap-2">
                            <User className="h-4 w-4" />
                            Agent Name
                          </FormLabel>
                          <FormControl>
                            <Input
                              {...field}
                              placeholder="John Doe"
                              data-testid="input-agent-name"
                            />
                          </FormControl>
                          <FormDescription>
                            Shown in client portal header
                          </FormDescription>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    {/* Agent Email */}
                    <FormField
                      control={form.control}
                      name="agentEmail"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel className="flex items-center gap-2">
                            <Mail className="h-4 w-4" />
                            Agent Email
                          </FormLabel>
                          <FormControl>
                            <Input
                              {...field}
                              type="email"
                              placeholder="agent@realestate.com"
                              data-testid="input-agent-email"
                            />
                          </FormControl>
                          <FormDescription>
                            Used for 'Contact Agent' links
                          </FormDescription>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    {/* Brokerage Name */}
                    <FormField
                      control={form.control}
                      name="brokerageName"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel className="flex items-center gap-2">
                            <Building2 className="h-4 w-4" />
                            Brokerage Name
                          </FormLabel>
                          <FormControl>
                            <Input
                              {...field}
                              placeholder="ABC Real Estate"
                              data-testid="input-brokerage-name"
                            />
                          </FormControl>
                          <FormDescription>
                            Displayed beside your name
                          </FormDescription>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </form>
                </Form>
              </CardContent>
              <CardFooter className="flex justify-between border-t pt-6">
                <Button
                  type="button"
                  variant="outline"
                  onClick={handleReset}
                  disabled={saveMutation.isPending || !settings}
                  data-testid="button-reset"
                >
                  Reset
                </Button>
                <Button
                  type="submit"
                  onClick={form.handleSubmit(onSubmit)}
                  disabled={saveMutation.isPending || !form.formState.isValid || !form.getValues("logoUrl")}
                  data-testid="button-save"
                >
                  {saveMutation.isPending ? (
                    <>
                      <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                      Saving...
                    </>
                  ) : (
                    "Save"
                  )}
                </Button>
              </CardFooter>
            </Card>

            {/* Right: Live Preview Card */}
            <Card data-testid="card-preview">
              <CardHeader>
                <CardTitle>Client Header Preview</CardTitle>
                <CardDescription>
                  How your branding will appear in the client portal
                </CardDescription>
              </CardHeader>
              <CardContent>
                <div className="border rounded-lg p-4 bg-background">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-4">
