import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { useToast } from "@/hooks/use-toast";
import { Download, Calendar, MapPin, Star, TrendingUp, Home, FileText, X } from "lucide-react";
import { format } from "date-fns";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";

interface ClientHistoryModalProps {
  isOpen: boolean;
  onClose: () => void;
  selectedClientId: string | null;
}

function ClientHistoryModal({ isOpen, onClose, selectedClientId }: ClientHistoryModalProps) {
  const { toast } = useToast();
  const [activeTab, setActiveTab] = useState("tours");

  // Fetch client history
  const { data: history, isLoading } = useQuery({
    queryKey: ["/api/clients", selectedClientId, "history"],
    queryFn: async () => {
      if (!selectedClientId) throw new Error("No client selected");
      const response = await fetch(`/api/clients/${selectedClientId}/history`, {
        credentials: "include",
      });
      if (!response.ok) throw new Error("Failed to fetch client history");
      return response.json();
    },
    enabled: isOpen && !!selectedClientId,
  });

  const handleExportPDF = () => {
    if (!history) return;

    const doc = new jsPDF();

    // Add title
    doc.setFontSize(20);
    doc.text("Client History Report", 14, 20);

    // Add client info
    doc.setFontSize(12);
    doc.text(`Client: ${history.client?.firstName || ""} ${history.client?.lastName || ""}`, 14, 30);
    doc.text(`Email: ${history.client?.email || "N/A"}`, 14, 37);
    doc.text(`Generated: ${format(new Date(), "MMM dd, yyyy HH:mm")}`, 14, 44);

    // Add summary statistics
    let yPos = 55;
    doc.setFontSize(14);
    doc.text("Summary", 14, yPos);
    yPos += 8;
    doc.setFontSize(10);
    doc.text(`Total Tours: ${history.summary?.totalTours || 0}`, 14, yPos);
    doc.text(`Completed Tours: ${history.summary?.completedTours || 0}`, 70, yPos);
    doc.text(`Total Offers: ${history.summary?.totalOffers || 0}`, 140, yPos);
    yPos += 5;
    doc.text(`Properties Viewed: ${history.summary?.totalPropertiesViewed || 0}`, 14, yPos);
    doc.text(`Ratings Given: ${history.summary?.totalRatings || 0}`, 70, yPos);
    doc.text(`Accepted Offers: ${history.summary?.acceptedOffers || 0}`, 140, yPos);
    yPos += 12;

    // Add tours section
    if (history.tours && history.tours.length > 0) {
      doc.setFontSize(14);
      doc.text("Tour History", 14, yPos);
      yPos += 7;

      const tourTableData = history.tours.flatMap((tour: any) => {
        const properties = tour.properties || [];
        // If no properties, still include the tour with N/A
        if (properties.length === 0) {
          return [[
            tour.scheduledDate ? format(new Date(tour.scheduledDate), "MMM dd, yyyy") : "N/A",
            "No properties",
            tour.status || "N/A",
            "N/A",
            "N/A",
          ]];
        }
        return properties.map((property: any) => ([
          tour.scheduledDate ? format(new Date(tour.scheduledDate), "MMM dd, yyyy") : "N/A",
          property.address?.substring(0, 40) || "N/A",
          tour.status || "N/A",
          property.rating?.starRating?.toString() || "N/A",
          property.rating?.feedback || "N/A",
        ]));
      });

      autoTable(doc, {
        startY: yPos,
        head: [["Date", "Property", "Status", "Rating", "Feedback"]],
        body: tourTableData,
        theme: "grid",
        styles: { fontSize: 8, cellPadding: 2 },
        headStyles: { fillColor: [59, 130, 246], textColor: [255, 255, 255] },
        columnStyles: {
          0: { cellWidth: 25 },
          1: { cellWidth: 60 },
          2: { cellWidth: 20 },
          3: { cellWidth: 15 },
          4: { cellWidth: 45 },
        },
      });

      yPos = (doc as any).lastAutoTable.finalY + 10;
    }

    // Add offers section
    if (history.offers && history.offers.length > 0) {
      if (yPos > 250) {
        doc.addPage();
        yPos = 20;
      }

      doc.setFontSize(14);
      doc.text("Offers", 14, yPos);
      yPos += 7;

      const offerTableData = history.offers.map((offer: any) => ([
        offer.createdAt ? format(new Date(offer.createdAt), "MMM dd, yyyy") : "N/A",
        offer.property?.address?.substring(0, 40) || "N/A",
        offer.offerAmount ? `$${Number(offer.offerAmount).toLocaleString()}` : "N/A",
        offer.status || "N/A",
      ]));

      autoTable(doc, {
        startY: yPos,
        head: [["Date", "Property", "Offer Amount", "Status"]],
        body: offerTableData,
        theme: "grid",
        styles: { fontSize: 8, cellPadding: 2 },
        headStyles: { fillColor: [59, 130, 246], textColor: [255, 255, 255] },
        columnStyles: {
          0: { cellWidth: 30 },
          1: { cellWidth: 80 },
          2: { cellWidth: 35 },
          3: { cellWidth: 25 },
        },
      });
    }

    // Save the PDF
    doc.save(`client-history-${history.client?.firstName}-${history.client?.lastName}-${format(new Date(), "yyyy-MM-dd")}.pdf`);

    toast({
      title: "Export Complete",
      description: "Client history has been exported to PDF.",
    });
  };

  const handleExportCSV = () => {
    if (!history) return;

    const csvHeaders = [
      "Date",
      "Type",
      "Property Address",
      "Status",
      "Rating",
      "Feedback",
      "Notes",
    ];

    const csvRows: string[][] = [];

    // Add tour data
    history.tours?.forEach((tour: any) => {
      tour.properties?.forEach((property: any) => {
        csvRows.push([
          tour.scheduledDate ? format(new Date(tour.scheduledDate), "yyyy-MM-dd") : "N/A",
          "Tour",
          property.address || "N/A",
          tour.status || "N/A",
          property.rating?.starRating?.toString() || "N/A",
          property.rating?.feedback || "N/A",
          property.rating?.notes || "N/A",
        ]);
      });
    });

    // Add offer data
    history.offers?.forEach((offer: any) => {
      csvRows.push([
        offer.createdAt ? format(new Date(offer.createdAt), "yyyy-MM-dd") : "N/A",
        "Offer",
        offer.property?.address || "N/A",
        offer.status || "N/A",
        "N/A",
        "N/A",
        offer.notes || "N/A",
      ]);
    });

    const csvContent = [
      csvHeaders.join(","),
      ...csvRows.map((row) => row.map((cell) => `"${cell.replace(/"/g, '""')}"`).join(",")),
    ].join("\n");

    const blob = new Blob([csvContent], { type: "text/csv" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `client-history-${history.client?.firstName}-${history.client?.lastName}-${format(new Date(), "yyyy-MM-dd")}.csv`;
    link.click();
    URL.revokeObjectURL(url);

    toast({
      title: "Export Successful",
      description: "Client history has been exported to CSV.",
    });
  };

  const getStatusColor = (status: string) => {
    const colors: Record<string, string> = {
      completed: "bg-green-500",
      scheduled: "bg-blue-500",
      in_progress: "bg-yellow-500",
      cancelled: "bg-red-500",
      accepted: "bg-green-500",
      pending: "bg-yellow-500",
      rejected: "bg-red-500",
    };
    return colors[status] || "bg-gray-500";
  };

  const getFeedbackColor = (feedback: string) => {
    if (feedback?.toLowerCase().includes("offer")) return "text-green-600";
    if (feedback?.toLowerCase().includes("hold")) return "text-yellow-600";
    if (feedback?.toLowerCase().includes("reject")) return "text-red-600";
    return "text-gray-600";
  };

  if (!selectedClientId) {
    return null;
  }

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-6xl max-h-[90vh] overflow-hidden flex flex-col" data-testid="dialog-client-history">
        <DialogHeader>
          <div className="flex items-center justify-between">
            <DialogTitle className="flex items-center gap-2">
              <FileText className="h-5 w-5" />
              Client History - {history?.client?.firstName} {history?.client?.lastName}
            </DialogTitle>
            <div className="flex gap-2">
              <Button
                variant="outline"
                size="sm"
                onClick={handleExportPDF}
                disabled={isLoading || !history}
                data-testid="button-export-pdf"
              >
                <FileText className="h-4 w-4 mr-2" />
                Export PDF
              </Button>
              <Button
                variant="outline"
                size="sm"
                onClick={handleExportCSV}
                disabled={isLoading || !history}
                data-testid="button-export-csv"
              >
                <Download className="h-4 w-4 mr-2" />
                Export CSV
              </Button>
            </div>
          </div>
          <p className="text-sm text-muted-foreground">
            Complete interaction timeline and activity history
          </p>
        </DialogHeader>

        {isLoading ? (
          <div className="flex-1 flex items-center justify-center" data-testid="loading-history">
            <div className="text-center">
              <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary mx-auto"></div>
              <p className="mt-2 text-sm text-muted-foreground">Loading client history...</p>
            </div>
          </div>
        ) : history ? (
          <>
            {/* Summary Statistics */}
            <div className="grid grid-cols-2 md:grid-cols-6 gap-4 mb-4">
              <Card data-testid="stat-total-tours">
                <CardContent className="p-4">
                  <div className="text-sm text-muted-foreground">Total Tours</div>
                  <div className="text-2xl font-bold">{history.summary?.totalTours || 0}</div>
                </CardContent>
              </Card>
              <Card data-testid="stat-completed-tours">
                <CardContent className="p-4">
                  <div className="text-sm text-muted-foreground">Completed</div>
                  <div className="text-2xl font-bold">{history.summary?.completedTours || 0}</div>
                </CardContent>
              </Card>
              <Card data-testid="stat-properties-viewed">
                <CardContent className="p-4">
                  <div className="text-sm text-muted-foreground">Properties</div>
                  <div className="text-2xl font-bold">{history.summary?.totalPropertiesViewed || 0}</div>
                </CardContent>
              </Card>
              <Card data-testid="stat-total-ratings">
                <CardContent className="p-4">
                  <div className="text-sm text-muted-foreground">Ratings</div>
                  <div className="text-2xl font-bold">{history.summary?.totalRatings || 0}</div>
                </CardContent>
              </Card>
              <Card data-testid="stat-total-offers">
                <CardContent className="p-4">
                  <div className="text-sm text-muted-foreground">Offers</div>
                  <div className="text-2xl font-bold">{history.summary?.totalOffers || 0}</div>
                </CardContent>
              </Card>
              <Card data-testid="stat-accepted-offers">
                <CardContent className="p-4">
                  <div className="text-sm text-muted-foreground">Accepted</div>
                  <div className="text-2xl font-bold text-green-600">{history.summary?.acceptedOffers || 0}</div>
                </CardContent>
              </Card>
            </div>

            {/* Tabs for Tours and Offers */}
            <Tabs value={activeTab} onValueChange={setActiveTab} className="flex-1 flex flex-col overflow-hidden">
              <TabsList className="grid w-full grid-cols-2">
                <TabsTrigger value="tours" data-testid="tab-tours">
                  <Calendar className="h-4 w-4 mr-2" />
                  Tours ({history.tours?.length || 0})
                </TabsTrigger>
                <TabsTrigger value="offers" data-testid="tab-offers">
                  <TrendingUp className="h-4 w-4 mr-2" />
                  Offers ({history.offers?.length || 0})
                </TabsTrigger>
              </TabsList>

              <div className="flex-1 overflow-y-auto mt-4">
                <TabsContent value="tours" className="space-y-4 mt-0">
                  {history.tours && history.tours.length > 0 ? (
                    history.tours.map((tour: any) => (
                      <Card key={tour.id} data-testid={`tour-${tour.id}`}>
                        <CardHeader>
                          <div className="flex items-center justify-between">
                            <CardTitle className="text-lg flex items-center gap-2">
                              <Calendar className="h-5 w-5" />
                              {tour.scheduledDate
                                ? format(new Date(tour.scheduledDate), "MMMM d, yyyy")
                                : "Date TBD"}
                            </CardTitle>
                            <Badge className={getStatusColor(tour.status)} data-testid={`tour-status-${tour.id}`}>
                              {tour.status}
                            </Badge>
                          </div>
                          <div className="text-sm text-muted-foreground">
                            {tour.totalProperties || 0} properties • {tour.totalRatings || 0} ratings
                          </div>
                        </CardHeader>
                        <CardContent className="space-y-3">
                          {tour.properties && tour.properties.length > 0 ? (
                            tour.properties.map((property: any) => (
                              <div
                                key={property.id}
                                className="border rounded-lg p-3 space-y-2"
                                data-testid={`property-${property.id}`}
                              >
                                <div className="flex items-start justify-between">
                                  <div className="flex items-start gap-2 flex-1">
                                    <Home className="h-4 w-4 mt-0.5 text-muted-foreground" />
                                    <div className="flex-1">
                                      <div className="font-medium">{property.address}</div>
                                      <div className="text-sm text-muted-foreground">
                                        {property.price ? `$${Number(property.price).toLocaleString()}` : "Price TBD"}
                                      </div>
                                    </div>
                                  </div>
                                  {property.rating && (
                                    <div className="text-right">
                                      <div className="flex items-center gap-1">
                                        <Star className="h-4 w-4 fill-yellow-400 text-yellow-400" />
                                        <span className="font-medium">{property.rating.starRating}</span>
                                      </div>
                                    </div>
                                  )}
                                </div>
                                {property.rating && (
                                  <div className="space-y-1 text-sm">
                                    {property.rating.feedback && (
                                      <div className={`font-medium ${getFeedbackColor(property.rating.feedback)}`}>
                                        {property.rating.feedback}
                                      </div>
                                    )}
                                    {property.rating.reason && (
                                      <div className="text-muted-foreground">
                                        Reason: {property.rating.reason}
                                      </div>
                                    )}
                                    {property.rating.notes && (
                                      <div className="text-muted-foreground italic">
                                        "{property.rating.notes}"
                                      </div>
                                    )}
                                  </div>
                                )}
                              </div>
                            ))
                          ) : (
                            <div className="text-sm text-muted-foreground">No properties in this tour</div>
                          )}
                          {tour.notes && (
                            <div className="text-sm text-muted-foreground italic border-t pt-2">
                              Tour notes: {tour.notes}
                            </div>
                          )}
                        </CardContent>
                      </Card>
                    ))
                  ) : (
                    <div className="text-center py-8 text-muted-foreground" data-testid="no-tours">
                      No tours found for this client
                    </div>
                  )}
                </TabsContent>

                <TabsContent value="offers" className="space-y-4 mt-0">
                  {history.offers && history.offers.length > 0 ? (
                    history.offers.map((offer: any) => (
                      <Card key={offer.id} data-testid={`offer-${offer.id}`}>
                        <CardHeader>
                          <div className="flex items-center justify-between">
                            <CardTitle className="text-lg flex items-center gap-2">
                              <TrendingUp className="h-5 w-5" />
                              Offer - {offer.createdAt ? format(new Date(offer.createdAt), "MMMM d, yyyy") : "Date Unknown"}
                            </CardTitle>
                            <Badge className={getStatusColor(offer.status)} data-testid={`offer-status-${offer.id}`}>
                              {offer.status}
                            </Badge>
                          </div>
                        </CardHeader>
                        <CardContent>
                          {offer.property && (
                            <div className="space-y-2">
                              <div className="flex items-center gap-2">
                                <MapPin className="h-4 w-4 text-muted-foreground" />
                                <span className="font-medium">{offer.property.address}</span>
                              </div>
                              <div className="text-sm text-muted-foreground">
                                Property Price: ${Number(offer.property.price || 0).toLocaleString()}
                              </div>
                              {offer.offerAmount && (
                                <div className="text-sm">
                                  Offer Amount: <span className="font-medium">${Number(offer.offerAmount).toLocaleString()}</span>
                                </div>
                              )}
                              {offer.closingDate && (
                                <div className="text-sm text-muted-foreground">
                                  Closing Date: {format(new Date(offer.closingDate), "MMMM d, yyyy")}
                                </div>
                              )}
                              {offer.notes && (
                                <div className="text-sm text-muted-foreground italic border-t pt-2 mt-2">
                                  {offer.notes}
                                </div>
                              )}
                            </div>
                          )}
                        </CardContent>
                      </Card>
                    ))
                  ) : (
                    <div className="text-center py-8 text-muted-foreground" data-testid="no-offers">
                      No offers found for this client
                    </div>
                  )}
                </TabsContent>
              </div>
            </Tabs>
          </>
        ) : (
          <div className="flex-1 flex items-center justify-center">
            <div className="text-center text-muted-foreground">
              <p>No history data available</p>
            </div>
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
}

export default ClientHistoryModal;

client/src/components/ui/toggle-group.ts.content:
"use client"

import * as React from "react"
import * as ToggleGroupPrimitive from "@radix-ui/react-toggle-group"
import { type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"
import { toggleVariants } from "@/components/ui/toggle"

const ToggleGroupContext = React.createContext<
  VariantProps<typeof toggleVariants>
>({
  size: "default",
  variant: "default",
})

const ToggleGroup = React.forwardRef<
  React.ElementRef<typeof ToggleGroupPrimitive.Root>,
  React.ComponentPropsWithoutRef<typeof ToggleGroupPrimitive.Root> &
    VariantProps<typeof toggleVariants>
>(({ className, variant, size, children, ...props }, ref) => (
  <ToggleGroupPrimitive.Root
    ref={ref}
    className={cn("flex items-center justify-center gap-1", className)}
    {...props}
  >
    <ToggleGroupContext.Provider value={{ variant, size }}>
      {children}
    </ToggleGroupContext.Provider>
  </ToggleGroupPrimitive.Root>
))

ToggleGroup.displayName = ToggleGroupPrimitive.Root.displayName

const ToggleGroupItem = React.forwardRef<
  React.ElementRef<typeof ToggleGroupPrimitive.Item>,
  React.ComponentPropsWithoutRef<typeof ToggleGroupPrimitive.Item> &
    VariantProps<typeof toggleVariants>
>(({ className, children, variant, size, ...props }, ref) => {
  const context = React.useContext(ToggleGroupContext)

  return (
    <ToggleGroupPrimitive.Item
      ref={ref}
      className={cn(
        toggleVariants({
          variant: context.variant || variant,
          size: context.size || size,
        }),
        className
      )}
      {...props}
    >
      {children}
    </ToggleGroupPrimitive.Item>
  )
})

ToggleGroupItem.displayName = ToggleGroupPrimitive.Item.displayName

export { ToggleGroup, ToggleGroupItem }

client/src/components/AddClientModal.tsx.content:
import { useState } from "react";
import { useMutation } from "@tanstack/react-query";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Label } from "@/components/ui/label";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { User, Mail, Home, Building2 } from "lucide-react";

// Form validation schema
const addClientSchema = z.object({
  firstName: z.string().min(1, "First name is required"),
  lastName: z.string().min(1, "Last name is required"),
  email: z.string().email("Please enter a valid email address"),
  clientType: z.enum(["buyer", "renter"], {
    required_error: "Please select a client type",
  }),
});

type AddClientFormData = z.infer<typeof addClientSchema>;

interface AddClientModalProps {
  isOpen: boolean;
  onClose: () => void;
}

export default function AddClientModal({ isOpen, onClose }: AddClientModalProps) {
  const { toast } = useToast();

  const form = useForm<AddClientFormData>({
    resolver: zodResolver(addClientSchema),
    defaultValues: {
      firstName: "",
      lastName: "",
      email: "",
      clientType: undefined,
    },
  });

  const addClientMutation = useMutation({
    mutationFn: async (data: AddClientFormData) => {
      const response = await apiRequest("POST", "/api/clients", data);
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/clients"] });
      queryClient.invalidateQueries({ queryKey: ["/api/stats"] });
      toast({
        title: "Client Added",
        description: "New client has been added successfully.",
      });
      form.reset();
      onClose();
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to add client. Please try again.",
        variant: "destructive",
      });
    },
  });

  const onSubmit = (data: AddClientFormData) => {
    addClientMutation.mutate(data);
  };

  const handleClose = () => {
    form.reset();
    onClose();
  };

  return (
    <Dialog open={isOpen} onOpenChange={handleClose}>
      <DialogContent className="max-w-md" data-testid="dialog-add-client">
        <DialogHeader>
          <DialogTitle>Add New Client</DialogTitle>
        </DialogHeader>

        <Form {...form}>
          <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4">
            <FormField
              control={form.control}
              name="firstName"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>First Name</FormLabel>
                  <FormControl>
                    <div className="relative">
                      <User className="absolute left-3 top-1/2 transform -translate-y-1/2 text-muted-foreground h-4 w-4" />
                      <Input
                        placeholder="Enter first name"
                        className="pl-9"
                        data-testid="input-client-first-name"
                        {...field}
                      />
                    </div>
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />

            <FormField
              control={form.control}
              name="lastName"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Last Name</FormLabel>
                  <FormControl>
                    <div className="relative">
                      <User className="absolute left-3 top-1/2 transform -translate-y-1/2 text-muted-foreground h-4 w-4" />
                      <Input
                        placeholder="Enter last name"
                        className="pl-9"
                        data-testid="input-client-last-name"
                        {...field}
                      />
                    </div>
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />

            <FormField
              control={form.control}
              name="email"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Email Address</FormLabel>
                  <FormControl>
                    <div className="relative">
                      <Mail className="absolute left-3 top-1/2 transform -translate-y-1/2 text-muted-foreground h-4 w-4" />
                      <Input
                        type="email"
                        placeholder="Enter email address"
                        className="pl-9"
                        data-testid="input-client-email"
                        {...field}
                      />
                    </div>
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />

            <FormField
              control={form.control}
              name="clientType"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Client Type</FormLabel>
                  <Select onValueChange={field.onChange} defaultValue={field.value}>
                    <FormControl>
                      <SelectTrigger data-testid="select-client-type-add">
                        <SelectValue placeholder="Select client type" />
                      </SelectTrigger>
                    </FormControl>
                    <SelectContent>
                      <SelectItem value="buyer" data-testid="option-buyer">
                        <div className="flex items-center gap-2">
                          <Home className="h-4 w-4" />
                          Buyer
                        </div>
                      </SelectItem>
                      <SelectItem value="renter" data-testid="option-renter">
                        <div className="flex items-center gap-2">
                          <Building2 className="h-4 w-4" />
                          Renter
                        </div>
                      </SelectItem>
                    </SelectContent>
                  </Select>
                  <FormMessage />
                </FormItem>
              )}
            />

            <div className="flex justify-end gap-3 pt-4">
              <Button
                type="button"
                variant="outline"
                onClick={handleClose}
                data-testid="button-cancel-add-client"
              >
                Cancel
              </Button>
              <Button
                type="submit"
                disabled={addClientMutation.isPending}
                data-testid="button-save-client"
              >
                {addClientMutation.isPending ? "Adding..." : "Add Client"}
              </Button>
            </div>
          </form>
        </Form>
      </DialogContent>
    </Dialog>
  );
}

