import { useState, useEffect } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { useMutation, useQuery } from "@tanstack/react-query";
import { useToast } from "@/hooks/use-toast";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { z } from "zod";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { 
  FileText,
  Clock,
  MapPin,
  Users,
  Star,
  CheckCircle,
  AlertCircle,
  TrendingUp,
  Save,
  Calendar,
  Route
} from "lucide-react";

interface TourRecapModalProps {
  isOpen: boolean;
  onClose: () => void;
  selectedDate: Date;
}

const tourRecapSchema = z.object({
  tourDate: z.string().min(1, "Date is required"),
  totalDistance: z.string().optional(),
  totalDuration: z.string().optional(),
  showingsCompleted: z.number().min(0, "Must be 0 or greater"),
  clientsSatisfaction: z.number().min(1).max(5, "Rating must be 1-5"),
  keyInsights: z.string().optional(),
  challengesFaced: z.string().optional(),
  opportunitiesIdentified: z.string().optional(),
  followUpActions: z.string().optional(),
  overallNotes: z.string().optional(),
});

type TourRecapData = z.infer<typeof tourRecapSchema>;

interface TourSummary {
  id: string;
  propertyAddress: string;
  clientName: string;
  status: string;
  duration: number;
  clientFeedback?: string;
  interestLevel?: number;
}

interface ExistingRecap {
  id: string;
  tourDate: string;
  totalDistance?: string;
  totalDuration?: string;
  showingsCompleted: number;
  clientsSatisfaction: number;
  keyInsights?: string;
  challengesFaced?: string;
  opportunitiesIdentified?: string;
  followUpActions?: string;
  overallNotes?: string;
  createdAt: string;
}

export default function TourRecapModal({ 
  isOpen, 
  onClose, 
  selectedDate 
}: TourRecapModalProps) {
  const { toast } = useToast();
  const [isEditing, setIsEditing] = useState(false);

  // Fetch tour summary for the selected date
  const { data: tourSummary = [], isLoading: summaryLoading } = useQuery<TourSummary[]>({
    queryKey: ["/api/tours/summary", selectedDate.toISOString().split('T')[0]],
    enabled: isOpen,
  });

  // Fetch existing recap if any
  const { data: existingRecap, isLoading: recapLoading } = useQuery<ExistingRecap | null>({
    queryKey: ["/api/tours/recap", selectedDate.toISOString().split('T')[0]],
    enabled: isOpen,
  });

  const form = useForm<TourRecapData>({
    resolver: zodResolver(tourRecapSchema),
    defaultValues: {
      tourDate: selectedDate.toISOString().split('T')[0],
      totalDistance: "",
      totalDuration: "",
      showingsCompleted: 0,
      clientsSatisfaction: 5,
      keyInsights: "",
      challengesFaced: "",
      opportunitiesIdentified: "",
      followUpActions: "",
      overallNotes: "",
    },
  });

  // Update form with existing recap data
  useEffect(() => {
    if (existingRecap) {
      form.reset({
        tourDate: existingRecap.tourDate,
        totalDistance: existingRecap.totalDistance || "",
        totalDuration: existingRecap.totalDuration || "",
        showingsCompleted: existingRecap.showingsCompleted,
        clientsSatisfaction: existingRecap.clientsSatisfaction,
        keyInsights: existingRecap.keyInsights || "",
        challengesFaced: existingRecap.challengesFaced || "",
        opportunitiesIdentified: existingRecap.opportunitiesIdentified || "",
        followUpActions: existingRecap.followUpActions || "",
        overallNotes: existingRecap.overallNotes || "",
      });
    } else if (tourSummary.length > 0) {
      // Auto-populate with tour data
      const completedTours = tourSummary.filter(tour => tour.status === "completed");
      form.setValue("showingsCompleted", completedTours.length);
    }
  }, [existingRecap, tourSummary, form]);

  // Save recap mutation
  const saveRecapMutation = useMutation({
    mutationFn: async (data: TourRecapData) => {
      if (existingRecap) {
        return apiRequest("PATCH", `/api/tours/recap/${existingRecap.id}`, data);
      } else {
        return apiRequest("POST", "/api/tours/recap", data);
      }
    },
    onSuccess: () => {
      toast({
        title: "Tour Recap Saved",
        description: "Your tour recap has been saved successfully.",
      });
      setIsEditing(false);
      queryClient.invalidateQueries({ queryKey: ["/api/tours/recap"] });
    },
    onError: () => {
      toast({
        title: "Save Failed",
        description: "Could not save tour recap. Please try again.",
        variant: "destructive",
      });
    },
  });

  const handleSaveRecap = async (data: TourRecapData) => {
    saveRecapMutation.mutate(data);
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case "completed":
        return "bg-green-100 text-green-800";
      case "in_progress":
        return "bg-yellow-100 text-yellow-800";
      case "cancelled":
        return "bg-red-100 text-red-800";
      default:
        return "bg-gray-100 text-gray-800";
    }
  };

  const getInterestIcon = (level?: number) => {
    if (!level) return null;
    if (level >= 4) return <TrendingUp className="h-4 w-4 text-green-600" />;
    if (level >= 3) return <Star className="h-4 w-4 text-yellow-600" />;
    return <AlertCircle className="h-4 w-4 text-red-600" />;
  };

  const completedTours = tourSummary.filter(tour => tour.status === "completed");
  const averageInterest = completedTours.length > 0 
    ? completedTours.reduce((sum, tour) => sum + (tour.interestLevel || 0), 0) / completedTours.length 
    : 0;

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-5xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <FileText className="h-5 w-5" />
            Tour Recap - {selectedDate.toLocaleDateString()}
          </DialogTitle>
        </DialogHeader>

        <div className="space-y-6">
          {/* Tour Summary Statistics */}
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
            <Card>
              <CardContent className="p-4 text-center">
                <CheckCircle className="h-8 w-8 text-green-600 mx-auto mb-2" />
                <p className="text-2xl font-bold text-green-800">{completedTours.length}</p>
                <p className="text-sm text-green-600">Completed Tours</p>
              </CardContent>
            </Card>
            <Card>
              <CardContent className="p-4 text-center">
                <Users className="h-8 w-8 text-blue-600 mx-auto mb-2" />
                <p className="text-2xl font-bold text-blue-800">{tourSummary.length}</p>
                <p className="text-sm text-blue-600">Total Scheduled</p>
              </CardContent>
            </Card>
            <Card>
              <CardContent className="p-4 text-center">
                <Star className="h-8 w-8 text-yellow-600 mx-auto mb-2" />
                <p className="text-2xl font-bold text-yellow-800">{averageInterest.toFixed(1)}</p>
                <p className="text-sm text-yellow-600">Avg Interest</p>
              </CardContent>
            </Card>
            <Card>
              <CardContent className="p-4 text-center">
                <Clock className="h-8 w-8 text-purple-600 mx-auto mb-2" />
                <p className="text-2xl font-bold text-purple-800">
                  {Math.round(completedTours.reduce((sum, tour) => sum + tour.duration, 0) / 60)}h
                </p>
                <p className="text-sm text-purple-600">Total Time</p>
              </CardContent>
            </Card>
          </div>

          {/* Tour Details */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Route className="h-5 w-5" />
                Tour Details
              </CardTitle>
            </CardHeader>
            <CardContent>
              {summaryLoading ? (
                <div className="space-y-3">
                  {[1, 2, 3].map((i) => (
                    <div key={i} className="animate-pulse border rounded-lg p-4">
                      <div className="h-4 bg-muted rounded w-1/3 mb-2"></div>
                      <div className="h-3 bg-muted rounded w-1/2"></div>
                    </div>
                  ))}
                </div>
              ) : tourSummary.length === 0 ? (
                <div className="text-center py-8">
                  <Calendar className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
                  <p className="text-muted-foreground">No tours scheduled for this date</p>
                </div>
              ) : (
                <div className="space-y-3">
                  {tourSummary.map((tour) => (
                    <div key={tour.id} className="border rounded-lg p-4">
                      <div className="flex items-start justify-between">
                        <div className="flex-1">
                          <div className="flex items-center gap-2 mb-2">
                            <MapPin className="h-4 w-4 text-muted-foreground" />
                            <p className="font-medium">{tour.propertyAddress}</p>
                            <Badge className={getStatusColor(tour.status)}>
                              {tour.status}
                            </Badge>
                            {getInterestIcon(tour.interestLevel)}
                          </div>
                          <div className="flex items-center gap-2 mb-1">
                            <Users className="h-4 w-4 text-muted-foreground" />
                            <p className="text-sm text-muted-foreground">
                              Client: {tour.clientName}
                            </p>
                          </div>
                          <div className="flex items-center gap-2">
                            <Clock className="h-4 w-4 text-muted-foreground" />
                            <p className="text-sm text-muted-foreground">
                              Duration: {tour.duration} minutes
                            </p>
                          </div>
                          {tour.clientFeedback && (
                            <p className="text-sm text-muted-foreground mt-2">
                              Feedback: {tour.clientFeedback}
                            </p>
                          )}
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </CardContent>
          </Card>

          {/* Recap Form */}
          <Card>
            <CardHeader>
              <div className="flex items-center justify-between">
                <CardTitle className="flex items-center gap-2">
                  <FileText className="h-5 w-5" />
                  Tour Recap {existingRecap && !isEditing && 
                    <Badge variant="secondary">
                      Saved {new Date(existingRecap.createdAt).toLocaleDateString()}
                    </Badge>
                  }
                </CardTitle>
                {existingRecap && !isEditing && (
                  <Button
                    variant="outline"
                    onClick={() => setIsEditing(true)}
                    data-testid="button-edit-recap"
                  >
                    Edit Recap
                  </Button>
                )}
              </div>
            </CardHeader>
            <CardContent>
              {(isEditing || !existingRecap) ? (
                <Form {...form}>
                  <form onSubmit={form.handleSubmit(handleSaveRecap)} className="space-y-4">
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                      <FormField
                        control={form.control}
                        name="totalDistance"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Total Distance</FormLabel>
                            <FormControl>
                              <Input
                                placeholder="e.g., 25.3 miles"
                                {...field}
                                data-testid="input-total-distance"
                              />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                      <FormField
                        control={form.control}
                        name="totalDuration"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Total Duration</FormLabel>
                            <FormControl>
                              <Input
                                placeholder="e.g., 4.5 hours"
                                {...field}
                                data-testid="input-total-duration"
                              />
                            </FormControl>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                      <FormField
                        control={form.control}
                        name="clientsSatisfaction"
                        render={({ field }) => (
                          <FormItem>
                            <FormLabel>Client Satisfaction (1-5)</FormLabel>
                            <Select value={field.value.toString()} onValueChange={(value) => field.onChange(parseInt(value))}>
                              <FormControl>
                                <SelectTrigger data-testid="select-satisfaction">
                                  <SelectValue placeholder="Rate satisfaction" />
                                </SelectTrigger>
                              </FormControl>
                              <SelectContent>
                                <SelectItem value="1">1 - Poor</SelectItem>
                                <SelectItem value="2">2 - Fair</SelectItem>
                                <SelectItem value="3">3 - Good</SelectItem>
                                <SelectItem value="4">4 - Very Good</SelectItem>
                                <SelectItem value="5">5 - Excellent</SelectItem>
                              </SelectContent>
                            </Select>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                    </div>

                    <FormField
                      control={form.control}
                      name="keyInsights"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Key Insights</FormLabel>
                          <FormControl>
                            <Textarea
                              placeholder="What were the key insights from today's tours?"
                              {...field}
                              data-testid="input-key-insights"
                            />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <FormField
                      control={form.control}
                      name="challengesFaced"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Challenges Faced</FormLabel>
                          <FormControl>
                            <Textarea
                              placeholder="What challenges did you encounter during the tours?"
                              {...field}
                              data-testid="input-challenges"
                            />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <FormField
                      control={form.control}
                      name="opportunitiesIdentified"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Opportunities Identified</FormLabel>
                          <FormControl>
                            <Textarea
                              placeholder="What opportunities did you identify for follow-up?"
                              {...field}
                              data-testid="input-opportunities"
                            />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <FormField
                      control={form.control}
                      name="followUpActions"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Follow-up Actions</FormLabel>
                          <FormControl>
                            <Textarea
                              placeholder="What actions need to be taken following today's tours?"
                              {...field}
                              data-testid="input-follow-up"
                            />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <FormField
                      control={form.control}
                      name="overallNotes"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Overall Notes</FormLabel>
                          <FormControl>
                            <Textarea
                              placeholder="Any additional notes about today's tour experience?"
                              {...field}
                              data-testid="input-overall-notes"
                            />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />

                    <div className="flex justify-end gap-3">
                      {existingRecap && (
                        <Button
                          type="button"
                          variant="outline"
                          onClick={() => setIsEditing(false)}
                        >
                          Cancel
                        </Button>
                      )}
                      <Button
                        type="submit"
                        disabled={saveRecapMutation.isPending}
                        data-testid="button-save-recap"
                      >
                        {saveRecapMutation.isPending ? (
                          <>
                            <Save className="h-4 w-4 mr-2 animate-spin" />
                            Saving...
                          </>
                        ) : (
                          <>
                            <Save className="h-4 w-4 mr-2" />
                            Save Recap
                          </>
                        )}
                      </Button>
                    </div>
                  </form>
                </Form>
              ) : (
                <div className="space-y-4">
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                    <div>
                      <p className="text-sm font-medium text-muted-foreground">Total Distance</p>
                      <p className="text-lg">{existingRecap.totalDistance || "Not recorded"}</p>
                    </div>
                    <div>
                      <p className="text-sm font-medium text-muted-foreground">Total Duration</p>
                      <p className="text-lg">{existingRecap.totalDuration || "Not recorded"}</p>
                    </div>
                    <div>
                      <p className="text-sm font-medium text-muted-foreground">Client Satisfaction</p>
                      <div className="flex items-center gap-1">
                        {[1, 2, 3, 4, 5].map((star) => (
                          <Star
                            key={star}
                            className={`h-4 w-4 ${
                              star <= existingRecap.clientsSatisfaction
                                ? "text-yellow-400 fill-current"
                                : "text-gray-300"
                            }`}
                          />
                        ))}
                        <span className="ml-2 text-lg font-medium">
                          {existingRecap.clientsSatisfaction}/5
                        </span>
                      </div>
                    </div>
                  </div>

                  {existingRecap.keyInsights && (
                    <div>
                      <p className="text-sm font-medium text-muted-foreground mb-1">Key Insights</p>
                      <p className="text-sm">{existingRecap.keyInsights}</p>
                    </div>
                  )}

                  {existingRecap.challengesFaced && (
                    <div>
                      <p className="text-sm font-medium text-muted-foreground mb-1">Challenges Faced</p>
                      <p className="text-sm">{existingRecap.challengesFaced}</p>
                    </div>
                  )}

                  {existingRecap.opportunitiesIdentified && (
                    <div>
                      <p className="text-sm font-medium text-muted-foreground mb-1">Opportunities Identified</p>
                      <p className="text-sm">{existingRecap.opportunitiesIdentified}</p>
                    </div>
                  )}

                  {existingRecap.followUpActions && (
                    <div>
                      <p className="text-sm font-medium text-muted-foreground mb-1">Follow-up Actions</p>
                      <p className="text-sm">{existingRecap.followUpActions}</p>
                    </div>
                  )}

                  {existingRecap.overallNotes && (
                    <div>
                      <p className="text-sm font-medium text-muted-foreground mb-1">Overall Notes</p>
                      <p className="text-sm">{existingRecap.overallNotes}</p>
                    </div>
                  )}
                </div>
              )}
            </CardContent>
          </Card>

          {/* Close Button */}
          <div className="flex justify-end">
            <Button variant="outline" onClick={onClose}>
              Close
            </Button>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

