import { useState } from "react";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { Checkbox } from "@/components/ui/checkbox";
import { Separator } from "@/components/ui/separator";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";
import { Download, Upload, FileText, Users, FileCheck, DollarSign, Trash2, Eye, CheckSquare, Square, Archive } from "lucide-react";
import type { Document, InsertDocument } from "@shared/schema";

interface DocumentCenterModalProps {
  isOpen: boolean;
  onClose: () => void;
  userId: string;
}

type DocumentType = "offer_placed" | "client_id" | "representative_agreement" | "offer_received" |
  "property_listing" | "inspection_report" | "appraisal" | "legal_document" | 
  "financial_document" | "insurance" | "lease_agreement" | "purchase_agreement" |
  "closing_document" | "marketing_material" | "floor_plan" | "photo_gallery" |
  "disclosure_form" | "warranty" | "contract" | "deed" | "title" | "survey" |
  "hoa_document" | "property_tax" | "utility_bill" | "mls_listing" | "other";

const documentTypeLabels: Record<DocumentType, string> = {
  offer_placed: "Offers Placed",
  client_id: "Client IDs",
  representative_agreement: "Representative Agreements",
  offer_received: "Offers Received",
  property_listing: "Property Listings",
  inspection_report: "Inspection Reports",
  appraisal: "Appraisals",
  legal_document: "Legal Documents",
  financial_document: "Financial Documents",
  insurance: "Insurance Documents",
  lease_agreement: "Lease Agreements",
  purchase_agreement: "Purchase Agreements",
  closing_document: "Closing Documents",
  marketing_material: "Marketing Materials",
  floor_plan: "Floor Plans",
  photo_gallery: "Photo Galleries",
  disclosure_form: "Disclosure Forms",
  warranty: "Warranties",
  contract: "Contracts",
  deed: "Deeds",
  title: "Title Documents",
  survey: "Survey Documents",
  hoa_document: "HOA Documents",
  property_tax: "Property Tax Records",
  utility_bill: "Utility Bills",
  mls_listing: "MLS Listings",
  other: "Other Documents",
};

const documentTypeIcons: Record<DocumentType, any> = {
  offer_placed: DollarSign,
  client_id: Users,
  representative_agreement: FileCheck,
  offer_received: FileText,
  property_listing: FileText,
  inspection_report: FileCheck,
  appraisal: DollarSign,
  legal_document: FileCheck,
  financial_document: DollarSign,
  insurance: FileText,
  lease_agreement: FileCheck,
  purchase_agreement: FileCheck,
  closing_document: FileText,
  marketing_material: FileText,
  floor_plan: FileText,
  photo_gallery: FileText,
  disclosure_form: FileCheck,
  warranty: FileText,
  contract: FileCheck,
  deed: FileText,
  title: FileText,
  survey: FileText,
  hoa_document: FileText,
  property_tax: DollarSign,
  utility_bill: FileText,
  mls_listing: FileText,
  other: FileText,
};

export function DocumentCenterModal({ isOpen, onClose, userId }: DocumentCenterModalProps) {
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const [selectedType, setSelectedType] = useState<DocumentType>("offer_placed");
  const [selectedClient, setSelectedClient] = useState<string>("");
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [file, setFile] = useState<File | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [tags, setTags] = useState<string>("");
  const [expirationDate, setExpirationDate] = useState<string>("");

  // Search and filtering state
  const [searchQuery, setSearchQuery] = useState("");
  const [filterType, setFilterType] = useState<DocumentType | "all">("all");
  const [sortBy, setSortBy] = useState<"name" | "date" | "size" | "type">("date");
  const [sortOrder, setSortOrder] = useState<"asc" | "desc">("desc");

  // Bulk operations state
  const [selectedDocuments, setSelectedDocuments] = useState<Set<string>>(new Set());
  const [bulkFiles, setBulkFiles] = useState<File[]>([]);
  const [showBulkUpload, setShowBulkUpload] = useState(false);
  const [isBulkUploading, setIsBulkUploading] = useState(false);
  const [isBulkDeleting, setIsBulkDeleting] = useState(false);
  const [isBulkDownloading, setIsBulkDownloading] = useState(false);

  // Fetch clients for the dropdown
  const { data: clients = [] } = useQuery<any[]>({
    queryKey: ["/api/clients"],
    enabled: isOpen,
  });

  // Fetch documents
  const { data: documents = [], isLoading } = useQuery<Document[]>({
    queryKey: ["/api/documents", userId],
    queryFn: async () => {
      const response = await apiRequest("GET", `/api/documents/${userId}`);
      return response.json();
    },
    enabled: isOpen && !!userId,
  });

  // Upload document mutation (Object Storage workflow)
  const uploadDocumentMutation = useMutation({
    mutationFn: async ({ file, metadata }: { file: File; metadata: any }) => {
      setIsUploading(true);

      // Step 1: Get presigned upload URL
      const uploadUrlResponse = await apiRequest("POST", "/api/documents/upload");
      const { uploadURL } = await uploadUrlResponse.json();

      // Step 2: Upload file directly to object storage
      const uploadResponse = await fetch(uploadURL, {
        method: "PUT",
        body: file,
        headers: {
          "Content-Type": file.type || "application/octet-stream",
        },
      });

      if (!uploadResponse.ok) {
        throw new Error("Failed to upload file to storage");
      }

      // Step 3: Create document metadata
      const metadataResponse = await apiRequest("PUT", "/api/documents", {
        ...metadata,
        uploadURL,
        mimeType: file.type || "application/octet-stream",
        size: file.size,
        originalName: file.name,
      });

      return metadataResponse.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/documents", userId] });
      toast({
        title: "Document Uploaded",
        description: "Your document has been uploaded successfully.",
      });
      resetForm();
    },
    onError: (error: any) => {
      toast({
        title: "Upload Failed",
        description: error.message || "Failed to upload document. Please try again.",
        variant: "destructive",
      });
    },
    onSettled: () => {
      setIsUploading(false);
    },
  });

  // Delete document mutation
  const deleteDocumentMutation = useMutation({
    mutationFn: async (documentId: string) => {
      await apiRequest("DELETE", `/api/documents/${documentId}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/documents", userId] });
      toast({
        title: "Document Deleted",
        description: "The document has been deleted successfully.",
      });
    },
    onError: () => {
      toast({
        title: "Delete Failed",
        description: "Failed to delete document. Please try again.",
        variant: "destructive",
      });
    },
  });

  // Bulk upload mutation
  const bulkUploadMutation = useMutation({
    mutationFn: async ({ files, documentType }: { files: File[], documentType: DocumentType }) => {
      setIsBulkUploading(true);
      const formData = new FormData();

      // Append each file with metadata
      files.forEach((file, index) => {
        formData.append(`files`, file);
        formData.append(`titles`, file.name.replace(/\.[^/.]+$/, ""));
        formData.append(`descriptions`, `Bulk uploaded document ${index + 1}`);
        formData.append(`documentTypes`, documentType);
      });

      formData.append('userId', userId);

      const response = await fetch("/api/documents/bulk-upload", {
        method: "POST",
        body: formData,
        credentials: "include",
      });

      if (!response.ok) {
        throw new Error("Bulk upload failed");
      }

      return response.json();
    },
    onSuccess: (result) => {
      queryClient.invalidateQueries({ queryKey: ["/api/documents", userId] });
      toast({
        title: "Bulk Upload Complete",
        description: `${result.uploaded.length} documents uploaded successfully. ${result.failed.length > 0 ? `${result.failed.length} failed.` : ''}`,
      });
      setBulkFiles([]);
      setShowBulkUpload(false);
    },
    onError: () => {
      toast({
        title: "Bulk Upload Failed",
        description: "Failed to upload documents. Please try again.",
        variant: "destructive",
      });
    },
    onSettled: () => {
      setIsBulkUploading(false);
    },
  });

  // Bulk delete mutation
  const bulkDeleteMutation = useMutation({
    mutationFn: async (documentIds: string[]) => {
      setIsBulkDeleting(true);
      const response = await apiRequest("DELETE", "/api/documents/bulk-delete", {
        documentIds
      });
      return response.json();
    },
    onSuccess: (result) => {
      queryClient.invalidateQueries({ queryKey: ["/api/documents", userId] });
      toast({
        title: "Bulk Delete Complete",
        description: `${result.deleted.length} documents deleted successfully. ${result.failed.length > 0 ? `${result.failed.length} failed.` : ''}`,
      });
      setSelectedDocuments(new Set());
    },
    onError: () => {
      toast({
        title: "Bulk Delete Failed",
        description: "Failed to delete documents. Please try again.",
        variant: "destructive",
      });
    },
    onSettled: () => {
      setIsBulkDeleting(false);
    },
  });

  // Bulk download mutation
  const bulkDownloadMutation = useMutation({
    mutationFn: async (documentIds: string[]) => {
      setIsBulkDownloading(true);
      const response = await apiRequest("POST", "/api/documents/bulk-download", {
        documentIds,
        zipFilename: `estate-vista-documents-${Date.now()}.zip`
      });
      return response.json();
    },
    onSuccess: (result) => {
      toast({
        title: "Bulk Download Ready",
        description: `Prepared ${result.documentsIncluded} documents for download.`,
      });
      // In a real implementation, this would trigger a file download
      console.log('Bulk download result:', result);
    },
    onError: () => {
      toast({
        title: "Bulk Download Failed",
        description: "Failed to prepare documents for download. Please try again.",
        variant: "destructive",
      });
    },
    onSettled: () => {
      setIsBulkDownloading(false);
    },
  });

  const resetForm = () => {
    setTitle("");
    setDescription("");
    setFile(null);
    setSelectedType("offer_placed");
    setSelectedClient("");
    setTags("");
    setExpirationDate("");
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      setFile(selectedFile);
      if (!title) {
        setTitle(selectedFile.name.replace(/\.[^/.]+$/, ""));
      }
    }
  };

  const handleUpload = () => {
    if (!file || !title.trim()) {
      toast({
        title: "Missing Information",
        description: "Please select a file and provide a title.",
        variant: "destructive",
      });
      return;
    }

    const processedTags = tags.trim() 
      ? tags.split(',').map(tag => tag.trim()).filter(Boolean) 
      : undefined;

    const metadata = {
      title: title.trim(),
      description: description.trim(),
      documentType: selectedType,
      clientId: selectedClient || undefined,
      tags: processedTags && processedTags.length > 0 ? processedTags.join(',') : undefined,
      expirationDate: expirationDate || undefined,
    };

    uploadDocumentMutation.mutate({ file, metadata });
  };

  const handleDownload = async (document: Document) => {
    try {
      const response = await fetch(`/api/documents/${document.id}/download`, {
        credentials: "include",
      });

      if (!response.ok) {
        throw new Error("Download failed");
      }

      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);
      const a = window.document.createElement("a");
      a.href = url;
      a.download = document.originalName;
      window.document.body.appendChild(a);
      a.click();
      window.URL.revokeObjectURL(url);
      window.document.body.removeChild(a);

      toast({
        title: "Download Started",
        description: `Downloading ${document.title}`,
      });
    } catch (error) {
      toast({
        title: "Download Failed",
        description: "Failed to download document. Please try again.",
        variant: "destructive",
      });
    }
  };

  const handleDelete = (documentId: string) => {
    if (confirm("Are you sure you want to delete this document? This action cannot be undone.")) {
      deleteDocumentMutation.mutate(documentId);
    }
  };

  // Bulk operations helper functions
  const handleBulkFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    setBulkFiles(files);
  };

  const handleBulkUpload = () => {
    if (bulkFiles.length === 0) {
      toast({
        title: "No Files Selected",
        description: "Please select files to upload.",
        variant: "destructive",
      });
      return;
    }

    bulkUploadMutation.mutate({
      files: bulkFiles,
      documentType: selectedType
    });
  };

  const toggleDocumentSelection = (documentId: string) => {
    const newSelection = new Set(selectedDocuments);
    if (newSelection.has(documentId)) {
      newSelection.delete(documentId);
    } else {
      newSelection.add(documentId);
    }
    setSelectedDocuments(newSelection);
  };

  const selectAllDocuments = () => {
    if (selectedDocuments.size === documents.length) {
      setSelectedDocuments(new Set());
    } else {
      setSelectedDocuments(new Set(documents.map(doc => doc.id)));
    }
  };

  const handleBulkDelete = () => {
    if (selectedDocuments.size === 0) {
      toast({
        title: "No Documents Selected",
        description: "Please select documents to delete.",
        variant: "destructive",
      });
      return;
    }

    if (confirm(`Are you sure you want to delete ${selectedDocuments.size} documents? This action cannot be undone.`)) {
      bulkDeleteMutation.mutate(Array.from(selectedDocuments));
    }
  };

  const handleBulkDownload = () => {
    if (selectedDocuments.size === 0) {
      toast({
        title: "No Documents Selected", 
        description: "Please select documents to download.",
        variant: "destructive",
      });
      return;
    }

    bulkDownloadMutation.mutate(Array.from(selectedDocuments));
  };

  const resetBulkOperations = () => {
    setSelectedDocuments(new Set());
    setBulkFiles([]);
    setShowBulkUpload(false);
  };

  // Filter and sort documents
  const filteredAndSortedDocuments = () => {
    let filtered = documents;

    // Apply search query
    if (searchQuery) {
      filtered = filtered.filter(doc => 
        doc.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
        doc.description?.toLowerCase().includes(searchQuery.toLowerCase()) ||
        doc.originalName.toLowerCase().includes(searchQuery.toLowerCase()) ||
        (doc.tags && doc.tags.some(tag => tag.toLowerCase().includes(searchQuery.toLowerCase())))
      );
    }

    // Apply type filter
    if (filterType !== "all") {
      filtered = filtered.filter(doc => doc.documentType === filterType);
    }

    // Apply sorting
    filtered.sort((a, b) => {
      let comparison = 0;
      switch (sortBy) {
        case "name":
          comparison = a.title.localeCompare(b.title);
          break;
        case "date":
          const aDate = a.createdAt ? new Date(a.createdAt).getTime() : 0;
          const bDate = b.createdAt ? new Date(b.createdAt).getTime() : 0;
          comparison = aDate - bDate;
          break;
        case "size":
          comparison = a.size - b.size;
          break;
        case "type":
          comparison = a.documentType.localeCompare(b.documentType);
          break;
      }
      return sortOrder === "asc" ? comparison : -comparison;
    });

    return filtered;
  };

  const getDocumentsByType = (type: DocumentType) => {
    const allFiltered = filteredAndSortedDocuments();
    return allFiltered.filter(doc => doc.documentType === type);
  };

  const formatFileSize = (bytes: number) => {
    if (bytes === 0) return "0 B";
    const k = 1024;
    const sizes = ["B", "KB", "MB", "GB"];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + " " + sizes[i];
  };

  const formatTags = (tags: string[] | null) => {
    if (!tags || tags.length === 0) return null;
    return tags.map((tag, index) => (
      <Badge key={index} variant="outline" className="text-xs mr-1 mb-1">
        {tag}
      </Badge>
    ));
  };

  const isExpired = (expirationDate: string | Date | null) => {
    if (!expirationDate) return false;
    const expiry = typeof expirationDate === 'string' ? new Date(expirationDate) : expirationDate;
    return expiry < new Date();
  };

  const isExpiringSoon = (expirationDate: string | Date | null) => {
    if (!expirationDate) return false;
    const expiry = typeof expirationDate === 'string' ? new Date(expirationDate) : expirationDate;
    const now = new Date();
    const threeDaysFromNow = new Date(now.getTime() + 3 * 24 * 60 * 60 * 1000);
    return expiry > now && expiry <= threeDaysFromNow;
  };

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-6xl max-h-[80vh] overflow-y-auto" data-testid="dialog-document-center">
        <DialogHeader>
          <DialogTitle>Document Center</DialogTitle>
        </DialogHeader>

        <div className="space-y-6">
          {/* Upload Section */}
          <div className="border rounded-lg p-6">
            <h3 className="text-lg font-semibold mb-4">Upload New Document</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <Label htmlFor="document-type">Document Type</Label>
                <Select value={selectedType} onValueChange={(value: DocumentType) => setSelectedType(value)}>
                  <SelectTrigger data-testid="select-document-type">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {Object.entries(documentTypeLabels).map(([type, label]) => (
                      <SelectItem key={type} value={type}>
                        {label}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <div>
                <Label htmlFor="document-title">Title</Label>
                <Input
                  id="document-title"
                  value={title}
                  onChange={(e) => setTitle(e.target.value)}
                  placeholder="Document title"
                  data-testid="input-document-title"
                />
              </div>

              <div className="md:col-span-2">
                <Label htmlFor="document-client">Associate with Client (Optional)</Label>
                <Select value={selectedClient} onValueChange={setSelectedClient}>
                  <SelectTrigger data-testid="select-document-client">
                    <SelectValue placeholder="Select a client (or leave blank for general documents)" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="null" data-testid="option-no-client">No Client (General Document)</SelectItem>
                    {clients.map((client) => (
                      <SelectItem 
                        key={client.id} 
                        value={client.id}
                        data-testid={`option-client-${client.id}`}
                      >
                        {client.firstName} {client.lastName} ({client.email})
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                <p className="text-xs text-muted-foreground mt-1">
                  Link this document to a specific client or leave blank for general documents
                </p>
              </div>

              <div className="md:col-span-2">
                <Label htmlFor="document-description">Description (Optional)</Label>
                <Textarea
                  id="document-description"
                  value={description}
                  onChange={(e) => setDescription(e.target.value)}
                  placeholder="Document description"
                  data-testid="textarea-document-description"
                />
              </div>

              <div>
                <Label htmlFor="document-tags">Tags (Optional)</Label>
                <Input
                  id="document-tags"
                  value={tags}
                  onChange={(e) => setTags(e.target.value)}
                  placeholder="e.g. urgent, review, final"
                  data-testid="input-document-tags"
                />
                <p className="text-xs text-muted-foreground mt-1">
                  Separate multiple tags with commas
                </p>
              </div>

              <div>
                <Label htmlFor="document-expiration">Expiration Date (Optional)</Label>
                <Input
                  id="document-expiration"
                  type="date"
                  value={expirationDate}
                  onChange={(e) => setExpirationDate(e.target.value)}
                  data-testid="input-document-expiration"
                />
                <p className="text-xs text-muted-foreground mt-1">
                  Set an expiration date for time-sensitive documents
                </p>
              </div>

              <div className="md:col-span-2">
                <Label htmlFor="document-file">File</Label>
                <Input
                  id="document-file"
                  type="file"
                  onChange={handleFileChange}
                  accept=".pdf,.doc,.docx,.xls,.xlsx,.ppt,.pptx,.jpg,.jpeg,.png,.gif,.bmp,.tiff,.svg,.txt,.rtf,.csv,.xml,.html,.zip,.rar,.dwg,.cad,.mp4,.mov,.avi,.wmv,.mp3,.wav"
                  data-testid="input-document-file"
                />
                {file && (
                  <p className="text-sm text-muted-foreground mt-1">
                    Selected: {file.name} ({formatFileSize(file.size)})
                  </p>
                )}
              </div>

              <div className="md:col-span-2 flex gap-2">
                <Button
                  onClick={handleUpload}
                  disabled={isUploading || !file || !title.trim()}
                  className="flex-1"
                  data-testid="button-upload-document"
                >
                  <Upload className="mr-2 h-4 w-4" />
                  {isUploading ? "Uploading..." : "Upload Document"}
                </Button>

                <Button
                  onClick={() => setShowBulkUpload(!showBulkUpload)}
                  variant="outline"
                  data-testid="button-toggle-bulk-upload"
                >
                  <Archive className="h-4 w-4 mr-2" />
                  Bulk Upload
                </Button>
              </div>
            </div>
          </div>

          {/* Bulk Upload Section */}
          {showBulkUpload && (
            <div className="border rounded-lg p-6 bg-blue-50 dark:bg-blue-950">
              <h3 className="text-lg font-semibold mb-4">Bulk Upload Documents</h3>
              <div className="space-y-4">
                <div>
                  <Label htmlFor="bulk-document-type">Document Type for All Files</Label>
                  <Select value={selectedType} onValueChange={(value: DocumentType) => setSelectedType(value)}>
                    <SelectTrigger data-testid="select-bulk-document-type">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      {Object.entries(documentTypeLabels).map(([type, label]) => (
                        <SelectItem key={type} value={type}>
                          {label}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>

                <div>
                  <Label htmlFor="bulk-files">Select Multiple Files</Label>
                  <Input
                    id="bulk-files"
                    type="file"
                    multiple
                    onChange={handleBulkFileChange}
                    accept=".pdf,.doc,.docx,.xls,.xlsx,.ppt,.pptx,.jpg,.jpeg,.png,.gif,.bmp,.tiff,.svg,.txt,.rtf,.csv,.xml,.html,.zip,.rar,.dwg,.cad,.mp4,.mov,.avi,.wmv,.mp3,.wav"
                    data-testid="input-bulk-files"
                  />
                  {bulkFiles.length > 0 && (
                    <div className="mt-2">
                      <p className="text-sm text-muted-foreground mb-1">
                        Selected {bulkFiles.length} files:
                      </p>
                      <div className="max-h-32 overflow-y-auto bg-white dark:bg-gray-800 border rounded p-2">
                        {bulkFiles.map((file, index) => (
                          <div key={index} className="text-sm py-1 flex justify-between">
                            <span>{file.name}</span>
                            <span className="text-muted-foreground">{formatFileSize(file.size)}</span>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}
                </div>

                <div className="flex gap-2">
                  <Button
                    onClick={handleBulkUpload}
                    disabled={bulkFiles.length === 0 || isBulkUploading}
                    className="flex-1"
                    data-testid="button-bulk-upload"
                  >
                    <Upload className="h-4 w-4 mr-2" />
                    {isBulkUploading ? "Uploading..." : `Upload ${bulkFiles.length} Documents`}
                  </Button>

                  <Button
                    onClick={() => {setBulkFiles([]); setShowBulkUpload(false);}}
                    variant="outline"
                    data-testid="button-cancel-bulk-upload"
                  >
                    Cancel
                  </Button>
                </div>
              </div>
            </div>
          )}

          {/* Bulk Actions for Existing Documents */}
          {documents.length > 0 && (
            <div className="border rounded-lg p-4 bg-gray-50 dark:bg-gray-900">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-4">
                  <div className="flex items-center gap-2">
                    <Checkbox
                      checked={selectedDocuments.size === documents.length && documents.length > 0}
                      onCheckedChange={selectAllDocuments}
                      data-testid="checkbox-select-all"
                    />
                    <span className="text-sm font-medium">
                      Select All ({selectedDocuments.size} of {documents.length} selected)
                    </span>
                  </div>
                </div>

                {selectedDocuments.size > 0 && (
                  <div className="flex gap-2">
                    <Button
                      onClick={handleBulkDownload}
                      variant="outline"
                      size="sm"
                      disabled={isBulkDownloading}
                      data-testid="button-bulk-download"
                    >
                      <Download className="h-4 w-4 mr-1" />
                      {isBulkDownloading ? "Preparing..." : `Download (${selectedDocuments.size})`}
                    </Button>

                    <Button
                      onClick={handleBulkDelete}
                      variant="destructive"
                      size="sm"
                      disabled={isBulkDeleting}
                      data-testid="button-bulk-delete"
                    >
                      <Trash2 className="h-4 w-4 mr-1" />
                      {isBulkDeleting ? "Deleting..." : `Delete (${selectedDocuments.size})`}
                    </Button>
                  </div>
                )}
              </div>

              {selectedDocuments.size > 0 && (
                <div className="text-sm text-muted-foreground">
                  {selectedDocuments.size} document(s) selected for bulk operations
                </div>
              )}
            </div>
          )}

          {/* Search and Filtering */}
          {documents.length > 0 && (
            <div className="border rounded-lg p-6 bg-blue-50 dark:bg-blue-950">
              <h3 className="text-lg font-semibold mb-4">Search & Filter Documents</h3>
              <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <div className="md:col-span-2">
                  <Label htmlFor="search-documents">Search Documents</Label>
                  <Input
                    id="search-documents"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    placeholder="Search by title, description, filename, or tags..."
                    data-testid="input-search-documents"
                  />
                </div>

                <div>
                  <Label htmlFor="filter-type">Filter by Type</Label>
                  <Select value={filterType} onValueChange={(value: DocumentType | "all") => setFilterType(value)}>
                    <SelectTrigger data-testid="select-filter-type">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="all">All Documents</SelectItem>
                      {Object.entries(documentTypeLabels).map(([type, label]) => (
                        <SelectItem key={type} value={type}>
                          {label}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>

                <div>
                  <Label htmlFor="sort-options">Sort By</Label>
                  <div className="flex gap-2">
                    <Select value={sortBy} onValueChange={(value: "name" | "date" | "size" | "type") => setSortBy(value)}>
                      <SelectTrigger className="flex-1" data-testid="select-sort-by">
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="date">Date</SelectItem>
                        <SelectItem value="name">Name</SelectItem>
                        <SelectItem value="size">Size</SelectItem>
                        <SelectItem value="type">Type</SelectItem>
                      </SelectContent>
                    </Select>
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() => setSortOrder(sortOrder === "asc" ? "desc" : "asc")}
                      data-testid="button-sort-order"
                    >
                      {sortOrder === "asc" ? "↑" : "↓"}
                    </Button>
                  </div>
                </div>
              </div>

              <div className="mt-4 flex items-center justify-between text-sm text-muted-foreground">
                <span>
                  Showing {filteredAndSortedDocuments().length} of {documents.length} documents
                </span>
                {(searchQuery || filterType !== "all") && (
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() => {
                      setSearchQuery("");
                      setFilterType("all");
                    }}
                    data-testid="button-clear-filters"
                  >
                    Clear Filters
                  </Button>
                )}
              </div>
            </div>
          )}

          {/* Documents by Type */}
          <div className="space-y-6">
            {Object.entries(documentTypeLabels).map(([type, label]) => {
              const Icon = documentTypeIcons[type as DocumentType];
              const typeDocuments = getDocumentsByType(type as DocumentType);

              return (
                <div key={type} className="border rounded-lg p-6">
                  <div className="flex items-center justify-between mb-4">
                    <div className="flex items-center">
                      <Icon className="h-5 w-5 mr-2" />
                      <h3 className="text-lg font-semibold">{label}</h3>
                      <Badge variant="secondary" className="ml-2">
                        {typeDocuments.length}
                      </Badge>
                    </div>
                  </div>

                  {isLoading ? (
                    <div className="space-y-2">
                      {[1, 2].map((i) => (
                        <div key={i} className="animate-pulse border rounded p-3">
                          <div className="h-4 bg-muted rounded w-1/3 mb-2"></div>
                          <div className="h-3 bg-muted rounded w-1/2"></div>
                        </div>
                      ))}
                    </div>
                  ) : typeDocuments.length === 0 ? (
                    <div className="text-center py-8 text-muted-foreground">
                      No {label.toLowerCase()} uploaded yet
                    </div>
                  ) : (
                    <div className="space-y-3">
                      {typeDocuments.map((document) => (
                        <div
                          key={document.id}
                          className="flex items-center justify-between p-3 border rounded hover:bg-muted/50"
                          data-testid={`document-item-${document.id}`}
                        >
                          <div className="flex items-center gap-3 flex-1">
                            <Checkbox
                              checked={selectedDocuments.has(document.id)}
                              onCheckedChange={() => toggleDocumentSelection(document.id)}
                              data-testid={`checkbox-document-${document.id}`}
                            />

                            <div className="flex-1">
                              <div className="flex items-center gap-2">
                                <div className="font-medium">{document.title}</div>
                                {isExpired(document.expirationDate) && (
                                  <Badge variant="destructive" className="text-xs">
                                    Expired
                                  </Badge>
                                )}
                                {isExpiringSoon(document.expirationDate) && (
                                  <Badge variant="outline" className="text-xs border-orange-500 text-orange-600">
                                    Expires Soon
                                  </Badge>
                                )}
                              </div>

                              <div className="text-sm text-muted-foreground">
                                {document.description && (
                                  <span>{document.description} • </span>
                                )}
                                {formatFileSize(document.size)} • 
                                {document.createdAt ? new Date(document.createdAt).toLocaleDateString() : "Unknown date"}
                                {document.expirationDate && (
                                  <span> • Expires: {new Date(document.expirationDate).toLocaleDateString()}</span>
                                )}
                              </div>

                              {document.tags && document.tags.length > 0 && (
                                <div className="mt-1 flex flex-wrap gap-1">
                                  {formatTags(document.tags)}
                                </div>
                              )}
                            </div>
                          </div>
                          <div className="flex items-center gap-2">
                            <Button
                              variant="outline"
                              size="sm"
                              onClick={() => handleDownload(document)}
                              data-testid={`button-download-${document.id}`}
                            >
                              <Download className="h-4 w-4" />
                            </Button>
                            <Button
                              variant="outline"
                              size="sm"
                              onClick={() => handleDelete(document.id)}
                              data-testid={`button-delete-${document.id}`}
                            >
                              <Trash2 className="h-4 w-4" />
                            </Button>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </div>

        <div className="flex justify-end">
          <Button variant="outline" onClick={onClose} data-testid="button-close-document-center">
            Close
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
}

export default DocumentCenterModal;

client/src/components/PersonalCalendarMo.content:
import { useState } from "react";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Calendar } from "@/components/ui/calendar";
import { Badge } from "@/components/ui/badge";
import { Card, CardContent } from "@/components/ui/card";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";
import { Calendar as CalendarIcon, Clock, Plus, Trash2, Edit, X } from "lucide-react";
import { format } from "date-fns";
import type { CalendarEvent, InsertCalendarEvent } from "@shared/schema";

interface PersonalCalendarModalProps {
  isOpen: boolean;
  onClose: () => void;
  userId: string;
}

type BlockType = "tour" | "showing" | "personal" | "blocked";

const blockTypeLabels: Record<BlockType, string> = {
  tour: "Tour",
  showing: "Showing", 
  personal: "Personal Time",
  blocked: "Blocked",
};

const blockTypeColors: Record<BlockType, string> = {
  tour: "bg-green-500",
  showing: "bg-blue-500",
  personal: "bg-purple-500",
  blocked: "bg-red-500",
};

export function PersonalCalendarModal({ isOpen, onClose, userId }: PersonalCalendarModalProps) {
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const [selectedDate, setSelectedDate] = useState<Date>(new Date());
  const [showAddForm, setShowAddForm] = useState(false);
  const [editingBlock, setEditingBlock] = useState<CalendarEvent | null>(null);

  // Form state
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [blockType, setBlockType] = useState<BlockType>("blocked");
  const [startTime, setStartTime] = useState("");
  const [endTime, setEndTime] = useState("");

  // Fetch calendar blocks
  const { data: calendarBlocks = [], isLoading } = useQuery<CalendarEvent[]>({
    queryKey: ["/api/calendar-events", userId],
    queryFn: async () => {
      const response = await apiRequest("GET", `/api/calendar-events/${userId}`);
      return response.json();
    },
    enabled: isOpen && !!userId,
  });

  // Create calendar block mutation
  const createBlockMutation = useMutation({
    mutationFn: async (data: InsertCalendarEvent) => {
      const response = await apiRequest("POST", "/api/calendar-events", data);
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/calendar-events", userId] });
      toast({
        title: "Calendar Block Added",
        description: "Your calendar block has been added successfully.",
      });
      resetForm();
    },
    onError: () => {
      toast({
        title: "Failed to Add Block",
        description: "Could not add calendar block. Please try again.",
        variant: "destructive",
      });
    },
  });

  // Update calendar block mutation
  const updateBlockMutation = useMutation({
    mutationFn: async ({ id, data }: { id: string; data: Partial<CalendarEvent> }) => {
      const response = await apiRequest("PATCH", `/api/calendar-events/${id}`, data);
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/calendar-events", userId] });
      toast({
        title: "Calendar Block Updated",
        description: "Your calendar block has been updated successfully.",
      });
      resetForm();
    },
    onError: () => {
      toast({
        title: "Failed to Update Block",
        description: "Could not update calendar block. Please try again.",
        variant: "destructive",
      });
    },
  });

  // Delete calendar block mutation
  const deleteBlockMutation = useMutation({
    mutationFn: async (blockId: string) => {
      await apiRequest("DELETE", `/api/calendar-events/${blockId}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/calendar-events", userId] });
      toast({
        title: "Calendar Block Deleted",
        description: "The calendar block has been deleted successfully.",
      });
    },
    onError: () => {
      toast({
        title: "Delete Failed",
        description: "Failed to delete calendar block. Please try again.",
        variant: "destructive",
      });
    },
  });

  const resetForm = () => {
    setTitle("");
    setDescription("");
    setBlockType("blocked");
    setStartTime("");
    setEndTime("");
    setShowAddForm(false);
    setEditingBlock(null);
  };

  const handleAddBlock = () => {
    if (!title.trim() || !startTime || !endTime) {
      toast({
        title: "Missing Information",
        description: "Please fill in all required fields.",
        variant: "destructive",
      });
      return;
    }

    const startDateTime = new Date(selectedDate);
    const [startHour, startMin] = startTime.split(':').map(Number);
    startDateTime.setHours(startHour, startMin, 0, 0);

    const endDateTime = new Date(selectedDate);
    const [endHour, endMin] = endTime.split(':').map(Number);
    endDateTime.setHours(endHour, endMin, 0, 0);

    if (endDateTime <= startDateTime) {
      toast({
        title: "Invalid Time Range",
        description: "End time must be after start time.",
        variant: "destructive",
      });
      return;
    }

    const blockData: InsertCalendarEvent = {
      userId,
      title,
      description: description || null,
      eventType: blockType,
      startTime: startDateTime,
      endTime: endDateTime,
      isBlocked: true,
    };

    if (editingBlock) {
      updateBlockMutation.mutate({ id: editingBlock.id, data: blockData });
    } else {
      createBlockMutation.mutate(blockData);
    }
  };

  const handleEditBlock = (block: CalendarEvent) => {
    setEditingBlock(block);
    setTitle(block.title);
    setDescription(block.description || "");
    setBlockType(block.eventType as BlockType);

    if (block.startTime) {
      const start = new Date(block.startTime);
      setStartTime(format(start, "HH:mm"));
      setSelectedDate(start);
    }

    if (block.endTime) {
      const end = new Date(block.endTime);
      setEndTime(format(end, "HH:mm"));
    }

    setShowAddForm(true);
  };

  const handleDeleteBlock = (blockId: string) => {
    if (confirm("Are you sure you want to delete this calendar block?")) {
      deleteBlockMutation.mutate(blockId);
    }
  };

  const getBlocksForDate = (date: Date) => {
    return calendarBlocks.filter(block => {
      if (!block.startTime) return false;
      const blockDate = new Date(block.startTime);
      return blockDate.toDateString() === date.toDateString();
    });
  };

  const selectedDateBlocks = getBlocksForDate(selectedDate);

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-4xl max-h-[80vh] overflow-y-auto" data-testid="dialog-personal-calendar">
        <DialogHeader>
          <DialogTitle className="flex items-center">
            <CalendarIcon className="mr-2 h-5 w-5" />
            Personal Calendar & Blocking
          </DialogTitle>
        </DialogHeader>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {/* Calendar Side */}
          <div className="space-y-4">
            <div>
              <h3 className="text-lg font-semibold mb-4">Select Date</h3>
              <Calendar
                mode="single"
                selected={selectedDate}
                onSelect={(date) => date && setSelectedDate(date)}
                className="rounded-md border"
                data-testid="calendar-date-picker"
              />
            </div>

            <Button
              onClick={() => setShowAddForm(true)}
              className="w-full"
              disabled={showAddForm}
              data-testid="button-add-calendar-block"
            >
              <Plus className="mr-2 h-4 w-4" />
              Add Time Block
            </Button>
          </div>

          {/* Blocks and Form Side */}
          <div className="space-y-4">
            {/* Add/Edit Form */}
            {showAddForm && (
              <Card>
                <CardContent className="p-4">
                  <div className="flex items-center justify-between mb-4">
                    <h4 className="font-semibold">
                      {editingBlock ? "Edit Time Block" : "Add Time Block"}
                    </h4>
                    <Button variant="ghost" size="sm" onClick={resetForm}>
                      <X className="h-4 w-4" />
                    </Button>
                  </div>

                  <div className="space-y-3">
                    <div>
                      <Label htmlFor="block-title">Title *</Label>
                      <Input
                        id="block-title"
                        value={title}
                        onChange={(e) => setTitle(e.target.value)}
                        placeholder="e.g., Dentist appointment, Personal time"
                        data-testid="input-block-title"
                      />
                    </div>

                    <div>
                      <Label htmlFor="block-type">Type</Label>
                      <Select value={blockType} onValueChange={(value: BlockType) => setBlockType(value)}>
                        <SelectTrigger data-testid="select-block-type">
                          <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                          {Object.entries(blockTypeLabels).map(([type, label]) => (
                            <SelectItem key={type} value={type}>
                              {label}
                            </SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                    </div>

                    <div className="grid grid-cols-2 gap-3">
                      <div>
                        <Label htmlFor="start-time">Start Time *</Label>
                        <Input
                          id="start-time"
                          type="time"
                          value={startTime}
                          onChange={(e) => setStartTime(e.target.value)}
                          data-testid="input-start-time"
                        />
                      </div>
                      <div>
                        <Label htmlFor="end-time">End Time *</Label>
                        <Input
                          id="end-time"
                          type="time"
                          value={endTime}
                          onChange={(e) => setEndTime(e.target.value)}
                          data-testid="input-end-time"
                        />
                      </div>
                    </div>

                    <div>
                      <Label htmlFor="block-description">Description</Label>
                      <Textarea
                        id="block-description"
                        value={description}
                        onChange={(e) => setDescription(e.target.value)}
                        placeholder="Additional details (optional)"
                        data-testid="textarea-block-description"
                      />
                    </div>

                    <div className="flex gap-2">
                      <Button
                        onClick={handleAddBlock}
                        disabled={createBlockMutation.isPending || updateBlockMutation.isPending}
                        data-testid="button-save-block"
                      >
                        {editingBlock ? "Update Block" : "Add Block"}
                      </Button>
                      <Button variant="outline" onClick={resetForm}>
                        Cancel
                      </Button>
                    </div>
                  </div>
                </CardContent>
              </Card>
            )}

            {/* Blocks for Selected Date */}
            <div>
              <h3 className="text-lg font-semibold mb-4">
                Blocks for {format(selectedDate, "MMMM d, yyyy")}
                <Badge variant="secondary" className="ml-2">
                  {selectedDateBlocks.length}
                </Badge>
              </h3>

              {isLoading ? (
                <div className="space-y-3">
                  {[1, 2, 3].map((i) => (
                    <div key={i} className="animate-pulse border rounded-lg p-3">
                      <div className="h-4 bg-muted rounded w-1/3 mb-2"></div>
                      <div className="h-3 bg-muted rounded w-1/2"></div>
                    </div>
                  ))}
                </div>
              ) : selectedDateBlocks.length === 0 ? (
                <div className="text-center py-8 text-muted-foreground border rounded-lg">
                  No blocks scheduled for this date
                </div>
              ) : (
                <div className="space-y-3">
                  {selectedDateBlocks
                    .sort((a, b) => {
                      if (!a.startTime || !b.startTime) return 0;
                      return new Date(a.startTime).getTime() - new Date(b.startTime).getTime();
                    })
                    .map((block) => (
                      <div
                        key={block.id}
                        className="flex items-center justify-between p-3 border rounded-lg hover:bg-muted/50"
                        data-testid={`calendar-block-${block.id}`}
                      >
                        <div className="flex-1">
                          <div className="flex items-center gap-2 mb-1">
                            <div className={`w-3 h-3 rounded-full ${blockTypeColors[block.eventType as BlockType]}`}></div>
                            <span className="font-medium">{block.title}</span>
                            <Badge variant="outline" className="text-xs">
                              {blockTypeLabels[block.eventType as BlockType]}
                            </Badge>
                          </div>
                          <div className="text-sm text-muted-foreground">
                            <Clock className="inline h-3 w-3 mr-1" />
                            {block.startTime && format(new Date(block.startTime), "h:mm a")} - 
                            {block.endTime && format(new Date(block.endTime), "h:mm a")}
                            {block.description && (
                              <span className="ml-2">• {block.description}</span>
                            )}
                          </div>
                        </div>
                        <div className="flex items-center gap-2">
                          <Button
                            variant="outline"
                            size="sm"
                            onClick={() => handleEditBlock(block)}
                            data-testid={`button-edit-${block.id}`}
                          >
                            <Edit className="h-4 w-4" />
                          </Button>
                          <Button
                            variant="outline"
                            size="sm"
                            onClick={() => handleDeleteBlock(block.id)}
                            data-testid={`button-delete-${block.id}`}
                          >
                            <Trash2 className="h-4 w-4" />
                          </Button>
                        </div>
                      </div>
                    ))}
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="flex justify-end">
          <Button variant="outline" onClick={onClose} data-testid="button-close-personal-calendar">
            Close
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
}

