import { useState } from "react";
import { useMutation } from "@tanstack/react-query";
import { useToast } from "@/hooks/use-toast";
import { apiRequest, queryClient } from "@/lib/queryClient";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { CheckCircle } from "lucide-react";

interface TourCompletionModalProps {
  isOpen: boolean;
  onClose: () => void;
  tourId: string;
}

export function TourCompletionModal({
  isOpen,
  onClose,
  tourId,
}: TourCompletionModalProps) {
  const { toast } = useToast();
  const [notes, setNotes] = useState("");

  const completeTourMutation = useMutation({
    mutationFn: async () => {
      await apiRequest("PATCH", `/api/tours/${tourId}/complete`, {});
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/tours"] });
      toast({
        title: "Success",
        description: "Tour marked as completed. Client will receive feedback request.",
      });
      setNotes("");
      onClose();
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to complete tour",
        variant: "destructive",
      });
    },
  });

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>Complete Tour</DialogTitle>
          <DialogDescription>
            Mark this tour as completed. The client will be notified and asked for feedback.
          </DialogDescription>
        </DialogHeader>

        <div className="space-y-4">
          <div>
            <label className="text-sm font-medium">Tour Notes (Optional)</label>
            <Textarea
              placeholder="Add any notes about this tour..."
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              className="mt-2"
            />
          </div>

          <div className="flex gap-3 justify-end">
            <Button variant="outline" onClick={onClose}>
              Cancel
            </Button>
            <Button
              onClick={() => completeTourMutation.mutate()}
              disabled={completeTourMutation.isPending}
              className="bg-primary text-primary-foreground hover:bg-primary/90"
            >
              <CheckCircle className="h-4 w-4 mr-2" />
              Mark as Complete
            </Button>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

client/src/components/UpcomingTourDetail.content:
import { useState, useRef } from "react";
import { useMutation, useQuery } from "@tanstack/react-query";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";
import GooglePlacesAutocomplete from "react-google-autocomplete";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import {
  Calendar,
  Clock,
  MapPin,
  Car,
  Home,
  Navigation,
  Loader,
} from "lucide-react";

interface UpcomingTourDetailsModalProps {
  isOpen: boolean;
  onClose: () => void;
  tour: any;
}

interface RouteOptimization {
  optimizedOrder: any[];
  totalDistance: string;
  totalDuration: string;
  startLocation: string;
}

export default function UpcomingTourDetailsModal({
  isOpen,
  onClose,
  tour,
}: UpcomingTourDetailsModalProps) {
  const { toast } = useToast();
  const [startingAddress, setStartingAddress] = useState("");
  const [optimizedRoute, setOptimizedRoute] = useState<RouteOptimization | null>(null);

  // Fetch tour properties (contains propertyId and order)
  const { data: tourPropertiesRaw = [], isLoading: propertiesLoading } = useQuery<any[]>({
    queryKey: [`/api/tours/${tour?.id}/properties`],
    enabled: isOpen && !!tour,
  });

  // Fetch all properties to get full details
  const { data: allProperties = [] } = useQuery<any[]>({
    queryKey: ["/api/properties"],
    enabled: isOpen && !!tour,
  });

  // Merge tour properties with full property details
  const tourProperties = tourPropertiesRaw
    .map((tp: any) => {
      const fullProperty = allProperties.find((p: any) => p.id === tp.propertyId);
      return {
        ...tp,
        ...fullProperty,
        address: fullProperty?.address || "Unknown Address",
        bedrooms: fullProperty?.bedrooms || 0,
        bathrooms: fullProperty?.bathrooms || 0,
        price: fullProperty?.price || 0,
      };
    })
    .sort((a: any, b: any) => (a.order || 0) - (b.order || 0));

  // Route optimization mutation
  const optimizeRouteMutation = useMutation({
    mutationFn: async (data: { startingAddress: string; tours: any[] }) => {
      const response = await apiRequest("POST", "/api/tours/optimize-route", data);
      return response.json();
    },
    onSuccess: (result: RouteOptimization) => {
      setOptimizedRoute(result);
      toast({
        title: "Route Optimized",
        description: `Route calculated: ${result.totalDistance}, ${result.totalDuration}`,
      });
    },
    onError: () => {
      toast({
        title: "Optimization Failed",
        description: "Could not optimize route. Please try again.",
        variant: "destructive",
      });
    },
  });

  const handleOptimizeRoute = () => {
    if (!startingAddress.trim()) {
      toast({
        title: "Starting Address Required",
        description: "Please enter your starting address.",
        variant: "destructive",
      });
      return;
    }

    if (tourProperties.length === 0) {
      toast({
        title: "No Properties",
        description: "This tour has no properties scheduled.",
        variant: "destructive",
      });
      return;
    }

    // Transform properties to tour format
    const toursForOptimization = tourProperties.map((prop: any) => ({
      id: prop.propertyId,
      propertyAddress: prop.address,
      clientName: "Tour",
      scheduledTime: "",
      duration: 30,
      latitude: prop.latitude,
      longitude: prop.longitude,
    }));

    optimizeRouteMutation.mutate({
      startingAddress,
      tours: toursForOptimization,
    });
  };

  const handleStartNavigation = () => {
    if (!optimizedRoute || optimizedRoute.optimizedOrder.length === 0) {
      toast({
        title: "No Route Available",
        description: "Please optimize a route first.",
        variant: "destructive",
      });
      return;
    }

    try {
      const origin = encodeURIComponent(startingAddress);
      const stops = optimizedRoute.optimizedOrder;
      const destination = encodeURIComponent(stops[stops.length - 1].propertyAddress);

      const waypoints = stops
        .slice(0, -1)
        .map((stop: any) => encodeURIComponent(stop.propertyAddress))
        .join("|");

      let mapsUrl = `https://www.google.com/maps/dir/?api=1&origin=${origin}&destination=${destination}`;
      if (waypoints) {
        mapsUrl += `&waypoints=${waypoints}`;
      }

      window.open(mapsUrl, "_blank");
    } catch (error) {
      toast({
        title: "Error",
        description: "Could not open Google Maps. Please try again.",
        variant: "destructive",
      });
    }
  };

  if (!tour) return null;

  const tourDate = new Date(tour.scheduledDate);

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-auto">
        <DialogHeader>
          <DialogTitle>Tour Details</DialogTitle>
        </DialogHeader>

        <div className="space-y-6">
          {/* Tour Header */}
          <div className="space-y-3">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Calendar className="h-4 w-4 text-muted-foreground" />
                <span className="font-medium">{tourDate.toLocaleDateString()}</span>
                <Badge className="bg-accent text-accent-foreground">
                  {tour.status === "scheduled" ? "Confirmed" : tour.status}
                </Badge>
              </div>
            </div>
            <div className="flex items-center gap-2 text-sm text-muted-foreground">
              <Clock className="h-4 w-4" />
              <span>
                {tourDate.toLocaleTimeString([], {
                  hour: "2-digit",
                  minute: "2-digit",
                })}
              </span>
            </div>
          </div>

          {/* Distance & Duration */}
          {tour.totalDistance && (
            <div className="grid grid-cols-2 gap-4">
              <Card>
                <CardContent className="pt-4">
                  <div className="flex items-center gap-2">
                    <Car className="h-4 w-4 text-primary" />
                    <div>
                      <p className="text-xs text-muted-foreground">Distance</p>
                      <p className="font-semibold">{tour.totalDistance} km</p>
                    </div>
                  </div>
                </CardContent>
              </Card>
              <Card>
                <CardContent className="pt-4">
                  <div className="flex items-center gap-2">
                    <Clock className="h-4 w-4 text-primary" />
                    <div>
                      <p className="text-xs text-muted-foreground">Est. Duration</p>
                      <p className="font-semibold">{tour.estimatedDuration || "TBD"} min</p>
                    </div>
                  </div>
                </CardContent>
              </Card>
            </div>
          )}

          {/* Properties */}
          <div className="space-y-3">
            <div className="flex items-center gap-2">
              <Home className="h-4 w-4 text-primary" />
              <h3 className="font-semibold">Properties Scheduled</h3>
              <Badge variant="outline">{tourProperties.length}</Badge>
            </div>
            {propertiesLoading ? (
              <div className="animate-pulse space-y-2">
                <div className="h-16 bg-muted rounded" />
                <div className="h-16 bg-muted rounded" />
              </div>
            ) : tourProperties.length > 0 ? (
              <div className="space-y-2">
                {tourProperties.map((prop: any, index: number) => (
                  <Card key={prop.id} className="bg-muted/50">
                    <CardContent className="pt-3">
                      <div className="flex gap-3">
                        <div className="flex h-8 w-8 items-center justify-center rounded bg-primary text-primary-foreground text-sm font-semibold">
                          {index + 1}
                        </div>
                        <div className="flex-1 min-w-0">
                          <p className="font-medium text-sm truncate">{prop.address}</p>
                          <p className="text-xs text-muted-foreground">
                            {prop.bedrooms} bed • {prop.bathrooms} bath • ${Number(prop.price).toLocaleString()}
                          </p>
                        </div>
                      </div>
                    </CardContent>
                  </Card>
                ))}
              </div>
            ) : (
              <p className="text-sm text-muted-foreground">No properties scheduled yet</p>
            )}
          </div>

          {/* Route Optimization Section */}
          <div className="space-y-3 pt-4 border-t">
            <h3 className="font-semibold text-sm">Route Optimization</h3>
            <div className="space-y-2">
              <Label htmlFor="starting-address">Starting Address</Label>
              <GooglePlacesAutocomplete
                apiKey={import.meta.env.VITE_GOOGLE_PLACES_API_KEY}
                inputClassName="w-full px-3 py-2 border border-input rounded-md bg-background text-foreground placeholder-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2"
                placeholder="Enter your starting location"
                onPlaceSelected={(place) => {
                  setStartingAddress(place.formatted_address || "");
                }}
                data-testid="input-starting-address"
              />
            </div>

            {optimizedRoute ? (
              <div className="space-y-3 bg-accent/10 p-3 rounded-lg">
                <div className="grid grid-cols-2 gap-2">
                  <div>
                    <p className="text-xs text-muted-foreground">Total Distance</p>
                    <p className="font-semibold text-sm">{optimizedRoute.totalDistance}</p>
                  </div>
                  <div>
                    <p className="text-xs text-muted-foreground">Total Duration</p>
                    <p className="font-semibold text-sm">{optimizedRoute.totalDuration}</p>
                  </div>
                </div>
                <Button
                  className="w-full bg-primary text-primary-foreground hover:bg-primary/90"
                  onClick={handleStartNavigation}
                  data-testid="button-start-navigation"
                >
                  <Navigation className="h-4 w-4 mr-2" />
                  Open in Google Maps
                </Button>
              </div>
            ) : (
              <Button
                className="w-full bg-accent text-accent-foreground hover:bg-accent/90"
                onClick={handleOptimizeRoute}
                disabled={optimizeRouteMutation.isPending || tourProperties.length === 0}
                data-testid="button-optimize-route"
              >
                {optimizeRouteMutation.isPending ? (
                  <>
                    <Loader className="h-4 w-4 mr-2 animate-spin" />
                    Optimizing...
                  </>
                ) : (
                  <>
                    <MapPin className="h-4 w-4 mr-2" />
                    Optimize Route
                  </>
                )}
              </Button>
            )}
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

