import { useAuth } from "@/hooks/useAuth";
import Header from "@/components/Header";
import MobileNav from "@/components/MobileNav";
import PropertyPhoto from "@/components/PropertyPhoto";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  ArrowLeft,
  Search,
  Home,
  MapPin,
  DollarSign,
  Maximize2,
  Heart,
  X,
  Filter,
  ChevronDown,
} from "lucide-react";
import { useMutation } from "@tanstack/react-query";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import Slider from "rc-slider";
import "rc-slider/assets/index.css";

export default function BrowseAllPropertiesPage() {
  const { user, isAuthenticated } = useAuth();
  const [, setLocation] = useLocation();
  const { toast } = useToast();
  const [searchQuery, setSearchQuery] = useState("");
  const [selectedPropertyId, setSelectedPropertyId] = useState<string | null>(
    null,
  );
  const [shortlistedIds, setShortlistedIds] = useState<Set<string>>(new Set());
  const [bedrooms, setBedrooms] = useState<string>("");
  const [bathrooms, setBathrooms] = useState<string>("");
  const [priceRange, setPriceRange] = useState<[number, number]>([0, 1000000]);
  const [areaRange, setAreaRange] = useState<[number, number]>([0, 10000]);
  const [propertyType, setPropertyType] = useState<string>("");
  const [showFilters, setShowFilters] = useState<boolean>(false);

  const { data: properties = [], isLoading } = useQuery<any[]>({
    queryKey: ["/api/properties"],
    enabled: isAuthenticated,
  });

  const { data: userShortlists = [] } = useQuery<any[]>({
    queryKey: ["/api/shortlists"],
    enabled: isAuthenticated,
  });

  // Update shortlisted IDs when data loads
  useEffect(() => {
    if (userShortlists.length > 0) {
      const ids = new Set(userShortlists.map((s: any) => s.property.id || s.propertyId));
      setShortlistedIds(ids);
    }
  }, [userShortlists]);

  const shortlistMutation = useMutation({
    mutationFn: async (propertyId: string) => {
      return apiRequest("POST", `/api/properties/${propertyId}/shortlist`, {});
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/shortlists"] });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to update shortlist",
        variant: "destructive",
      });
    },
  });

  const removeShortlistMutation = useMutation({
    mutationFn: async (propertyId: string) => {
      return apiRequest("DELETE", `/api/properties/${propertyId}/shortlist`, {});
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/shortlists"] });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to remove from shortlist",
        variant: "destructive",
      });
    },
  });

  const handleShortlist = (propertyId: string) => {
    if (shortlistedIds.has(propertyId)) {
      removeShortlistMutation.mutate(propertyId);
      setShortlistedIds((prev) => {
        const newSet = new Set(prev);
        newSet.delete(propertyId);
        return newSet;
      });
    } else {
      shortlistMutation.mutate(propertyId);
      setShortlistedIds((prev) => {
        const newSet = new Set(prev);
        newSet.add(propertyId);
        return newSet;
      });
    }
  };

  // Filter properties based on search and filters
  const filteredProperties = useMemo(() => {
    return properties.filter((property) => {
      // Search filter
      const searchMatch =
        property.address.toLowerCase().includes(searchQuery.toLowerCase()) ||
        property.city.toLowerCase().includes(searchQuery.toLowerCase()) ||
        property.province.toLowerCase().includes(searchQuery.toLowerCase()) ||
        property.mlsNumber?.toString().includes(searchQuery);

      // Bedrooms filter
      if (bedrooms && property.bedrooms < parseInt(bedrooms)) return false;

      // Bathrooms filter
      if (bathrooms && property.bathrooms < parseInt(bathrooms)) return false;

      // Price range filter
      const price = Number(property.price);
      if (price < priceRange[0] || price > priceRange[1]) return false;

      // Area range filter
      const area = Number(property.area) || 0;
      if (area < areaRange[0] || area > areaRange[1]) return false;

      // Property type filter
      if (propertyType && property.propertyType !== propertyType) return false;

      return searchMatch;
    });
  }, [
    properties,
    searchQuery,
    bedrooms,
    bathrooms,
    priceRange,
    areaRange,
    propertyType,
  ]);

  const hasActiveFilters =
    bedrooms ||
    bathrooms ||
    priceRange[0] > 0 ||
    priceRange[1] < maxPrice ||
    areaRange[0] > 0 ||
    areaRange[1] < maxArea ||
    propertyType;

  const resetFilters = () => {
    setBedrooms("");
    setBathrooms("");
    setPriceRange([0, maxPrice]);
    setAreaRange([0, maxArea]);
    setPropertyType("");
  };

  // Get unique property types
  const propertyTypes = properties
    .map((p) => p.propertyType)
    .filter((type, index, self) => type && self.indexOf(type) === index);

  // Calculate max values for range inputs
  const maxPrice = properties.length > 0 
    ? Math.max(...properties.map((p) => Number(p.price)))
    : 1000000;
  const maxArea = properties.length > 0 
    ? Math.max(...properties.map((p) => Number(p.area) || 0))
    : 10000;

  if (!isAuthenticated) {
    return <div>Loading...</div>;
  }

  return (
    <div className="min-h-screen flex flex-col bg-background">
      <Header userRole="client" upcomingTours={0} shortlistCount={0} />

      <main className="flex-1 overflow-auto">
        <div className="max-w-7xl mx-auto px-3 sm:px-4 lg:px-8 py-4 sm:py-6 lg:py-8">
          {/* Header */}
          <div className="mb-6">
            <Button
              variant="ghost"
              size="sm"
              onClick={() => setLocation("/")}
              className="mb-4"
              data-testid="button-back"
            >
              <ArrowLeft className="h-4 w-4 mr-2" />
              Back
            </Button>

            <h1 className="text-2xl md:text-3xl font-bold mb-2">
              Browse All Properties
            </h1>
            <p className="text-muted-foreground">
              Explore available properties
            </p>
          </div>

          {/* Search Bar with Filter Button */}
          <div className="mb-6">
            <div className="flex gap-2 mb-4">
              <div className="relative flex-1">
                <Search className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
                <Input
                  placeholder="Search by address, city, province, or MLS number..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="pl-10"
                  data-testid="input-search-properties"
                />
              </div>
              <Button
                variant="outline"
                size="icon"
                onClick={() => setShowFilters(!showFilters)}
                data-testid="button-toggle-filters"
              >
                <Filter className="h-4 w-4" />
              </Button>
            </div>

            {/* Collapsible Filters */}
            {showFilters && (
              <Card className="p-4 bg-secondary/30 space-y-4">
                {/* Row 1: Bedrooms, Bathrooms, Property Type */}
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
                  <div>
                    <label className="text-sm font-medium mb-1 block">
                      Min Bedrooms
                    </label>
                    <Input
                      type="number"
                      min="0"
                      placeholder="Any"
                      value={bedrooms}
                      onChange={(e) => setBedrooms(e.target.value)}
                      data-testid="input-bedrooms-filter"
                    />
                  </div>
                  <div>
                    <label className="text-sm font-medium mb-1 block">
                      Min Bathrooms
                    </label>
                    <Input
                      type="number"
                      min="0"
                      step="0.5"
                      placeholder="Any"
                      value={bathrooms}
                      onChange={(e) => setBathrooms(e.target.value)}
                      data-testid="input-bathrooms-filter"
                    />
                  </div>
                  <div>
                    <label className="text-sm font-medium mb-1 block">
                      Property Type
                    </label>
                    <Select value={propertyType} onValueChange={setPropertyType}>
                      <SelectTrigger data-testid="select-property-type-filter">
                        <SelectValue placeholder="All Types" />
                      </SelectTrigger>
                      <SelectContent>
                        {propertyTypes.map((type) => (
                          <SelectItem key={type} value={type}>
                            {type}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                </div>

                {/* Price Range */}
                <div>
                  <label className="text-sm font-medium mb-3 block">
                    Price Range: ${priceRange[0].toLocaleString()} - ${priceRange[1].toLocaleString()}
                  </label>
                  <Slider
                    range
                    min={0}
                    max={maxPrice}
                    value={priceRange}
                    onChange={(value) => setPriceRange(value as [number, number])}
                    step={10000}
                    marks={{
                      0: "$0",
                      [maxPrice]: `$${(maxPrice / 1000000).toFixed(1)}M`,
                    }}
                    data-testid="dual-range-price-filter"
                    className="!bg-secondary"
                    trackStyle={[{ backgroundColor: "hsl(var(--primary))" }]}
                    handleStyle={[
                      { backgroundColor: "hsl(var(--primary))" },
                      { backgroundColor: "hsl(var(--primary))" },
                    ]}
                  />
                  <div className="grid grid-cols-2 gap-2 mt-3">
                    <Input
                      type="number"
                      placeholder="Min"
                      value={priceRange[0]}
                      onChange={(e) => setPriceRange([Number(e.target.value), priceRange[1]])}
                      data-testid="input-price-min-filter"
                    />
                    <Input
                      type="number"
                      placeholder="Max"
                      value={priceRange[1]}
                      onChange={(e) => setPriceRange([priceRange[0], Number(e.target.value)])}
                      data-testid="input-price-max-filter"
                    />
                  </div>
                </div>

                {/* Area Range */}
                <div>
                  <label className="text-sm font-medium mb-3 block">
                    Area Range: {areaRange[0]} - {areaRange[1]}
                  </label>
                  <Slider
                    range
                    min={0}
                    max={maxArea}
                    value={areaRange}
                    onChange={(value) => setAreaRange(value as [number, number])}
                    step={100}
                    marks={{
                      0: "0",
                      [maxArea]: `${(maxArea / 1000).toFixed(0)}k`,
                    }}
                    data-testid="dual-range-area-filter"
                    className="!bg-secondary"
                    trackStyle={[{ backgroundColor: "hsl(var(--primary))" }]}
                    handleStyle={[
                      { backgroundColor: "hsl(var(--primary))" },
                      { backgroundColor: "hsl(var(--primary))" },
                    ]}
                  />
                  <div className="grid grid-cols-2 gap-2 mt-3">
                    <Input
                      type="number"
                      placeholder="Min"
                      value={areaRange[0]}
                      onChange={(e) => setAreaRange([Number(e.target.value), areaRange[1]])}
                      data-testid="input-area-min-filter"
                    />
                    <Input
                      type="number"
                      placeholder="Max"
                      value={areaRange[1]}
                      onChange={(e) => setAreaRange([areaRange[0], Number(e.target.value)])}
                      data-testid="input-area-max-filter"
                    />
                  </div>
                </div>

                {/* Reset Button */}
                {hasActiveFilters && (
                  <div className="flex justify-end pt-2">
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={resetFilters}
                      data-testid="button-reset-filters"
                    >
                      <X className="h-4 w-4 mr-1" />
                      Reset Filters
                    </Button>
                  </div>
                )}
              </Card>
            )}
          </div>

          {/* Properties Grid */}
          {isLoading ? (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6">
              {[1, 2, 3, 4, 5, 6].map((i) => (
                <div key={i} className="animate-pulse">
                  <div className="h-48 bg-muted rounded-lg mb-3"></div>
                  <div className="h-4 bg-muted rounded w-3/4 mb-2"></div>
                  <div className="h-3 bg-muted rounded w-1/2"></div>
                </div>
              ))}
            </div>
          ) : filteredProperties.length === 0 ? (
            <Card>
              <CardContent className="flex flex-col items-center justify-center py-12">
                <Home className="h-12 w-12 text-muted-foreground mb-4" />
                <h3 className="text-lg font-semibold mb-2">
                  No properties found
                </h3>
                <p className="text-muted-foreground text-center">
                  {searchQuery
                    ? "Try adjusting your search filters"
                    : "No properties available"}
                </p>
              </CardContent>
            </Card>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6">
              {filteredProperties.map((property) => (
                <Card
                  key={property.id}
                  className="overflow-hidden hover:shadow-lg transition-shadow cursor-pointer"
                  onClick={() => setSelectedPropertyId(property.id)}
                  data-testid={`property-card-${property.id}`}
                >
                  <div className="relative h-48 overflow-hidden">
                    <PropertyPhoto
                      propertyId={property.id}
                      className="w-full h-full object-cover"
                      showPhotoCount={true}
                      userRole="client"
                    />
                  </div>

                  <CardContent className="p-4">
                    <h3 className="font-semibold mb-1 line-clamp-2">
                      {property.address}
                    </h3>
                    <p className="text-sm text-muted-foreground mb-1">
                      {property.city}, {property.province}
                    </p>
                    {property.mlsNumber && (
                      <p className="text-xs text-muted-foreground mb-3">
                        MLS: {property.mlsNumber}
                      </p>
                    )}

                    {/* Property Stats */}
                    <div className="grid grid-cols-2 gap-2 mb-4 text-sm">
                      <div>
                        <div className="font-semibold text-primary">
                          {property.bedrooms}
                        </div>
                        <div className="text-xs text-muted-foreground">
                          Bedrooms
                        </div>
                      </div>
                      <div>
                        <div className="font-semibold text-primary">
                          {property.bathrooms}
                        </div>
                        <div className="text-xs text-muted-foreground">
                          Bathrooms
                        </div>
                      </div>
                      <div className="col-span-2">
                        <div className="font-semibold text-primary">
                          ${Number(property.price).toLocaleString()}
                        </div>
                        <div className="text-xs text-muted-foreground">
                          Price
                        </div>
                      </div>
                      {property.area && (
                        <div className="col-span-2">
                          <div className="font-semibold text-primary">
                            {property.area}
                          </div>
                          <div className="text-xs text-muted-foreground">
                            Area
                          </div>
                        </div>
                      )}
                    </div>

                    {/* Type Badge */}
                    <div className="mb-3 flex items-center justify-between">
                      <span className="inline-block px-2 py-1 bg-primary/10 text-primary text-xs rounded">
                        {property.propertyType || "Property"}
                      </span>
                      <button
                        onClick={(e) => {
                          e.stopPropagation();
                          handleShortlist(property.id);
                        }}
                        className="p-2 hover:bg-secondary rounded-full transition-colors"
                        data-testid={`button-shortlist-${property.id}`}
                      >
                        <Heart
                          className={`h-5 w-5 ${
                            shortlistedIds.has(property.id)
                              ? "fill-red-500 text-red-500"
                              : "text-muted-foreground"
                          }`}
                        />
                      </button>
                    </div>

                    <Button
                      size="sm"
                      className="w-full"
                      data-testid={`button-view-details-${property.id}`}
                    >
                      View Details
                    </Button>
                  </CardContent>
                </Card>
              ))}
            </div>
          )}

          {/* Results Count */}
          {!isLoading && filteredProperties.length > 0 && (
            <div className="mt-6 text-center text-sm text-muted-foreground">
              Showing {filteredProperties.length} of {properties.length}{" "}
              properties
            </div>
          )}
        </div>
      </main>
    </div>
  );
}

