import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { useLocation } from "wouter";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import PropertyPhoto from "@/components/PropertyPhoto";
import { ChevronLeft, ChevronRight, Home } from "lucide-react";

export default function BrowsePropertiesCarousel() {
  const [, setLocation] = useLocation();
  const [currentIndex, setCurrentIndex] = useState(0);

  // Fetch top 5 properties
  const { data: allProperties = [], isLoading } = useQuery<any[]>({
    queryKey: ["/api/properties"],
  });

  const topProperties = allProperties.slice(0, 5);
  const currentProperty = topProperties[currentIndex] || null;

  const handlePrevious = () => {
    setCurrentIndex((prev) => (prev - 1 + topProperties.length) % topProperties.length);
  };

  const handleNext = () => {
    setCurrentIndex((prev) => (prev + 1) % topProperties.length);
  };

  if (isLoading || topProperties.length === 0) {
    return null;
  }

  return (
    <Card className="mb-6">
      <div className="p-4 sm:p-6 border-b border-border">
        <div className="flex items-center justify-between">
          <h2 className="text-xl font-semibold">Browse Properties</h2>
          <Button
            variant="outline"
            size="sm"
            onClick={() => setLocation("/browse-properties")}
            data-testid="button-browse-more"
          >
            Browse More
          </Button>
        </div>
      </div>

      <CardContent className="p-4 sm:p-6">
        {currentProperty ? (
          <div className="space-y-4">
            {/* Property Photo */}
            <div className="w-full h-64 sm:h-80 rounded-lg overflow-hidden">
              <PropertyPhoto
                propertyId={currentProperty.id}
                className="w-full h-full object-cover"
                showPhotoCount={true}
                userRole="client"
              />
            </div>

            {/* Property Details */}
            <div className="space-y-2">
              <h3 className="text-lg sm:text-xl font-semibold">{currentProperty.address}</h3>
              <p className="text-sm text-muted-foreground">
                {currentProperty.city}, {currentProperty.province} {currentProperty.postalCode}
              </p>

              {/* Stats Grid */}
              <div className="grid grid-cols-4 gap-2 mt-4">
                <div className="text-center">
                  <div className="text-lg sm:text-xl font-bold text-primary">
                    {currentProperty.bedrooms}
                  </div>
                  <div className="text-xs sm:text-sm text-muted-foreground">Beds</div>
                </div>
                <div className="text-center">
                  <div className="text-lg sm:text-xl font-bold text-primary">
                    {currentProperty.bathrooms}
                  </div>
                  <div className="text-xs sm:text-sm text-muted-foreground">Baths</div>
                </div>
                <div className="text-center">
                  <div className="text-lg sm:text-xl font-bold text-primary">
                    ${Number(currentProperty.price).toLocaleString()}
                  </div>
                  <div className="text-xs sm:text-sm text-muted-foreground">Price</div>
                </div>
                <div className="text-center">
                  <div className="text-lg sm:text-xl font-bold text-primary">
                    {currentProperty.area || "N/A"}
                  </div>
                  <div className="text-xs sm:text-sm text-muted-foreground">Area</div>
                </div>
              </div>
            </div>

            {/* Navigation Controls */}
            <div className="flex items-center justify-between mt-6">
              <Button
                variant="outline"
                size="icon"
                onClick={handlePrevious}
                disabled={topProperties.length <= 1}
                data-testid="button-prev-property"
              >
                <ChevronLeft className="h-4 w-4" />
              </Button>

              <div className="flex gap-1">
                {topProperties.map((_, index) => (
                  <div
                    key={index}
                    className={`h-2 rounded-full transition-all ${
                      index === currentIndex ? "bg-primary w-8" : "bg-muted w-2"
                    }`}
                    data-testid={`indicator-${index}`}
                  />
                ))}
              </div>

              <Button
                variant="outline"
                size="icon"
                onClick={handleNext}
                disabled={topProperties.length <= 1}
                data-testid="button-next-property"
              >
                <ChevronRight className="h-4 w-4" />
              </Button>
            </div>

            <p className="text-center text-xs sm:text-sm text-muted-foreground">
              {currentIndex + 1} of {topProperties.length}
            </p>
          </div>
        ) : (
          <div className="text-center py-8">
            <Home className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
            <p className="text-muted-foreground">No properties available</p>
          </div>
        )}
      </CardContent>
    </Card>
  );
}

client/src/pages/ClientToursPage.tsx.content:
import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { useAuth } from "@/hooks/useAuth";
import { useToast } from "@/hooks/use-toast";
import { apiRequest, queryClient } from "@/lib/queryClient";
import type { Tour } from "@shared/schema";
import Header from "@/components/Header";
import MobileNav from "@/components/MobileNav";
import TourRequestModal from "@/components/TourRequestModal";
import { PropertyRatingModal } from "@/components/PropertyRatingModal";
import { PropertyMediaGallery } from "@/components/PropertyMediaGallery";
import TourRemindersManager from "@/components/TourRemindersManager";
import UpcomingTourDetailsModal from "@/components/UpcomingTourDetailsModal";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { 
  Calendar,
  Download,
  Share2,
  Home,
  MapPin,
  Car,
  History,
  Camera,
  Plus,
  Star,
  Clock,
  Bell,
  ArrowLeft
} from "lucide-react";
import { useLocation } from "wouter";

// Component to display a single past tour with properties and ratings
function PastTourCard({ tour, onRateProperty, onViewMedia }: { 
  tour: any; 
  onRateProperty: (propertyId: string, tourId: string, address: string) => void;
  onViewMedia: (property: any, tourId: string, rating: any) => void;
}) {
  // Fetch properties in this tour
  const { data: tourProperties = [], isLoading: propertiesLoading, isError: propertiesError } = useQuery<any[]>({
    queryKey: [`/api/tours/${tour.id}/properties`],
  });

  // Fetch ratings for this tour
  const { data: ratings = [], isLoading: ratingsLoading, isError: ratingsError } = useQuery<any[]>({
    queryKey: [`/api/tours/${tour.id}/ratings`],
  });

  // Merge properties with their ratings
  const propertiesWithRatings = tourProperties.map((tp: any) => {
    const rating = ratings.find((r: any) => r.propertyId === tp.propertyId);
    return {
      ...tp,
      rating,
      hasRating: !!rating && !rating.remindLater,
    };
  });

  return (
    <div 
      className="border border-border rounded-lg p-4"
      data-testid={`past-tour-${tour.id}`}
    >
      <div className="flex items-start justify-between mb-3">
        <div>
          <div className="flex items-center space-x-2 mb-1">
            <span className="font-medium">
              {tour.scheduledDate ? 
                new Date(tour.scheduledDate).toLocaleDateString() : 
                "Date Unknown"
              }
            </span>
            <Badge variant="secondary">
              {tour.status === "completed" ? "Completed" : tour.status}
            </Badge>
          </div>
          <p className="text-sm text-muted-foreground">
            {tour.scheduledDate ? 
              new Date(tour.scheduledDate).toLocaleTimeString([], {
                hour: '2-digit',
                minute: '2-digit'
              }) : "Time Unknown"
            }
          </p>
        </div>
      </div>

      <div className="space-y-2 mb-3">
        <div className="flex items-center text-sm">
          <MapPin className="h-4 w-4 mr-2" />
          <span>{tour.totalDistance ? `${tour.totalDistance} km traveled` : "Distance not recorded"}</span>
        </div>
        <div className="flex items-center text-sm">
          <Clock className="h-4 w-4 mr-2" />
          <span>{tour.estimatedDuration ? `${tour.estimatedDuration} min` : "Duration not recorded"}</span>
        </div>
      </div>

      {/* Properties Viewed */}
      {propertiesLoading || ratingsLoading ? (
        <div className="animate-pulse mt-4 pt-4 border-t">
          <div className="h-4 bg-muted rounded w-1/4 mb-3"></div>
          <div className="h-16 bg-muted rounded"></div>
        </div>
      ) : propertiesError || ratingsError ? (
        <div className="mt-4 pt-4 border-t border-border">
          <p className="text-sm text-destructive">Failed to load property ratings</p>
        </div>
      ) : propertiesWithRatings.length > 0 ? (
        <div className="mt-4 pt-4 border-t border-border">
          <h4 className="font-medium text-sm mb-3">
            Properties Viewed ({propertiesWithRatings.length})
          </h4>
          <div className="space-y-3">
            {propertiesWithRatings.map((property: any) => (
              <div 
                key={property.id}
                className="bg-muted/30 rounded-lg p-3 space-y-2"
                data-testid={`tour-property-${property.id}`}
              >
                <div className="flex items-start justify-between">
                  <div className="flex-1">
                    <p className="font-medium text-sm">{property.address}</p>
                    <p className="text-xs text-muted-foreground">
                      {property.bedrooms} bed • {property.bathrooms} bath • ${Number(property.price).toLocaleString()}
                    </p>
                  </div>
                </div>

                {/* Rating Display or Rate Button */}
                {property.hasRating ? (
                  <div className="space-y-2">
                    <div className="flex items-start gap-3 mt-2 p-2 bg-background rounded border">
                      <div className="flex-1">
                        <div className="flex items-center gap-2 mb-1">
                          <div className="flex">
                            {[1, 2, 3, 4, 5].map((star) => (
                              <Star
                                key={star}
                                className={`h-3 w-3 ${
                                  star <= property.rating.rating
                                    ? "fill-yellow-400 text-yellow-400"
                                    : "text-gray-300"
                                }`}
                              />
                            ))}
                          </div>
                          <Badge 
                            variant="outline" 
                            className="text-xs"
                            data-testid={`rating-category-${property.id}`}
                          >
                            {property.rating.feedbackCategory === 'offer_now' && '🎯 Float Offer'}
                            {property.rating.feedbackCategory === 'hold_later' && '⏸️ Park for Future'}
                            {property.rating.feedbackCategory === 'reject' && '❌ Reject'}
                          </Badge>
                        </div>
                        <p className="text-xs text-muted-foreground">
                          {property.rating.reason}
                        </p>
                        {property.rating.notes && (
                          <p className="text-xs text-muted-foreground mt-1 italic">
                            "{property.rating.notes}"
                          </p>
                        )}
                      </div>
                    </div>
                    <Button
                      size="sm"
                      variant="outline"
                      className="w-full text-xs"
                      onClick={() => onViewMedia(property, tour.id, property.rating)}
                      data-testid={`button-view-media-${property.id}`}
                    >
                      <Camera className="h-3 w-3 mr-1" />
                      View Photos & Documents
                    </Button>
                  </div>
                ) : (
                  <div className="space-y-2">
                    <Button
                      size="sm"
                      variant="outline"
                      className="w-full text-xs bg-primary/5 border-primary/20 text-primary hover:bg-primary/10"
                      onClick={() => onRateProperty(property.propertyId, tour.id, property.address)}
                      data-testid={`button-rate-property-${property.id}`}
                    >
                      <Star className="h-3 w-3 mr-1" />
                      Rate This Property
                    </Button>
                    <Button
                      size="sm"
                      variant="outline"
                      className="w-full text-xs"
                      onClick={() => onViewMedia(property, tour.id, null)}
                      data-testid={`button-view-media-${property.id}`}
                    >
                      <Camera className="h-3 w-3 mr-1" />
                      View Photos & Documents
                    </Button>
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      ) : null}
    </div>
  );
}

export default function ClientToursPage() {
  const { user, isAuthenticated, isLoading } = useAuth();
  const [, setLocation] = useLocation();
  const { toast } = useToast();
  const [showTourRequestModal, setShowTourRequestModal] = useState(false);
  const [showPropertyRatingModal, setShowPropertyRatingModal] = useState(false);
  const [selectedPropertyForRating, setSelectedPropertyForRating] = useState<{
    propertyId: string;
    tourId: string;
    address: string;
  } | null>(null);
  const [showPropertyMediaGallery, setShowPropertyMediaGallery] = useState(false);
  const [selectedPropertyForMedia, setSelectedPropertyForMedia] = useState<{
    property: any;
    tourId: string;
    rating: any;
  } | null>(null);
  const [showTourRemindersDialog, setShowTourRemindersDialog] = useState(false);
  const [selectedTourForReminders, setSelectedTourForReminders] = useState<{
    tourId: string;
    userId: string;
  } | null>(null);
  const [selectedUpcomingTour, setSelectedUpcomingTour] = useState<any | null>(null);
  const [showUpcomingTourDetails, setShowUpcomingTourDetails] = useState(false);

  // Fetch upcoming tours
  const { data: tours = [], isLoading: toursLoading } = useQuery<Tour[]>({
    queryKey: ["/api/tours"],
    enabled: isAuthenticated,
  });

  const upcomingTours = tours.filter((tour: any) => {
    // Exclude cancelled and completed tours
    if (tour.status === "cancelled" || tour.status === "completed") return false;

    // Only show tours with future dates
    const tourDate = new Date(tour.scheduledDate);
    const now = new Date();
    return tourDate > now;
  });

  const pastTours = tours.filter((tour: any) => {
    // Exclude cancelled tours
    if (tour.status === "cancelled") return false;

    const tourDate = new Date(tour.scheduledDate);
    const now = new Date();
    const isPast = tourDate <= now;

    // Show if tour date is past OR status is completed
    return isPast || tour.status === "completed";
  }).sort((a: any, b: any) => new Date(b.scheduledDate).getTime() - new Date(a.scheduledDate).getTime());

  if (!isAuthenticated || isLoading) {
    return null;
  }

  return (
    <div className="min-h-screen flex flex-col bg-background">
      <Header 
        userRole="client" 
        upcomingTours={upcomingTours.length}
        shortlistCount={0}
      />

      <main className="flex-1 overflow-auto">
        <div className="max-w-7xl mx-auto px-3 sm:px-4 lg:px-8 py-4 sm:py-6 lg:py-8">
          <Button
            variant="ghost"
            size="sm"
            onClick={() => setLocation("/")}
            className="mb-4"
            data-testid="button-back"
          >
            <ArrowLeft className="h-4 w-4 mr-2" />
            Back
          </Button>

          <h1 className="text-2xl md:text-3xl font-bold mb-2">Your Tours</h1>
          <p className="text-muted-foreground mb-6">Manage your upcoming and past property tours</p>

          <div className="space-y-6">
            {/* Upcoming Tours */}
            <Card>
              <div className="p-6 border-b border-border">
                <div className="flex items-center justify-between">
                  <h2 className="text-xl font-semibold">Upcoming Tours</h2>
                  <Button 
                    className="bg-primary text-primary-foreground hover:bg-primary/90"
                    onClick={() => setShowTourRequestModal(true)}
                    data-testid="button-request-tour"
                  >
                    <Plus className="h-4 w-4 mr-2" />
                    Request Tour
                  </Button>
                </div>
              </div>

              <CardContent className="p-6">
                {toursLoading ? (
                  <div className="animate-pulse border border-accent/20 bg-accent/5 rounded-lg p-4">
                    <div className="h-4 bg-muted rounded w-1/3 mb-2"></div>
                    <div className="h-3 bg-muted rounded w-1/2 mb-4"></div>
                    <div className="h-3 bg-muted rounded w-2/3"></div>
                  </div>
                ) : upcomingTours.length === 0 ? (
                  <div className="text-center py-8">
                    <Calendar className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
                    <p className="text-muted-foreground">No upcoming tours scheduled</p>
                  </div>
                ) : (
                  <div className="space-y-4">
                    {upcomingTours.map((tour: any) => (
                      <div 
                        key={tour.id} 
                        className="border border-accent/20 bg-accent/5 rounded-lg p-4 cursor-pointer hover:bg-accent/10 transition-colors"
                        onClick={() => {
                          setSelectedUpcomingTour(tour);
                          setShowUpcomingTourDetails(true);
                        }}
                        data-testid={`upcoming-tour-${tour.id}`}
                      >
                        <div className="flex items-start justify-between mb-3">
                          <div>
                            <div className="flex items-center space-x-2 mb-1">
                              <span className="font-medium">
                                {tour.scheduledDate ? 
                                  new Date(tour.scheduledDate).toLocaleDateString() : 
                                  "Date TBD"
                                }
                              </span>
                              <Badge className="bg-accent text-accent-foreground">
                                {tour.status === "scheduled" ? "Confirmed" : tour.status}
                              </Badge>
                            </div>
                            <p className="text-sm text-muted-foreground">
                              {tour.scheduledDate ? 
                                new Date(tour.scheduledDate).toLocaleTimeString([], {
                                  hour: '2-digit',
                                  minute: '2-digit'
                                }) : "Time TBD"
                              }
                            </p>
                          </div>
                        </div>

                        <div className="space-y-2">
                          <div className="flex items-center text-sm">
                            <Home className="h-4 w-4 mr-2" />
                            <span>Properties scheduled (details TBD)</span>
                          </div>
                          <div className="flex items-center text-sm">
                            <MapPin className="h-4 w-4 mr-2" />
                            <span>Areas to be determined</span>
                          </div>
                          <div className="flex items-center text-sm">
                            <Car className="h-4 w-4 mr-2" />
                            <span>
                              {tour.totalDistance ? `~${tour.totalDistance} km total distance` : "Distance TBD"}
                            </span>
                          </div>
                        </div>

                        <div className="mt-4 pt-4 border-t border-accent/20">
                          <div className="flex flex-wrap gap-2">
                            <Button 
                              size="sm" 
                              className="bg-accent text-accent-foreground hover:bg-accent/90"
                              onClick={() => {
                                setSelectedTourForReminders({
                                  tourId: tour.id,
                                  userId: user?.id || "",
                                });
                                setShowTourRemindersDialog(true);
                              }}
                              data-testid={`button-set-reminders-${tour.id}`}
                            >
                              <Bell className="h-4 w-4 mr-1" />
                              Set Reminders
                            </Button>
                            <Button 
                              size="sm" 
                              className="bg-accent text-accent-foreground hover:bg-accent/90"
                              data-testid="button-download-itinerary"
                            >
                              <Download className="h-4 w-4 mr-1" />
                              Download Itinerary
                            </Button>
                            <Button 
                              size="sm" 
                              variant="outline" 
                              className="border-accent text-accent hover:bg-accent/10"
                              data-testid="button-share-with-group"
                            >
                              <Share2 className="h-4 w-4 mr-1" />
                              Share with Group
                            </Button>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </CardContent>
            </Card>

            {/* Past Tours */}
            <Card>
              <div className="p-6 border-b border-border">
                <h2 className="text-xl font-semibold">Past Tours</h2>
              </div>

              <CardContent className="p-6">
                {toursLoading ? (
                  <div className="animate-pulse border border-border rounded-lg p-4">
                    <div className="h-4 bg-muted rounded w-1/3 mb-2"></div>
                    <div className="h-3 bg-muted rounded w-1/2"></div>
                  </div>
                ) : pastTours.length === 0 ? (
                  <div className="text-center py-8">
                    <History className="h-12 w-12 text-muted-foreground mx-auto mb-4" />
                    <p className="text-muted-foreground">No past tours yet</p>
                  </div>
                ) : (
                  <div className="space-y-4">
                    {pastTours.map((tour: any) => (
                      <PastTourCard
                        key={tour.id}
                        tour={tour}
                        onRateProperty={(propertyId, tourId, address) => {
                          setSelectedPropertyForRating({ propertyId, tourId, address });
                          setShowPropertyRatingModal(true);
                        }}
                        onViewMedia={(property, tourId, rating) => {
                          setSelectedPropertyForMedia({ property, tourId, rating });
                          setShowPropertyMediaGallery(true);
                        }}
                      />
                    ))}
                  </div>
                )}
              </CardContent>
            </Card>
          </div>
        </div>
      </main>

      <MobileNav userRole="client" />

      <TourRequestModal 
        isOpen={showTourRequestModal} 
        onClose={() => setShowTourRequestModal(false)} 
      />

      {selectedPropertyForRating && (
        <PropertyRatingModal
          isOpen={showPropertyRatingModal}
          onClose={() => {
            setShowPropertyRatingModal(false);
            setSelectedPropertyForRating(null);
          }}
          propertyId={selectedPropertyForRating.propertyId}
          tourId={selectedPropertyForRating.tourId}
          propertyAddress={selectedPropertyForRating.address}
        />
      )}

      {selectedPropertyForMedia && (
        <PropertyMediaGallery
          open={showPropertyMediaGallery}
          onOpenChange={(open) => {
            setShowPropertyMediaGallery(open);
            if (!open) {
              setSelectedPropertyForMedia(null);
            }
          }}
          propertyId={selectedPropertyForMedia.property.propertyId}
          tourId={selectedPropertyForMedia.tourId}
          property={selectedPropertyForMedia.property}
          rating={selectedPropertyForMedia.rating}
        />
      )}

      {selectedTourForReminders && (
        <TourRemindersManager
          isOpen={showTourRemindersDialog}
          onClose={() => {
            setShowTourRemindersDialog(false);
            setSelectedTourForReminders(null);
          }}
          tourId={selectedTourForReminders.tourId}
          userId={selectedTourForReminders.userId}
        />
      )}

      <UpcomingTourDetailsModal
        isOpen={showUpcomingTourDetails}
        onClose={() => {
          setShowUpcomingTourDetails(false);
          setSelectedUpcomingTour(null);
        }}
        tour={selectedUpcomingTour}
      />
    </div>
  );
}

