import { useQuery } from "@tanstack/react-query";
import { useAuth } from "@/hooks/useAuth";
import Header from "@/components/Header";
import MobileNav from "@/components/MobileNav";
import PropertyPhoto from "@/components/PropertyPhoto";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { ArrowLeft, Home } from "lucide-react";
import { useLocation } from "wouter";

export default function PropertyShortlistsPage() {
  const { user, isAuthenticated } = useAuth();
  const [, setLocation] = useLocation();

  const { data: shortlists = [], isLoading } = useQuery<any[]>({
    queryKey: ["/api/shortlists"],
    enabled: isAuthenticated,
  });

  if (!isAuthenticated) {
    return <div>Loading...</div>;
  }

  return (
    <div className="min-h-screen flex flex-col bg-background">
      <Header userRole="client" upcomingTours={0} shortlistCount={shortlists.length} />
      <MobileNav userRole="client" />

      <main className="flex-1 overflow-auto">
        <div className="max-w-7xl mx-auto px-3 sm:px-4 lg:px-8 py-4 sm:py-6 lg:py-8">
          {/* Header */}
          <div className="mb-6">
            <Button
              variant="ghost"
              size="sm"
              onClick={() => setLocation("/")}
              className="mb-4"
              data-testid="button-back"
            >
              <ArrowLeft className="h-4 w-4 mr-2" />
              Back
            </Button>

            <h1 className="text-2xl md:text-3xl font-bold mb-2">My Shortlisted Properties</h1>
            <p className="text-muted-foreground">Properties you've saved for later</p>
          </div>

          {/* Shortlists Grid */}
          {isLoading ? (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6">
              {[1, 2, 3, 4, 5, 6].map((i) => (
                <div key={i} className="animate-pulse">
                  <div className="h-48 bg-muted rounded-lg mb-3"></div>
                  <div className="h-4 bg-muted rounded w-3/4 mb-2"></div>
                  <div className="h-3 bg-muted rounded w-1/2"></div>
                </div>
              ))}
            </div>
          ) : shortlists.length === 0 ? (
            <Card>
              <CardContent className="flex flex-col items-center justify-center py-12">
                <Home className="h-12 w-12 text-muted-foreground mb-4" />
                <h3 className="text-lg font-semibold mb-2">No shortlisted properties</h3>
                <p className="text-muted-foreground text-center mb-4">
                  Start adding properties to your shortlist to compare later
                </p>
                <Button onClick={() => setLocation("/browse-properties")}>
                  Browse Properties
                </Button>
              </CardContent>
            </Card>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6">
              {shortlists.map((shortlist: any) => (
                <Card
                  key={shortlist.id}
                  className="overflow-hidden hover:shadow-lg transition-shadow"
                  data-testid={`shortlist-card-${shortlist.property.id}`}
                >
                  <div className="relative h-48 overflow-hidden">
                    <PropertyPhoto
                      propertyId={shortlist.property.id}
                      className="w-full h-full object-cover"
                      showPhotoCount={true}
                      userRole="client"
                    />
                  </div>

                  <CardContent className="p-4">
                    <h3 className="font-semibold mb-1 line-clamp-2">{shortlist.property.address}</h3>
                    <p className="text-sm text-muted-foreground mb-1">
                      {shortlist.property.city}, {shortlist.property.province}
                    </p>
                    {shortlist.property.mlsNumber && (
                      <p className="text-xs text-muted-foreground mb-3">
                        MLS: {shortlist.property.mlsNumber}
                      </p>
                    )}

                    {/* Property Stats */}
                    <div className="grid grid-cols-2 gap-2 mb-4 text-sm">
                      <div>
                        <div className="font-semibold text-primary">{shortlist.property.bedrooms}</div>
                        <div className="text-xs text-muted-foreground">Bedrooms</div>
                      </div>
                      <div>
                        <div className="font-semibold text-primary">{shortlist.property.bathrooms}</div>
                        <div className="text-xs text-muted-foreground">Bathrooms</div>
                      </div>
                      <div className="col-span-2">
                        <div className="font-semibold text-primary">
                          ${Number(shortlist.property.price).toLocaleString()}
                        </div>
                        <div className="text-xs text-muted-foreground">Price</div>
                      </div>
                      {shortlist.property.area && (
                        <div className="col-span-2">
                          <div className="font-semibold text-primary">{shortlist.property.area}</div>
                          <div className="text-xs text-muted-foreground">Area</div>
                        </div>
                      )}
                    </div>

                    {/* Type Badge */}
                    <div className="mb-3">
                      <span className="inline-block px-2 py-1 bg-primary/10 text-primary text-xs rounded">
                        {shortlist.property.propertyType || "Property"}
                      </span>
                    </div>

                    <Button size="sm" className="w-full" data-testid="button-view-details">
                      View Details
                    </Button>
                  </CardContent>
                </Card>
              ))}
            </div>
          )}

          {/* Results Count */}
          {!isLoading && shortlists.length > 0 && (
            <div className="mt-6 text-center text-sm text-muted-foreground">
              {shortlists.length} {shortlists.length === 1 ? "property" : "properties"} shortlisted
            </div>
          )}
        </div>
      </main>
    </div>
  );
}
